/* Visual Data Music — DATASET (auto-assembled from per-domain branches). 2313 entries across 14 domains. Loaded before app.js. */
const TYPES={"industry":{"c":"#f78ca0","label":"Industry"},"business":{"c":"#ffd166","label":"Business"},"rights":{"c":"#63e6be","label":"Rights & Law"},"creation":{"c":"#8ecae6","label":"Creation & Composition"},"instruments":{"c":"#ff9e6d","label":"Instruments & Tools"},"production":{"c":"#74c0fc","label":"Recording & Production"},"sound":{"c":"#48cae4","label":"Sound & Technology"},"genres":{"c":"#c084fc","label":"Genres & Styles"},"traditions":{"c":"#d4a373","label":"World Traditions"},"performance":{"c":"#f48fb1","label":"Performance & Live"},"events":{"c":"#ffa8a8","label":"Events & Experiences"},"media":{"c":"#e879f9","label":"Media & Distribution"},"roles":{"c":"#b5b5ff","label":"Roles & Careers"},"education":{"c":"#9be3c0","label":"Education & Scholarship"},"root":{"c":"#ffffff","label":"Music"}};
const CAT=["industry","business","rights","creation","instruments","production","sound","genres","traditions","performance","events","media","roles","education"];
const DATA={"name":"MUSIC","root":true,"children":[{"name":"Industry","type":"industry","v":26,"children":[{"name":"Core Sectors","v":16,"meta":{"def":"The three revenue pillars of the recorded and performed music business, plus adjacent income streams.","note":"Global recorded-music revenue passed US$28bn in the mid-2020s; live and publishing add tens of billions more."},"children":[{"name":"Recorded Music","v":12,"meta":{"def":"The business of capturing, owning and exploiting sound recordings (the 'master' rights).","money":"Consumers and platforms pay for streams/downloads/physical; income splits between label (owns master) and artist per contract."},"children":[{"name":"Streaming Revenue","meta":{"def":"Income from on-demand and radio-style streaming of recordings, now the dominant recorded-music source.","ex":"Spotify, Apple Music, Amazon Music, YouTube Music, Tencent, Deezer","money":"Platform pays a per-stream royalty pool (~55-70%) split by market share to rights-holders, then to artists.","note":"The 'pro-rata' pooled model is contested by 'user-centric' payout advocates."}},{"name":"Download Sales","meta":{"def":"Permanent digital purchase of a track or album as a file.","ex":"iTunes Store, Bandcamp downloads, Beatport, Bleep","money":"One-off purchase, ~70% to rights-holder; a declining format outside DJ and audiophile niches."}},{"name":"Physical Sales","meta":{"def":"Income from tangible formats sold at retail or direct.","ex":"Vinyl LPs, CDs, cassettes, boxsets","money":"Wholesale to retailer then markup to consumer; vinyl has revived to the biggest physical earner.","aka":"Physical goods, hardgoods"}},{"name":"Neighbouring Rights","meta":{"def":"Royalties owed to the performer and master-owner when a recording is played in public or broadcast.","ex":"Radio airplay, TV, bars, gyms collected by SoundExchange (US), PPL (UK)","money":"Broadcasters/venues pay collective societies which distribute 50/50 to performers and master owners.","aka":"Related rights, performance rights in recordings"}}]},{"name":"Music Publishing","v":12,"meta":{"def":"The business of owning and monetising the underlying song (composition and lyrics), distinct from the recording.","money":"Songwriters assign copyright to publishers who license uses and collect royalties, typically splitting 50/50 or better to the writer.","note":"A single song generates two separate copyrights: the composition (publishing) and each master recording of it."},"children":[{"name":"Mechanical Royalties","meta":{"def":"Payment owed to songwriters/publishers each time a song is reproduced on a recording or stream.","ex":"US statutory rate set by the CRB; collected by The MLC, Harry Fox, MCPS","money":"Labels and streaming services pay per reproduction to the composition owner."}},{"name":"Performance Royalties (Compositions)","meta":{"def":"Royalties for the public performance or broadcast of a song's composition.","ex":"Collected by ASCAP, BMI, SESAC, GMR (US); PRS (UK); GEMA (Germany); SACEM (France)","money":"Venues, broadcasters and streamers pay PROs which distribute to writers and publishers.","aka":"PRO royalties"}},{"name":"Synchronisation Licensing","meta":{"def":"Licensing a song for use timed to visual media.","ex":"Film, TV, ads, video games, trailers, TikTok","money":"Producer negotiates an upfront sync fee split between publisher (song) and label (master).","aka":"Sync"}},{"name":"Print Music & Sheet Music","meta":{"def":"Publishing and sale of notated music, songbooks and lyric reprints.","ex":"Hal Leonard, Alfred Music, Musicnotes, choral/band folios","money":"Buyers pay for scores/parts; per-copy royalty to composer/publisher."}},{"name":"Sub-publishing","meta":{"def":"Local publishers appointed to administer and collect a catalogue's rights in foreign territories.","ex":"A US publisher appointing a German sub-publisher to collect GEMA income","money":"Sub-publisher keeps a commission (often 10-25%) and remits the rest.","note":"Essential because collection societies are national."}},{"name":"Catalogue Acquisition","meta":{"def":"Investment funds and majors buying songwriter catalogues as yield-bearing assets.","ex":"Hipgnosis Songs Fund, Primary Wave, Bob Dylan/Springsteen catalogue sales","money":"Buyer pays a multiple of annual royalties (often 15-30x) for future income streams.","note":"Turned song royalties into a mainstream alternative-asset class in the 2020s."}}]},{"name":"Live Music","v":12,"meta":{"def":"The business of staging concerts, tours and festivals and the services around them.","money":"Fans pay for tickets; income splits among artist, promoter, venue and agent after production costs.","note":"For most artists live is now the largest single income source, dwarfing recorded royalties."},"children":[{"name":"Concert Promotion","meta":{"def":"Financing, booking and marketing individual shows and tours, taking the box-office risk.","ex":"Live Nation, AEG Presents, DEAG, regional independent promoters","money":"Promoter guarantees the artist a fee or a split of net box office (e.g. 80/20 or 90/10)."}},{"name":"Booking Agencies","meta":{"def":"Agents who represent artists to secure and negotiate live bookings.","ex":"WME, CAA, UTA, Wasserman, Paradigm (absorbed)","money":"Agent takes ~10% of the artist's live fees."}},{"name":"Venues","meta":{"def":"Physical spaces staging live music, from clubs to stadiums.","ex":"Clubs, theatres, arenas (O2, MSG), stadiums, amphitheatres, sheds","money":"Venue earns rental/hire, ticket rebates, and food/drink; often owns or is owned by promoters."}},{"name":"Festivals","meta":{"def":"Multi-artist, often multi-day live events sold as a single ticket.","ex":"Glastonbury, Coachella, Tomorrowland, Rock am Ring, Fuji Rock","money":"Ticket + sponsorship + concessions fund artist fees and huge production budgets."}},{"name":"Touring Production & Crew","meta":{"def":"The technical and logistical operation that moves and stages a tour.","ex":"Tour managers, FOH/monitor engineers, riggers, backline techs, truckers, caterers","money":"Artist pays crew wages, trucking and staging as tour costs before splits."}},{"name":"Ancillary Live Income","meta":{"def":"Non-ticket revenue captured at live events.","ex":"VIP packages, meet-and-greets, parking, camping, on-site merch","money":"High-margin add-ons increasingly bundled into premium ticket tiers."}}]},{"name":"Merchandising","v":10,"meta":{"def":"The design, manufacture and sale of branded artist and band products.","money":"Fans pay retail; income splits between artist, merch company and, at shows, the venue's cut.","aka":"Merch"},"children":[{"name":"Tour & Venue Merch","meta":{"def":"Products sold at the physical merch stand during shows.","ex":"T-shirts, hoodies, tour posters, patches, event-dated items","money":"Venue typically takes 10-30% of gross merch sales at the stand."}},{"name":"Direct-to-Consumer Merch","meta":{"def":"Artist-branded online stores selling apparel and goods worldwide.","ex":"Shopify stores, Bravado/UMG, Bandcamp merch, Fourthwall","money":"Higher margin than venue sales; artist keeps more after fulfilment fees."}},{"name":"Fashion Collaborations","meta":{"def":"Premium apparel lines co-created with fashion brands or as standalone labels.","ex":"Kanye x Adidas Yeezy, Travis Scott x Nike, Billie Eilish drops","money":"Licensing royalties plus brand equity; blurs music and streetwear industries."}},{"name":"Collectibles & Licensed Goods","meta":{"def":"Niche branded merchandise beyond apparel.","ex":"Funko Pop figures, enamel pins, vinyl toys, mugs, phone cases, lighters","money":"Usually licensed to specialist manufacturers for a royalty."}}]},{"name":"Brand Partnerships & Sync","v":8,"meta":{"def":"Commercial deals placing music and artists into brands, ads and other media.","money":"Brands and producers pay fees for association, endorsement or usage rights."},"children":[{"name":"Endorsements & Sponsorship","meta":{"def":"Brands paying artists to represent products or sponsor tours.","ex":"Pepsi, Red Bull tour sponsorship, instrument endorsement deals","money":"Flat fee or per-activation payment to the artist."}},{"name":"Ad Sync & Bespoke Music","meta":{"def":"Composing or licensing music specifically for advertising.","ex":"Ad agencies, sync houses, jingle/library composers","money":"Sync fee plus, sometimes, a buyout of the recording."}},{"name":"Production Music Libraries","meta":{"def":"Pre-cleared catalogues of music licensed cheaply for media on standard terms.","ex":"Universal Production Music, Audio Network, Epidemic Sound, KPM, De Wolfe","money":"Blanket or per-use licences; often work-for-hire so the library owns everything.","aka":"Library music, stock music, needle-drop"}}]}]},{"name":"Recorded-Music Value Chain","v":14,"meta":{"def":"The sequential stages that turn a song into a product in a listener's hands.","note":"Creation to consumption; digital collapsed several middle stages but physical still runs the full chain."},"children":[{"name":"Creation & A&R","v":10,"meta":{"def":"Finding, signing and developing artists and songs.","aka":"Artists and Repertoire"},"children":[{"name":"A&R Scouting","meta":{"def":"The label function that discovers talent and matches artists with songs and producers.","ex":"Label A&R reps, scouts trawling TikTok/SoundCloud, showcase gigs","money":"Label invests advances hoping to recoup from future sales."}},{"name":"Songwriting & Topline","meta":{"def":"Creating the composition, often in professional co-writing sessions and camps.","ex":"Writing camps, topliners, Max Martin/Ludwig Göransson-style writer-producers","money":"Writers earn publishing splits; session fees for some hired writers."}},{"name":"Demo Production","meta":{"def":"Rough recordings made to pitch a song or secure a deal.","ex":"Bedroom demos, DAW pre-production, spec tracks","money":"Usually self-funded; a gate to advances."}}]},{"name":"Recording & Production","v":12,"meta":{"def":"Capturing and shaping the master recording.","money":"Funded by label advance or self-financed; producers/engineers paid fees plus points."},"children":[{"name":"Recording Studios","meta":{"def":"Facilities equipped for professional multitrack recording.","ex":"Abbey Road, Electric Lady, Capitol, Blackbird, home project studios","money":"Studios charge a day/hourly rate; project studios undercut big rooms."}},{"name":"Producers & Engineers","meta":{"def":"The creative and technical staff who craft and capture the recording.","ex":"Record producers, tracking/mix engineers, vocal producers, programmers","money":"Flat fee and/or 'points' (a % of the master royalty)."}},{"name":"Mixing","meta":{"def":"Balancing recorded tracks into a finished stereo or immersive mix.","ex":"Mix engineers like Serban Ghenea, Manny Marroquin; Dolby Atmos mixes","money":"Per-song mix fee, often several thousand dollars for top mixers."}},{"name":"Mastering","meta":{"def":"Final sonic polish and format-specific preparation of a finished mix.","ex":"Sterling Sound, Gateway, Abbey Road mastering; loudness for streaming","money":"Per-track or per-album fee; separate specialist trade.","note":"Vinyl mastering differs from digital and feeds directly into lacquer cutting."}}]},{"name":"Manufacturing Stage","meta":{"def":"Physical production of records, discs and tapes from the master (see Physical Manufacturing branch).","ex":"Vinyl pressing, CD replication, cassette duplication","money":"Labels pay plants per unit; long lead times constrain vinyl supply."}},{"name":"Distribution Stage","meta":{"def":"Getting finished product and digital files into stores and platforms.","ex":"Physical distributors, digital aggregators (DSP delivery)","money":"Distributor takes a fee or margin; see Distribution & Logistics branch."}},{"name":"Retail Stage","meta":{"def":"Point of sale to the consumer, physical or digital.","ex":"Record shops, big-box chains, streaming storefronts, Bandcamp","money":"Retailer margin on physical; platform revenue share on digital."}},{"name":"Consumption & Data","v":8,"meta":{"def":"The listener's use of the product and the data it generates back up the chain.","note":"Streaming turned consumption into a real-time data feed steering A&R and marketing."},"children":[{"name":"Charts & Certification","meta":{"def":"Measuring sales/streams into ranked charts and sales-award thresholds.","ex":"Billboard Hot 100, Official UK Charts, gold/platinum discs, Luminate data","money":"Chart position drives marketing spend and playlist/radio leverage."}},{"name":"Playlisting & Discovery","meta":{"def":"Editorial and algorithmic placement that drives what listeners hear.","ex":"Spotify RapCaviar, Apple editorial, algorithmic radio, TikTok virality","money":"A key modern promotion battleground; pitching is free but competitive."}}]}]},{"name":"Company Structure","v":14,"meta":{"def":"How the industry is organised by scale of company, from global majors to bedroom self-releasers.","note":"Independents collectively rival the majors in market share when counted together."},"children":[{"name":"The Big Three Majors","v":12,"meta":{"def":"The three multinational conglomerates that dominate recorded music and publishing.","money":"Control roughly two-thirds of the recorded market and own vast catalogues.","aka":"The majors"},"children":[{"name":"Universal Music Group","v":8,"meta":{"def":"The largest major label group, publicly listed and Netherlands/US-based.","ex":"Interscope, Republic, Capitol, Def Jam, Island, Motown, Deutsche Grammophon; UMPG publishing; Bravado merch","note":"Spun out of Vivendi and floated on Euronext Amsterdam in 2021."},"children":[{"name":"UMG Frontline Labels","meta":{"def":"UMG's active artist-signing imprints.","ex":"Interscope Geffen A&M, Republic Records, Capitol Music Group, Def Jam, Island"}},{"name":"Universal Music Publishing Group","meta":{"def":"UMG's publishing arm administering song copyrights.","ex":"Catalogues incl. major pop/rock writers; global sub-publishing network","money":"Collects mechanicals, performance and sync on behalf of writers."}}]},{"name":"Sony Music Entertainment","v":8,"meta":{"def":"The recorded-music arm of Japan's Sony, with a huge separately-run publisher.","ex":"Columbia, RCA, Epic, Arista, Legacy; Sony Music Publishing (ex-EMI); The Orchard distribution","note":"Sony Music Publishing became the world's largest publisher after buying EMI Music Publishing."},"children":[{"name":"Sony Recorded Labels","meta":{"def":"Sony's frontline and catalogue recording imprints.","ex":"Columbia, RCA, Epic, Arista, Legacy Recordings"}},{"name":"Sony Music Publishing","meta":{"def":"The world's largest music publisher, formed by absorbing EMI Music Publishing.","ex":"Leiber & Stoller, Motown, and modern hit catalogues","aka":"formerly Sony/ATV"}}]},{"name":"Warner Music Group","v":8,"meta":{"def":"The smallest of the three majors, US-listed and controlled by Access Industries.","ex":"Atlantic, Warner Records, Elektra, Parlophone; Warner Chappell Music; ADA distribution","note":"Only pure-play major that is publicly traded as a standalone music company."},"children":[{"name":"Warner Recorded Labels","meta":{"def":"WMG's recording imprints.","ex":"Atlantic Records, Warner Records, Elektra, Parlophone, Rhino (catalogue)"}},{"name":"Warner Chappell Music","meta":{"def":"WMG's global publishing company.","ex":"Deep standards catalogue plus contemporary writers","money":"Administers and collects songwriter royalties worldwide."}}]}]},{"name":"Independent Labels","v":12,"meta":{"def":"Labels operating outside the majors, ranging from mini-majors to micro-imprints.","money":"Often use major-owned or independent distributors; typically offer artists higher royalty rates."},"children":[{"name":"Mini-Majors & Large Indies","meta":{"def":"Well-capitalised independents that rival majors on some releases.","ex":"Beggars Group (XL, 4AD, Rough Trade), Concord, BMG, Secretly Group, Kobalt/AWAL","note":"BMG built a rights-management model without traditional distribution overhead."}},{"name":"Genre & Boutique Labels","meta":{"def":"Specialist indies defined by a genre, scene or aesthetic.","ex":"Sub Pop, Stones Throw, Warp, Ninja Tune, Sacred Bones, Numero Group","money":"Small runs, loyal fanbases, strong vinyl and reissue focus."}},{"name":"Label Services Companies","meta":{"def":"Firms providing marketing, distribution and funding while artists keep their masters.","ex":"Kobalt, AWAL, [PIAS], The Orchard, ADA, Believe","money":"Take a service fee/commission rather than owning the copyright.","aka":"Artist services"}}]},{"name":"DIY & Self-Release","v":10,"meta":{"def":"Artists releasing and running their careers without a label.","money":"Artist keeps most revenue but bears all costs and risk.","aka":"Independent artists, unsigned"},"children":[{"name":"Digital Aggregators","meta":{"def":"Services that deliver self-releasing artists' music to streaming platforms.","ex":"DistroKid, TuneCore, CD Baby, Amuse, Ditto, RouteNote","money":"Flat annual fee or a revenue share; artist keeps rights."}},{"name":"Bandcamp Model","meta":{"def":"Direct fan-to-artist sales of digital and physical music and merch.","ex":"Bandcamp, Bandcamp Fridays waiving fees","money":"Artist sets price and keeps ~80-85%; strong for niche and physical."}},{"name":"Bedroom & Netlabels","meta":{"def":"Home-run micro-operations and free/pay-what-you-want online-only labels.","ex":"SoundCloud rappers, netlabels, Patreon-funded artists","money":"Crowdfunding, tips and subscriptions replace advances."}}]}]},{"name":"Physical Manufacturing","v":16,"meta":{"def":"The industrial and craft processes that turn a master into pressed, replicated and duplicated physical media.","note":"Vinyl's revival strained a shrunken plant base, reviving old crafts like lacquer cutting and galvanic plating."},"children":[{"name":"Vinyl Record Pressing","v":14,"meta":{"def":"The multi-stage process of manufacturing vinyl records from a cut master to a finished disc.","money":"Plants charge per unit with steep setup costs and long queues; a fully mechanical, labour-intensive process.","note":"Most presses in use are refurbished machines from the 1970s-80s alongside new Newbilt/WarmTone/Viryl builds."},"children":[{"name":"Lacquer Cutting","meta":{"def":"Cutting the audio as a spiral groove into a lacquer-coated aluminium disc on a lathe.","ex":"Neumann VMS70/80 lathes, SX-74 cutter heads; cutting engineers at Abbey Road, Sterling","note":"MDC in Japan was for years the near-sole maker of blank lacquers; a 2020 fire caused a global shortage.","aka":"Disc mastering, cutting"}},{"name":"DMM (Direct Metal Mastering)","meta":{"def":"Cutting the groove directly into a copper-plated disc, skipping the lacquer stage.","ex":"Neumann DMM lathes; used by some German plants","note":"Avoids lacquer supply issues and can improve high-frequency detail."}},{"name":"Half-Speed Mastering","meta":{"def":"Cutting the lacquer at half the playback speed with the source at half speed for greater high-frequency accuracy.","ex":"Abbey Road Half-Speed, Miles Showell reissues, Mobile Fidelity","money":"Premium reissue selling point at higher price points.","note":"The cutter head has more time per groove cycle, easing high-frequency demands."}},{"name":"Electroforming & Plating","meta":{"def":"Galvanic silvering and nickel plating of the lacquer to create metal parts.","ex":"Silver spray, nickel bath, the 'father'/'mother'/'stamper' three-step process","note":"Turns a soft lacquer into hard metal parts able to press thousands of records.","aka":"Galvanics, plating"}},{"name":"Stampers","meta":{"def":"The final negative nickel plates mounted in the press to stamp grooves into vinyl.","ex":"Stampers derived from the 'mother'; each wears out after ~1,000-2,000 pressings","money":"New stampers must be grown when one wears, adding cost on long runs."}},{"name":"Pressing & Biscuits","meta":{"def":"Compression-moulding a puck ('biscuit') of PVC between two stampers with labels into a disc.","ex":"Hydraulic/automatic presses, ~150-180g PVC pucks, steam heat and water cooling","note":"Labels are baked in dry so as not to smear; edges are trimmed after pressing."}},{"name":"Test Pressings","meta":{"def":"A handful of early pressings sent for approval before the full run.","ex":"Typically 5-20 white-label copies signed off by artist/label","money":"Prized collectibles; a QC checkpoint to catch skips and noise.","aka":"TP, whites"}},{"name":"Dead Wax & Matrix","meta":{"def":"The blank run-out area near the label carrying stamped and hand-etched identifiers.","ex":"Matrix numbers, plant stamps, cutter initials, mastering engineer messages (e.g. 'PORKY')","note":"Collectors read dead-wax codes to identify pressing plant, stamper and edition.","aka":"Run-out groove, matrix"}},{"name":"Coloured & Picture Discs","meta":{"def":"Novelty vinyl variants using coloured, splattered or image-embedded PVC.","ex":"Splatter, marbled, glow-in-dark, picture discs, 'dinked' 7-inches, lathe cuts","money":"Sold at premiums to collectors; picture discs often trade sound quality for looks."}},{"name":"Vinyl Grading & Records","meta":{"def":"Weights, speeds and sizes that define vinyl as a product.","ex":"180g audiophile LP, 12-inch 45rpm, 7-inch single, 10-inch, 33/45/78 rpm","note":"Heavier weight and 45rpm cuts are marketed as higher fidelity."}}]},{"name":"CD & DVD Replication","v":10,"meta":{"def":"Manufacturing optical discs by moulding data pits from a glass master.","money":"Cheap at scale (cents per disc) but with high minimum orders; a mature, declining industry.","note":"Replication (moulded) differs from duplication (burned CD-Rs) used for short runs."},"children":[{"name":"Glass Mastering","meta":{"def":"Laser-etching the data as pits onto a photoresist glass master to create the stamper.","ex":"Laser beam recorders, cleanroom process","note":"The optical equivalent of vinyl's lacquer and plating stages."}},{"name":"Injection Moulding & Metallising","meta":{"def":"Moulding polycarbonate discs from the stamper then sputtering a reflective aluminium layer.","ex":"Polycarbonate pucks, aluminium sputtering, lacquer top-coat","money":"High-speed lines turn out discs in seconds each."}},{"name":"CD-R Duplication","meta":{"def":"Burning short runs onto recordable discs rather than moulding them.","ex":"Tower burners, on-demand runs for indie/promo","money":"Economical below a few hundred units where moulding minimums don't apply."}},{"name":"Optical Formats","meta":{"def":"The family of disc products beyond the standard CD.","ex":"SACD, DVD-Audio, Blu-ray Audio, HDCD, enhanced CD, Minidisc (magneto-optical)","note":"High-res optical formats mostly failed commercially but survive in audiophile niches."}}]},{"name":"Cassette Duplication","v":8,"meta":{"def":"Recording audio onto magnetic tape wound into compact cassette shells.","money":"Very low unit cost and tiny minimums; revived as a cheap collectible for DIY artists.","note":"National Audio Company in the US is a key surviving pancake-tape and duplication supplier."},"children":[{"name":"High-Speed Loop Duplication","meta":{"def":"Copying a master onto pancake tape at many times normal speed, then loading shells.","ex":"Loop-bin duplicators, real-time duplication for audiophile runs","note":"Real-time copying is slower but prized for fidelity by tape enthusiasts."}},{"name":"Shells & Tape Stock","meta":{"def":"The physical cassette housing and the magnetic tape formulation inside.","ex":"Type I ferric, Type II chrome, C-30/C-60/C-90 lengths, coloured shells","money":"Fresh chrome/ferric stock is scarce; some duplicators recycle or make their own."}}]},{"name":"Packaging & Print","v":12,"meta":{"def":"The sleeves, cases, inserts and printed materials that package physical music.","money":"Print and packaging can rival pressing cost, especially on deluxe editions.","aka":"Print & finishing"},"children":[{"name":"Jewel Cases & Digipaks","meta":{"def":"The plastic and card housings for CDs.","ex":"Standard jewel case, slimline, digipak, digisleeve, O-card","note":"Digipaks and card sleeves replaced brittle jewel cases for eco and cost reasons."}},{"name":"Gatefold Sleeves","meta":{"def":"A double LP jacket that folds open like a book, allowing large artwork and multiple discs.","ex":"Classic prog and concept-album gatefolds; tip-on jackets with wrapped edges","money":"More board and gluing labour than a single sleeve; a premium format."}},{"name":"Inner Sleeves & Inserts","meta":{"def":"The protective and informational materials inside a record jacket.","ex":"Poly-lined anti-static inners, printed lyric inners, posters, download cards, obi strips","note":"Japanese obi strips are collectible bands wrapped around the jacket spine."}},{"name":"Jacket Printing & Finishing","meta":{"def":"The printing crafts applied to sleeves and packaging.","ex":"Offset litho, spot UV, foil blocking, embossing, tip-on jackets, matte/gloss lamination","money":"Special finishes drive up deluxe-edition retail prices."}},{"name":"Boxsets & Deluxe Editions","meta":{"def":"Elaborate multi-format collector packages bundling extras.","ex":"Numbered boxsets, hardback book editions, bonus 7-inches, art prints","money":"High-margin superfan products; a growth area amid streaming's low unit value."}}]}]},{"name":"Physical Formats as Products","v":12,"meta":{"def":"The tangible media formats treated as distinct consumer products across history.","note":"Formats define pricing tiers, collectability and the shape of the manufacturing supply chain."},"children":[{"name":"Vinyl Formats","v":8,"meta":{"def":"The range of vinyl products sold to consumers."},"children":[{"name":"LP Album","meta":{"def":"The 12-inch 33rpm long-play album, the flagship vinyl product.","ex":"Standard, 180g, 45rpm double, half-speed remaster editions","money":"The best-selling physical format of the streaming era."}},{"name":"7-inch Single","meta":{"def":"The small 45rpm record historically used for singles.","ex":"A-side/B-side singles, jukebox pressings, flexi giveaways","note":"Large-hole 'dinked' 7-inches for jukeboxes are a collector variant."}},{"name":"12-inch Single","meta":{"def":"A single-track-per-side 12-inch cut loud for club play.","ex":"Dance/remix maxi-singles, DJ promos, dubplates","note":"The wider groove spacing allows higher volume and bass for DJs."}}]},{"name":"Tape & Optical Products","v":8,"meta":{"def":"Consumer tape and disc formats sold as products."},"children":[{"name":"Compact Cassette","meta":{"def":"The analogue tape format, revived as a cheap collectible.","ex":"Album cassettes, limited coloured shells, mixtapes","money":"Low price and novelty appeal to younger buyers and DIY acts."}},{"name":"Compact Disc","meta":{"def":"The 12cm optical audio disc, still dominant in some markets.","ex":"Album CD, maxi-CD single, enhanced CD","note":"Remains huge in Japan and Germany even as it declines elsewhere."}},{"name":"Legacy & Niche Formats","meta":{"def":"Obsolete or specialist physical formats with collector value.","ex":"8-track cartridge, MiniDisc, DAT, reel-to-reel, shellac 78s, flexi-discs","note":"Reel-to-reel tape releases are a tiny ultra-audiophile market."}}]}]},{"name":"Distribution & Logistics","v":14,"meta":{"def":"The companies and systems that move music (physical and digital) from maker to seller.","money":"Distributors take a margin or fee and often provide financing and marketing."},"children":[{"name":"Physical Distribution","v":10,"meta":{"def":"Warehousing, selling-in and shipping of physical product to retail.","money":"Distributor buys wholesale or takes consignment, marking up to retailers."},"children":[{"name":"Major-Owned Distributors","meta":{"def":"The majors' in-house physical and digital distribution arms.","ex":"Universal's distribution, Sony's RED/The Orchard, Warner's ADA","money":"Carry own labels plus distributed indie clients for a fee."}},{"name":"Independent Distributors","meta":{"def":"Distributors serving indie labels and shops outside the majors.","ex":"Redeye, Secretly Distribution, Forte, Cargo, Kudos, Bertus","note":"Vital lifeline connecting small labels to record shops."}},{"name":"One-Stops & Wholesalers","meta":{"def":"Intermediaries that aggregate many labels' catalogues so shops can order from one source.","ex":"AMPED, Alliance Entertainment, Baker & Taylor (historic)","money":"Stock a broad catalogue; shops trade slightly higher cost for convenience.","aka":"One-stop"}},{"name":"Fulfilment & Logistics","meta":{"def":"Warehousing, pick-pack and shipping operations behind physical and D2C sales.","ex":"3PL warehouses, Bandcamp/Shopify fulfilment partners, freight forwarders","money":"Per-order and storage fees; a major cost in D2C merch and vinyl."}}]},{"name":"Digital Distribution","v":10,"meta":{"def":"Delivery of audio files and metadata to streaming and download platforms worldwide.","money":"Aggregators charge fees or revenue shares to place tracks on DSPs."},"children":[{"name":"DSP Delivery & Aggregators","meta":{"def":"Firms that ingest releases and deliver them to all digital service providers.","ex":"Believe, The Orchard, DistroKid, TuneCore, Symphonic, FUGA","money":"Fee per release or commission on royalties collected."}},{"name":"Metadata & Delivery Standards","meta":{"def":"The identifiers and data formats that make tracks findable and payable.","ex":"ISRC (recording), ISWC (composition), UPC/EAN, DDEX messaging","note":"Bad metadata causes 'black-box' unmatched royalties worth hundreds of millions.","aka":"Rights data"}},{"name":"Content Delivery Networks","meta":{"def":"The internet infrastructure that streams audio to listeners at scale.","ex":"CDN edge servers, transcoding to Ogg/AAC, adaptive bitrate","note":"Invisible plumbing that replaced physical logistics for streaming."}}]}]},{"name":"Retail","v":12,"meta":{"def":"The channels where consumers actually buy or subscribe to music.","money":"Retail margin on physical goods; platform revenue share on digital access."},"children":[{"name":"Independent Record Shops","v":8,"meta":{"def":"Specialist bricks-and-mortar stores selling vinyl, CDs and culture.","money":"Thin margins; sustained by curation, community and events."},"children":[{"name":"Local Record Stores","meta":{"def":"Neighbourhood shops mixing new and used stock.","ex":"Rough Trade, Amoeba Music, Sister Ray, Reckless Records","note":"Record Store Day exclusives are a key annual sales spike."}},{"name":"Second-Hand & Rarities","meta":{"def":"Dealers in used, rare and collectible records.","ex":"Discogs marketplace, crate-digging shops, record fairs","money":"Value driven by pressing, condition and scarcity; graded to Goldmine standard."}}]},{"name":"Big-Box & Chain Retail","meta":{"def":"Mass-market general retailers stocking hit music at low margin as footfall drivers.","ex":"Walmart, Target, HMV, FNAC, Amazon (physical), supermarkets","money":"Loss-leader pricing on chart titles; exclusive coloured-vinyl variants."}},{"name":"Direct-to-Consumer & D2C","meta":{"def":"Artists and labels selling straight to fans, capturing full margin and data.","ex":"Bandcamp, artist Shopify stores, label webshops, superfan bundles","money":"Higher margin and first-party fan data; bundles vinyl with tickets/merch."}},{"name":"Streaming Storefronts","meta":{"def":"The subscription and ad-supported platforms that are now the primary 'retail' of music.","ex":"Spotify, Apple Music, Amazon, YouTube, Tidal, Deezer, Tencent, NetEase","money":"Subscription/ad revenue pooled and paid out per stream to rights-holders."}}]},{"name":"Trade Bodies & Collective Management","v":14,"meta":{"def":"The associations, societies and regulators that represent industry interests and administer rights.","note":"They lobby, litigate piracy, set standards, certify sales and collect and distribute royalties."},"children":[{"name":"Recorded-Music Trade Associations","v":10,"meta":{"def":"Bodies representing record labels' commercial and legal interests.","money":"Funded by member label dues; run anti-piracy and certification programmes."},"children":[{"name":"RIAA","meta":{"def":"The Recording Industry Association of America, representing US labels.","ex":"Runs gold/platinum certification, anti-piracy litigation, US lobbying","aka":"Recording Industry Association of America"}},{"name":"IFPI","meta":{"def":"The global federation of the recording industry, coordinating international policy and anti-piracy.","ex":"Publishes the Global Music Report; issues ISRC standard","aka":"International Federation of the Phonographic Industry"}},{"name":"BPI","meta":{"def":"The British record-industry body, running the BRIT Awards and UK certifications.","ex":"BRIT Certified silver/gold/platinum; Mercury Prize; BRIT Awards","aka":"British Phonographic Industry"}},{"name":"A2IM","meta":{"def":"The American Association of Independent Music, the US indie-label trade body.","ex":"Libera Awards, indie advocacy, DSP negotiations","aka":"American Association of Independent Music"}}]},{"name":"Rights & Licensing Collectives","v":10,"meta":{"def":"Organisations that license rights on behalf of many owners and distribute royalties.","money":"Take a small administration fee before paying members.","aka":"CMOs, collecting societies"},"children":[{"name":"Merlin","meta":{"def":"The global digital-licensing agency that negotiates DSP deals for independents collectively.","ex":"Represents thousands of indie labels/distributors in Spotify/Apple deals","money":"Gives indies major-scale bargaining power with platforms.","aka":"Merlin Network"}},{"name":"Performance Rights Organisations","meta":{"def":"Societies collecting public-performance royalties for songwriters and publishers.","ex":"ASCAP, BMI, SESAC, GMR, PRS, GEMA, SACEM, JASRAC","money":"License venues, broadcasters and streamers with blanket licences."}},{"name":"Mechanical Collectives","meta":{"def":"Bodies that collect and distribute mechanical reproduction royalties.","ex":"The MLC (US), Harry Fox Agency, MCPS (UK)","money":"The MLC was created by the US Music Modernization Act to pay streaming mechanicals."}},{"name":"Neighbouring-Rights Societies","meta":{"def":"Collectives paying performers and masters for broadcast and public performance.","ex":"SoundExchange (US digital), PPL (UK), GVL (Germany)","money":"Distribute broadcaster/venue fees 50/50 to performers and labels."}}]}]},{"name":"Markets by Region","v":12,"meta":{"def":"The geography of the recorded-music market, ranked and characterised by region.","note":"The US remains the largest single market; Asia and Latin America are fastest-growing."},"children":[{"name":"North America","meta":{"def":"The largest recorded-music region, led by the United States.","ex":"US (#1 market), Canada; Nashville, LA, New York industry hubs","money":"Streaming-dominant with a strong vinyl revival."}},{"name":"Europe","meta":{"def":"A large mature market spanning strong physical and streaming economies.","ex":"UK, Germany (CD-strong), France, Nordics (streaming pioneers)","note":"The Nordics were early streaming adopters via Spotify's Swedish origin."}},{"name":"Asia-Pacific","v":8,"meta":{"def":"The largest and fastest-growing regional bloc, diverse across markets."},"children":[{"name":"Japan","meta":{"def":"A uniquely physical-heavy market and long the world's #2.","ex":"CD singles, handshake events, Oricon charts, obi strips","money":"Physical and collector culture keeps CDs central."}},{"name":"South Korea & K-pop Export","meta":{"def":"A market built around idol-group album bundling and global fandom economics.","ex":"Photocards, versioned albums, HYBE, SM, JYP, YG","money":"Superfan bundling drives huge physical 'album' sales counted as units."}},{"name":"China","meta":{"def":"A vast, fast-growing streaming market shaped by a few super-apps.","ex":"Tencent Music (QQ Music, Kugou, Kuwo), NetEase Cloud Music","note":"Digital 'virtual album' sales and fan tipping are large revenue forms."}}]},{"name":"Latin America","meta":{"def":"A high-growth streaming region driving global Latin-genre expansion.","ex":"Brazil, Mexico; reggaeton and regional Mexican global surge","money":"Streaming-led growth with rising ad and subscription uptake."}},{"name":"Africa & Middle East","meta":{"def":"Emerging markets with booming local scenes and mobile-first consumption.","ex":"Nigeria/Afrobeats, South Africa/Amapiano, MENA streaming (Anghami)","note":"Afrobeats' global rise made Nigeria a strategic major-label territory."}}]},{"name":"Instrument-Manufacturing Industry","v":14,"meta":{"def":"The industry that designs and builds musical instruments and their components.","money":"Manufacturers sell to distributors, dealers and direct; endorsement deals seed pro use.","aka":"MI industry, musical instruments"},"children":[{"name":"Fretted & Guitars","v":10,"meta":{"def":"Makers of guitars, basses and related fretted instruments and their parts."},"children":[{"name":"Electric Guitar & Bass Makers","meta":{"def":"Firms building solid- and semi-hollow electric guitars and basses.","ex":"Fender, Gibson, Ibanez, PRS, Music Man, Rickenbacker","money":"Tiered brands (e.g. Fender/Squier) span pro to entry price points."}},{"name":"Acoustic Guitar Makers","meta":{"def":"Builders of steel- and nylon-string acoustic guitars.","ex":"Martin, Taylor, Gibson acoustics, Yamaha, Cordoba","note":"Tonewood sourcing is regulated under CITES for rosewood/ebony."}},{"name":"Luthiery & Custom Shops","meta":{"def":"Hand-built and bespoke instrument crafts and repair.","ex":"Custom-shop guitars, boutique luthiers, violin/cello makers","money":"High-margin, low-volume; long waiting lists for master builders."}},{"name":"Strings, Pickups & Hardware","meta":{"def":"The components and consumables ecosystem around fretted instruments.","ex":"D'Addario, Ernie Ball strings; Seymour Duncan, EMG pickups; tuners, bridges","money":"Recurring consumable revenue (strings) plus upgrade parts."}}]},{"name":"Keyboards & Electronic Instruments","v":8,"meta":{"def":"Makers of pianos, synthesizers, drum machines and controllers."},"children":[{"name":"Pianos","meta":{"def":"Acoustic grand and upright piano manufacturers.","ex":"Steinway & Sons, Yamaha, Kawai, Bösendorfer, Fazioli","money":"Concert grands are ultra-premium; digital pianos serve the mass market."}},{"name":"Synthesizers & Drum Machines","meta":{"def":"Electronic sound-generating instruments and grooveboxes.","ex":"Moog, Roland, Korg, Sequential, Elektron, classic TR-808/TB-303","note":"Vintage 808/303 units command collector prices that spawned reissues."}},{"name":"MIDI Controllers & Software Instruments","meta":{"def":"Control surfaces and virtual instruments driving modern production.","ex":"Akai MPC, Native Instruments Komplete, Ableton Push, VST plugins","money":"Software instruments and sample libraries are a fast-growing subsector."}}]},{"name":"Percussion, Brass & Orchestral","v":8,"meta":{"def":"Makers of drums, cymbals, wind, brass and orchestral instruments."},"children":[{"name":"Drums & Cymbals","meta":{"def":"Manufacturers of drum kits, hardware and cymbals.","ex":"DW, Pearl, Tama, Ludwig; Zildjian, Sabian, Meinl cymbals","note":"Zildjian's cymbal alloy is a centuries-old family secret."}},{"name":"Brass & Woodwind","meta":{"def":"Builders of trumpets, saxophones, clarinets, flutes and more.","ex":"Yamaha, Bach, Selmer, Buffet Crampon, Conn-Selmer","money":"Student to professional tiers; strong education-market sales."}},{"name":"Orchestral Strings","meta":{"def":"Makers of violins, violas, cellos and double basses.","ex":"Factory-made student instruments to master-crafted and antique fine instruments","note":"Antique Cremonese violins (Stradivari, Guarneri) trade as investment assets."}}]}]},{"name":"Pro-Audio & PA Industry","v":12,"meta":{"def":"The industry supplying recording, mixing and live-sound equipment and services.","money":"Sells to studios, venues, touring companies, broadcasters and creators.","aka":"Pro audio, MI/pro-audio"},"children":[{"name":"Studio & Recording Gear","v":10,"meta":{"def":"Equipment used to capture and mix recordings."},"children":[{"name":"Microphones","meta":{"def":"Transducers that capture sound for recording and live use.","ex":"Neumann, Shure SM57/58, AKG, Sennheiser, Royer ribbons","money":"Vintage tube mics (e.g. U47) trade at collector prices."}},{"name":"Consoles & Outboard","meta":{"def":"Mixing desks and rack processors central to studio signal flow.","ex":"SSL, Neve, API consoles; 1176, LA-2A, Pultec outboard","note":"Classic Neve/API preamps are prized and endlessly cloned."}},{"name":"DAWs & Interfaces","meta":{"def":"Software and hardware that host digital recording.","ex":"Pro Tools, Logic, Ableton Live, Cubase; Universal Audio, RME interfaces","money":"Subscription and perpetual-licence software plus hardware sales."}},{"name":"Monitors & Acoustics","meta":{"def":"Studio loudspeakers and room treatment for accurate monitoring.","ex":"Yamaha NS-10, Genelec, ADAM Audio; bass traps, diffusers","note":"The NS-10 became an industry reference despite modest looks."}}]},{"name":"Live Sound & PA Systems","v":10,"meta":{"def":"Amplification and loudspeaker systems for live events."},"children":[{"name":"Line-Array PA","meta":{"def":"Vertically-arrayed loudspeaker systems that cover large audiences evenly.","ex":"L-Acoustics, d&b audiotechnik, Meyer Sound, JBL VTX","money":"Bought by rental/production companies who hire them to tours."}},{"name":"Amplifiers & Backline","meta":{"def":"Instrument amplification used on stage.","ex":"Marshall, Fender, Ampeg, Mesa/Boogie; guitar/bass cabs","aka":"Backline"}},{"name":"Mixing & Signal Processing","meta":{"def":"Live consoles and processing that mix and route stage audio.","ex":"DiGiCo, Avid VENUE, Midas, Yamaha CL/QL digital desks","money":"Digital consoles with recallable scenes now standard on tours."}},{"name":"Stage & Lighting Rigging","meta":{"def":"The structural, lighting and effects systems around live sound.","ex":"Truss, motors, moving-head lights, lasers, IEM/wireless systems","money":"Supplied by production-rental firms as part of a touring package."}}]}]},{"name":"Ticketing Industry","v":10,"meta":{"def":"The systems and companies that sell and control access to live events.","money":"Fees on face value (service, facility, processing) are a major revenue layer.","note":"Vertical integration of promoter, venue and ticketer draws antitrust scrutiny."},"children":[{"name":"Primary Ticketing","meta":{"def":"The initial authorised sale of tickets from the venue/promoter to fans.","ex":"Ticketmaster, AXS, See Tickets, Eventim, DICE, Eventbrite","money":"Charges booking and service fees on top of face value; splits rebates with venues."}},{"name":"Secondary & Resale","meta":{"def":"Resale of tickets, officially or on the grey/black market.","ex":"StubHub, Viagogo, verified resale, touts/scalpers","money":"Marketplace takes commission from buyer and seller; contested by fans and regulators."}},{"name":"Anti-Scalping & Access Control","meta":{"def":"Technologies and rules to curb touting and manage entry.","ex":"Dynamic pricing, paperless/mobile tickets, ID-linked resale caps, verified fan","note":"Dynamic 'platinum' pricing sparked backlash for pushing face values sky-high."}},{"name":"Box Office & Settlement","meta":{"def":"The accounting process reconciling ticket income after a show.","ex":"Manifest, deals/settlement sheets, comps, holds, kills","money":"Determines the artist's payout after guarantees, costs and splits."}}]},{"name":"Bootleg & Counterfeit Shadow Economy","v":12,"meta":{"def":"The illicit and grey-market economy of unauthorised recordings, goods and access.","money":"Diverts revenue from rights-holders; fought by IFPI and trade bodies.","aka":"Piracy, grey market"},"children":[{"name":"Unofficial Recordings","v":8,"meta":{"def":"Recordings released without the rights-holder's authorisation."},"children":[{"name":"Live Bootlegs","meta":{"def":"Unauthorised recordings of concerts sold or traded among fans.","ex":"Audience tapes, soundboard leaks, tour bootleg vinyl","note":"Some acts (e.g. the Grateful Dead) tolerated 'taper' culture."}},{"name":"Counterfeit Pressings","meta":{"def":"Illegal copies of official releases packaged to imitate the real product.","ex":"Fake 'coloured vinyl' reissues, counterfeit CDs, replica jackets","money":"Undercut official price; degrade artist revenue and quality reputation."}},{"name":"Leaks & Pre-Release Piracy","meta":{"def":"Unreleased material escaping before official launch.","ex":"Studio leaks, hacked cloud files, watermarked promo leaks","note":"Forensic audio watermarking is used to trace the leak source."}}]},{"name":"Digital Piracy","v":8,"meta":{"def":"Unauthorised online copying and access to recordings."},"children":[{"name":"File-Sharing & Torrents","meta":{"def":"Peer-to-peer distribution of copyrighted music.","ex":"Napster (historic), BitTorrent trackers, private trackers","note":"Napster's 1999 rise triggered the industry's streaming pivot."}},{"name":"Stream-Ripping","meta":{"def":"Extracting downloadable files from streaming/video services.","ex":"YouTube-to-MP3 sites, ripping apps","money":"Now the dominant form of music piracy, targeted by IFPI takedowns."}},{"name":"Stream Manipulation","meta":{"def":"Artificially inflating streams to steal royalty payouts or chart position.","ex":"Bot farms, click farms, fake artist/'ghost' tracks, playlist fraud","money":"Siphons the pooled royalty pot from legitimate artists.","aka":"Streaming fraud"}}]},{"name":"Counterfeit Merch & Goods","meta":{"def":"Fake artist-branded apparel and products sold outside official channels.","ex":"Bootleg tour tees sold outside venues, counterfeit online stores","money":"Bootleggers pay no royalty; venues police the surrounding streets on show days."}}]}]},{"name":"Business","type":"business","v":26,"children":[{"name":"Record Labels","v":14,"meta":{"def":"Companies that finance, produce, distribute and market recorded music in exchange for rights and revenue.","ex":"Universal Music Group, Sony Music, XL Recordings, Sub Pop","aka":"Labels, record companies","money":"Labels invest upfront (advances, production, marketing) and recoup from artist royalties, keeping the master-recording income."},"children":[{"name":"Major Labels","v":8,"meta":{"def":"The three globally dominant, multinational, publicly-traded music corporations that control most recorded-music market share.","ex":"Universal Music Group, Sony Music Entertainment, Warner Music Group","aka":"The Big Three, majors","money":"Collect ~70% of global recorded revenue; fund large advances and offset flops with hit portfolios.","note":"Once the 'Big Six', consolidated via EMI's 2012 breakup."}},{"name":"Major Frontline Divisions","v":6,"meta":{"def":"The flagship active-roster labels owned by a major, distinct from catalogue units.","ex":"Interscope, Def Jam, Columbia, Atlantic, Capitol","aka":"Frontline labels","money":"Operate on parent balance sheet; profit rolls up to the major's group accounts."}},{"name":"Independent Labels","v":6,"meta":{"def":"Labels not owned or controlled by a major, funding releases from their own capital.","ex":"Merge, Domino, Ninja Tune, Stones Throw, Dischord","aka":"Indies","money":"Self-financed; often 50/50 profit-share deals rather than low royalty rates.","note":"Trade body: Merlin (digital licensing) and A2IM in the US."},"children":[{"name":"Fully-Independent Label","v":3,"meta":{"def":"An indie financed and distributed entirely outside major-label ownership.","ex":"Dischord, Sub Pop (early), Constellation","aka":"True indie","money":"Self-funds and self-distributes; keeps all masters and profit."}},{"name":"Major-Distributed Independent","v":3,"meta":{"def":"An indie that stays independent but uses a major's distribution network.","ex":"Indies via ADA (Warner) or The Orchard (Sony)","aka":"Distributed indie","money":"Distributor takes a fee; label keeps ownership and creative control.","note":"Blurs the indie/major line at the distribution level."}},{"name":"Artist-Owned Label","v":3,"meta":{"def":"An independent label founded and owned by the artists who release on it.","ex":"Jack White's Third Man, Adele-style self-owned masters, Chance's model","aka":"Artist-run label","money":"Artists retain masters and the label's profit share entirely."}}]},{"name":"Imprint","v":4,"meta":{"def":"A branded label name that sits under a larger label's infrastructure, often run by an artist or executive.","ex":"GOOD Music (Def Jam), Roc-A-Fella, OVO Sound, Cash Money","aka":"Vanity imprint","money":"Parent funds and distributes; imprint head earns an override/profit-share on signings."}},{"name":"Vanity Label","v":3,"meta":{"def":"A label name granted to a star artist as a prestige/creative vehicle, backed fully by the parent.","ex":"Maverick (Madonna/Warner), Nothing Records (Trent Reznor)","aka":"Vanity imprint deal","money":"Artist gets a label logo and A&R budget; parent recoups from the imprint's releases first."}},{"name":"Sublabel","v":3,"meta":{"def":"A specialised label operating beneath a parent to serve a distinct genre or sub-market.","ex":"Warp's Arkestra, R&S's Apollo, Ostgut Ton's Unterton","aka":"Sub-label","money":"Shares parent's back office; P&L consolidated into the parent label."}},{"name":"Distributed Label","v":3,"meta":{"def":"An independent label that keeps ownership but pays a bigger company to distribute its releases.","ex":"Labels via [PIAS], Secretly Distribution, The Orchard, ADA","aka":"P&D partner label","money":"Distributor takes a distribution fee (10-30%); label keeps masters and the rest."}},{"name":"Production House Label","v":3,"meta":{"def":"A production company that records artists then upstreams finished masters to a major for release.","ex":"Bad Boy, Roc Nation, Top Dawg Entertainment (TDE)","aka":"P&D upstream, production deal label","money":"Delivers masters to a major for a licence fee/profit-share; major handles marketing and distribution."}},{"name":"DIY / Self-Release","v":3,"meta":{"def":"An artist acting as their own label, releasing directly with no label partner.","ex":"Chance the Rapper, Bandcamp self-releases, DistroKid uploads","aka":"Independent artist, unsigned, artist-owned","money":"Artist keeps ~80-100% of net income after a distributor's flat fee or small cut."}},{"name":"Boutique Label","v":3,"meta":{"def":"A small, tightly-curated label built around a distinct aesthetic and modest roster.","ex":"4AD (early), Erased Tapes, Text Records, Awesome Tapes From Africa","aka":"Curated indie","money":"Low overhead, small pressings; margin from vinyl and loyal fanbase D2C."}},{"name":"Reissue / Archival Label","v":3,"meta":{"def":"A label that specialises in licensing, restoring and re-releasing older or obscure recordings.","ex":"Numero Group, Light in the Attic, Rhino, Soul Jazz, Now-Again","aka":"Reissue imprint, catalogue label","money":"Licenses old masters for an advance/royalty and profits from collectors and sync placement."}},{"name":"Catalogue Division","v":3,"meta":{"def":"A major's unit that manages back-catalogue exploitation and legacy-artist repackaging.","ex":"UMe (Universal Music Enterprises), Legacy Recordings (Sony), Rhino (WMG)","aka":"Legacy division","money":"High-margin: no new recording costs, revenue from streaming, box sets, syncs and anniversaries."}},{"name":"Christian / Gospel Label","v":3,"meta":{"def":"A faith-market label serving CCM, worship and gospel through dedicated retail and radio.","ex":"Capitol CMG, Provident, Fair Trade Services, Motown Gospel","aka":"CCM label","money":"Church retail, worship-song royalties and Christian radio; strong sync into faith media."}},{"name":"Library / Production-Music Label","v":3,"meta":{"def":"A label producing pre-cleared instrumental music built specifically for sync in media.","ex":"KPM, De Wolfe, Extreme Music, APM, Audio Network","aka":"Production music house, stock music","money":"One-stop licences to TV/film/ads; blanket deals with broadcasters plus performance royalties."}}]},{"name":"Label Departments","v":14,"meta":{"def":"The functional divisions inside a record company that discover, produce, market and monetise releases.","ex":"A&R, marketing, promotion, publicity, sync, legal, finance","aka":"Label functions","money":"Departmental budgets are overheads recouped against release P&Ls or carried by the label."},"children":[{"name":"A&R","v":5,"meta":{"def":"Artists & Repertoire: the talent-scouting and creative-development arm that signs and shapes artists.","ex":"Scouting demos, matching artists to producers, song selection, greenlighting recording budgets","aka":"A and R, talent department","money":"Controls signing advances and recording budgets; A&R staff may earn bonuses on their signings' success.","note":"'A&R admin' handles paperwork, splits, sample clearances and label copy."},"children":[{"name":"A&R Scout","v":3,"meta":{"def":"Front-line talent finder who discovers unsigned acts at gigs, online and via demos.","ex":"Attending showcases, monitoring TikTok/SoundCloud buzz, working local scenes","aka":"Talent scout","money":"Salaried/freelance; may earn a finder's bonus if a scouted act is signed."}},{"name":"A&R Manager","v":3,"meta":{"def":"Senior A&R who signs artists and steers their creative and commercial development.","ex":"Choosing singles, pairing artists with producers, approving budgets","aka":"A&R executive","money":"Controls recording budgets and may share bonuses on their roster's success."}},{"name":"A&R Administration","v":3,"meta":{"def":"Back-office A&R handling contracts, splits, clearances, credits and label copy.","ex":"Registering songwriter splits, clearing samples, filing metadata","aka":"A&R admin","money":"Ensures correct royalty flows; errors here cost the label and artists money."}},{"name":"Song / Catalogue A&R","v":3,"meta":{"def":"Publishing-side A&R matching songs and writers to artists and sync opportunities.","ex":"Pitching a topline to a pop act, arranging co-writes and camps","aka":"Creative A&R (publishing)","money":"Drives cuts that generate mechanical, performance and sync income."}}]},{"name":"Marketing","v":4,"meta":{"def":"Plans and funds the campaign to build awareness and demand for a release.","ex":"Rollout strategy, ad buys, playlist pitching plans, merch tie-ins, brand deals","aka":"Brand marketing","money":"Runs the marketing spend which is recoupable against the artist's royalties."}},{"name":"Promotion / Radio Plugging","v":4,"meta":{"def":"Works records onto radio and streaming editorial to secure airplay and playlist adds.","ex":"Pitching to BBC Radio 1, US Top 40 adds, playlist plugging to Spotify editors","aka":"Radio promo, pluggers","money":"Salaried plus indie pluggers on retainer; airplay drives performance royalties and chart position.","note":"Historically tainted by 'payola' scandals over pay-for-play."}},{"name":"Publicity / PR","v":4,"meta":{"def":"Secures press coverage, interviews, reviews and manages the artist's media narrative.","ex":"Album reviews, cover features, interview bookings, crisis management","aka":"Press office, media relations","money":"In-house team or external PR firm on monthly retainer (£1-5k+), often recoupable."}},{"name":"Sales","v":3,"meta":{"def":"Manages physical and digital retail accounts to get product stocked and featured.","ex":"Amazon, retail chains, indie record shops, iTunes merchandising slots","aka":"Trade marketing, commercial","money":"Negotiates wholesale price, returns and retail marketing contributions."}},{"name":"Digital / Streaming","v":4,"meta":{"def":"Manages DSP relationships, playlist pitching, metadata and digital audience data.","ex":"Spotify for Artists, Apple pitching, YouTube CMS, TikTok strategy, data analytics","aka":"Streaming team, digital strategy","money":"Optimises release timing and playlisting to maximise per-stream micro-royalties."}},{"name":"Sync Licensing","v":4,"meta":{"def":"Pitches and clears master recordings for use in film, TV, advertising and games.","ex":"Placing a track in a Netflix show, an Apple ad, an EA game trailer","aka":"Sync team, film & TV licensing","money":"Negotiates one-off sync fees (split with publishing) plus back-end performance royalties.","note":"A hit sync can relaunch a catalogue song (e.g. Kate Bush via Stranger Things)."},"children":[{"name":"Film & TV Sync","v":3,"meta":{"def":"Placing recordings into scripted and unscripted screen productions.","ex":"A needle-drop in a prestige drama, a reality-show montage","aka":"Screen sync","money":"One-off fee plus back-end performance royalties on broadcast."}},{"name":"Advertising Sync","v":3,"meta":{"def":"Licensing music for commercials, the highest-paying sync category.","ex":"A national TV campaign, a viral sportswear ad","aka":"Ad sync, commercial licensing","money":"Large flat fees scaled by media spend, territory and term."}},{"name":"Games & Interactive Sync","v":3,"meta":{"def":"Licensing music into video games, apps and interactive experiences.","ex":"A track in a racing game, a rhythm-game licence, Fortnite events","aka":"Game sync","money":"Buyout or per-unit fees; growing as gaming rivals film in scale."}}]},{"name":"Business Affairs / Legal","v":4,"meta":{"def":"Drafts and negotiates contracts, clears rights and handles the label's legal risk.","ex":"Recording agreements, sample clearances, licensing terms, litigation","aka":"Legal & business affairs, BALA","money":"Protects the label's rights positions; sets recoupment and royalty terms in contracts."}},{"name":"Finance / Royalties","v":4,"meta":{"def":"Accounts for income, calculates artist royalties and issues statements and audits.","ex":"Semi-annual royalty statements, recoupment tracking, mechanical accounting","aka":"Royalty department, finance & accounting","money":"Applies deductions (packaging, breakage, reserves) and reports recoupable balances to artists."}},{"name":"Product Management","v":3,"meta":{"def":"Coordinates a release across all departments from schedule to delivery.","ex":"Setting release dates, packaging, coordinating masters, artwork and DSP delivery","aka":"Project management, campaign management","money":"Owns the release P&L and keeps the campaign on budget."}},{"name":"International","v":3,"meta":{"def":"Coordinates releases and marketing across the label's overseas territories and affiliates.","ex":"Priority-setting to foreign affiliates, overseas radio, territory release timing","aka":"International marketing, global team","money":"Drives foreign royalties; local affiliates take a share of territory income."}},{"name":"Creative / Art","v":3,"meta":{"def":"Produces the visual identity: artwork, packaging, photography and video assets.","ex":"Album covers, music-video commissioning, brand look, merch design","aka":"Art department, creative services","money":"Design and video costs are usually recoupable production expenses."}},{"name":"New Business / Digital Ventures","v":3,"meta":{"def":"Develops non-traditional revenue: brand partnerships, tech, D2C and emerging formats.","ex":"Brand tie-ins, NFT drops, app partnerships, D2C store, gaming integrations","aka":"Commercial development, strategic marketing","money":"Opens new income lines beyond recorded royalties, often shared with the artist."}},{"name":"Synch & Brand Partnerships","v":3,"meta":{"def":"Builds artist-brand campaigns and sponsorship deals beyond one-off syncs.","ex":"Artist as brand ambassador, tour sponsorship, co-created products","aka":"Brand solutions","money":"Brand pays a fee split between label and artist; can be outside the recording contract."}}]},{"name":"Artist Team","v":10,"meta":{"def":"The professionals an artist hires to run the business, career and daily operations around their music.","ex":"Manager, lawyer, agent, business manager, publicist, tour manager","aka":"The team, artist camp, entourage","money":"Most are paid a commission (10-20%) or fee out of the artist's earnings."},"children":[{"name":"Manager","v":5,"meta":{"def":"The artist's chief strategist and representative who oversees the whole career and team.","ex":"Scooter Braun, Cliff Burnstein, Irving Azoff","aka":"Personal manager, artist manager","money":"Typically 15-20% commission on the artist's gross income across all activities.","note":"Usually the highest-paid single team member; deal set by a management agreement."},"children":[{"name":"Personal Manager","v":3,"meta":{"def":"The lead manager overseeing all strategy, deals and the wider team.","ex":"The manager who sits across records, touring, brand and press","aka":"Lead manager","money":"Commissions 15-20% of the artist's gross across activities."}},{"name":"Management Company","v":3,"meta":{"def":"A firm managing a roster of artists with shared infrastructure and staff.","ex":"Full Stop, Roc Nation Management, Q Prime, TaP","aka":"Management firm","money":"Commission income across the roster funds staff and services."}},{"name":"Self-Management","v":3,"meta":{"def":"An artist managing their own career without a dedicated manager.","ex":"DIY artists coordinating their own releases and bookings","aka":"Artist-managed","money":"Artist keeps the ~20% a manager would take but bears the workload."}}]},{"name":"Business Manager","v":4,"meta":{"def":"Handles the artist's money: banking, budgeting, taxes, investments and bill-paying.","ex":"Managing tour cashflow, filing taxes, investment advice, LLC accounting","aka":"Financial manager","money":"Charges ~5% of gross or a flat/hourly fee; distinct from the personal manager."}},{"name":"Tour Manager","v":4,"meta":{"def":"Runs the day-to-day logistics of a tour on the road: travel, schedule, settlements, crew.","ex":"Advancing shows, hotel and bus logistics, nightly box-office settlement","aka":"TM","money":"Paid a weekly salary or day-rate for the tour, plus per diems and travel."}},{"name":"Booking Agent","v":4,"meta":{"def":"Books live performances and negotiates fees, routing and touring for the artist.","ex":"CAA, WME, UTA, Wasserman, Paradigm agents","aka":"Agent, live agent","money":"Takes ~10% commission on gross live/performance fees.","note":"In some US states agents must be licensed; managers legally cannot procure work."},"children":[{"name":"Responsible Agent","v":3,"meta":{"def":"The lead agent owning the artist relationship and overall touring strategy.","ex":"The named agent an artist signs with at a major agency","aka":"Lead agent","money":"Earns the agency's ~10% on the artist's live income."}},{"name":"Territory Agent","v":3,"meta":{"def":"A regional agent handling bookings within a specific territory.","ex":"A European agent, a separate North American agent","aka":"Regional agent","money":"Shares the agency commission for shows in their territory."}},{"name":"Booking Agency","v":3,"meta":{"def":"The firm employing agents and representing a live roster to promoters.","ex":"CAA, WME, Wasserman, UTA, X-ray","aka":"Live agency","money":"Aggregates commissions across its roster to fund the business."}}]},{"name":"Publicist","v":3,"meta":{"def":"Manages the artist's personal press and public image, independent of the label's PR.","ex":"Pitching cover stories, red-carpet coverage, image management","aka":"Personal PR","money":"Monthly retainer paid by the artist (roughly $2-10k/month)."}},{"name":"Lawyer / Attorney","v":4,"meta":{"def":"The entertainment attorney who negotiates deals, protects rights and can shop the artist.","ex":"Negotiating a record deal, clearing samples, trademarking a name","aka":"Music lawyer, entertainment attorney","money":"Bills hourly ($400-1000+), a flat fee, or 5% 'value billing' on deals negotiated."}},{"name":"Accountant","v":3,"meta":{"def":"Prepares accounts, audits royalty statements and manages tax compliance.","ex":"Royalty audits of a label, tax returns, tour accounting","aka":"CPA, royalty auditor","money":"Hourly or fixed fee; royalty audits can recover large und-paid sums on a contingency."}},{"name":"Day-to-Day Manager","v":3,"meta":{"def":"A junior manager who handles routine tasks under the lead manager on bigger acts.","ex":"Scheduling, coordinating the team, handling label requests","aka":"Junior manager","money":"Salaried by the management company or paid from the manager's commission."}},{"name":"Production Manager","v":3,"meta":{"def":"Oversees the technical build of a live show: staging, sound, lighting, freight and crew.","ex":"Stage design build, trucking, rigging, local-crew hire","aka":"PM","money":"Salaried/day-rate for major tours; controls the production budget."}},{"name":"Assistant / Personal Assistant","v":3,"meta":{"def":"Manages the artist's personal schedule, errands and private logistics.","ex":"Diary management, travel, personal appointments","aka":"PA","money":"Salaried directly by the artist."}},{"name":"Stylist & Creative Director","v":3,"meta":{"def":"Shapes the artist's visual and fashion identity across shows, videos and press.","ex":"Wardrobe, stage looks, video art direction, brand aesthetic","aka":"Image consultant","money":"Fee or retainer paid by the artist; wardrobe often sponsored by fashion brands."}}]},{"name":"Agreements & Deals","v":16,"meta":{"def":"The contracts that govern how music rights, work and income are shared between artists and companies.","ex":"Recording contract, 360 deal, publishing deal, management agreement","aka":"Music contracts","money":"Each defines who owns what and how revenue is split, advanced and recouped."},"children":[{"name":"Recording Contracts","v":10,"meta":{"def":"Deals under which a label acquires rights to an artist's recordings in exchange for investment.","ex":"Exclusive recording agreement, 360 deal, distribution, licensing","aka":"Record deals","money":"Label advances money and recoups from the artist's recording royalties."},"children":[{"name":"Recording Contract (Exclusive)","v":5,"meta":{"def":"A standard deal binding an artist to deliver records exclusively to one label for a term/options.","ex":"A multi-album major-label deal with option periods","aka":"Exclusive recording agreement, record deal","money":"Label owns masters, pays 15-25% royalty, recoups all advances first.","note":"The classic 'record deal'; artist often unrecouped for years."},"children":[{"name":"Net Receipts Deal","v":3,"meta":{"def":"Modern royalty basis paying the artist a share of the label's net income.","ex":"25% of net receipts on streaming income","aka":"Profit-basis royalty","money":"Artist share applied after DSP and distribution costs are removed."}},{"name":"Retail-Basis (PPD) Deal","v":3,"meta":{"def":"Legacy royalty basis paying a percentage of the published dealer price.","ex":"18% of PPD on physical sales, minus packaging deductions","aka":"PPD royalty, retail royalty","money":"Lots of deductions shrank the base the artist's rate applied to."}},{"name":"Multi-Album Term Deal","v":3,"meta":{"def":"A long exclusive commitment of several albums via firm plus option periods.","ex":"'1 firm + 4 options', each option one LP","aka":"Term recording agreement","money":"Locks the artist in while the label holds all the options."}}]},{"name":"360 Deal","v":4,"meta":{"def":"A deal where the label shares in all of an artist's income streams, not just recordings.","ex":"Robbie Williams/EMI, Madonna/Live Nation, many modern major deals","aka":"Multiple-rights deal, all-in deal","money":"Label takes a cut (often 10-30%) of touring, merch, publishing and endorsements too.","note":"Justified by labels bearing marketing risk in the streaming era."}},{"name":"Distribution Deal","v":4,"meta":{"def":"Company distributes an artist's or label's finished masters without owning them.","ex":"The Orchard, [PIAS], AWAL, DistroKid, TuneCore","aka":"Distro deal, D deal","money":"Distributor takes a fee (10-30% or a flat rate) and the creator keeps the masters and rest."}},{"name":"Licensing Deal","v":4,"meta":{"def":"Owner licenses finished masters to a label/territory for a fixed term rather than assigning them.","ex":"Licensing a US-made album to a European label for 5 years","aka":"Master licence deal, P&D licence","money":"Licensee pays an advance/royalty; rights revert to the owner at term's end.","note":"Preferred by artists who want to keep long-term ownership."}},{"name":"Production Deal","v":3,"meta":{"def":"A producer/production company signs the artist then upstreams to a bigger label.","ex":"An artist signed to a producer's company, released via a major","aka":"Production company deal, P&D upstream","money":"Producer takes a middle cut between the label and the artist.","note":"Artist can end up double-commissioned; often criticised."}},{"name":"Development Deal","v":3,"meta":{"def":"A short, low-commitment deal to develop an unproven artist before a full contract.","ex":"Funding demos and a few singles with an option to sign fully","aka":"Demo deal, singles deal","money":"Small advance/budget; label holds an option to upgrade to a full deal."}},{"name":"Joint Venture","v":3,"meta":{"def":"Two companies co-own a label or release, sharing costs and profits roughly equally.","ex":"A major and an entrepreneur co-founding an imprint 50/50","aka":"JV","money":"Costs and net profits split per the JV percentage after recoupment."}},{"name":"Imprint / Vanity Deal","v":3,"meta":{"def":"A deal giving an artist/exec their own label name and A&R budget under a parent.","ex":"A star's imprint funded and distributed by their major","aka":"Label deal, vanity imprint deal","money":"Parent funds signings and recoups first; imprint head shares in profits."}}]},{"name":"Publishing Agreements","v":8,"meta":{"def":"Deals covering songwriting copyrights (the composition), separate from recordings.","ex":"Publishing deal, admin deal, co-pub, sub-publishing, single-song","aka":"Song deals","money":"Publisher collects and splits songwriter royalties (mechanical, performance, sync)."},"children":[{"name":"Publishing Deal (Exclusive)","v":4,"meta":{"def":"A songwriter assigns copyright in their songs to a publisher for exploitation.","ex":"A full exclusive songwriter agreement with a major publisher","aka":"ESA, exclusive songwriter agreement","money":"Publisher advances money, takes ~20-25% and collects worldwide; writer keeps the rest.","note":"Publisher owns copyright for the term; reverts later if negotiated."}},{"name":"Administration (Admin) Deal","v":3,"meta":{"def":"A publisher registers and collects royalties but does not own the copyright.","ex":"Kobalt, Songtrust, Sentric admin services","aka":"Admin deal","money":"Admin takes a small fee (10-20%); writer keeps 100% ownership and the rest.","note":"Popular with established writers who don't need an advance."}},{"name":"Co-Publishing Deal","v":4,"meta":{"def":"Writer and publisher co-own the copyright, sharing the publisher's share of income.","ex":"A typical '75/25' co-pub where the writer keeps 75% of total income","aka":"Co-pub","money":"Writer keeps 100% of the writer's share plus ~50% of the publisher's share.","note":"The most common modern songwriter deal."}},{"name":"Sub-Publishing Deal","v":3,"meta":{"def":"A local publisher collects a catalogue's royalties in a foreign territory.","ex":"A UK publisher appointing a Japanese sub-publisher for Japan","aka":"Sub-pub","money":"Sub-publisher takes 10-25% of territory income and remits the rest."}},{"name":"Single-Song Assignment","v":3,"meta":{"def":"A writer assigns just one song (not their whole catalogue) to a publisher.","ex":"Assigning one hit co-write to the co-writer's publisher","aka":"SSA, single-song agreement","money":"Publisher takes its share of that one song's income only."}},{"name":"Work-for-Hire","v":3,"meta":{"def":"The commissioner owns the copyright from creation; the creator is treated as an employee for that work.","ex":"Jingle composing, library music, ghost-writing, film-score cues","aka":"WFH, buyout","money":"Creator gets a one-off fee and usually no ongoing royalties or ownership."}}]},{"name":"Representation Agreements","v":5,"meta":{"def":"Contracts appointing team members to represent the artist for a commission.","ex":"Management agreement, booking agreement, producer agreement","aka":"Service agreements","money":"Set commission rates and terms for the artist's professional team."},"children":[{"name":"Management Agreement","v":4,"meta":{"def":"The contract appointing a manager to represent the artist's overall career.","ex":"A 3-year term at 20% commission with a post-term 'sunset' clause","aka":"Management contract","money":"Manager earns 15-20% of gross; sunset clause tapers commission after the term.","note":"Key clauses: term, scope, commission base, post-term rights."}},{"name":"Booking Agreement","v":3,"meta":{"def":"Appoints a booking agent to procure and negotiate live engagements.","ex":"An exclusive agency agreement for worldwide live representation","aka":"Agency agreement","money":"Agent commissions ~10% of live gross fees."}},{"name":"Producer Agreement","v":4,"meta":{"def":"Sets a record producer's fee, royalty and credit for producing recordings.","ex":"A 3-4 point producer royalty plus an advance/fee per track","aka":"Producer contract","money":"Producer earns a fee plus 'points' (3-5% royalty), usually recorded prospectively.","note":"'Record One' vs 'account' royalty basis is a key negotiation."}},{"name":"Session / Side-Artist Agreement","v":3,"meta":{"def":"Engages a session musician or featured performer for a recording.","ex":"A session drummer's MU-rate day fee; a featured rapper's flat fee","aka":"Session contract, featured-artist agreement","money":"Usually a one-off session fee (union scale) plus possible performer royalties.","note":"Session players earn equitable remuneration on broadcast/streaming."}},{"name":"Band Partnership Agreement","v":3,"meta":{"def":"An internal contract among band members setting income splits, name ownership and departures.","ex":"Splitting income equally, deciding who keeps the band name if a member leaves","aka":"Band agreement, inter-band agreement","money":"Defines how band income and expenses are shared and what leavers are owed."}}]},{"name":"Licensing & Commercial Agreements","v":7,"meta":{"def":"Deals licensing music or an artist's name for specific commercial uses.","ex":"Sync, master use, mechanical, merch, endorsement, brand deals","aka":"Exploitation agreements","money":"Third parties pay fees/royalties to use music or the artist's brand."},"children":[{"name":"Sync Agreement","v":4,"meta":{"def":"Licenses a song (composition) for use in timed sync with visual media.","ex":"A song used under a TV-show scene, film, ad or trailer","aka":"Synchronisation licence","money":"One-off sync fee paid to the publisher (and matched by a master licence to the label).","note":"Both the song and the master must be cleared for any sync."}},{"name":"Master Use Licence","v":3,"meta":{"def":"Licenses the specific sound recording for a sync or sample use.","ex":"Licensing the original master of a track for a movie scene","aka":"Master licence","money":"Fee paid to the master owner (label), separate from the sync fee to the publisher."}},{"name":"Mechanical Licence","v":4,"meta":{"def":"Grants the right to reproduce a composition on records, downloads or streams.","ex":"A cover version licensed via the Harry Fox Agency or MLC","aka":"Mechanical rights","money":"Pays a statutory mechanical rate per copy/stream to the songwriter/publisher.","note":"US statutory rate; the MLC administers streaming mechanicals since 2021."}},{"name":"Merchandising Deal","v":4,"meta":{"def":"Licenses an artist's name and imagery for merchandise, or funds merch production.","ex":"Bravado (UMG), Ambassador, tour and D2C merch deals","aka":"Merch deal","money":"Merch company pays an advance and royalty; venues take a 'hall fee' cut on tour sales.","note":"Tour merch splits with venues can be 20-35% of gross."}},{"name":"Endorsement Deal","v":3,"meta":{"def":"An artist is paid to endorse or use a product publicly.","ex":"A guitarist endorsing an amp brand, a drummer with a cymbal deal","aka":"Sponsorship, ambassador deal","money":"Brand pays a fee and/or free gear; may require exclusivity to the brand."}},{"name":"Brand Partnership Deal","v":3,"meta":{"def":"A deeper artist-brand collaboration beyond a simple endorsement.","ex":"A co-designed sneaker, a tour sponsorship, a branded content series","aka":"Brand collaboration, brand tie-in","money":"Brand funds the campaign; fee split between artist, manager and sometimes label.","note":"Often the biggest single payday for mid-tier artists."}}]}]},{"name":"Deal Mechanics","v":12,"meta":{"def":"The specific financial levers and clauses that determine how much an artist actually earns from a deal.","ex":"Advance, recoupment, royalty rate, points, cross-collateralisation","aka":"Contract terms, deal points","money":"These clauses decide the flow, timing and reductions of money owed to artists."},"children":[{"name":"Advance","v":4,"meta":{"def":"An upfront prepayment against future royalties, paid to the artist on signing/delivery.","ex":"A $250k album advance recoupable from record royalties","aka":"Signing advance, recording fund","money":"Not free money: fully recouped from the artist's royalties before they see more.","note":"Often a 'recording fund' the artist uses to make the record and keeps the rest."},"children":[{"name":"Signing Advance","v":3,"meta":{"def":"A lump sum paid on signing as an incentive, separate from recording costs.","ex":"A six-figure cheque on inking a major deal","aka":"Signing bonus","money":"Recoupable from royalties like any other advance."}},{"name":"Recording Fund","v":3,"meta":{"def":"A budget covering recording costs where the artist keeps any surplus.","ex":"A $200k album fund; the artist pockets what's left after making the record","aka":"All-in fund","money":"Recoupable; incentivises the artist to record cheaply and keep the difference."}},{"name":"Delivery / Advance-on-Delivery","v":3,"meta":{"def":"Advance instalments paid as the artist hits delivery milestones.","ex":"Half on signing, half on delivering the finished masters","aka":"Milestone advance","money":"Staggers the label's cash outlay and ties money to completion."}},{"name":"Tour Support","v":3,"meta":{"def":"Money the label advances to cover a loss-making but promotionally valuable tour.","ex":"Covering the shortfall on a support tour to build an audience","aka":"Tour deficit funding","money":"Recoupable from record royalties; not a gift.","note":"Often cross-collateralised with recording income."}}]},{"name":"Recoupment","v":4,"meta":{"def":"The process of the label recovering its recoupable costs out of the artist's royalty share.","ex":"Advances, video and marketing costs deducted before royalties are paid","aka":"Recouping","money":"Artist earns nothing above the advance until the recoupable balance hits zero.","note":"Label still owns the masters even if never recouped."}},{"name":"Royalty Rate","v":4,"meta":{"def":"The percentage of income the artist earns on sales/streams of their recordings.","ex":"18-25% of net receipts on a modern streaming-era deal","aka":"Artist royalty, base rate","money":"Applied after deductions to the price base to calculate the artist's earnings.","note":"Old deals used a % of retail; modern deals use % of net receipts."}},{"name":"Points","v":3,"meta":{"def":"Royalty percentage points, the unit in which producer and artist royalties are counted.","ex":"A producer getting '3 points'; an artist on '20 points'","aka":"Royalty points","money":"Each point equals 1% of the applicable royalty base."}},{"name":"Cross-Collateralisation","v":4,"meta":{"def":"Allowing the label to recoup a loss on one project from the income of another.","ex":"Recouping an unrecouped album's debt from the next album's royalties","aka":"Cross-collat","money":"Ties an artist's projects together so profits offset losses across the deal.","note":"Especially harsh when it crosses recording with publishing or touring."}},{"name":"Reversion","v":3,"meta":{"def":"A clause returning ownership of masters or songs to the creator after a set period.","ex":"Masters reverting to the artist 15 years after release","aka":"Reversion clause, rights reversion","money":"Creator regains the asset and its future income once triggered.","note":"In the US, copyright 'termination rights' allow reversion after 35 years."}},{"name":"Controlled Composition Clause","v":4,"meta":{"def":"A clause capping the mechanical royalties payable on an artist's own songs.","ex":"Paying 75% of the statutory mechanical rate, capped at 10-11 songs per album","aka":"Controlled comp clause","money":"Reduces what the label owes the artist as songwriter, saving the label money.","note":"The classic '3/4 rate' — 75% of statutory — plus a per-album song cap."}},{"name":"Breakage","v":3,"meta":{"def":"A historical deduction assuming a percentage of physical records broke in transit.","ex":"A 10% breakage deduction on royalties for shipped vinyl/CDs","aka":"Breakage allowance","money":"Reduced royalties by pretending stock was damaged — even for digital.","note":"A relic that lingered into digital deals; widely litigated."}},{"name":"Packaging Deduction","v":3,"meta":{"def":"A deduction from the royalty base for the cost of physical packaging.","ex":"A 25% packaging deduction on CD royalties","aka":"Container charge","money":"Shrinks the price base on which the artist royalty is calculated.","note":"Often far exceeded the real packaging cost — a hidden reduction."}},{"name":"Minimum Delivery Commitment","v":3,"meta":{"def":"The number of records/songs the artist must deliver to satisfy the contract.","ex":"Deliver one album per option period of 10+ new masters","aka":"MDC, delivery requirement","money":"Failing to deliver can extend the term or trigger breach."}},{"name":"Option Periods","v":3,"meta":{"def":"The label's right (not obligation) to extend the deal for further albums.","ex":"A '1 firm + 4 options' deal, each option one album","aka":"Options","money":"Label can drop the artist between options but the artist is locked in if renewed.","note":"Options are one-sided: only the label can exercise them."}},{"name":"Reserves Against Returns","v":3,"meta":{"def":"Royalties the label withholds to cover physical product that may be returned unsold.","ex":"Holding back 30% of royalties for two accounting periods","aka":"Reserves","money":"Delays payment to the artist; released ('liquidated') once returns settle."}}]},{"name":"Revenue & Business Models","v":14,"meta":{"def":"The distinct income streams and commercial strategies the music business runs on.","ex":"Streaming, touring, sync, merch, publishing, brand deals","aka":"Income streams, monetisation","money":"Each model routes money from a payer (fan, brand, platform) to rights-holders."},"children":[{"name":"Streaming / Subscription","v":5,"meta":{"def":"Recurring income from on-demand streaming platforms paying per play from a revenue pool.","ex":"Spotify, Apple Music, Amazon Music, YouTube Music, Tidal","aka":"DSP income, streaming royalties","money":"Platforms pool subscription/ad money and pay pro-rata per stream to rights-holders.","note":"Now the largest recorded-music revenue source globally."},"children":[{"name":"Premium On-Demand","v":3,"meta":{"def":"Paid subscription tier where users stream any track on demand ad-free.","ex":"Spotify Premium, Apple Music, Amazon Music Unlimited","aka":"Subscription streaming","money":"Highest per-stream payout; subscription pool split pro-rata by play share."}},{"name":"Ad-Supported Streaming","v":3,"meta":{"def":"Free tier funded by advertising rather than subscription fees.","ex":"Spotify Free, YouTube ad-supported, free-tier ads","aka":"Freemium, ad tier","money":"Advertising revenue pool pays far lower per-stream than premium."}},{"name":"UGC & Content ID","v":3,"meta":{"def":"Monetising music used in user-generated video via automated rights matching.","ex":"YouTube Content ID, TikTok/Meta licensing, Facebook Rights Manager","aka":"User-generated content revenue","money":"Platform pays rights-holders when their music is detected in uploads."}},{"name":"Non-Interactive / Webcasting","v":3,"meta":{"def":"Radio-style streams where users can't choose exact tracks, paid via statutory rates.","ex":"Pandora radio, SiriusXM, non-interactive webcasters","aka":"Digital radio","money":"In the US, SoundExchange collects statutory performance royalties for these."}},{"name":"Fan-Powered / User-Centric","v":3,"meta":{"def":"A payout model dividing each fan's fee among only the artists they actually played.","ex":"SoundCloud Fan-Powered Royalties, Deezer's UCPS trial","aka":"User-centric payment system (UCPS)","money":"Reallocates money toward niche artists a listener genuinely streams.","note":"An alternative to the dominant pro-rata pool model."}}]},{"name":"Direct-to-Consumer (D2C)","v":4,"meta":{"def":"Selling music, merch and experiences straight to fans without retail intermediaries.","ex":"Bandcamp, artist webstores, vinyl pre-orders, deluxe bundles","aka":"D2C, direct sales","money":"Artist keeps the bulk of revenue minus platform/fulfilment fees.","note":"Bandcamp Fridays waive fees to send ~100% to artists."},"children":[{"name":"Physical D2C","v":3,"meta":{"def":"Selling physical formats direct to fans, often via pre-order.","ex":"Vinyl and cassette pre-orders, signed CD bundles","aka":"Direct physical sales","money":"Artist keeps most revenue after manufacturing and shipping costs."}},{"name":"Digital D2C","v":3,"meta":{"def":"Selling downloads and digital content straight to fans.","ex":"Bandcamp downloads, exclusive digital drops","aka":"Direct digital sales","money":"Higher payout than streaming; fan pays a set price per item."}},{"name":"Superfan Bundles","v":3,"meta":{"def":"High-value packages bundling music, merch and experiences for dedicated fans.","ex":"Deluxe box sets, ticket-plus-vinyl bundles, signed editions","aka":"VIP bundles, superfan tier","money":"Captures the top of fans' willingness to pay; a key label growth focus.","note":"Central to the 2024-25 'superfan monetisation' push by DSPs and labels."}}]},{"name":"Sync Licensing Income","v":4,"meta":{"def":"Fees earned when music is licensed for film, TV, ads, games and trailers.","ex":"A car-ad placement paying a six-figure sync fee","aka":"Sync revenue","money":"Payer buys a sync (song) + master licence; fees split between publisher and label.","note":"High-margin and a major discovery driver."}},{"name":"Touring & Live","v":5,"meta":{"def":"Income from concerts, festivals and live appearances, the biggest earner for many acts.","ex":"Ticket sales, guarantees, VIP packages, festival fees","aka":"Live income","money":"Promoter pays a guarantee and/or split; costs (crew, production) come off the top.","note":"Live Nation/AEG dominate promotion; Ticketmaster dominates ticketing."},"children":[{"name":"Guarantee vs Door Deal","v":3,"meta":{"def":"How a live fee is structured: a fixed guarantee, a share of the door, or the greater of both.","ex":"$10k guarantee vs 85/15 split after costs, 'versus' whichever is higher","aka":"Deal memo, backend split","money":"Promoter pays costs and a guarantee, then splits net profit with the artist."}},{"name":"Festival Fees","v":3,"meta":{"def":"Flat fees paid to artists to appear at festivals, scaled by billing and draw.","ex":"Coachella, Glastonbury, Primavera slot fees","aka":"Festival guarantee","money":"Festival pays a set fee; headliners command far higher guarantees than undercard."}},{"name":"VIP & Meet-and-Greet","v":3,"meta":{"def":"Premium ticket tiers bundling early entry, merch, soundcheck or photo access.","ex":"VIP packages sold via CID or Laylo, meet-and-greet upsells","aka":"VIP packages, upgrades","money":"High-margin add-ons; revenue often kept largely by the artist's team."}},{"name":"Residency","v":3,"meta":{"def":"A multi-date engagement at one venue, avoiding touring costs.","ex":"Las Vegas residencies, London arena runs, club DJ residencies","aka":"Residency deal","money":"Venue pays a large per-show or aggregate fee for an exclusive run."}},{"name":"Support / Opening Slot","v":3,"meta":{"def":"A junior act performing before the headliner, sometimes paying to be on the bill.","ex":"An emerging act opening an arena tour for exposure","aka":"Support slot","money":"Support earns a small fee, or occasionally 'buys on' by paying the tour."}}]},{"name":"Merchandising","v":4,"meta":{"def":"Sales of branded goods: apparel, vinyl, posters and collectibles.","ex":"Tour t-shirts, hoodies, exclusive vinyl, collectible bundles","aka":"Merch revenue","money":"High margin at gigs (minus venue hall fee) and online D2C.","note":"Often the most reliable cash for touring artists."},"children":[{"name":"Tour Merchandise","v":3,"meta":{"def":"Merch sold at live shows, often event-dated and exclusive.","ex":"Tour t-shirts, event posters, city-specific items","aka":"Venue merch","money":"Venue takes a 'hall fee' (20-35%) of gross before the artist's cut."}},{"name":"D2C / Online Merch","v":3,"meta":{"def":"Merch sold directly through an artist's online store to fans anywhere.","ex":"Shopify stores, Bandcamp merch, official webstores","aka":"Webstore merch","money":"No venue cut; artist keeps more after fulfilment and platform fees."}},{"name":"Licensed Merchandise","v":3,"meta":{"def":"Third parties license an artist's brand to make and sell merchandise at retail.","ex":"Band tees in fashion retailers, licensed accessories","aka":"Retail licensing","money":"Licensee pays a royalty on sales for using the artist's name and imagery."}},{"name":"Limited & Collectible Editions","v":3,"meta":{"def":"Scarce, premium items designed to drive collector demand and higher margins.","ex":"Numbered vinyl variants, signed prints, deluxe box sets","aka":"Special editions","money":"Scarcity commands premium pricing and strong D2C margins."}}]},{"name":"Music Publishing Income","v":5,"meta":{"def":"Royalties earned by songwriters and publishers from the composition copyright.","ex":"Performance, mechanical, sync and print royalties","aka":"Songwriting income, pub income","money":"Collected by PROs, the MLC and publishers, then split with writers.","note":"Publishing income often outlasts recording income over a career."},"children":[{"name":"Performance Royalties","v":4,"meta":{"def":"Royalties from public performance and broadcast of a composition.","ex":"Radio play, live performance, streaming, venue and TV broadcast","aka":"PRO royalties","money":"Collected by PROs (ASCAP, BMI, PRS, GEMA) and split 50/50 writer/publisher.","note":"The songwriter's 'writer share' is paid directly and can't be assigned away."}},{"name":"Mechanical Royalties","v":3,"meta":{"def":"Royalties for reproducing a composition on records, downloads and streams.","ex":"Per-unit and per-stream mechanicals collected by the MLC/HFA","aka":"Mechanicals","money":"Statutory or negotiated rate paid to the songwriter/publisher per copy or stream."}},{"name":"Print & Folio Royalties","v":3,"meta":{"def":"Income from sheet music, songbooks and licensed lyric reproduction.","ex":"Sheet-music sales, licensed lyric sites, songbook folios","aka":"Print rights","money":"Small but steady; publisher licenses printers and lyric services."}}]},{"name":"Brand & Sponsorship Deals","v":4,"meta":{"def":"Income from associating an artist with brands, ambassadorships and sponsored content.","ex":"Tour sponsors, branded singles, ambassador contracts","aka":"Brand revenue","money":"Brands pay fees to reach the artist's audience; split across the team.","note":"Increasingly central as recording margins thin."}},{"name":"Licensing Income","v":3,"meta":{"def":"Broader licensing of masters and rights beyond sync, e.g. compilations and territory deals.","ex":"Compilation licences, fitness/retail background music, sampling clearances","aka":"Master licensing","money":"Licensees pay fees/royalties to the rights owner for defined uses."}},{"name":"Crowdfunding & Membership","v":4,"meta":{"def":"Fans directly fund artists via campaigns or recurring subscriptions.","ex":"Patreon, Kickstarter, PledgeMusic (defunct), Bandcamp subscriptions","aka":"Fan funding, Patreon model","money":"Fans pay per-project or monthly; artist keeps most minus platform fees.","note":"Recurring memberships give predictable income independent of labels."}},{"name":"NFTs & Web3","v":3,"meta":{"def":"Selling music, art and access as blockchain tokens with programmable royalties.","ex":"Sound.xyz drops, Royal fractional royalty tokens, Async Music","aka":"Music NFTs, tokenisation","money":"Fans buy tokens; smart contracts can pay creators a cut on every resale.","note":"Hype cooled after 2022; niche but persistent among some artists."}},{"name":"Fan Clubs & Communities","v":3,"meta":{"def":"Paid or gated fan communities offering exclusive access, presales and content.","ex":"Official fan clubs, Discord tiers, presale access memberships","aka":"Fan memberships","money":"Membership fees plus presale and exclusive-merch upsell revenue."}},{"name":"Catalogue Acquisition & Investment","v":4,"meta":{"def":"Buying existing rights catalogues as income-producing financial assets.","ex":"Bob Dylan's songs to UMPG, Springsteen's catalogue to Sony","aka":"Catalogue sales, rights acquisition","money":"Buyers pay a multiple of annual income (often 15-30x) for future royalty streams.","note":"Fuelled a rights-buying boom in the late 2010s-2020s."}},{"name":"Neighbouring Rights","v":3,"meta":{"def":"Royalties for performers and master owners when recordings are broadcast or played publicly.","ex":"Radio and TV airplay, public venues, some webcasting","aka":"Related rights, equitable remuneration","money":"Collected by bodies like PPL/SoundExchange and split between label and performers.","note":"The US pays these only for digital (SoundExchange), not terrestrial radio."}}]},{"name":"Music Finance","v":10,"meta":{"def":"The investment and financing side of music: funds, lenders and vehicles that put capital into rights.","ex":"Hipgnosis, Primary Wave, royalty advances, catalogue funds","aka":"Music investment","money":"Investors deploy capital to buy or lend against future royalty income for a return."},"children":[{"name":"Advance Funding","v":3,"meta":{"def":"Companies that pay creators a lump sum now against their future royalty earnings.","ex":"beatBread, Duetti, Sound Royalties, Chordcash","aka":"Non-recoupable advances, royalty advances","money":"Provider recoups from the creator's future royalties, keeping ownership with the artist.","note":"Marketed as a label-free alternative to a record advance."}},{"name":"Catalogue Funds","v":5,"meta":{"def":"Investment funds that acquire and manage large portfolios of music rights.","ex":"Hipgnosis Songs Fund, Primary Wave, Round Hill, Litmus, Concord","aka":"Rights funds, song funds","money":"Raise investor capital, buy catalogues, and pay returns from royalty income.","note":"Hipgnosis's public-market struggles (2023-24) tested the model."},"children":[{"name":"Publicly-Listed Rights Fund","v":3,"meta":{"def":"A stock-exchange-listed vehicle letting retail investors buy into a song portfolio.","ex":"Hipgnosis Songs Fund (LSE), Round Hill Music Royalty Fund","aka":"Listed royalty trust","money":"Shareholders receive dividends from the catalogue's royalty income."}},{"name":"Private Catalogue Fund","v":3,"meta":{"def":"A privately-raised fund acquiring rights for institutional investors.","ex":"Primary Wave, Litmus Music, Influence Media","aka":"Private rights fund","money":"Limited partners commit capital; returns come from royalties and resale."}},{"name":"Major-Backed Acquisition Arm","v":3,"meta":{"def":"A major label/publisher's own division buying catalogues to grow its holdings.","ex":"Sony's and Universal's catalogue acquisitions of legacy artists","aka":"Strategic buyer","money":"Deep balance sheets outbid funds; income folds into group royalties."}},{"name":"Catalogue Valuation Multiple","v":3,"meta":{"def":"The pricing metric for a catalogue: a multiple of its annual net income.","ex":"Buying at 18x 'NPS' (net publisher share) annual income","aka":"NPS multiple, earnings multiple","money":"Higher multiples for stable, 'evergreen' catalogues with proven longevity."}}]},{"name":"Royalty Lending","v":3,"meta":{"def":"Loans secured against an artist's or catalogue's royalty stream as collateral.","ex":"A bank lending against projected streaming income","aka":"Royalty-backed lending, music asset lending","money":"Lender is repaid from royalties plus interest; rights revert on repayment.","note":"Royalties treated as securitisable, cash-flowing assets."}},{"name":"Private Equity & Institutional Capital","v":4,"meta":{"def":"Large investors treating music rights as a stable, uncorrelated asset class.","ex":"Blackstone (Hipgnosis), KKR, Apollo, pension funds, Shamrock","aka":"Institutional music investment","money":"Deploys billions to buy catalogues seeking steady royalty yields.","note":"Reframed music as an 'alternative asset' like real estate."}},{"name":"Fractional Royalty Marketplaces","v":3,"meta":{"def":"Platforms letting retail investors buy shares of song royalties.","ex":"Royalty Exchange, ANote Music, JKBX, Royal","aka":"Royalty trading, music shares","money":"Investors buy a fraction of a song's income and earn a share of royalties.","note":"Democratises rights ownership; liquidity and pricing remain challenges."}},{"name":"Music Bonds & Securitisation","v":3,"meta":{"def":"Bundling royalty streams into tradeable securities that pay bondholders.","ex":"Bowie Bonds (1997), Northsight and later catalogue securitisations","aka":"Bowie Bonds, asset-backed securities","money":"Artist gets cash upfront; investors are repaid from future royalties over the bond term.","note":"The 1997 Bowie Bonds pioneered securitising music royalties."}},{"name":"Venture & Startup Investment","v":3,"meta":{"def":"VC funding into music-tech, distribution and creator-economy startups.","ex":"Investment in DistroKid, UnitedMasters, Splice, Endel","aka":"Music-tech VC","money":"Investors take equity betting on platform growth and exits."}},{"name":"Label Services & Funding Companies","v":3,"meta":{"def":"Firms that provide capital plus label-style services while artists keep their masters.","ex":"AWAL, [PIAS] Recordings, Believe, Cinq Music","aka":"Artist services, label-services deals","money":"Fund marketing and take a revenue share; artist retains ownership.","note":"A middle path between DIY and a full label deal."}},{"name":"Grants & Public Funding","v":3,"meta":{"def":"Non-repayable public and institutional funding for artists and projects.","ex":"PRS Foundation, Arts Council England, Canada's FACTOR, Creative Europe","aka":"Arts grants, music funding bodies","money":"Bodies award grants for recording, touring and development, no equity taken."}},{"name":"Collection Societies as Financers","v":3,"meta":{"def":"PROs and collective-management orgs that advance or distribute members' royalties.","ex":"PRS, GEMA, SACEM, ASCAP, BMI member advances and cash-flow","aka":"CMOs, collecting societies","money":"Collect and distribute royalties, sometimes advancing against pending income.","note":"Deduct an administration fee before distributing to members."}}]},{"name":"Niche Deal Clauses & Income","v":8,"meta":{"def":"Specialised contractual clauses and obscure income buckets that materially affect who gets paid.","ex":"MFN clauses, per-stream rates, black box income, 3/4 rate","aka":"Fine-print terms","money":"These niche terms quietly redirect meaningful sums between parties."},"children":[{"name":"Most-Favoured-Nation (MFN) Clause","v":4,"meta":{"def":"A guarantee that a party gets terms at least as good as anyone else in the same deal.","ex":"Sample owners each demanding MFN so no co-owner is paid a higher rate","aka":"MFN, favoured-nations","money":"Auto-levels rates up to the highest granted, raising total clearance cost.","note":"Common in multi-sample tracks and compilation/sync clearances."}},{"name":"Per-Stream Rate","v":4,"meta":{"def":"The tiny amount paid out per individual stream, derived from a revenue pool.","ex":"Roughly $0.003-0.005 per Spotify stream to the rights-holder","aka":"Per-play rate","money":"Not a fixed price: pool-share model divides platform revenue by total streams.","note":"Spotify's 2024 threshold demonetises tracks under 1,000 annual streams."}},{"name":"Black Box Income","v":4,"meta":{"def":"Royalties collected but unattributed to a specific rights-holder due to bad metadata.","ex":"Unmatched mechanical royalties held by the MLC or PROs","aka":"Unclaimed royalties, unmatched funds","money":"Eventually distributed by market share to publishers, favouring the majors.","note":"The MLC held hundreds of millions in historical unmatched royalties."}},{"name":"Controlled Comp 3/4 Rate","v":3,"meta":{"def":"The reduced mechanical rate (75% of statutory) labels pay on the artist's own songs.","ex":"Paying $0.0705 instead of $0.094 statutory per song per unit","aka":"Three-quarter rate, 75% rate","money":"Cuts the songwriter's mechanicals by a quarter, saving the label money.","note":"Core mechanism of the controlled composition clause."}},{"name":"Sunset Clause","v":3,"meta":{"def":"A clause tapering a former manager's commission after the management term ends.","ex":"20% for year one post-term, 10% year two, then nothing","aka":"Sunset provision","money":"Limits how long an ex-manager keeps earning on deals they started."}},{"name":"Escalation Clause","v":3,"meta":{"def":"A term raising the royalty rate once sales/streams pass set thresholds.","ex":"Royalty rising from 18% to 20% after 500,000 units","aka":"Royalty escalation, escalator","money":"Rewards success by lifting the artist's rate at higher volumes."}},{"name":"Key-Man Clause","v":3,"meta":{"def":"Lets an artist exit if a specific named executive leaves the company.","ex":"An artist signed because of one A&R exec who then departs","aka":"Key-person clause","money":"Protects the artist's reason for signing; can trigger release from the deal."}},{"name":"Leaving-Member Clause","v":3,"meta":{"def":"Governs what happens to a band's deal and rights when a member leaves.","ex":"A departing member still owing the label solo albums","aka":"Leaving member provision","money":"Label may retain the leaver as a solo act or keep the band name with others."}}]}]},{"name":"Rights & Law","type":"rights","v":26,"children":[{"name":"The Two Copyrights","v":12,"meta":{"def":"Every piece of recorded music contains two separate copyrights that coexist: the underlying musical work and the sound recording of it.","ex":"One song ('Yesterday') vs one recording of it (The Beatles' 1965 master)","aka":"song vs master; work vs recording; ©/composition and ℗/phonogram","money":"Composition earns for songwriters/publishers; recording earns for artists/labels; a licensee usually must clear both","note":"The split is why a cover song pays the original writer but a new label owns the new master"},"children":[{"name":"Musical Work / Composition","v":12,"meta":{"def":"The underlying song itself: melody, harmony and lyrics as authored, independent of any recording.","ex":"Sheet music, a demo, the abstract 'song'","aka":"the song, the composition, the 'PA' work (US), © copyright","money":"Owned/controlled by songwriters and their music publishers","note":"Marked with © and identified by an ISWC"},"children":[{"name":"Composition Copyright","v":4,"meta":{"def":"The exclusive right in the notes-and-words work fixed by its author.","ex":"Rights in 'Happy Birthday' as a tune, apart from any recording","aka":"song copyright, © right","money":"Vests in the songwriter(s), routinely assigned to a publisher for exploitation","note":"Can exist even if never recorded, e.g. a lead sheet in a drawer"}},{"name":"Lyrics Rights","v":4,"meta":{"def":"Copyright in the words of a song as a literary/musical component of the work.","ex":"Reprinting lyrics in a book or on a lyrics site","aka":"words rights, lyric reprint right","money":"Lyricist's share of the composition; lyric-display services (Musixmatch/Genius) licence via publishers","note":"Lyric-only display licences are distinct from performance/mechanical"}},{"name":"Melody & Harmony (Underlying Work)","v":4,"meta":{"def":"The musical elements (tune, chord movement, structure) that make the composition protectable.","ex":"The hook line that a jury compares in an infringement case","aka":"musical elements","money":"Composer's share of writer royalties","note":"Common chord progressions and scales are not protectable, only original expression"}},{"name":"Arrangement Copyright","v":4,"meta":{"def":"A new copyright in a substantially original arrangement of an existing or public-domain work.","ex":"An orchestral arrangement of a folk tune","aka":"arr. credit","money":"Arranger earns a writer share only if authorised or if the base work is public domain","note":"Unauthorised arrangements of protected works are infringing derivatives"}},{"name":"Songwriter / Author","v":4,"meta":{"def":"The human creator(s) of the composition and first owner of its copyright.","ex":"Lennon-McCartney, Diane Warren","aka":"composer, lyricist, writer","money":"Receives the writer's share of mechanical, performance and sync income","note":"Identified across societies by an IPI/CAE number"}},{"name":"Lead Sheet / Notation","v":4,"meta":{"def":"The written musical notation that can serve as the fixation/deposit of a composition.","ex":"A melody-plus-chords chart filed with the copyright office","aka":"notation, chart, transcription","money":"No direct royalty; underlies print licensing","note":"In the US, pre-1972 works often relied on notation deposits"}}]},{"name":"Sound Recording / Master","v":10,"meta":{"def":"The particular fixed recording of a performance of a work, a separate copyright from the song.","ex":"Whitney Houston's 1992 recording of 'I Will Always Love You'","aka":"master, the record, phonogram, 'SR' work (US), ℗ right","money":"Usually owned by the record label (or artist if independent)","note":"Marked with ℗ and identified by an ISRC"},"children":[{"name":"Master Recording Copyright","v":4,"meta":{"def":"The exclusive right in a specific captured recording.","ex":"The multitrack and final mix a label owns","aka":"master right, ℗ copyright","money":"Label recoups its advance/production spend before paying artist royalties","note":"Whoever pays for and fixes the recording tends to own it, absent a contract saying otherwise"}},{"name":"Phonogram Right (℗)","v":4,"meta":{"def":"The producer's right in a phonogram recognised internationally, symbolised by ℗.","ex":"℗ 1973 notice on a vinyl label","aka":"producer's right, phonographic right","money":"Underpins neighbouring-rights income collected by bodies like PPL","note":"Established by the Rome and Geneva Phonograms Conventions"}},{"name":"Featured Artist","v":4,"meta":{"def":"The named performer(s) whose performance is captured on the master.","ex":"The billed singer or band on the release","aka":"main artist, billed performer","money":"Gets the featured share of neighbouring-rights and label royalties","note":"Typically ~65% of the performer pool vs featured/non-featured split"}},{"name":"Record Producer / Label","v":4,"meta":{"def":"The party that finances and organises the recording, the first owner of the master.","ex":"A major label or an independent producer","aka":"phonogram producer, master owner","money":"Collects the producer share of recording royalties and licenses masters out","note":"Producer as creative role is distinct from producer as legal rights owner"}},{"name":"Session / Non-Featured Musician","v":4,"meta":{"def":"Hired performers on a recording who are not the billed artist.","ex":"The string section or backing band on a session","aka":"sidemen, non-featured performers","money":"Paid a session fee plus a non-featured neighbouring-rights share (e.g. via PPL/AFM funds)","note":"Often work-for-hire but many territories still grant them equitable remuneration"}}]},{"name":"How They Interrelate","v":10,"meta":{"def":"Rules that govern how the two copyrights arise, last and combine.","ex":"Fixation, originality and duration doctrines","aka":"copyright fundamentals","money":"Determine when and whether royalties can be charged at all","note":"A use often requires clearing both copyrights simultaneously"},"children":[{"name":"Dual-Copyright System","v":4,"meta":{"def":"The principle that composition and recording are cleared and paid separately.","ex":"A sync deal needs a sync licence (song) and a master-use licence (recording)","aka":"song-and-master clearance","money":"Two invoices, two owners, for one piece of audio","note":"Missing one clearance is the most common licensing error"}},{"name":"One Song, Many Recordings","v":4,"meta":{"def":"A single composition can spawn unlimited separate sound recordings, each its own copyright.","ex":"Hundreds of cover versions of 'Summertime'","aka":"cover proliferation","money":"Each recording pays the same underlying writers; each master is separately owned","note":"Explains why covers are legal under compulsory mechanical licensing"}},{"name":"Fixation Requirement","v":4,"meta":{"def":"Copyright attaches only once a work is fixed in a tangible medium.","ex":"Humming a tune is not protected until recorded or notated","aka":"fixation, embodiment","money":"No fixation means no enforceable right to license","note":"US law is explicit; some countries protect certain unfixed works"}},{"name":"Originality Threshold","v":4,"meta":{"def":"The minimum creativity a work needs to qualify for copyright.","ex":"A standard I-IV-V progression alone is too generic","aka":"originality, creativity requirement","money":"Sets the boundary of what can be owned and monetised","note":"Feist (US) requires a 'modicum of creativity', not mere effort"}},{"name":"Copyright Duration Basics","v":4,"meta":{"def":"How long each right lasts before entering the public domain.","ex":"Composition life+70; sound recordings commonly 70 years from release in the EU","aka":"term of protection","money":"After expiry, works can be used royalty-free","note":"Composition and recording can expire at very different times"}}]}]},{"name":"Rights Bundles","v":14,"meta":{"def":"Copyright is a bundle of separately licensable exclusive rights plus moral and neighbouring rights.","ex":"Reproduction, performance, sync, adaptation, attribution","aka":"the rights bundle, exclusive rights","money":"Each right is a separate revenue stream that can be licensed independently","note":"Owners can slice rights by territory, medium, term and exclusivity"},"children":[{"name":"Economic Rights","v":12,"meta":{"def":"The exploitation rights that generate licensing income.","ex":"Copying, distributing, performing, adapting","aka":"exploitation rights, restricted acts","money":"Licensed for fees and royalties","note":"Enumerated in national statutes and WIPO treaties"},"children":[{"name":"Reproduction Right","v":4,"meta":{"def":"The right to make copies of a work or recording.","ex":"Pressing CDs, ripping a track, server copies for streaming","aka":"mechanical right (for compositions), copying right","money":"Generates mechanical royalties for compositions and copy fees for masters","note":"Even transient server/cache copies can implicate it"}},{"name":"Distribution Right","v":4,"meta":{"def":"The right to distribute copies of a work to the public.","ex":"Selling physical records or permanent downloads","aka":"release right, making-copies-available","money":"Underlies sales-based mechanicals and wholesale revenue","note":"Limited by first-sale/exhaustion once a copy is lawfully sold"}},{"name":"Public Performance Right","v":4,"meta":{"def":"The right to perform or play a work in public.","ex":"Radio play, live concerts, music in a bar or shop","aka":"performing right","money":"Collected by PROs (ASCAP/PRS etc.) and paid to writers and publishers","note":"In the US, sound recordings have NO general public-performance right, only a digital one"}},{"name":"Communication to the Public","v":4,"meta":{"def":"The right to transmit a work to the public, including by broadcast and online.","ex":"TV broadcast, webcasting, cable retransmission","aka":"broadcast right, transmission right","money":"Licensed to broadcasters and platforms; feeds PRO and neighbouring-rights income","note":"An EU/international framing that overlaps US public-performance concepts"}},{"name":"Making Available Right","v":4,"meta":{"def":"The right to offer a work so the public can access it at a time and place they choose.","ex":"On-demand streaming and download-to-own","aka":"on-demand right","money":"Core right licensed to interactive services like Spotify and Apple Music","note":"Created by the 1996 WIPO Internet Treaties for the on-demand era"}},{"name":"Adaptation / Derivative Right","v":4,"meta":{"def":"The right to create new works based on the original.","ex":"Translations, remixes, arrangements, sampling, medleys","aka":"derivative-works right, transformation right","money":"Licensed via adaptation/remix or interpolation deals with split of royalties","note":"A moral-rights integrity claim can block adaptations even when economics are agreed"}},{"name":"Synchronisation Right","v":4,"meta":{"def":"The right to combine music in timed relation with visual images.","ex":"Music in a film scene, TV ad or video game","aka":"sync right","money":"Licensed for negotiated one-off sync fees, no statutory rate","note":"Applies to the composition; the recording needs a parallel master-use licence"}},{"name":"Print Right","v":4,"meta":{"def":"The right to reproduce a composition as printed or digital sheet music.","ex":"Songbooks, choral scores, digital notation","aka":"graphic rights, sheet-music right","money":"Generates print royalties, historically a fixed per-copy or percentage rate","note":"The oldest music royalty, predating recordings"}},{"name":"Rental & Lending Right","v":4,"meta":{"def":"The right to control commercial rental and public lending of copies.","ex":"Rental of recorded music; library lending remuneration","aka":"rental right","money":"Yields equitable rental/lending remuneration in many territories","note":"Introduced by the EU Rental Directive"}},{"name":"Importation Right","v":4,"meta":{"def":"The right to control importation of copies made abroad.","ex":"Blocking grey-market parallel imports of records","aka":"parallel-import control","money":"Protects territorial pricing and exclusive-distribution deals","note":"Interacts with regional exhaustion rules"}}]},{"name":"Moral Rights","v":8,"meta":{"def":"Personal, often inalienable rights of the author protecting the author-work bond.","ex":"Being credited and protecting the work from distortion","aka":"droit moral","money":"Non-economic but can force payment or block uses if breached","note":"Strong in civil-law Europe, weaker/waivable in the US and UK"},"children":[{"name":"Right of Attribution","v":4,"meta":{"def":"The author's right to be identified as creator of the work.","ex":"Songwriter credit on a release or in a film","aka":"right of paternity, credit right","money":"Missing credit can trigger damages or contractual penalties","note":"Often the practical basis of 'written by' credits"}},{"name":"Right of Integrity","v":4,"meta":{"def":"The right to object to distortion or derogatory treatment of the work.","ex":"Blocking a remix that mutilates a composition","aka":"integrity right","money":"Can void a licence or demand payment to permit an edit","note":"Cited when artists object to political use of their songs"}},{"name":"Right of Disclosure","v":4,"meta":{"def":"The author's right to decide when and whether to make a work public.","ex":"Withholding an unfinished demo from release","aka":"right of divulgation","money":"Prevents forced monetisation of unreleased work","note":"Recognised chiefly in civil-law systems"}},{"name":"Right Against False Attribution","v":4,"meta":{"def":"The right not to have works falsely credited to one.","ex":"Objecting to a track wrongly billed as by a famous writer","aka":"false-credit right","money":"Supports passing-off and misattribution claims","note":"Distinct from the positive right to be credited"}},{"name":"Moral-Rights Waiver","v":4,"meta":{"def":"A contractual waiver of moral rights where local law allows it.","ex":"A UK work-for-hire contract waiving integrity/attribution","aka":"waiver clause","money":"Lets buyers freely edit and use without moral-rights claims","note":"Void in France and other territories that treat moral rights as inalienable"}}]},{"name":"Neighbouring / Related Rights","v":10,"meta":{"def":"Rights of those who bring works to the public: performers, producers and broadcasters.","ex":"A drummer's right in a recording; a label's phonogram right","aka":"related rights, droits voisins","money":"Generate equitable remuneration collected by CMOs like PPL/SoundExchange","note":"Framed by the Rome, WPPT and Beijing treaties"},"children":[{"name":"Performers' Rights","v":4,"meta":{"def":"Rights of performers in the fixation and use of their performances.","ex":"A singer's right in the recording of their vocal","aka":"artist neighbouring rights","money":"Yield equitable remuneration when recordings are broadcast or played publicly","note":"Beijing Treaty extends these to audiovisual performances"}},{"name":"Phonogram Producers' Rights","v":4,"meta":{"def":"The producer/label's related right in the sound recording.","ex":"A label's right to remuneration for radio spins","aka":"producer neighbouring rights","money":"Collected by producer CMOs and split with performers","note":"The ℗ right in action"}},{"name":"Broadcasters' Rights","v":4,"meta":{"def":"Rights of broadcasting organisations in their transmissions/signals.","ex":"A broadcaster controlling rebroadcast of its signal","aka":"signal rights","money":"Licensed for retransmission and fixation of broadcasts","note":"Subject of a long-running WIPO Broadcast Treaty negotiation"}},{"name":"Equitable Remuneration","v":4,"meta":{"def":"A statutory right to fair payment when recordings are broadcast or performed, not an exclusive right.","ex":"Radio pays a single fee split between performers and producer","aka":"ER, secondary-use remuneration","money":"Collected by CMOs and split 50/50 between performer and producer in many territories","note":"Performers cannot contract this away in some jurisdictions"}},{"name":"Rome Convention Rights","v":4,"meta":{"def":"The 1961 treaty baseline for performers, producers and broadcasters.","ex":"Minimum protection standards adopted nationally","aka":"Rome Convention (1961)","money":"Enables cross-border collection of neighbouring-rights income","note":"The US is not a Rome member, complicating foreign performer payments"}}]}]},{"name":"Royalties","v":14,"meta":{"def":"The recurring payments owners receive when their rights are exploited.","ex":"Mechanical, performance, sync, streaming and neighbouring-rights royalties","aka":"music income streams","money":"Flow from users to owners, usually via publishers, labels and collection societies","note":"Most recorded uses generate several royalties at once"},"children":[{"name":"Composition-Side Royalties","v":10,"meta":{"def":"Income earned by songwriters and publishers from the underlying work.","ex":"Mechanical, performance, print, sync of the song","aka":"writer/publisher income","money":"Split between writer's share and publisher's share","note":"Flows regardless of who owns the recording"},"children":[{"name":"Mechanical Royalty","v":4,"meta":{"def":"A per-copy or per-reproduction royalty for reproducing a composition.","ex":"Paid on downloads, CDs, vinyl and interactive streams","aka":"mechanicals","money":"US statutory rate ~12.4¢ per track under 5 min; collected by The MLC/HFA and paid to publishers","note":"Named for the old 'mechanical' reproduction of piano rolls and discs"}},{"name":"Performance Royalty (PRO)","v":4,"meta":{"def":"Royalty for public performance/broadcast of a composition.","ex":"Radio spins, TV, live shows, venue play","aka":"performing-right royalty","money":"Collected by PROs (ASCAP, BMI, PRS...) and split 50/50 writer and publisher","note":"The writer's 50% is paid directly to the writer, protected from publisher debts"}},{"name":"Sync Fee (Composition)","v":4,"meta":{"def":"A negotiated fee to synchronise a composition with visuals.","ex":"Song used under a film scene or ad","aka":"sync royalty","money":"One-off fee negotiated by the publisher, no statutory rate; can range from hundreds to six figures","note":"Often split 50/50 between writer and publisher by contract"}},{"name":"Print Royalty","v":4,"meta":{"def":"Royalty from printed and digital sheet-music sales.","ex":"Songbook and choral-score sales","aka":"sheet-music royalty","money":"Historically a fixed per-copy sum or a percentage of retail to the publisher/writer","note":"The earliest music royalty, from the 19th-century sheet-music trade"}},{"name":"Grand Rights Royalty","v":4,"meta":{"def":"Royalty for dramatic performance of music within a staged work.","ex":"Music in a musical, opera or ballet","aka":"dramatic performing-right royalty","money":"Negotiated directly with the publisher/rights owner, outside blanket PRO licences","note":"Contrasts with 'small rights' handled by PROs"}}]},{"name":"Recording-Side Royalties","v":10,"meta":{"def":"Income earned by performers, producers and labels from the master.","ex":"Artist royalties, master-use fees, neighbouring rights","aka":"recording income","money":"Often subject to recoupment of label advances first","note":"US public-performance income for masters is digital-only"},"children":[{"name":"Master-Use Fee","v":4,"meta":{"def":"Fee to use a specific sound recording, typically alongside a sync.","ex":"Licensing the original master for a trailer","aka":"master licence fee","money":"Negotiated one-off paid to the master owner (label/artist); no statutory rate","note":"Usually paired with a composition sync fee at similar value ('most-favoured-nations')"}},{"name":"Neighbouring-Rights Royalty","v":4,"meta":{"def":"Remuneration for broadcast/public play of a recording, split performer/producer.","ex":"Radio and venue play in territories that grant the right","aka":"related-rights royalty","money":"Collected by CMOs (PPL, SCPP...) and split ~50/50 performer and producer","note":"US artists collect little of this abroad because the US grants no reciprocal right"}},{"name":"Digital Performance (SoundExchange)","v":4,"meta":{"def":"US statutory royalty for non-interactive digital performance of recordings.","ex":"Internet radio, SiriusXM, Pandora radio mode","aka":"digital performance royalty","money":"Collected by SoundExchange: 45% featured artist, 5% non-featured, 50% rights owner","note":"Paid directly to artists, bypassing the label's books"}},{"name":"Needletime","v":4,"meta":{"def":"Historic and ongoing remuneration for broadcasters playing recorded music.","ex":"BBC/commercial radio payments for spinning records","aka":"needle-time royalty","money":"Collected in the UK by PPL and split between performers and record companies","note":"Named for the phonograph needle's time on the record"}},{"name":"Artist Royalty (Record Royalty)","v":4,"meta":{"def":"The contractual royalty a label pays the artist on sales/streams.","ex":"A percentage of revenue per stream or unit","aka":"record deal royalty, points","money":"Often 15-25% of revenue, payable only after the advance is recouped","note":"Streaming has shifted many deals toward revenue-share splits"}}]},{"name":"Streaming Royalties","v":10,"meta":{"def":"The blended royalties an interactive stream generates for both copyrights.","ex":"A Spotify play pays performance + mechanical + master royalties","aka":"streaming income","money":"Platforms pay a pool split among rights holders, then down to creators","note":"A single stream triggers multiple simultaneous royalties"},"children":[{"name":"Streaming Mechanical","v":4,"meta":{"def":"The reproduction/mechanical component of an interactive-stream royalty.","ex":"The mechanical slice Spotify pays for the song","aka":"interactive-streaming mechanical","money":"In the US set by the CRB (headline rate rising toward 15.35% of revenue), paid via The MLC","note":"Subject of the Phonorecords III/IV rate battles"}},{"name":"Streaming Performance","v":4,"meta":{"def":"The public-performance/communication component of a stream, for the composition.","ex":"The PRO slice of a Spotify play","aka":"digital performance (composition)","money":"Collected by PROs and split writer/publisher","note":"Distinct from the recording's digital-performance royalty"}},{"name":"Per-Stream Micro-Royalty","v":4,"meta":{"def":"The tiny fraction-of-a-cent value attributed to one stream.","ex":"Roughly $0.003-$0.005 per stream on major DSPs","aka":"per-stream rate","money":"Not a fixed price but a back-calculated share of the revenue pool","note":"Varies by country, plan type and each platform's payout pool"}},{"name":"Pro-Rata (Market-Share) Pool","v":4,"meta":{"def":"The dominant model where all subscriber money is pooled and split by total stream share.","ex":"Spotify's standard royalty accounting","aka":"big-pool model","money":"Your payout = your streams / all streams x the payable pool","note":"Criticised for diverting casual-listener money to top artists"}},{"name":"User-Centric Royalty Model","v":4,"meta":{"def":"An alternative where each listener's fee is split only among what they played.","ex":"SoundCloud's 'fan-powered' payouts","aka":"UCPS, fan-powered royalties","money":"Your fan's subscription flows only to the artists that fan actually streamed","note":"Favours niche and superfan-driven artists"}}]},{"name":"Advances, Splits & Unclaimed","v":12,"meta":{"def":"The accounting mechanisms and gaps around royalty flows.","ex":"Advances, recoupment, controlled-composition clauses, black box","aka":"royalty accounting","money":"Determine how much actually reaches creators","note":"Where much industry value is won or lost"},"children":[{"name":"Minimum Guarantee / Advance","v":4,"meta":{"def":"An upfront payment recoupable against future royalties.","ex":"A publishing or label advance; a platform's minimum guarantee","aka":"MG, advance","money":"Paid now, then deducted from earnings until repaid","note":"Non-refundable if unrecouped, but blocks further payment until cleared"}},{"name":"Recoupment","v":4,"meta":{"def":"The process by which advances and costs are recovered from royalties before payout.","ex":"Recording and marketing costs charged against artist royalties","aka":"recouping","money":"Artist sees no royalties until the recoupable balance is zero","note":"Costs are recouped at the artist's royalty rate, effectively a loan the artist repays"}},{"name":"Controlled Composition Clause","v":4,"meta":{"def":"A contract term capping mechanicals on songs the artist writes/controls.","ex":"Reduced-rate (e.g. 75%) mechanicals on a limited number of tracks","aka":"controlled comp clause","money":"Lowers what the label pays the artist-as-writer, boosting label margin","note":"Common in US label deals, restricted in some territories"}},{"name":"Producer Points","v":4,"meta":{"def":"A percentage royalty ('points') paid to a record producer.","ex":"3-5 points of the artist royalty for a hit producer","aka":"points","money":"Paid from the artist's royalty pool, often recoupable then payable from record one","note":"'Record-one' language lets producers earn before the artist recoups"}},{"name":"Black Box / Unclaimed Royalty","v":4,"meta":{"def":"Royalties collected but unattributable to a specific rights holder.","ex":"Streaming mechanicals with missing/faulty metadata","aka":"black box, unallocated funds","money":"Held then often distributed by market share, favouring big catalogues","note":"The MLC holds a large historical unmatched pool"}},{"name":"Escheatment","v":4,"meta":{"def":"Transfer of long-unclaimed royalties to the state as abandoned property.","ex":"Uncashed royalty balances after statutory dormancy periods","aka":"unclaimed-property escheat","money":"Money leaves the industry to state coffers if never claimed","note":"Drives societies to run 'unclaimed works' search tools"}}]}]},{"name":"Licensing","v":16,"meta":{"def":"The permissions that authorise specific uses of the two copyrights.","ex":"Mechanical, sync, master-use, blanket and open licences","aka":"music clearances","money":"Fees and royalties flow through licences from user to owner","note":"A use may need several licences at once from different parties"},"children":[{"name":"Composition Licences","v":12,"meta":{"def":"Permissions to use the underlying song.","ex":"Mechanical, cover, print, interpolation, sync of the composition","aka":"song clearances","money":"Paid to publishers or their agents","note":"Some are compulsory, others freely negotiated"},"children":[{"name":"Mechanical Licence","v":4,"meta":{"def":"Permission to reproduce and distribute a composition on records/downloads/streams.","ex":"Licensing a song for your album pressing","aka":"mechanical","money":"Pays the statutory or negotiated mechanical rate to the publisher via HFA/The MLC","note":"Can be obtained compulsorily once a song has been released"}},{"name":"Compulsory / Statutory Licence","v":4,"meta":{"def":"A licence granted by law at a fixed rate once conditions are met, without owner consent.","ex":"US Section 115 mechanical; blanket streaming licence","aka":"statutory licence, Section 115","money":"Pays the government-set rate, removing negotiation","note":"Prevents owners from blocking covers or setting arbitrary prices"}},{"name":"Cover-Song Licence","v":4,"meta":{"def":"A mechanical licence to record and release your own version of a released song.","ex":"A band recording a cover for Spotify via Easy Song/HFA","aka":"cover licence","money":"Pays statutory mechanicals to the original writers/publishers","note":"Does not allow lyric/melody changes, that needs an adaptation licence"}},{"name":"Sync Licence","v":4,"meta":{"def":"Permission to synchronise a composition with visual media.","ex":"Clearing a song for a TV episode","aka":"synchronisation licence","money":"Negotiated fee to the publisher; no statutory rate","note":"Needs a matching master-use licence for a specific recording"}},{"name":"Print Licence","v":4,"meta":{"def":"Permission to reproduce a composition as sheet music or lyrics.","ex":"Publishing a choral arrangement or lyric booklet","aka":"sheet-music licence","money":"Pays print royalties to the publisher/writer","note":"Covers folios, single-song sheets and lyric reprints"}},{"name":"Interpolation Clearance","v":4,"meta":{"def":"Permission to re-play or re-sing part of an existing composition in a new song.","ex":"Replaying a famous melody without sampling the original recording","aka":"interpolation licence, replay clearance","money":"Original writers get a negotiated share of the new song's writer credits/royalties","note":"Clears only the composition, so no master licence is needed"}}]},{"name":"Recording Licences","v":8,"meta":{"def":"Permissions to use a specific master recording.","ex":"Master-use, sampling and master-sync licences","aka":"master clearances","money":"Paid to the master owner (label/artist)","note":"No compulsory licence exists for masters, all are negotiated"},"children":[{"name":"Master-Use Licence","v":4,"meta":{"def":"Permission to use a particular sound recording in a project.","ex":"Using the original hit master in a movie","aka":"master licence","money":"Negotiated fee to the label/master owner; freely priced","note":"Refusal forces a re-record or a different track"}},{"name":"Sampling Clearance","v":4,"meta":{"def":"Permission to reuse a portion of an existing recording in a new one.","ex":"Clearing a drum break for a hip-hop track","aka":"sample clearance","money":"Master owner takes a fee and/or points; the song's publisher takes writer share too","note":"Two clearances needed: the master and the underlying composition"}},{"name":"Master-Sync Licence","v":4,"meta":{"def":"The recording-side counterpart to a sync, permitting a master in timed media.","ex":"Master clearance for an advertisement","aka":"master sync","money":"Negotiated fee to the master owner alongside the composition sync","note":"Often priced on a most-favoured-nations basis with the song sync"}}]},{"name":"Blanket & Performance Licences","v":12,"meta":{"def":"Broad licences that cover large repertoires for public use.","ex":"PRO blanket licences for venues and broadcasters","aka":"repertoire licences","money":"Flat/tariff fees pooled and distributed to members","note":"Let users play millions of songs without per-song deals"},"children":[{"name":"Blanket Licence","v":4,"meta":{"def":"One licence covering a society's entire repertoire for a set fee.","ex":"A broadcaster's ASCAP or PRS blanket","aka":"repertoire-wide licence","money":"A tariff/flat fee (often revenue-based) distributed by usage data","note":"The efficiency backbone of collective licensing"}},{"name":"Public-Performance Licence","v":4,"meta":{"def":"Permission for a business to play music publicly.","ex":"A cafe's PRO licence to play the radio to customers","aka":"PPL/PRS-for-business licence","money":"Business pays PROs, which pay writers, publishers and (for recordings) performers/labels","note":"In the UK two licences (PRS + PPL) cover song and recording"}},{"name":"Venue / Festival Licence","v":4,"meta":{"def":"Live-performance licence covering music played at an event or venue.","ex":"A concert hall or festival PRO licence","aka":"live-performance licence","money":"Usually a percentage of box-office/gross paid to the PRO for setlist writers","note":"Headliner setlists drive who gets paid from the pool"}},{"name":"Background Music Licence","v":4,"meta":{"def":"Licence for ambient/piped music in commercial premises.","ex":"In-store playlists via a music-supplier service","aka":"in-store/BGM licence","money":"Fees to PROs and neighbouring-rights bodies, often bundled by B2B suppliers","note":"Suppliers like a music-service provider handle multi-society clearance"}},{"name":"Podcast Licence","v":4,"meta":{"def":"Clearance to use commercial music in podcasts, which are treated as reproduction+distribution.","ex":"Getting a song into an episode legally","aka":"podcast music clearance","money":"Requires negotiated sync+master deals; podcast-safe libraries sell simplified licences","note":"Most PRO blankets do NOT cover on-demand podcast reproduction"}},{"name":"Extended Collective Licence","v":4,"meta":{"def":"A licence that binds even non-member rights holders in a repertoire, by statute.","ex":"Nordic-model licences for mass digitisation","aka":"ECL","money":"Users pay the CMO which must account to opted-out or unrepresented owners","note":"Used to solve orphan/unlocatable-owner clearance at scale"}}]},{"name":"Open & Low-Friction Licences","v":12,"meta":{"def":"Pre-cleared or simplified licences that avoid case-by-case negotiation.","ex":"Creative Commons, royalty-free, production-music libraries","aka":"pre-cleared music","money":"Often one-time or subscription fees, sometimes free","note":"Popular with creators who need speed and legal certainty"},"children":[{"name":"Creative Commons Licence","v":4,"meta":{"def":"Standardised public licences letting creators grant reuse rights in advance.","ex":"CC BY, CC BY-NC, CC0 for a track","aka":"CC licence","money":"Usually free to use if you follow terms like attribution/non-commercial","note":"Irrevocable, so creators must choose carefully"}},{"name":"Royalty-Free Licence","v":4,"meta":{"def":"A licence paid once (or by subscription) with no ongoing per-use royalties.","ex":"Stock-music tracks for videos","aka":"RF music","money":"One upfront fee grants broad reuse without further payments","note":"'Royalty-free' means no recurring royalty, not free of charge"}},{"name":"Production Music / Library Licence","v":4,"meta":{"def":"Licence for pre-cleared catalogue music written for media use.","ex":"A library cue under a documentary","aka":"library music, stock music","money":"Sync fee plus back-end PRO performance royalties when broadcast","note":"Library composers rely heavily on broadcast performance income"}},{"name":"Micro-Licensing","v":4,"meta":{"def":"Low-cost, self-serve licensing of tracks for small creators.","ex":"Buying a single-video sync for a YouTube clip","aka":"self-serve licensing","money":"Small flat fees via marketplaces, sometimes subscription-based","note":"Scales the sync model down to individual influencers"}},{"name":"Direct Licence","v":4,"meta":{"def":"A licence negotiated directly with the owner, bypassing the collective society.","ex":"A broadcaster licensing a large publisher directly","aka":"direct deal, source licence","money":"Owner keeps the CMO's admin cut but must self-administer","note":"Digital withdrawal from PROs enabled major-publisher direct deals"}},{"name":"AI Training / TDM Licence","v":4,"meta":{"def":"Emerging licence to use catalogues for text-and-data-mining and AI model training.","ex":"A label licensing recordings to train a generative model","aka":"TDM licence, AI-training deal","money":"Negotiated fees/opt-outs; framed by the EU DSM Directive's TDM exception","note":"A fast-evolving front line of rights disputes"}}]}]},{"name":"Publishing","v":14,"meta":{"def":"The business of exploiting and administering musical works on behalf of songwriters.","ex":"Publishers, admin deals, catalogues, splits and sub-publishing","aka":"music publishing","money":"Publishers collect writers' income and take a share for their services","note":"Concerns the composition copyright, not the recording"},"children":[{"name":"Roles & Deal Structures","v":12,"meta":{"def":"The kinds of relationships between songwriters and publishers.","ex":"Admin, co-publishing, full-publishing, self-publishing","aka":"publishing deals","money":"Differ in how ownership and income are shared","note":"Range from pure service to full copyright buyout"},"children":[{"name":"Music Publisher","v":4,"meta":{"def":"The company that markets, licenses and administers compositions for writers.","ex":"A major or independent publishing house","aka":"publisher","money":"Takes the publisher's share (often up to 50% of net) for its work","note":"Pitches songs for cover, sync and playlist placements"}},{"name":"Administration (Admin Deal)","v":4,"meta":{"def":"A service deal where the admin registers, collects and pays, but takes no copyright.","ex":"A songwriter using an admin service to collect globally","aka":"admin deal","money":"Admin keeps a small percentage (typically 10-25%), writer keeps ownership","note":"Popular with self-releasing writers who just need collection"}},{"name":"Co-Publishing Deal","v":4,"meta":{"def":"A deal where writer and publisher co-own the copyright and split the publisher's share.","ex":"A 50/50 co-pub common for signed writers","aka":"co-pub","money":"Writer keeps 100% writer share plus ~half the publisher share (~75% of income)","note":"The industry-standard signed-writer arrangement"}},{"name":"Full Publishing (Buyout)","v":4,"meta":{"def":"The publisher takes the entire publisher's share and administers everything.","ex":"A traditional 50/50 full publishing deal","aka":"traditional publishing deal","money":"Writer keeps the 50% writer share; publisher keeps the full 50% publisher share","note":"Often comes with a larger advance than a co-pub"}},{"name":"Self-Publishing","v":4,"meta":{"def":"A writer owning their own publishing entity and keeping all shares.","ex":"Registering your own publishing company with a PRO","aka":"DIY publishing","money":"Writer keeps 100% of both shares but must self-administer or hire an admin","note":"Requires PRO publisher affiliation to collect the publisher share"}},{"name":"Sub-Publishing","v":4,"meta":{"def":"Appointing local publishers abroad to collect and exploit in their territories.","ex":"A US publisher using a German sub-publisher for GEMA income","aka":"sub-pub","money":"Sub-publisher takes a territorial cut (often 10-25%) of foreign income","note":"Bridges gaps where the home publisher lacks local relationships"}}]},{"name":"Splits & Shares","v":10,"meta":{"def":"How ownership and income of a composition are divided.","ex":"Writer share, publisher share, split sheets","aka":"song splits","money":"Define each contributor's percentage of every royalty","note":"Undocumented splits are a top cause of music disputes"},"children":[{"name":"Songwriter Share (Writer's Share)","v":4,"meta":{"def":"The portion of a composition's income belonging to the writers, conventionally 50%.","ex":"The 'writer' line on a PRO statement","aka":"writer's share","money":"Paid directly to writers by PROs, insulated from the publisher's debts","note":"Cannot normally be assigned away in the performance context"}},{"name":"Publisher Share","v":4,"meta":{"def":"The other conventional 50% of a composition's income, tied to administration.","ex":"The 'publisher' line on a statement","aka":"publisher's share","money":"Paid to the publisher (or self-publishing writer's entity)","note":"What co-pub/admin deals actually negotiate over"}},{"name":"Split Sheet","v":4,"meta":{"def":"A document recording each contributor's ownership percentage of a song.","ex":"A signed sheet after a writing session","aka":"songwriter split agreement","money":"Governs how all future royalties are divided","note":"Best signed in the room before memories and relationships fade"}},{"name":"Co-Writer Split","v":4,"meta":{"def":"The agreed percentage division among multiple songwriters.","ex":"Three writers at 33.3% each","aka":"writer splits","money":"Each writer's percentage of the aggregate writer share","note":"Default law may presume equal shares absent agreement"}},{"name":"Reversion Clause","v":4,"meta":{"def":"A contract term returning rights to the writer after a set period or on conditions.","ex":"Catalogue reverting after 15 years or if unexploited","aka":"rights reversion","money":"Writer regains full control and future income after reversion","note":"A negotiated cousin of statutory termination rights"}}]},{"name":"Registration & Administration","v":10,"meta":{"def":"The back-office work of protecting and collecting on compositions.","ex":"Copyright registration, society registration, metadata, audits","aka":"rights administration","money":"Ensures royalties are correctly matched and paid","note":"Bad metadata is a leading cause of unpaid royalties"},"children":[{"name":"Copyright Registration","v":4,"meta":{"def":"Filing a work with a national copyright office.","ex":"Registering a song with the US Copyright Office","aka":"copyright filing","money":"In the US it is a prerequisite to sue and to claim statutory damages/fees","note":"Copyright exists on creation; registration adds enforcement power"}},{"name":"Society Work Registration","v":4,"meta":{"def":"Registering a work and its splits with PROs and mechanical societies.","ex":"Filing a new song with ASCAP and The MLC","aka":"work notification","money":"Enables the society to match usage and pay the right owners","note":"Conflicting registrations by co-writers freeze payment"}},{"name":"Metadata Delivery","v":4,"meta":{"def":"Supplying accurate identifying data with a release.","ex":"ISWC, ISRC, writer IPIs, splits and titles","aka":"credits metadata","money":"Correct metadata routes royalties; errors send them to black boxes","note":"Standardised through the DDEX messaging formats"}},{"name":"Royalty Collection & Distribution","v":4,"meta":{"def":"Gathering income from many sources and paying it out to owners.","ex":"A publisher aggregating PRO, mechanical and sync income","aka":"collection & payout","money":"The core service publishers and CMOs provide for their cut","note":"Involves matching usage reports to registered works"}},{"name":"Audit Right","v":4,"meta":{"def":"A contractual right to examine a payer's books for underpayment.","ex":"An artist auditing a label's royalty accounting","aka":"royalty audit","money":"Recovers underpaid royalties, often revealing significant sums","note":"Usually limited to a window (e.g. three years) after each statement"}}]}]},{"name":"Collection Societies (PROs & CMOs)","v":16,"meta":{"def":"Organisations that license rights collectively and distribute royalties to members.","ex":"ASCAP, PRS, GEMA, SoundExchange, The MLC","aka":"PROs, CMOs, collecting societies","money":"License users, take an admin fee, and pay members via usage data","note":"Different societies collect different rights in different territories"},"children":[{"name":"US Societies & Bodies","v":14,"meta":{"def":"The performing-rights and mechanical/digital bodies operating in the United States.","ex":"ASCAP, BMI, SESAC, GMR, SoundExchange, The MLC, HFA","aka":"US PROs and MROs","money":"Fragmented by right: performance, mechanical, digital-recording","note":"The US uniquely splits these across many bodies"},"children":[{"name":"ASCAP","v":4,"meta":{"def":"The largest US performing-rights organisation, a member-owned non-profit.","ex":"Collects for songwriters like a huge US catalogue","aka":"American Society of Composers, Authors and Publishers","money":"Collects composition public-performance royalties for writers and publishers","note":"Operates under a DOJ consent decree with rate-court oversight"}},{"name":"BMI","v":4,"meta":{"def":"A major US performing-rights organisation, historically non-profit, now for-profit.","ex":"Represents a vast pool of writers and publishers","aka":"Broadcast Music, Inc.","money":"Collects composition performance royalties; also under a consent decree","note":"Sold to a private-equity group in 2024"}},{"name":"SESAC","v":4,"meta":{"def":"A smaller, invitation-only US performing-rights organisation, for-profit.","ex":"Selective roster of writers and publishers","aka":"SESAC (originally Society of European Stage Authors and Composers)","money":"Collects performance royalties; negotiates outside the consent-decree system","note":"Membership is by invitation, unlike ASCAP/BMI"}},{"name":"GMR","v":4,"meta":{"def":"A boutique US PRO representing a small, elite roster.","ex":"Founded by Irving Azoff with marquee writers","aka":"Global Music Rights","money":"Collects performance royalties and leverages its roster in direct negotiations","note":"Its formation sparked antitrust litigation with broadcasters"}},{"name":"SoundExchange","v":4,"meta":{"def":"The US CMO for digital public-performance of sound recordings.","ex":"Collects from webcasters, SiriusXM and internet radio","aka":"SoundExchange","money":"Pays 45% featured artist, 5% non-featured, 50% rights owner","note":"Pays performers directly, even non-featured session players"}},{"name":"The MLC","v":4,"meta":{"def":"The Mechanical Licensing Collective administering US blanket streaming mechanicals.","ex":"Collects mechanicals from Spotify, Apple, Amazon","aka":"The Mechanical Licensing Collective","money":"Distributes streaming mechanical royalties and holds the unmatched black box","note":"Created by the 2018 Music Modernization Act"}},{"name":"HFA","v":4,"meta":{"def":"A long-standing US mechanical-rights agency issuing licences and processing royalties.","ex":"Historic issuer of US mechanical licences","aka":"Harry Fox Agency","money":"Administers mechanical licences and royalty processing for publishers/services","note":"Now owned by a rights-tech company after decades under the NMPA"}}]},{"name":"UK & Mechanical Bodies","v":8,"meta":{"def":"The core UK collective bodies for performance, mechanicals and recordings.","ex":"PRS, PPL, MCPS","aka":"UK collecting societies","money":"Cover composition performance, mechanicals and recording remuneration","note":"PRS and MCPS jointly operate as PRS for Music"},"children":[{"name":"PRS for Music","v":4,"meta":{"def":"The UK performing-right society for songwriters, composers and publishers.","ex":"Licenses broadcasters, venues and online for the composition","aka":"Performing Right Society","money":"Collects composition public-performance and communication royalties","note":"Operates jointly with MCPS under the PRS for Music umbrella"}},{"name":"PPL","v":4,"meta":{"def":"The UK society collecting for recorded-music performers and record companies.","ex":"Licenses radio, TV and public places playing records","aka":"Phonographic Performance Limited","money":"Collects neighbouring-rights income and splits it performer/label","note":"Operates PPL PRS Ltd with PRS for one-stop business licensing"}},{"name":"MCPS","v":4,"meta":{"def":"The UK mechanical-copyright society licensing reproduction of compositions.","ex":"Mechanical royalties on CDs, downloads and some streams","aka":"Mechanical-Copyright Protection Society","money":"Collects composition mechanical royalties for writers and publishers","note":"Administered together with PRS for Music"}}]},{"name":"International CMOs","v":12,"meta":{"def":"National collecting societies around the world, linked by reciprocal deals.","ex":"GEMA, SACEM, SIAE, JASRAC, SOCAN, APRA AMCOS","aka":"foreign societies","money":"Collect domestically and remit foreign works via reciprocal agreements","note":"Most collect both performance and mechanical in their territory"},"children":[{"name":"GEMA","v":4,"meta":{"def":"Germany's performance and mechanical rights society.","ex":"Licenses German broadcast, live and online music use","aka":"Gesellschaft fuer musikalische Auffuehrungs- und Vervielfaeltigungsrechte","money":"Collects both performance and mechanical royalties for composition owners","note":"Its long standoff with YouTube shaped EU platform-liability debates"}},{"name":"SACEM","v":4,"meta":{"def":"France's society for authors, composers and music publishers.","ex":"One of the world's oldest CMOs, founded 1851","aka":"Societe des auteurs, compositeurs et editeurs de musique","money":"Collects composition performance and mechanical royalties","note":"Runs cross-border hubs handling digital mechanicals for many publishers"}},{"name":"SIAE","v":4,"meta":{"def":"Italy's authors' and publishers' collecting society.","ex":"Licenses Italian music, plus other creative works","aka":"Societa Italiana degli Autori ed Editori","money":"Collects performance and mechanical royalties in Italy","note":"Historically held a statutory monopoly on collective licensing"}},{"name":"JASRAC","v":4,"meta":{"def":"Japan's dominant music copyright collecting society.","ex":"Licenses broadcast, karaoke, live and online use in Japan","aka":"Japanese Society for Rights of Authors, Composers and Publishers","money":"Collects composition performance and reproduction royalties","note":"Faced antitrust scrutiny over its broadcast blanket practices"}},{"name":"SOCAN","v":4,"meta":{"def":"Canada's society for performing and reproduction rights of compositions.","ex":"Licenses Canadian broadcast, live and digital music","aka":"Society of Composers, Authors and Music Publishers of Canada","money":"Collects performance and (via acquisitions) mechanical royalties","note":"Also administers reproduction rights through subsidiaries"}},{"name":"APRA AMCOS","v":4,"meta":{"def":"The combined performance and mechanical society for Australia and New Zealand.","ex":"Licenses ANZ broadcast, venues and streaming","aka":"Australasian Performing Right Assoc. / Australasian Mechanical Copyright Owners Soc.","money":"APRA collects performance; AMCOS collects mechanicals; run jointly","note":"A single one-stop body for the Australasian region"}}]},{"name":"Umbrella Bodies & Functions","v":10,"meta":{"def":"International federations and the mechanics that link societies globally.","ex":"CISAC, BIEM, IFPI, reciprocal agreements","aka":"global rights infrastructure","money":"Coordinate cross-border collection and standards","note":"The plumbing that lets a song earn worldwide"},"children":[{"name":"CISAC","v":4,"meta":{"def":"The global confederation of authors' collective-management societies.","ex":"Umbrella for hundreds of CMOs worldwide","aka":"International Confederation of Societies of Authors and Composers","money":"Sets standards and tools underpinning cross-border royalty flows","note":"Maintains identifiers and documentation systems like ISWC/IPI infrastructure"}},{"name":"BIEM","v":4,"meta":{"def":"The international body of mechanical-rights societies.","ex":"Negotiates standard mechanical terms with the recording industry","aka":"Bureau International des Societes gerant les droits d'Enregistrement","money":"Frames the BIEM-IFPI standard mechanical royalty rate in many territories","note":"Counterpart to CISAC on the mechanical side"}},{"name":"IFPI","v":4,"meta":{"def":"The global trade body representing the recorded-music industry.","ex":"Advocates for labels and issues global market data","aka":"International Federation of the Phonographic Industry","money":"Not a collector, but sets standards (like the ISRC) and defends recording rights","note":"Administers the ISRC and Global Release Identifier registries"}},{"name":"Reciprocal Agreement","v":4,"meta":{"def":"A bilateral deal letting each society collect for the other's members in its territory.","ex":"ASCAP and PRS collecting for each other's writers","aka":"reciprocal representation agreement","money":"Foreign earnings flow home minus each society's admin fee","note":"The mechanism by which a US writer earns from a German radio play"}},{"name":"Collective Management Organisation","v":4,"meta":{"def":"The general term for any body licensing rights collectively for many owners.","ex":"PROs, mechanical societies and neighbouring-rights bodies","aka":"CMO, collecting society","money":"Aggregates many owners so users get one-stop licences","note":"Regulated in the EU by the Collective Rights Management Directive"}}]}]},{"name":"Law, Disputes & Identifiers","v":16,"meta":{"def":"The doctrines, conflicts and codes that govern and track music rights.","ex":"Work-for-hire, termination, fair use, DMCA, ISWC/ISRC","aka":"music copyright law","money":"Determines who owns, who can use, and how money is routed","note":"Where the industry's biggest fights and payouts are decided"},"children":[{"name":"Ownership & Duration Doctrines","v":10,"meta":{"def":"Rules about who owns rights and for how long.","ex":"Work-for-hire, termination, public domain, orphan works","aka":"ownership rules","money":"Control whether rights can be reclaimed or freely used","note":"Timing rules can be worth fortunes as catalogues age"},"children":[{"name":"Work-for-Hire","v":4,"meta":{"def":"A doctrine treating the commissioning party as author/owner of a created work.","ex":"A jingle written under a work-for-hire contract","aka":"work made for hire, WFH","money":"Owner keeps all rights; creator gets a fee, no ongoing royalties or reversion","note":"Sound recordings' WFH status is legally contested in the US"}},{"name":"Termination / Reversion (35-Year US)","v":4,"meta":{"def":"A US statutory right for authors to reclaim assigned copyrights after a set period.","ex":"A writer terminating a 1980s publishing grant","aka":"Section 203/304 termination, copyright reversion","money":"Author regains US rights and future income, overriding old contracts","note":"Exercisable 35-40 years after grant; blocked for genuine works-for-hire"}},{"name":"Public Domain","v":4,"meta":{"def":"The status of works whose copyright has expired or was never held.","ex":"Classical repertoire and old folk songs","aka":"PD","money":"Free to use, but a modern recording/arrangement of a PD work may still be protected","note":"Composition and recording can enter PD decades apart"}},{"name":"Orphan Works","v":4,"meta":{"def":"Copyrighted works whose owner cannot be identified or located.","ex":"An old recording with no traceable rights holder","aka":"orphaned rights","money":"Users risk liability; some regimes allow use after a diligent search","note":"Extended collective licensing is one solution to the orphan problem"}},{"name":"Copyright Term (Life+70)","v":4,"meta":{"def":"The standard duration of composition copyright in most major markets.","ex":"Protection until 70 years after the last author's death","aka":"duration, term of protection","money":"Sets when a catalogue stops earning and becomes free","note":"Sound-recording terms differ (e.g. 70 years from release in the EU/UK)"}}]},{"name":"Exceptions & Defences","v":10,"meta":{"def":"Legal doctrines that permit unlicensed use in defined circumstances.","ex":"Fair use, fair dealing, parody, de minimis","aka":"copyright exceptions, limitations","money":"If they apply, no licence or royalty is owed","note":"Narrow, fact-specific and heavily litigated"},"children":[{"name":"Fair Use","v":4,"meta":{"def":"A flexible US defence weighing purpose, nature, amount and market effect.","ex":"Transformative commentary, some parody and criticism","aka":"fair-use doctrine (17 USC 107)","money":"A successful fair-use finding means no payment to the owner","note":"Unpredictable; decided case by case by courts"}},{"name":"Fair Dealing","v":4,"meta":{"def":"The narrower UK/Commonwealth cousin of fair use, limited to listed purposes.","ex":"Criticism, review, quotation, news reporting","aka":"fair-dealing exceptions","money":"No royalty if use fits an enumerated category and is fair","note":"Unlike US fair use, purposes are a closed statutory list"}},{"name":"Parody Exception","v":4,"meta":{"def":"A limitation permitting humorous or critical imitation of a work.","ex":"Weird Al-style comedic reworkings (often still licensed courteously)","aka":"parody/pastiche/caricature exception","money":"Genuine parody may avoid a licence fee entirely","note":"US 2 Live Crew case (Campbell) recognised parody as potential fair use"}},{"name":"De Minimis Use","v":4,"meta":{"def":"The principle that trivially small takings are not actionable.","ex":"An almost imperceptible fragment of a sample","aka":"de minimis non curat lex","money":"If truly trivial, no clearance or payment is required","note":"The Bridgeport ruling rejected de minimis for sound-recording samples in the 6th Circuit"}},{"name":"Compulsory-Licence Defence","v":4,"meta":{"def":"The statutory guarantee that anyone may cover a released song at a set rate.","ex":"Recording a cover under Section 115 without owner consent","aka":"cover-right defence","money":"Owner must accept the statutory mechanical rate, cannot refuse","note":"Only covers non-dramatic recording, not adaptation or first release"}}]},{"name":"Infringement & Disputes","v":12,"meta":{"def":"The conflicts that arise when rights are allegedly copied or misused.","ex":"Sampling suits, similarity claims, landmark cases","aka":"copyright litigation","money":"Damages, injunctions and forced writer-credit splits","note":"High-profile verdicts reshape industry practice"},"children":[{"name":"Copyright Infringement","v":4,"meta":{"def":"Unauthorised exercise of an exclusive right in a work or recording.","ex":"Releasing music using someone's song without a licence","aka":"infringement","money":"Exposes the user to actual damages, profits or statutory damages","note":"US statutory damages can reach $150,000 per work if wilful"}},{"name":"Sampling Law","v":4,"meta":{"def":"The body of case law on reusing fragments of recordings/compositions.","ex":"Bridgeport v Dimension; Germany's Metall auf Metall (Kraftwerk)","aka":"sample-clearance law","money":"Unlicensed sampling risks damages and forfeited profits","note":"US and EU courts diverge on whether tiny samples need clearance"}},{"name":"Plagiarism / Substantial Similarity","v":4,"meta":{"def":"Claims that a new song copies protectable expression of an earlier one.","ex":"'Stairway to Heaven', 'Dark Horse' and 'Shape of You' cases","aka":"substantial-similarity claim","money":"Can force damages and retroactive co-writer credit/royalties","note":"Turns on access plus similarity of original expression, not mere style"}},{"name":"'Blurred Lines' Case","v":4,"meta":{"def":"The landmark 2015 verdict finding infringement of Marvin Gaye's 'Got to Give It Up'.","ex":"Thicke/Williams held liable for evoking a song's feel","aka":"Williams v Gaye","money":"Roughly $5m plus running royalties to the Gaye estate","note":"Criticised for protecting 'groove/vibe' rather than specific notes"}},{"name":"Interpolation Dispute","v":4,"meta":{"def":"A conflict over re-use of a melody/lyric that ends in credit and split changes.","ex":"Olivia Rodrigo adding writers after similarity claims","aka":"credit dispute","money":"Often settled by granting retroactive writer percentages","note":"Increasingly resolved pre-emptively to avoid litigation"}},{"name":"Sound-Alike / Re-Record","v":4,"meta":{"def":"Producing a deliberate imitation of a recording to avoid master-use fees.","ex":"A 'sound-alike' cover used in an ad when the original was too costly","aka":"soundalike, cover-for-sync","money":"Avoids master fee but still needs the composition sync licence","note":"Can risk right-of-publicity claims if it mimics a distinctive voice"}}]},{"name":"Digital Enforcement","v":8,"meta":{"def":"How rights are policed and monetised on online platforms.","ex":"DMCA safe harbour, Content ID, takedowns","aka":"online rights enforcement","money":"Turns unlicensed uploads into claims, blocks or ad revenue","note":"Balances platform liability against rights-holder control"},"children":[{"name":"DMCA / Safe Harbour","v":4,"meta":{"def":"US law shielding platforms from liability if they remove infringing content on notice.","ex":"YouTube's protection for user uploads","aka":"Digital Millennium Copyright Act, Section 512","money":"Shifts policing cost to rights holders via takedown notices","note":"The EU's Article 17 pushes more liability onto platforms"}},{"name":"Content ID","v":4,"meta":{"def":"YouTube's automated fingerprinting system that matches uploads to registered works.","ex":"A rights holder claiming ad revenue on a fan video","aka":"content fingerprinting","money":"Lets owners block, track or monetise matched uploads","note":"Central to YouTube's music payouts and to false-claim complaints"}},{"name":"Takedown Notice","v":4,"meta":{"def":"A formal request to remove infringing content under safe-harbour rules.","ex":"A DMCA notice to a host to remove a leaked track","aka":"DMCA notice, notice-and-takedown","money":"Free to send but no direct payment; can be met with a counter-notice","note":"Abuse of the process can itself create liability"}},{"name":"Notice-and-Stay-Down","v":4,"meta":{"def":"An obligation to prevent re-uploads of already-notified infringing content.","ex":"Filtering that stops the same file returning","aka":"stay-down obligation","money":"Reduces owners' repeat-notice burden and leakage","note":"Advanced by EU law but resisted as de facto upload filtering"}}]},{"name":"Identifiers & Metadata","v":12,"meta":{"def":"The standard codes that uniquely identify works, recordings and parties.","ex":"ISWC, ISRC, IPI, ISNI, GRid, DDEX","aka":"music metadata standards","money":"Correct codes route royalties to the right owners","note":"The invisible plumbing that makes global collection possible"},"children":[{"name":"ISWC","v":4,"meta":{"def":"A global code uniquely identifying a musical composition.","ex":"T-034.524.680-1 for a specific song","aka":"International Standard Musical Work Code","money":"Links performance/mechanical royalties across societies to the right work","note":"One ISWC covers all recordings of that composition"}},{"name":"ISRC","v":4,"meta":{"def":"A global code uniquely identifying a specific sound (or video) recording.","ex":"USRC17607839 on a released track","aka":"International Standard Recording Code","money":"Routes streaming/neighbouring-rights income to the correct master","note":"Each distinct recording, mix or edit gets its own ISRC"}},{"name":"IPI / CAE","v":4,"meta":{"def":"A number identifying a writer or publisher party across societies.","ex":"An IPI on a PRO account","aka":"Interested Parties Information / Composer-Author-Publisher number","money":"Ensures the right person is paid their writer/publisher share","note":"Managed through the CISAC-linked international database"}},{"name":"ISNI","v":4,"meta":{"def":"A public-registry identifier for the public identity of a creator or organisation.","ex":"An ISNI for an artist across databases","aka":"International Standard Name Identifier","money":"Improves matching so credits and royalties attach to the right person","note":"Broader than IPI; used across libraries and rights systems"}},{"name":"GRid / UPC","v":4,"meta":{"def":"Codes identifying digital releases (GRid) and physical/retail products (UPC/EAN).","ex":"A UPC barcode on an album; a GRid for a digital bundle","aka":"Global Release Identifier / Universal Product Code","money":"Track sales and stream reporting at the release/product level","note":"GRid was designed for the electronic-release supply chain"}},{"name":"DDEX Standard","v":4,"meta":{"def":"The messaging standards for exchanging music metadata and reports across the supply chain.","ex":"ERN release notifications and DSR sales reports","aka":"Digital Data Exchange","money":"Standardises the data that drives accurate royalty accounting","note":"The lingua franca between distributors, DSPs and societies"}}]}]}]},{"name":"Creation & Composition","type":"creation","v":26,"children":[{"name":"Songwriting","v":12,"meta":{"def":"The craft of creating a song by combining melody, lyric and harmony into a repeatable structure.","ex":"pop, rock, country, folk songwriting","aka":"song craft, composing songs","note":"Distinguished from composition by its focus on the concise, lyric-bearing song."},"children":[{"name":"Song Forms","v":10,"meta":{"def":"The large-scale sectional blueprints that organise a song into recurring and contrasting parts.","ex":"verse-chorus, AABA, 12-bar","aka":"song structures","note":"Form choices strongly signal genre expectations to listeners."},"children":[{"name":"Verse-Chorus","v":4,"meta":{"def":"Alternates a changing verse with a repeating chorus that carries the main hook.","ex":"most pop and rock singles since the 1960s","aka":"VCVC form","note":"The chorus usually holds the title and highest energy."}},{"name":"AABA","v":4,"meta":{"def":"Two matching verses, a contrasting bridge, then a return of the verse.","ex":"'Somewhere Over the Rainbow', 'Yesterday'","aka":"American Songbook form, 32-bar form","note":"Dominated Tin Pan Alley and jazz standards."}},{"name":"Twelve-Bar Blues","v":3,"meta":{"def":"A 12-measure harmonic cycle built on I, IV and V chords with a set lyric pattern.","ex":"'Sweet Home Chicago', 'Hound Dog'","aka":"blues form","note":"Its AAB lyric repeats the first line before a resolving third line."}},{"name":"Strophic","v":3,"meta":{"def":"Repeats the same music for every stanza of text.","ex":"hymns, ballads, 'The Times They Are a-Changin''","aka":"one-part song form, AAA","note":"Oldest and simplest song form, common in folk."}},{"name":"Through-Composed","v":3,"meta":{"def":"Continuously new material with little or no sectional repetition.","ex":"Schubert's 'Erlkönig', progressive rock suites","aka":"durchkomponiert","note":"Favours narrative songs where music tracks the text moment by moment."}},{"name":"Verse-Refrain","v":3,"meta":{"def":"Verses close with a short recurring refrain line rather than a full chorus.","ex":"many jazz standards, early folk","aka":"refrain form","note":"The refrain is often just the title sung at each verse's end."}}]},{"name":"Song Sections","v":10,"meta":{"def":"The building-block passages that combine into a song's overall form.","ex":"verse, chorus, bridge, pre-chorus","aka":"song parts","note":"Each section has a conventional length and energy role."},"children":[{"name":"Verse","v":3,"meta":{"def":"The narrative section that advances the story with changing lyrics over repeating music.","ex":"opening stanzas of a pop song","aka":"stanza","note":"Typically lower in energy to set up the chorus lift."}},{"name":"Chorus","v":3,"meta":{"def":"The repeating high-point section carrying the main message and hook.","ex":"the 'sing-along' part of a hit","aka":"refrain","note":"Often contains the song title as a memory anchor."}},{"name":"Bridge","v":3,"meta":{"def":"A contrasting section giving fresh melody or harmony before a final chorus.","ex":"the 'middle eight' departure in a pop tune","aka":"middle eight, release","note":"Frequently eight bars, hence 'middle eight'."}},{"name":"Pre-Chorus","v":3,"meta":{"def":"A transitional passage building tension between verse and chorus.","ex":"the 'lift' before a chorus drop","aka":"climb, build, channel","note":"Often raises harmonic tension to make the chorus feel bigger."}},{"name":"Intro","v":2,"meta":{"def":"An opening passage that establishes key, groove or hook before the vocal enters.","ex":"a four-bar instrumental riff opening","aka":"introduction","note":"Modern streaming favours very short or absent intros."}},{"name":"Outro","v":2,"meta":{"def":"The closing section that resolves or fades the song out.","ex":"a repeated chorus fade, a coda tag","aka":"coda, tag, ending","note":"Can vamp on the hook or use a hard button ending."}},{"name":"Post-Chorus","v":2,"meta":{"def":"A hooky section following the chorus that extends its impact.","ex":"wordless 'oh-oh' vocal hooks","aka":"chorus reprise","note":"Rose to prominence in 2010s EDM-influenced pop."}},{"name":"Drop","v":2,"meta":{"def":"The rhythmic and textural climax in dance-based songs after a build.","ex":"the beat drop in EDM and future bass","aka":"the beat drop","note":"Often instrumental, functioning as the song's real hook."}}]},{"name":"The Hook","v":6,"meta":{"def":"A short, memorable musical or lyrical idea designed to catch the ear.","ex":"a catchy riff, a repeated title phrase","aka":"the catch","note":"A song may layer melodic, lyrical and rhythmic hooks at once."},"children":[{"name":"Melodic Hook","v":2,"meta":{"def":"A memorable pitch phrase that lodges in the ear.","ex":"the vocal riff of 'Bad Romance'","aka":"vocal hook","note":"Often the very phrase listeners hum afterward."}},{"name":"Instrumental Hook","v":2,"meta":{"def":"A signature riff or lick that identifies the song without words.","ex":"the 'Seven Nation Army' bass riff","aka":"signature riff","note":"Can double as an intro and recurring motif."}},{"name":"Lyric Hook","v":2,"meta":{"def":"A catchy verbal phrase, often the title, that anchors the song.","ex":"'I Will Always Love You'","aka":"title hook","note":"Best hooks pair a strong phrase with a strong note."}},{"name":"Earworm","v":2,"meta":{"def":"A tune fragment that involuntarily repeats in the mind.","ex":"'Baby Shark', 'Can't Get You Out of My Head'","aka":"stuck song syndrome, sticky music","note":"Studies link earworms to simple contours and small pitch leaps."}}]},{"name":"Lyric Writing","v":12,"meta":{"def":"The craft of shaping words for singing, balancing sound, meaning and rhythm.","ex":"verse narratives, chorus payoffs","aka":"lyric craft, penning lyrics","note":"Prosody, the fit of word stress to melody, is a central discipline."},"children":[{"name":"Rhyme","v":5,"meta":{"def":"Matching of end sounds between words for cohesion and payoff.","ex":"perfect, slant, internal rhyme","aka":"rhyming","note":"Modern lyrics favour slant rhyme for a natural feel."},"children":[{"name":"Perfect Rhyme","v":2,"meta":{"def":"Exact match of stressed vowel and following sounds.","ex":"'time' / 'rhyme'","aka":"full rhyme","note":"Feels resolved but can sound predictable."}},{"name":"Slant Rhyme","v":2,"meta":{"def":"Near-match of sounds that are close but not identical.","ex":"'shape' / 'keep'","aka":"near rhyme, half rhyme, imperfect rhyme","note":"Central to hip-hop and contemporary pop lyricism."}},{"name":"Internal Rhyme","v":2,"meta":{"def":"Rhyme occurring within a line rather than at its end.","ex":"'I drive myself to sleep at the deep'","aka":"middle rhyme","note":"Drives the density and flow of rap verses."}},{"name":"Rhyme Scheme","v":2,"meta":{"def":"The pattern of rhymes across lines of a stanza.","ex":"AABB, ABAB, ABCB","aka":"rhyme pattern","note":"ABCB is common in folk and country ballads."}}]},{"name":"Meter and Prosody","v":3,"meta":{"def":"The rhythmic fit of stressed and unstressed syllables to the melody.","ex":"matching accented words to strong beats","aka":"lyrical rhythm, scansion","note":"Misplaced stress (a 'false accent') is a classic beginner flaw."}},{"name":"Narrative and Storytelling","v":2,"meta":{"def":"Building a lyric around characters, arc and point of view.","ex":"story songs like 'The Night the Lights Went Out in Georgia'","aka":"lyric narrative","note":"First, second and third person choices shape intimacy."}},{"name":"Imagery and Metaphor","v":2,"meta":{"def":"Concrete sensory language and figurative comparison to convey emotion.","ex":"'like a bridge over troubled water'","aka":"figurative language","note":"Show-don't-tell imagery outlasts abstract statement."}},{"name":"Theme and Concept","v":2,"meta":{"def":"The central idea or throughline unifying a lyric.","ex":"heartbreak, defiance, nostalgia","aka":"song concept","note":"A clear one-line concept keeps the lyric focused."}},{"name":"Line and Stanza","v":2,"meta":{"def":"The organisation of lyrics into lines and grouped stanzas.","ex":"four-line verses, two-line refrains","aka":"lyric form","note":"Line length controls pacing and breath."}}]},{"name":"Writing Approaches","v":10,"meta":{"def":"Working methods and collaborative practices for generating songs.","ex":"co-writing, toplining, writing to a track","aka":"songwriting workflows","note":"Modern pop is overwhelmingly collaborative and track-first."},"children":[{"name":"Co-Writing","v":2,"meta":{"def":"Two or more writers collaborating on a single song.","ex":"Lennon-McCartney, Nashville writing rounds","aka":"collaboration, songwriting partnership","note":"Splits are typically negotiated by contribution or equal shares."}},{"name":"Toplining","v":2,"meta":{"def":"Writing the vocal melody and lyric over a pre-made instrumental.","ex":"a topliner voicing a producer's beat","aka":"topline writing","note":"A topline is the melody-plus-lyric layer atop the track."}},{"name":"Writing to a Track","v":2,"meta":{"def":"Composing a song around an existing beat or production.","ex":"hip-hop and EDM vocal writing","aka":"track-first writing","note":"Reverses the classic melody-then-arrangement order."}},{"name":"Songwriting Camps","v":2,"meta":{"def":"Intensive multi-day sessions gathering writers and producers to generate songs.","ex":"K-pop and major-label camps","aka":"writing camps","note":"Can produce dozens of demos pitched to one artist."}},{"name":"Songwriting Prompts","v":2,"meta":{"def":"Constraints or seeds used to spark ideas.","ex":"title-first, one-word, chord-loop prompts","aka":"writing exercises","note":"Deadlines and limits often boost output more than free inspiration."}},{"name":"Demoing","v":2,"meta":{"def":"Recording a rough version to capture and pitch a song.","ex":"guitar-vocal demo, full production demo","aka":"the demo","note":"A 'work tape' is the roughest first capture on a phone."}}]},{"name":"Borrowing and Reuse","v":8,"meta":{"def":"Techniques that build new songs from pre-existing musical material.","ex":"sampling, interpolation, quotation","aka":"referential writing","note":"Each carries distinct copyright and clearance implications."},"children":[{"name":"Sampling","v":3,"meta":{"def":"Reusing a portion of an existing recording within a new song.","ex":"a drum break looped in hip-hop","aka":"the sample","note":"Requires clearing both the master and the underlying composition."}},{"name":"Interpolation","v":3,"meta":{"def":"Re-recording a melody or lyric from another song rather than sampling it.","ex":"Olivia Rodrigo interpolating Paramore","aka":"replay","note":"Avoids master clearance but still needs the publishing license."}},{"name":"Flip","v":2,"meta":{"def":"Transforming a sample into a substantially new musical context.","ex":"chopped and pitched soul flips","aka":"sample flip","note":"Central to producer culture in hip-hop and beat-making."}},{"name":"Quotation","v":2,"meta":{"def":"Briefly referencing a recognisable tune inside a new work.","ex":"a familiar fanfare woven into a solo","aka":"musical quote","note":"Common in jazz improvisation as an inside joke."}},{"name":"Contrafact","v":2,"meta":{"def":"A new melody written over an existing chord progression.","ex":"'Ornithology' over 'How High the Moon'","aka":"contrafactum","note":"Let jazz musicians reuse standard changes without licensing the tune."}}]}]},{"name":"Composition","v":14,"meta":{"def":"The art of creating extended, notated musical works, especially in the classical tradition.","ex":"symphony, sonata, opera, fugue","aka":"art-music composing, écriture","note":"Emphasises large-scale form, development and orchestration."},"children":[{"name":"Instrumental Forms","v":12,"meta":{"def":"Multi-section architectures for works without voices.","ex":"sonata form, rondo, theme and variations","aka":"absolute music forms","note":"Sonata form organised the Classical and Romantic instrumental repertoire."},"children":[{"name":"Sonata Form","v":3,"meta":{"def":"A movement design of exposition, development and recapitulation of themes.","ex":"first movements of Classical symphonies","aka":"sonata-allegro form, first-movement form","note":"Built on tonal contrast between a first and second key area."}},{"name":"Rondo","v":2,"meta":{"def":"A recurring refrain alternating with contrasting episodes.","ex":"ABACA, ABACABA schemes","aka":"rondo form","note":"Often used for bright, dance-like finales."}},{"name":"Theme and Variations","v":2,"meta":{"def":"A theme restated in successively altered versions.","ex":"Bach's Goldberg Variations","aka":"variation form","note":"Variations can change harmony, rhythm, mode or texture."}},{"name":"Fugue","v":3,"meta":{"def":"A contrapuntal work where a subject is imitated across independent voices.","ex":"Bach's 'The Art of Fugue'","aka":"fuga","note":"Features exposition, episodes and devices like stretto."}},{"name":"Canon","v":2,"meta":{"def":"Strict imitation where voices repeat the same melody at a fixed delay.","ex":"Pachelbel's Canon, 'Row, Row, Row Your Boat'","aka":"round (for the simplest kind)","note":"A perpetual canon loops back to its beginning."}},{"name":"Suite","v":2,"meta":{"def":"A set of contrasting movements, often stylised dances.","ex":"Bach's cello suites, Holst's 'The Planets'","aka":"partita, ordre","note":"Baroque suites strung allemandes, courantes and gigues."}},{"name":"Fantasia","v":2,"meta":{"def":"A free-form work that follows imagination over set structure.","ex":"Bach's Chromatic Fantasia","aka":"fantasy, fancy","note":"Often improvisatory and rhapsodic in character."}},{"name":"Prelude","v":2,"meta":{"def":"A short introductory or standalone piece, often exploring one idea.","ex":"Chopin's 24 Preludes","aka":"praeludium","note":"Originally preceded a fugue or larger work."}},{"name":"Etude","v":2,"meta":{"def":"A study piece built to develop a specific technique, sometimes concert-worthy.","ex":"Chopin and Liszt etudes","aka":"study","note":"The concert etude elevates technical drill to art."}}]},{"name":"Large Ensemble Works","v":8,"meta":{"def":"Compositions for orchestra or large forces.","ex":"symphony, concerto, tone poem","aka":"orchestral genres","note":"The symphony became the flagship of Western art music."},"children":[{"name":"Symphony","v":3,"meta":{"def":"An extended multi-movement work for orchestra.","ex":"Beethoven's Ninth, Mahler's symphonies","aka":"sinfonia","note":"Classic four-movement plan: fast, slow, dance, finale."}},{"name":"Concerto","v":3,"meta":{"def":"A work contrasting a solo instrument against the orchestra.","ex":"Tchaikovsky's Violin Concerto","aka":"solo concerto","note":"The cadenza spotlights the soloist unaccompanied."}},{"name":"Tone Poem","v":2,"meta":{"def":"A single-movement orchestral work depicting a story, scene or idea.","ex":"Strauss's 'Also sprach Zarathustra'","aka":"symphonic poem","note":"A hallmark of Romantic programme music."}},{"name":"Overture","v":2,"meta":{"def":"An orchestral opener to an opera or a standalone concert piece.","ex":"the '1812 Overture'","aka":"ouverture","note":"Concert overtures detach the form from any staged work."}},{"name":"Concerto Grosso","v":2,"meta":{"def":"A Baroque concerto contrasting a small solo group with the full ensemble.","ex":"Handel's Op. 6","aka":"grand concerto","note":"The solo group is the 'concertino', the full band the 'ripieno'."}}]},{"name":"Chamber Forms","v":8,"meta":{"def":"Works for small ensembles with one player per part.","ex":"string quartet, piano trio","aka":"chamber music","note":"Prizes intimate dialogue and equality between instruments."},"children":[{"name":"String Quartet","v":3,"meta":{"def":"A work for two violins, viola and cello.","ex":"Haydn's and Beethoven's quartets","aka":"quartet","note":"Considered the summit of chamber writing."}},{"name":"Piano Trio","v":2,"meta":{"def":"A work for piano, violin and cello.","ex":"Schubert's E-flat Trio","aka":"trio","note":"Balances the piano against two strings."}},{"name":"Sonata (Duo)","v":2,"meta":{"def":"A multi-movement work for one or two instruments, often with piano.","ex":"violin sonata, cello sonata","aka":"duo sonata","note":"Distinct from the abstract 'sonata form' movement design."}},{"name":"Quintet","v":2,"meta":{"def":"A work for five instruments in varied combinations.","ex":"Schubert's 'Trout' Quintet","aka":"wind quintet, brass quintet","note":"Adding one player to a quartet reshapes the texture."}},{"name":"Divertimento","v":2,"meta":{"def":"A light, entertaining multi-movement chamber piece.","ex":"Mozart's divertimenti","aka":"serenade, cassation","note":"Often written for social or outdoor occasions."}}]},{"name":"Vocal and Choral Forms","v":10,"meta":{"def":"Composed works featuring the voice, sacred or secular.","ex":"mass, oratorio, art song","aka":"vocal genres","note":"Text and music interact through word-painting and declamation."},"children":[{"name":"Mass","v":2,"meta":{"def":"A setting of the Catholic liturgy's ordinary texts.","ex":"Bach's Mass in B minor","aka":"missa","note":"Sets Kyrie, Gloria, Credo, Sanctus and Agnus Dei."}},{"name":"Requiem","v":2,"meta":{"def":"A mass for the dead, often expanded into a concert work.","ex":"Mozart's and Verdi's Requiems","aka":"missa pro defunctis","note":"Adds the dramatic 'Dies irae' sequence."}},{"name":"Oratorio","v":2,"meta":{"def":"A large unstaged work for voices and orchestra on a sacred story.","ex":"Handel's 'Messiah'","aka":"sacred oratorio","note":"Like opera but without costumes, sets or action."}},{"name":"Cantata","v":2,"meta":{"def":"A multi-movement vocal work with instrumental accompaniment.","ex":"Bach's church cantatas","aka":"kantate","note":"Combines recitatives, arias and chorales."}},{"name":"Art Song (Lied)","v":3,"meta":{"def":"A composed setting of a poem for solo voice and piano.","ex":"Schubert's 'Winterreise'","aka":"lied, mélodie","note":"A grouped set is a 'song cycle'."}},{"name":"Motet","v":2,"meta":{"def":"A polyphonic sacred choral work, usually unaccompanied.","ex":"Renaissance motets by Palestrina","aka":"motetus","note":"A cornerstone of Renaissance sacred polyphony."}},{"name":"Madrigal","v":2,"meta":{"def":"A secular polyphonic vocal work setting poetry, often about love.","ex":"Monteverdi's madrigals","aka":"madrigale","note":"Famous for vivid word-painting of the text."}},{"name":"Chorale","v":2,"meta":{"def":"A hymn tune harmonised in four voices, a staple of harmony study.","ex":"Bach's chorale harmonisations","aka":"hymn setting","note":"The model text for teaching voice leading."}}]},{"name":"Dramatic Forms","v":6,"meta":{"def":"Staged musical works uniting drama, voice and orchestra.","ex":"opera, ballet, musical theatre","aka":"music theatre","note":"Opera integrates aria, recitative and orchestra into drama."},"children":[{"name":"Opera","v":3,"meta":{"def":"A staged drama sung throughout with orchestra.","ex":"Verdi's 'La traviata', Mozart's 'Don Giovanni'","aka":"opera seria, opera buffa","note":"Alternates aria (lyrical) and recitative (speech-like) singing."}},{"name":"Aria","v":2,"meta":{"def":"A lyrical solo song within an opera or oratorio.","ex":"'Nessun dorma'","aka":"air","note":"The da capo aria repeats its opening section with ornamentation."}},{"name":"Recitative","v":2,"meta":{"def":"Speech-like singing that carries dialogue and plot.","ex":"sung dialogue between arias","aka":"recitativo","note":"'Secco' recitative uses sparse continuo accompaniment."}},{"name":"Ballet Score","v":2,"meta":{"def":"Orchestral music composed to accompany dance narrative.","ex":"Tchaikovsky's 'Swan Lake'","aka":"dance score","note":"Structured around choreographed set pieces and variations."}},{"name":"Singspiel","v":2,"meta":{"def":"A German opera mixing spoken dialogue with songs.","ex":"Mozart's 'The Magic Flute'","aka":"song-play","note":"An ancestor of the modern musical."}}]},{"name":"Film and Media Scoring","v":8,"meta":{"def":"Composing music to accompany film, television and games.","ex":"orchestral scores, leitmotif underscore","aka":"screen scoring, soundtrack composing","note":"Music is synchronised to picture and dramatic cues."},"children":[{"name":"Underscore","v":2,"meta":{"def":"Background music supporting a scene's emotion beneath dialogue.","ex":"tense strings under a chase","aka":"score, cue","note":"Meant to be felt more than consciously heard."}},{"name":"Leitmotif","v":3,"meta":{"def":"A recurring theme tied to a character, place or idea.","ex":"the 'Imperial March' for Darth Vader","aka":"leading motive, signature theme","note":"Wagner pioneered the device in his operas."}},{"name":"Mickey-Mousing","v":2,"meta":{"def":"Music that mirrors on-screen action beat for beat.","ex":"a rising scale as a character climbs","aka":"hitting the action","note":"Named for its heavy use in early cartoons."}},{"name":"Temp Track","v":2,"meta":{"def":"Placeholder music an editor uses before the real score exists.","ex":"borrowed cues during editing","aka":"temp music","note":"'Temp love' can bias directors toward imitating the placeholder."}},{"name":"Adaptive Game Music","v":2,"meta":{"def":"Score that changes in response to player action and game state.","ex":"combat music that layers in on threat","aka":"interactive, dynamic music","note":"Uses vertical layering and horizontal re-sequencing."}}]},{"name":"Compositional Techniques","v":8,"meta":{"def":"Craft methods for developing and organising musical material.","ex":"motivic development, serialism, orchestration","aka":"compositional devices","note":"Development transforms small ideas into large structures."},"children":[{"name":"Motivic Development","v":3,"meta":{"def":"Growing a work by transforming a small musical cell.","ex":"Beethoven's Fifth four-note motif","aka":"thematic development","note":"Devices include inversion, augmentation and fragmentation."}},{"name":"Orchestration","v":3,"meta":{"def":"Assigning musical material to specific instruments and colours.","ex":"Ravel's orchestration of 'Pictures at an Exhibition'","aka":"instrumentation","note":"Balances range, blend and dynamic weight across the ensemble."}},{"name":"Serialism","v":2,"meta":{"def":"Composing from an ordered row of all twelve pitches.","ex":"Schoenberg's twelve-tone method","aka":"dodecaphony, twelve-tone technique","note":"Total serialism extends ordering to rhythm and dynamics."}},{"name":"Aleatoric Music","v":2,"meta":{"def":"Composition leaving elements to chance or performer choice.","ex":"Cage's 'Music of Changes'","aka":"chance music, indeterminacy","note":"Scores may specify probabilities rather than fixed notes."}},{"name":"Minimalism","v":2,"meta":{"def":"Building works from slowly shifting repeated patterns.","ex":"Reich's 'Music for 18 Musicians'","aka":"process music","note":"Uses phasing, additive process and steady pulse."}},{"name":"Word Painting","v":2,"meta":{"def":"Musical gestures that illustrate the literal meaning of a text.","ex":"rising notes on the word 'ascend'","aka":"text painting, madrigalism","note":"A defining trait of Renaissance madrigals."}}]}]},{"name":"Arrangement","v":10,"meta":{"def":"Adapting an existing composition for particular voices, instruments or contexts.","ex":"big-band charts, vocal harmony stacks","aka":"arranging","note":"Distinct from composition: reshapes existing material rather than inventing it."},"children":[{"name":"Reharmonisation","v":4,"meta":{"def":"Replacing a melody's original chords with new harmonies.","ex":"jazz reharm of a standard","aka":"reharm","note":"Techniques include tritone substitution and modal interchange."},"children":[{"name":"Chord Substitution","v":2,"meta":{"def":"Swapping a chord for one with a related function.","ex":"tritone sub replacing a V7","aka":"sub","note":"Preserves function while changing colour."}},{"name":"Modal Interchange","v":2,"meta":{"def":"Borrowing chords from a parallel mode or key.","ex":"a minor iv in a major key","aka":"borrowed chords, mode mixture","note":"Adds emotional shading without leaving the tonic."}},{"name":"Passing Chords","v":2,"meta":{"def":"Transitional chords inserted to smooth motion between main chords.","ex":"chromatic passing diminished chords","aka":"connecting chords","note":"Enrich harmonic rhythm without altering the destination."}}]},{"name":"Voicing","v":4,"meta":{"def":"The specific vertical spacing and ordering of a chord's notes.","ex":"close voicing, drop-2 voicing","aka":"chord voicing","note":"Voicing choice shapes texture as much as the chord itself."},"children":[{"name":"Close and Open Voicing","v":2,"meta":{"def":"Chord tones packed within an octave versus spread wider.","ex":"close-position piano block chords","aka":"spacing","note":"Open voicings sound broader and clearer."}},{"name":"Drop Voicings","v":2,"meta":{"def":"Voicings formed by lowering a chord tone by an octave.","ex":"drop-2, drop-3 guitar voicings","aka":"drop-2/drop-3","note":"A staple of jazz guitar and big-band brass."}},{"name":"Voicing for Ensemble","v":2,"meta":{"def":"Distributing chord tones across an ensemble's instruments.","ex":"spread voicings across a horn section","aka":"orchestral spacing","note":"Avoids muddiness in low registers by widening low intervals."}}]},{"name":"Ensemble Arranging","v":6,"meta":{"def":"Writing parts tailored to a specific group of performers.","ex":"big band, string section, a cappella","aka":"charting","note":"Each ensemble carries idiomatic ranges and doublings."},"children":[{"name":"Big Band Charting","v":2,"meta":{"def":"Arranging for jazz saxes, brass and rhythm section.","ex":"Basie and Ellington charts","aka":"big-band arranging","note":"Uses section writing, shout choruses and soli passages."}},{"name":"String Arranging","v":2,"meta":{"def":"Writing parts for a string section behind a song or score.","ex":"sweeping pop string pads","aka":"string charts","note":"Divisi splits a section into multiple simultaneous parts."}},{"name":"Horn Section Arranging","v":2,"meta":{"def":"Writing punchy brass and reed lines for pop, soul and funk.","ex":"Tower of Power horn stabs","aka":"horn charts","note":"Stabs, pads and unison lines are core devices."}},{"name":"Rhythm Section Arranging","v":2,"meta":{"def":"Coordinating drums, bass, keys and guitar into a groove.","ex":"a locked bass-and-drum pocket","aka":"groove arranging","note":"Defines feel through part interlock and space."}}]},{"name":"Vocal Arranging","v":5,"meta":{"def":"Arranging sung parts into harmony and layered textures.","ex":"backing vocal stacks, a cappella","aka":"vocal harmony writing","note":"Balances lead clarity against harmonic support."},"children":[{"name":"Harmony Stack","v":2,"meta":{"def":"Layered vocal parts harmonising a lead line.","ex":"third-and-fifth stacked backing vocals","aka":"vocal stack, BVs","note":"Doubling and octaves thicken the wall of vocals."}},{"name":"A Cappella Arranging","v":2,"meta":{"def":"Arranging a full song for voices alone.","ex":"collegiate a cappella, barbershop","aka":"vocal-only arranging","note":"Includes vocal bass and mouth-percussion parts."}},{"name":"Call and Response Vocals","v":2,"meta":{"def":"Alternating lead and answering group vocal phrases.","ex":"gospel choir responses","aka":"antiphonal vocals","note":"Rooted in gospel and African vocal traditions."}},{"name":"Counter-Melody","v":2,"meta":{"def":"A secondary sung line complementing the main melody.","ex":"a descant soaring over the tune","aka":"descant, obbligato","note":"Often enters late to lift a final chorus."}}]},{"name":"Adaptation and Reworking","v":6,"meta":{"def":"Transforming a work into a new medium, style or version.","ex":"transcription, cover, remix","aka":"reworking","note":"Ranges from faithful transcription to radical reinvention."},"children":[{"name":"Transcription","v":2,"meta":{"def":"Notating or rescoring music from a recording or another medium.","ex":"a solo transcribed to sheet music","aka":"transcribing","note":"Also means rewriting a piece for a different instrument."}},{"name":"Cover Arrangement","v":2,"meta":{"def":"A new performance and arrangement of an existing song.","ex":"an acoustic cover of a pop hit","aka":"cover version","note":"Reinterpretation can change genre, tempo and mood entirely."}},{"name":"Remix","v":2,"meta":{"def":"Rearranging a recording's stems into a new version.","ex":"a club remix of a pop single","aka":"the remix","note":"Functions as arrangement using recorded parts as raw material."}},{"name":"Medley","v":2,"meta":{"def":"A continuous sequence stitching several songs together.","ex":"a show-opening hits medley","aka":"potpourri","note":"Requires smooth key and tempo transitions between tunes."}},{"name":"Mashup","v":2,"meta":{"def":"Combining elements of two or more songs into one.","ex":"one song's vocal over another's beat","aka":"bootleg, blend","note":"Depends on matching key and tempo of the sources."}}]}]},{"name":"Music Theory","v":16,"meta":{"def":"The study of the elements and structures that make up music.","ex":"scales, chords, harmony, counterpoint","aka":"theory","note":"Provides the shared vocabulary underlying composition and analysis."},"children":[{"name":"Pitch and Intervals","v":8,"meta":{"def":"The theory of individual tones and the distances between them.","ex":"note names, octaves, thirds, fifths","aka":"pitch theory","note":"Interval quality (major, minor, perfect) defines harmonic colour."},"children":[{"name":"Pitch","v":2,"meta":{"def":"The perceived highness or lowness of a tone set by frequency.","ex":"A4 at 440 Hz","aka":"tone height","note":"Pitch class ignores octave, grouping all C's together."}},{"name":"Note","v":2,"meta":{"def":"A named musical pitch with a specific letter and accidental.","ex":"C, F-sharp, B-flat","aka":"tone","note":"Enharmonic notes sound alike but are spelled differently."}},{"name":"Interval","v":3,"meta":{"def":"The pitch distance between two notes, measured by size and quality.","ex":"major third, perfect fifth, tritone","aka":"melodic or harmonic interval","note":"The tritone was once called 'diabolus in musica'."}},{"name":"Octave","v":2,"meta":{"def":"The interval between a pitch and one at twice its frequency.","ex":"C4 to C5","aka":"the eighth","note":"Notes an octave apart share the same letter name."}},{"name":"Overtone Series","v":2,"meta":{"def":"The natural harmonics sounding above a fundamental pitch.","ex":"harmonics on a bugle","aka":"harmonic series, partials","note":"It underlies timbre and the physical basis of consonance."}},{"name":"Enharmonic Equivalence","v":2,"meta":{"def":"Two note spellings that sound the same in equal temperament.","ex":"F-sharp equals G-flat","aka":"enharmonics","note":"Spelling choice depends on harmonic context."}}]},{"name":"Scales and Modes","v":12,"meta":{"def":"Ordered collections of pitches forming the basis of melody and key.","ex":"major, minor, Dorian, pentatonic","aka":"scale theory","note":"Mode choice sets a passage's characteristic flavour."},"children":[{"name":"Major Scale","v":2,"meta":{"def":"A seven-note scale with a bright W-W-H-W-W-W-H step pattern.","ex":"C major: C D E F G A B","aka":"Ionian mode","note":"The reference scale of Western tonal music."}},{"name":"Minor Scales","v":3,"meta":{"def":"Scales with a lowered third giving a darker character.","ex":"natural, harmonic, melodic minor","aka":"minor","note":"Harmonic minor raises the seventh for a stronger cadence."}},{"name":"Church Modes","v":4,"meta":{"def":"Seven diatonic scales rotating the major scale's steps.","ex":"Dorian, Phrygian, Lydian, Mixolydian","aka":"diatonic modes, ecclesiastical modes","note":"Ionian and Aeolian equal today's major and natural minor."},"children":[{"name":"Dorian","v":2,"meta":{"def":"A minor mode with a raised sixth.","ex":"D to D on white keys","aka":"second mode","note":"Common in jazz, folk and modal rock."}},{"name":"Phrygian","v":2,"meta":{"def":"A minor mode with a lowered second giving a Spanish flavour.","ex":"E to E on white keys","aka":"third mode","note":"Central to flamenco and metal riffing."}},{"name":"Lydian","v":2,"meta":{"def":"A major mode with a raised fourth for a dreamy lift.","ex":"F to F on white keys","aka":"fourth mode","note":"Beloved in film scoring for wonder and awe."}},{"name":"Mixolydian","v":2,"meta":{"def":"A major mode with a lowered seventh, dominant in feel.","ex":"G to G on white keys","aka":"fifth mode","note":"The default for blues, rock and Celtic tunes."}},{"name":"Locrian","v":2,"meta":{"def":"A diminished mode with lowered second and fifth, very unstable.","ex":"B to B on white keys","aka":"seventh mode","note":"Rare because its tonic triad is diminished."}}]},{"name":"Pentatonic Scale","v":2,"meta":{"def":"A five-note scale omitting the semitone-clashing degrees.","ex":"major and minor pentatonics","aka":"five-note scale","note":"Ubiquitous across folk, blues and world music."}},{"name":"Blues Scale","v":2,"meta":{"def":"A minor pentatonic with an added flattened 'blue' note.","ex":"the flat-five blue note","aka":"blues pentatonic","note":"The blue note is bent between major and minor thirds."}},{"name":"Chromatic Scale","v":2,"meta":{"def":"All twelve semitones within an octave in sequence.","ex":"C to C by half steps","aka":"twelve-tone scale","note":"Used for colour, tension and passing motion."}},{"name":"Whole-Tone Scale","v":2,"meta":{"def":"A six-note scale built entirely of whole steps.","ex":"C D E F-sharp G-sharp A-sharp","aka":"hexatonic whole-tone","note":"Its symmetry gives a floating, keyless quality."}},{"name":"Octatonic Scale","v":2,"meta":{"def":"An eight-note scale alternating whole and half steps.","ex":"diminished scale in jazz","aka":"diminished scale","note":"Symmetrical, favoured by Stravinsky and jazz players."}}]},{"name":"Chords","v":12,"meta":{"def":"Groups of pitches sounded together as harmonic units.","ex":"triads, sevenths, extended chords","aka":"harmony blocks","note":"Chord quality arises from stacked interval structure."},"children":[{"name":"Triad","v":3,"meta":{"def":"A three-note chord of stacked thirds.","ex":"major, minor, diminished, augmented triads","aka":"three-note chord","note":"The foundation of Western harmony."}},{"name":"Seventh Chord","v":3,"meta":{"def":"A triad with an added seventh above the root.","ex":"dominant 7, major 7, minor 7","aka":"7th chord","note":"The dominant seventh drives most cadences."}},{"name":"Extended Chord","v":2,"meta":{"def":"A chord stacking further thirds beyond the seventh.","ex":"ninth, eleventh, thirteenth chords","aka":"tall chords","note":"Core to jazz and lush pop harmony."}},{"name":"Suspended Chord","v":2,"meta":{"def":"A chord replacing the third with a second or fourth.","ex":"sus2, sus4","aka":"suspension","note":"Creates tension that usually resolves to the third."}},{"name":"Diminished Chord","v":2,"meta":{"def":"A chord of stacked minor thirds, tense and unstable.","ex":"diminished triad, fully diminished seventh","aka":"dim chord","note":"The symmetric dim7 pivots to many keys."}},{"name":"Augmented Chord","v":2,"meta":{"def":"A major triad with a raised fifth.","ex":"C augmented: C E G-sharp","aka":"aug chord","note":"Symmetrical and restless, often a passing colour."}},{"name":"Power Chord","v":2,"meta":{"def":"A two-note chord of root and fifth, omitting the third.","ex":"distorted guitar fifths","aka":"fifth chord, five chord","note":"Neither major nor minor, ideal under distortion."}},{"name":"Inversion","v":2,"meta":{"def":"A chord with a note other than the root in the bass.","ex":"first and second inversions","aka":"chord inversion","note":"Smooths bass lines and voice leading."}}]},{"name":"Harmony and Progression","v":12,"meta":{"def":"How chords combine and move to create tonal motion.","ex":"ii-V-I, circle of fifths, cadence","aka":"harmonic theory","note":"Function theory labels chords by tonic, subdominant and dominant roles."},"children":[{"name":"Chord Progression","v":3,"meta":{"def":"An ordered sequence of chords forming a harmonic path.","ex":"I-IV-V, vi-IV-I-V","aka":"changes, progression","note":"Roman numerals label chords relative to the key."},"children":[{"name":"ii-V-I","v":2,"meta":{"def":"A cadential progression that is the backbone of jazz harmony.","ex":"Dm7-G7-Cmaj7 in C","aka":"two-five-one","note":"Chains of ii-Vs modulate through many keys."}},{"name":"I-V-vi-IV","v":2,"meta":{"def":"A four-chord loop underpinning countless pop songs.","ex":"C-G-Am-F","aka":"the four-chord song, pop-punk progression","note":"Endlessly reused across decades of hits."}},{"name":"Twelve-Bar Blues Changes","v":2,"meta":{"def":"The I-IV-V harmonic cycle of the blues.","ex":"the standard blues turnaround","aka":"blues changes","note":"The turnaround at bar 11-12 sets up the repeat."}},{"name":"Circle Progression","v":2,"meta":{"def":"Chords moving by descending fifths around the circle.","ex":"vi-ii-V-I motion","aka":"circle of fifths progression","note":"Root motion by fifth is the strongest in tonal music."}}]},{"name":"Functional Harmony","v":2,"meta":{"def":"The system of chord roles that create expectation and resolution.","ex":"tonic, subdominant, dominant functions","aka":"harmonic function","note":"Tension builds on dominant, releases to tonic."}},{"name":"Cadence","v":3,"meta":{"def":"A chord pairing that punctuates a phrase's end.","ex":"authentic, plagal, half, deceptive","aka":"harmonic cadence","note":"The authentic V-I is the strongest close."}},{"name":"Modulation","v":2,"meta":{"def":"The process of changing from one key to another.","ex":"pivot-chord and direct modulation","aka":"key change","note":"A common-chord pivot smooths the transition."}},{"name":"Circle of Fifths","v":2,"meta":{"def":"A diagram ordering keys by fifths and their signatures.","ex":"C-G-D-A around the circle","aka":"cycle of fifths","note":"Maps key relationships and guides modulation."}},{"name":"Consonance and Dissonance","v":2,"meta":{"def":"The relative stability or tension of sounding intervals and chords.","ex":"a stable third versus a tense tritone","aka":"concord and discord","note":"Dissonance craves resolution to consonance."}},{"name":"Tonality and Atonality","v":2,"meta":{"def":"Whether music centres on a home key or avoids one.","ex":"tonal Mozart versus atonal Webern","aka":"key-centred vs keyless","note":"Atonality treats all twelve tones as equal."}}]},{"name":"Counterpoint and Voice Leading","v":6,"meta":{"def":"The art of combining independent melodic lines that sound well together.","ex":"species counterpoint, Bach chorales","aka":"polyphonic writing","note":"Governs how individual voices move between chords."},"children":[{"name":"Species Counterpoint","v":2,"meta":{"def":"A graded method for learning to combine melodic lines.","ex":"first through fifth species","aka":"Fuxian counterpoint","note":"Codified in Fux's 'Gradus ad Parnassum'."}},{"name":"Voice Leading","v":2,"meta":{"def":"Guiding each voice smoothly from chord to chord.","ex":"keeping common tones, moving by step","aka":"part-writing","note":"Aims to avoid parallel fifths and octaves."}},{"name":"Imitation","v":2,"meta":{"def":"One voice restating a phrase just introduced by another.","ex":"the subject entries of a fugue","aka":"imitative counterpoint","note":"Canon is its strictest form."}},{"name":"Invertible Counterpoint","v":2,"meta":{"def":"Counterpoint that still works when the voices swap high and low.","ex":"double counterpoint at the octave","aka":"double counterpoint","note":"A prized device in fugal writing."}}]}]},{"name":"Rhythm and Meter","v":12,"meta":{"def":"The organisation of music in time through beats, accents and patterns.","ex":"tempo, time signature, syncopation","aka":"rhythmic theory","note":"Meter groups beats; rhythm patterns them within the grid."},"children":[{"name":"Beat","v":2,"meta":{"def":"The basic recurring pulse of music.","ex":"tapping your foot to a song","aka":"pulse","note":"The downbeat is the first, strongest beat of a measure."}},{"name":"Tempo","v":3,"meta":{"def":"The speed of the beat, measured in beats per minute.","ex":"allegro, adagio, 120 BPM","aka":"pace","note":"Italian terms give both speed and character."}},{"name":"Time Signature","v":3,"meta":{"def":"The symbol setting how many beats fill each measure and their value.","ex":"4/4, 3/4, 6/8","aka":"meter signature","note":"The top number counts beats, the bottom names the beat value."}},{"name":"Meter","v":6,"meta":{"def":"The pattern of strong and weak beats grouping the pulse.","ex":"simple, compound, odd meters","aka":"metre","note":"Meter shapes where accents naturally fall."},"children":[{"name":"Simple Meter","v":2,"meta":{"def":"Meter where each beat divides into two.","ex":"2/4, 3/4, 4/4","aka":"duple division","note":"The most common feel in Western music."}},{"name":"Compound Meter","v":2,"meta":{"def":"Meter where each beat divides into three.","ex":"6/8, 9/8, 12/8","aka":"triple division","note":"Gives a rolling, lilting swing."}},{"name":"Odd Meter","v":2,"meta":{"def":"Meter with an irregular beat grouping.","ex":"5/4, 7/8, 'Take Five'","aka":"asymmetric meter, irregular meter","note":"Common in Balkan, prog and modern jazz."}}]},{"name":"Syncopation","v":2,"meta":{"def":"Accenting beats or offbeats against the expected pulse.","ex":"ragtime and funk accents","aka":"off-beat accent","note":"A prime source of groove and surprise."}},{"name":"Polyrhythm","v":2,"meta":{"def":"Two or more conflicting rhythms sounding at once.","ex":"three against two","aka":"cross-rhythm","note":"Central to West African and Latin music."}},{"name":"Polymeter","v":2,"meta":{"def":"Different meters played simultaneously with a shared pulse.","ex":"4/4 against 3/4","aka":"polymetre","note":"Distinct from polyrhythm, which keeps one meter."}},{"name":"Groove","v":2,"meta":{"def":"The felt rhythmic pocket and momentum of a performance.","ex":"a tight funk pocket","aka":"the pocket, feel","note":"Micro-timing gives a groove its human character."}},{"name":"Swing","v":2,"meta":{"def":"Uneven eighth-notes with a long-short lilt.","ex":"jazz swing feel","aka":"shuffle feel","note":"Swing ratios range from subtle to a hard triplet."}},{"name":"Backbeat","v":2,"meta":{"def":"Accent on beats two and four in a 4/4 groove.","ex":"the snare hits of rock and soul","aka":"the two and four","note":"Defines the drive of most popular music."}},{"name":"Clave","v":2,"meta":{"def":"A rhythmic pattern that organises Afro-Cuban music.","ex":"son clave, rumba clave","aka":"the key pattern","note":"Music is said to be 'in clave' when it aligns with the pattern."}},{"name":"Rubato","v":2,"meta":{"def":"Expressive flexing of tempo, speeding and slowing for feeling.","ex":"Chopin nocturne phrasing","aka":"tempo rubato, stolen time","note":"Literally 'robbed' time, later paid back."}},{"name":"Ostinato and Hemiola","v":2,"meta":{"def":"Repeating rhythmic figures and shifting three-against-two groupings.","ex":"a driving bass ostinato, a hemiola cadence","aka":"rhythmic ostinato","note":"Hemiola briefly reframes two bars of triple as three of duple."}}]},{"name":"Melody and Form","v":8,"meta":{"def":"The shaping of tuneful lines and the small structures that build them.","ex":"motif, phrase, riff, theme","aka":"melodic construction","note":"Melody unfolds through contour, repetition and contrast."},"children":[{"name":"Motif","v":2,"meta":{"def":"The smallest recognisable musical idea.","ex":"the four-note Beethoven Fifth cell","aka":"figure, cell","note":"The building block of thematic development."}},{"name":"Phrase","v":2,"meta":{"def":"A complete musical thought, like a sentence in music.","ex":"a four-bar melodic phrase","aka":"melodic phrase","note":"Antecedent and consequent phrases balance in a period."}},{"name":"Theme","v":2,"meta":{"def":"A principal melodic idea that a work develops.","ex":"the main theme of a symphony","aka":"subject, tune","note":"Themes recur and transform across a piece."}},{"name":"Riff","v":2,"meta":{"def":"A short repeated melodic-rhythmic figure, often instrumental.","ex":"the 'Smoke on the Water' riff","aka":"hook riff","note":"The signature building block of rock and funk."}},{"name":"Lick","v":2,"meta":{"def":"A short melodic phrase used in solos and fills.","ex":"a blues guitar lick","aka":"phrase, chop","note":"Players build a personal vocabulary of licks."}},{"name":"Ostinato","v":2,"meta":{"def":"A persistently repeated melodic or rhythmic pattern.","ex":"a repeating bass ostinato","aka":"riff (loosely), ground","note":"The repeating bass form is a 'ground bass'."}},{"name":"Melodic Contour","v":2,"meta":{"def":"The overall shape of a melody's rise and fall.","ex":"arch, ascending, wave contours","aka":"melodic shape","note":"Contour is memorable even when exact pitches are forgotten."}},{"name":"Call and Response","v":2,"meta":{"def":"A phrase answered by a contrasting reply.","ex":"leader-and-chorus in gospel","aka":"antiphony","note":"A cross-cultural device from work songs to jazz."}}]},{"name":"Dynamics and Expression","v":8,"meta":{"def":"The elements that shape a performance's volume, colour and feel.","ex":"dynamics, articulation, timbre, texture","aka":"musical expression","note":"These parameters turn notes into interpretation."},"children":[{"name":"Dynamics","v":2,"meta":{"def":"The relative loudness and softness of music.","ex":"piano, forte, crescendo","aka":"volume markings","note":"Ranges from pianissimo (very soft) to fortissimo (very loud)."}},{"name":"Articulation","v":3,"meta":{"def":"How individual notes are attacked and connected.","ex":"staccato, legato, accent, tenuto","aka":"note attack","note":"Legato connects notes; staccato detaches them."}},{"name":"Phrasing","v":2,"meta":{"def":"Shaping a line's rise, fall and breathing points.","ex":"a singer's expressive arc","aka":"musical phrasing","note":"Good phrasing gives melody a sense of speech."}},{"name":"Timbre","v":2,"meta":{"def":"The tone colour distinguishing one sound source from another.","ex":"a flute versus an oboe on the same note","aka":"tone colour, tone quality","note":"Determined largely by the overtone balance."}},{"name":"Texture","v":5,"meta":{"def":"How melodic and harmonic layers combine in a piece.","ex":"monophony, homophony, polyphony","aka":"musical texture","note":"Texture ranges from a single line to dense counterpoint."},"children":[{"name":"Monophony","v":2,"meta":{"def":"A single melodic line with no accompaniment.","ex":"Gregorian chant","aka":"monophonic texture","note":"The oldest and simplest musical texture."}},{"name":"Homophony","v":2,"meta":{"def":"A melody supported by chordal accompaniment.","ex":"a singer with guitar chords","aka":"homophonic texture","note":"The dominant texture of popular music."}},{"name":"Polyphony","v":2,"meta":{"def":"Multiple independent melodic lines sounding together.","ex":"a fugue, a Renaissance motet","aka":"polyphonic texture, counterpoint","note":"Each voice carries its own melodic interest."}},{"name":"Heterophony","v":2,"meta":{"def":"Simultaneous varied versions of one melody.","ex":"traditional gamelan and Middle Eastern music","aka":"heterophonic texture","note":"Players ornament a shared tune differently at once."}}]},{"name":"Ornamentation","v":3,"meta":{"def":"Decorative notes added to embellish a melody.","ex":"trills, mordents, grace notes, turns","aka":"embellishment, agréments","note":"Baroque performers improvised much ornamentation."}}]},{"name":"Notation","v":12,"meta":{"def":"Systems for writing music down so it can be read and reproduced.","ex":"staff notation, tablature, lead sheet","aka":"music writing","note":"Different traditions favour different notation systems."},"children":[{"name":"Staff Notation","v":3,"meta":{"def":"The standard five-line system placing notes by pitch and duration.","ex":"classical sheet music","aka":"standard notation, staff","note":"Uses clefs, key and time signatures to fix reading."}},{"name":"Tablature","v":2,"meta":{"def":"Notation showing where to place fingers rather than pitches.","ex":"guitar and lute tab","aka":"tab","note":"Numbers on string lines mark frets to press."}},{"name":"Lead Sheet","v":2,"meta":{"def":"A sketch giving melody, lyrics and chord symbols.","ex":"a jazz standard in a fake book","aka":"chart","note":"A whole 'fake book' collects lead sheets."}},{"name":"Chord Chart","v":2,"meta":{"def":"Notation giving only the chords and structure of a song.","ex":"a rhythm-section chart","aka":"chord sheet","note":"Leaves rhythmic realisation to the players."}},{"name":"Nashville Number System","v":2,"meta":{"def":"Notating chords by scale-degree numbers for easy transposition.","ex":"1-4-5 instead of named chords","aka":"the number system","note":"Lets session players change key instantly."}},{"name":"Figured Bass","v":2,"meta":{"def":"A Baroque shorthand of numerals under a bass line for harmony.","ex":"continuo realisation","aka":"thoroughbass, basso continuo","note":"Keyboardists improvised the chords above the figures."}},{"name":"Solfege","v":2,"meta":{"def":"Syllables assigned to scale degrees for sight-singing.","ex":"do, re, mi, fa, sol, la, ti","aka":"solfeggio, sol-fa","note":"Movable-do shifts 'do' to any key's tonic."}},{"name":"Piano Roll and MIDI","v":2,"meta":{"def":"A grid display of note pitch and length used in software.","ex":"notes drawn in a DAW","aka":"MIDI editor","note":"Descends from the perforated rolls of player pianos."}},{"name":"Graphic Notation","v":2,"meta":{"def":"Visual symbols conveying music beyond standard notation.","ex":"Cage and Crumb scores","aka":"graphic score","note":"Invites performer interpretation of shapes and marks."}},{"name":"Braille Music","v":2,"meta":{"def":"A tactile notation letting blind musicians read scores.","ex":"raised-dot music transcription","aka":"braille score","note":"Encodes pitch, rhythm and expression in dot cells."}},{"name":"Percussion Notation","v":2,"meta":{"def":"Notation mapping unpitched drums to staff positions or grids.","ex":"drum-kit notation, rhythm grid","aka":"drum notation","note":"Uses a neutral clef and special noteheads."}}]}]},{"name":"Instruments & Tools","type":"instruments","v":26,"children":[{"name":"Chordophones (Strings)","v":14,"meta":{"def":"Instruments that produce sound from vibrating strings stretched between fixed points.","ex":"Violin, guitar, piano, harp","note":"Largest and most diverse instrument family."},"children":[{"name":"Bowed Strings","v":12,"meta":{"def":"Strings sounded by drawing a friction bow across them for sustained tone.","ex":"Violin family, viols","note":"Bow hair is horsehair rosined for grip."},"children":[{"name":"Violin Family","v":10,"meta":{"def":"The four standard orchestral bowed strings tuned in fifths.","ex":"Stradivari, Guarneri del Gesu","note":"Evolved in 16th-century Italy from the viol and lira."},"children":[{"name":"Violin","v":5,"meta":{"def":"Highest-pitched bowed string, tuned G-D-A-E, played under the chin.","ex":"Stradivarius; Itzhak Perlman, Hilary Hahn","region":"Cremona, Italy","note":"Also called the fiddle in folk contexts."}},{"name":"Viola","v":4,"meta":{"def":"Alto bowed string a fifth below the violin, tuned C-G-D-A, read in alto clef.","ex":"Lionel Tertis, Yuri Bashmet","note":"Larger body but no ideal size, so proportions vary."}},{"name":"Cello","v":5,"meta":{"def":"Tenor-bass bowed string played upright between the knees, tuned C-G-D-A.","ex":"Pablo Casals, Yo-Yo Ma","note":"Full name violoncello; rests on an endpin spike."}},{"name":"Double Bass","v":5,"meta":{"def":"Largest, lowest bowed string, tuned in fourths E-A-D-G, foundation of jazz and orchestra.","ex":"Charles Mingus, Ron Carter","note":"Bowed (arco) or plucked (pizzicato); ancestor is the viol."}}]},{"name":"Viols & Early Bowed","v":8,"meta":{"def":"Fretted, gut-strung bowed instruments of the Renaissance and Baroque held on or between the legs.","ex":"Consort of viols","note":"Underhand bow grip and sloping shoulders distinguish them."},"children":[{"name":"Viola da Gamba","v":4,"meta":{"def":"Fretted six-string bowed instrument held on the legs, gentle and reedy in tone.","ex":"Jordi Savall; music of Marais, Sainte-Colombe","region":"Renaissance Europe","note":"Gamba means leg in Italian."}},{"name":"Hurdy-Gurdy","v":4,"meta":{"def":"Strings sounded by a rosined wheel cranked by hand while keys stop the melody string.","ex":"French vielle a roue","region":"Medieval Europe","note":"Buzzing bridge (chien) adds a rhythmic drone."}},{"name":"Nyckelharpa","v":3,"meta":{"def":"Swedish keyed fiddle with sympathetic strings sounded by a bow and stopped by keys.","ex":"Swedish folk revival","region":"Sweden","note":"Appears on Swedish medieval church carvings."}}]},{"name":"World Bowed Strings","v":10,"meta":{"def":"Regional bowed fiddles, many spike fiddles played upright on the knee.","ex":"Erhu, morin khuur","note":"Often two strings with a bow threaded between them."},"children":[{"name":"Erhu","v":4,"meta":{"def":"Chinese two-string spike fiddle with a snakeskin soundbox and no fingerboard.","ex":"Chinese classical and folk ensembles","region":"China","note":"Bow hair passes between the two strings."}},{"name":"Morin Khuur","v":4,"meta":{"def":"Mongolian horsehead fiddle with two strings made of bundled horsehair.","ex":"Mongolian long-song accompaniment","region":"Mongolia","note":"UNESCO Intangible Cultural Heritage."}},{"name":"Sarangi","v":3,"meta":{"def":"Bowed short-necked North Indian fiddle with dozens of sympathetic strings.","ex":"Hindustani vocal accompaniment","region":"North India","note":"Said to sound closest to the human voice."}},{"name":"Rebab","v":3,"meta":{"def":"Ancient bowed spike fiddle spread across the Islamic world, often skin-faced.","ex":"Arabic, Persian, and gamelan ensembles","region":"Middle East / Southeast Asia","note":"An ancestor of the European violin."}},{"name":"Kokyu","v":3,"meta":{"def":"Japan's only traditional bowed instrument, a small three or four string fiddle.","ex":"Sankyoku and min'yo ensembles","region":"Japan","note":"The player rotates the instrument, not the bow."}}]}]},{"name":"Plucked Strings","v":16,"meta":{"def":"Strings set in motion by fingers, fingernails, or a plectrum.","ex":"Guitar, harp, sitar, banjo","note":"The most widespread string category worldwide."},"children":[{"name":"Guitars","v":12,"meta":{"def":"Fretted, waisted plucked strings, typically six strings tuned E-A-D-G-B-E.","ex":"Martin, Gibson, Fender","note":"The world's most popular instrument."},"children":[{"name":"Classical Guitar","v":5,"meta":{"def":"Nylon-strung acoustic guitar with a wide flat neck, fingerpicked.","ex":"Ramirez; Andres Segovia, John Williams","region":"Spain","note":"Descends from the Spanish vihuela and Baroque guitar."}},{"name":"Steel-String Acoustic","v":5,"meta":{"def":"Flat-top acoustic guitar with steel strings for a bright, loud tone.","ex":"Martin D-28, Gibson J-45","note":"Dreadnought body shape named after a battleship."}},{"name":"Electric Guitar","v":6,"meta":{"def":"Solid or hollow guitar whose magnetic pickups convert string vibration to signal.","ex":"Fender Stratocaster, Gibson Les Paul; Jimi Hendrix","note":"Defined rock, blues, and metal."}},{"name":"Bass Guitar","v":5,"meta":{"def":"Low-pitched electric guitar tuned E-A-D-G an octave below the guitar.","ex":"Fender Precision, Jazz Bass; James Jamerson","note":"Replaced the double bass in most popular music."}},{"name":"Twelve-String Guitar","v":3,"meta":{"def":"Guitar with paired courses of strings for a shimmering, chorused sound.","ex":"Rickenbacker 360/12; Leadbelly","note":"Each course tuned in octaves or unison."}},{"name":"Resonator Guitar","v":3,"meta":{"def":"Guitar with a spun metal cone instead of a wooden top for extra volume.","ex":"Dobro, National; blues and bluegrass slide","note":"Invented before electric amplification existed."}}]},{"name":"Lute Family","v":10,"meta":{"def":"Plucked strings with a rounded back and a neck bearing a fretted or fretless fingerboard.","ex":"European lute, oud","note":"Name derives from Arabic al-oud."},"children":[{"name":"Lute","v":4,"meta":{"def":"Pear-shaped fretted plucked instrument with a bent-back pegbox, central to Renaissance music.","ex":"John Dowland repertoire","region":"Renaissance Europe","note":"Can carry a dozen or more courses of strings."}},{"name":"Oud","v":4,"meta":{"def":"Fretless short-necked lute of the Arab world with a deep bowl back.","ex":"Munir Bashir, Farid al-Atrash","region":"Middle East","note":"Fretless neck enables microtonal maqam music."}},{"name":"Mandolin","v":4,"meta":{"def":"Small teardrop lute with four paired courses, tuned like a violin and tremolo-picked.","ex":"Gibson F-5; Bill Monroe","region":"Italy","note":"Bluegrass adopted the flat-backed archtop style."}},{"name":"Bouzouki","v":3,"meta":{"def":"Long-necked Greek lute with a bright metallic tone, heart of rebetiko music.","ex":"Manolis Chiotis","region":"Greece","note":"Irish players adopted a flat-backed variant."}},{"name":"Pipa","v":3,"meta":{"def":"Chinese four-string pear-shaped lute played with fingernails in rapid tremolo.","ex":"Chinese classical repertoire","region":"China","note":"Over two thousand years old."}}]},{"name":"Banjos & Ukuleles","v":8,"meta":{"def":"Small plucked strings, some with drum-like skin heads, central to American folk.","ex":"Banjo, ukulele","note":"Banjo derives from West African skin-headed lutes."},"children":[{"name":"Banjo","v":5,"meta":{"def":"Plucked string with a circular drumhead body giving a bright percussive twang.","ex":"Gibson Mastertone; Earl Scruggs","region":"West Africa / USA","note":"Five-string style uses a high drone thumb string."}},{"name":"Ukulele","v":4,"meta":{"def":"Small four-string Hawaiian instrument tuned G-C-E-A with a gentle sound.","ex":"Kamaka; Israel Kamakawiwo'ole","region":"Hawaii","note":"Adapted from the Portuguese machete."}},{"name":"Banjolele","v":3,"meta":{"def":"Hybrid with a ukulele neck on a small banjo body for volume and twang.","ex":"George Formby","note":"Popular in 1920s-30s music hall."}}]},{"name":"Harps","v":8,"meta":{"def":"Strings stretched across an open triangular frame, plucked with both hands.","ex":"Concert harp, Celtic harp","note":"Strings run perpendicular to the soundboard."},"children":[{"name":"Concert (Pedal) Harp","v":5,"meta":{"def":"Large 47-string orchestral harp with seven pedals to change key chromatically.","ex":"Lyon & Healy; Marcel Grandjany","note":"Each pedal has three positions for flat, natural, sharp."}},{"name":"Celtic (Lever) Harp","v":4,"meta":{"def":"Smaller diatonic harp using blade levers to sharpen individual strings.","ex":"Irish and Scottish folk harp","region":"Ireland / Scotland","note":"Emblem on the flag and coinage of Ireland."}},{"name":"Lyre","v":3,"meta":{"def":"Ancient yoke harp with strings running from a crossbar to a soundbox.","ex":"Greek kithara, Ethiopian begena","region":"Ancient Greece / East Africa","note":"Symbol of Apollo and of poetry."}}]},{"name":"World Plucked Strings","v":14,"meta":{"def":"Regional plucked instruments from Asia, Africa, and the Andes.","ex":"Sitar, koto, kora, charango","note":"Many use sympathetic strings or gourd resonators."},"children":[{"name":"Sitar","v":4,"meta":{"def":"Long-necked North Indian lute with movable frets and sympathetic strings buzzing over a wide bridge.","ex":"Ravi Shankar, Nikhil Banerjee","region":"North India","note":"Popularized in the West by the Beatles."}},{"name":"Koto","v":4,"meta":{"def":"Japanese 13-string zither with movable bridges, plucked with finger picks.","ex":"Michio Miyagi","region":"Japan","note":"The national instrument of Japan."}},{"name":"Guzheng","v":4,"meta":{"def":"Chinese plucked zither with movable bridges, ancestor of the koto.","ex":"Chinese classical solo repertoire","region":"China","note":"Modern versions have 21 strings."}},{"name":"Balalaika","v":4,"meta":{"def":"Russian three-string lute with a distinctive triangular body.","ex":"Russian folk orchestras","region":"Russia","note":"Made in a family of sizes from piccolo to contrabass."}},{"name":"Kora","v":4,"meta":{"def":"West African 21-string harp-lute with a large calabash gourd resonator.","ex":"Toumani Diabate","region":"West Africa (Mande)","note":"Played by hereditary griot musicians."}},{"name":"Charango","v":3,"meta":{"def":"Small Andean lute with ten strings in five courses, once made from an armadillo shell.","ex":"Andean folk (Bolivia, Peru)","region":"Andes","note":"High bright tone above the guitar."}},{"name":"Shamisen","v":3,"meta":{"def":"Japanese three-string fretless lute with a skin-covered body, struck with a large plectrum.","ex":"Kabuki and Tsugaru music","region":"Japan","note":"The bachi plectrum also strikes the skin like a drum."}},{"name":"Saz / Baglama","v":3,"meta":{"def":"Long-necked Turkish lute with movable frets for microtones.","ex":"Anatolian folk and Alevi music","region":"Turkey","note":"Frets are tied nylon that can be shifted."}},{"name":"Biwa","v":3,"meta":{"def":"Japanese short-necked fretted lute struck with a large wedge plectrum, used for narrative song.","ex":"Heike biwa storytelling","region":"Japan","note":"Frets are tall to allow pitch-bending pressure."}},{"name":"Dobro / Lap Steel","v":3,"meta":{"def":"Guitar played flat on the lap and stopped with a sliding steel bar.","ex":"Hawaiian and country music","region":"Hawaii / USA","note":"Precursor to the pedal steel guitar."}}]}]},{"name":"Struck Strings","v":10,"meta":{"def":"Strings set vibrating by hammers, either mechanical or handheld.","ex":"Piano, hammered dulcimer","note":"Bridge the string and percussion families."},"children":[{"name":"Hammered Dulcimer","v":4,"meta":{"def":"Trapezoidal box zither whose many strings are struck with small handheld hammers.","ex":"Appalachian and folk ensembles","region":"Widespread (Middle East to Appalachia)","note":"Not related to the plucked Appalachian dulcimer."}},{"name":"Cimbalom","v":4,"meta":{"def":"Large chromatic hammered dulcimer with a damper pedal, central to Hungarian and Romani music.","ex":"Kodaly's Hary Janos","region":"Hungary / Eastern Europe","note":"Standardized on legs by Jozsef Schunda in 1874."}},{"name":"Santoor","v":4,"meta":{"def":"Trapezoidal hammered dulcimer of Kashmir struck with lightweight mallets.","ex":"Shivkumar Sharma","region":"Kashmir / Persia","note":"Sharma brought it into Hindustani classical music."}},{"name":"Yangqin","v":3,"meta":{"def":"Chinese hammered dulcimer struck with flexible bamboo beaters.","ex":"Chinese orchestra repertoire","region":"China","note":"Name means foreign zither, reflecting its Persian roots."}}]}]},{"name":"Aerophones (Wind)","v":14,"meta":{"def":"Instruments sounded by vibrating a column or body of air.","ex":"Flute, trumpet, clarinet, accordion","note":"Divided by how the air is set vibrating."},"children":[{"name":"Woodwinds","v":16,"meta":{"def":"Wind instruments sounded by an air edge or a vibrating reed, historically wooden.","ex":"Flute, clarinet, oboe, saxophone","note":"Saxophones are brass but count as woodwind by their reed."},"children":[{"name":"Flutes","v":12,"meta":{"def":"Edge-blown woodwinds with no reed, sounded by splitting an air stream.","ex":"Concert flute, recorder","note":"Among the oldest instruments known to humanity."},"children":[{"name":"Concert Flute","v":5,"meta":{"def":"Transverse metal flute of the orchestra with a Boehm key system.","ex":"Muramatsu, Powell; James Galway","note":"Modern silver design perfected by Theobald Boehm."}},{"name":"Piccolo","v":4,"meta":{"def":"Small flute pitched an octave above the concert flute, brilliant and piercing.","ex":"Orchestral and marching bands","note":"Name means little in Italian; loudest orchestral instrument."}},{"name":"Recorder","v":4,"meta":{"def":"Fipple flute with a whistle mouthpiece and a soft, breathy tone.","ex":"Soprano, alto, tenor, bass consort","region":"Medieval / Renaissance Europe","note":"Ubiquitous as a school instrument."}},{"name":"Pan Flute","v":4,"meta":{"def":"Set of stopped tubes of graduated length bound in a row, blown across the tops.","ex":"Andean siku, Romanian nai; Gheorghe Zamfir","region":"Andes / Eastern Europe","note":"Named for the Greek god Pan."}},{"name":"Shakuhachi","v":4,"meta":{"def":"Japanese end-blown bamboo flute prized for breathy, meditative tone.","ex":"Zen honkyoku repertoire","region":"Japan","note":"Once played by wandering komuso monks."}},{"name":"Dizi","v":3,"meta":{"def":"Chinese transverse bamboo flute with a buzzing membrane hole (mokong).","ex":"Chinese folk and opera","region":"China","note":"The tissue membrane gives a bright reedy buzz."}},{"name":"Ney","v":3,"meta":{"def":"Ancient end-blown reed flute of the Middle East with a haunting airy tone.","ex":"Sufi and Persian classical music","region":"Middle East / Persia","note":"Central to Sufi devotional music."}},{"name":"Native American Flute","v":3,"meta":{"def":"End-blown duct flute with two chambers and a carved fetish block.","ex":"R. Carlos Nakai","region":"North America","note":"Traditionally tuned to a pentatonic minor scale."}},{"name":"Bansuri","v":3,"meta":{"def":"North Indian transverse bamboo flute with a warm, breathy classical tone.","ex":"Hariprasad Chaurasia","region":"North India","note":"Associated with the god Krishna."}},{"name":"Fife","v":3,"meta":{"def":"Small, high, keyless transverse flute used in military and marching music.","ex":"Fife and drum corps","region":"Europe","note":"Shrill enough to cut through a battlefield."}}]},{"name":"Single-Reed Woodwinds","v":10,"meta":{"def":"Woodwinds sounded by one cane reed beating against a mouthpiece.","ex":"Clarinet, saxophone","note":"Reed strength affects tone and resistance."},"children":[{"name":"Clarinet","v":5,"meta":{"def":"Cylindrical single-reed woodwind with a wide range and warm tone, overblowing a twelfth.","ex":"Buffet R13; Benny Goodman","note":"B-flat is standard; A clarinet used in orchestra."}},{"name":"Bass Clarinet","v":4,"meta":{"def":"Large clarinet pitched an octave below the standard, with an upturned bell.","ex":"Eric Dolphy","note":"Curved neck and bell resemble a saxophone."}},{"name":"Alto Saxophone","v":5,"meta":{"def":"Mid-range single-reed brass-bodied woodwind in E-flat, the most common sax.","ex":"Selmer Mark VI; Charlie Parker","note":"Invented by Adolphe Sax around 1840."}},{"name":"Tenor Saxophone","v":5,"meta":{"def":"Larger B-flat saxophone with a rich, husky voice, iconic in jazz.","ex":"John Coltrane, Sonny Rollins","note":"The signature jazz sax sound."}},{"name":"Soprano & Baritone Sax","v":4,"meta":{"def":"The high straight soprano and the low bulky baritone bookend the sax family.","ex":"Sidney Bechet (soprano); Gerry Mulligan (baritone)","note":"Full family spans sopranino to bass and contrabass."}}]},{"name":"Double-Reed Woodwinds","v":10,"meta":{"def":"Woodwinds sounded by two cane reeds vibrating against each other.","ex":"Oboe, bassoon","note":"Players often hand-make their own reeds."},"children":[{"name":"Oboe","v":5,"meta":{"def":"Conical double-reed woodwind with a penetrating, reedy tone, sounds the orchestra's tuning A.","ex":"Loree; Heinz Holliger","note":"Its stable pitch makes it the tuning reference."}},{"name":"Cor Anglais","v":3,"meta":{"def":"Alto oboe (English horn) in F with a pear-shaped bell and mellow tone.","ex":"Dvorak New World Symphony solo","note":"Neither English nor a horn."}},{"name":"Bassoon","v":5,"meta":{"def":"Large conical double-reed bass woodwind with a folded tube and a bocal crook.","ex":"Heckel; the Rite of Spring opening","note":"Tube unfolds to over two and a half metres."}},{"name":"Contrabassoon","v":3,"meta":{"def":"Bassoon sounding an octave lower, the deepest standard orchestral woodwind.","ex":"Ravel's Ma Mere l'Oye","note":"Nearly six metres of tubing folded four times."}},{"name":"Shehnai / Suona","v":3,"meta":{"def":"Loud conical double-reed horn of India and China used for outdoor and ceremonial music.","ex":"Bismillah Khan (shehnai)","region":"India / China","note":"Considered auspicious at weddings and festivals."}}]}]},{"name":"Brass","v":12,"meta":{"def":"Lip-vibrated wind instruments (labrosones) sounded by buzzing the lips into a cup mouthpiece.","ex":"Trumpet, trombone, tuba","note":"Pitch changes via valves, slide, and lip tension."},"children":[{"name":"High Brass","v":8,"meta":{"def":"Higher-pitched brass with small mouthpieces and bright, brilliant tone.","ex":"Trumpet, cornet, bugle","note":"Usually valved except the bugle."},"children":[{"name":"Trumpet","v":5,"meta":{"def":"Bright three-valve brass instrument in B-flat, lead voice of jazz and fanfares.","ex":"Bach Stradivarius; Miles Davis, Louis Armstrong","note":"Piccolo trumpet used for Baroque high parts."}},{"name":"Cornet","v":4,"meta":{"def":"Conical-bore valved brass, mellower and rounder than the trumpet.","ex":"British brass bands; early Louis Armstrong","note":"More compact wrap than the trumpet."}},{"name":"Flugelhorn","v":3,"meta":{"def":"Wide conical brass in B-flat with a dark, velvety flugel tone.","ex":"Chuck Mangione, Art Farmer","note":"Favoured for lyrical jazz ballads."}},{"name":"Bugle","v":3,"meta":{"def":"Valveless brass sounding only the natural harmonic series, used for military calls.","ex":"Reveille, Taps","note":"Pitch changes come only from the lips."}}]},{"name":"Low Brass","v":10,"meta":{"def":"Larger brass instruments providing tenor and bass voices.","ex":"Trombone, tuba, euphonium","note":"Trombone uses a slide instead of valves."},"children":[{"name":"Trombone","v":5,"meta":{"def":"Tenor brass whose pitch is changed by a telescoping slide with seven positions.","ex":"Conn 88H; J.J. Johnson","note":"The only orchestral brass without valves."}},{"name":"French Horn","v":5,"meta":{"def":"Coiled brass with a wide flaring bell, played with the hand in the bell, mellow and rich.","ex":"Dennis Brain; Mozart concertos","note":"Double horn combines F and B-flat sides via a trigger."}},{"name":"Euphonium","v":4,"meta":{"def":"Conical tenor-bass brass with a warm, singing tone, a mainstay of brass bands.","ex":"British and American brass bands","note":"Name means well-sounding in Greek."}},{"name":"Tuba","v":5,"meta":{"def":"Largest, lowest brass instrument, foundation of the brass section.","ex":"Orchestral and band bass lines","note":"Sousaphone is a marching tuba that wraps around the body."}}]}]},{"name":"Free-Reed Aerophones","v":12,"meta":{"def":"Instruments sounded by reeds vibrating freely in a frame, fed by bellows or breath.","ex":"Accordion, harmonica, sheng","note":"Reed pitch is fixed by its own length, not an air column."},"children":[{"name":"Harmonica","v":5,"meta":{"def":"Small handheld free-reed instrument played by inhaling and exhaling over channels.","ex":"Hohner Marine Band; Little Walter, Toots Thielemans","note":"Diatonic blues harp bent to reach missing notes."}},{"name":"Accordion","v":5,"meta":{"def":"Bellows-driven free-reed box with a keyboard or buttons and preset chord bass.","ex":"Piano and button (Bayan) styles","region":"Europe","note":"Piano-accordion has a right-hand keyboard."}},{"name":"Concertina","v":4,"meta":{"def":"Small hexagonal bellows free-reed instrument with buttons on both ends.","ex":"Anglo, English, and Duet systems","region":"England / Germany","note":"Central to Irish and English folk music."}},{"name":"Bandoneon","v":4,"meta":{"def":"Square bellows free-reed instrument, the soul of Argentine tango.","ex":"Astor Piazzolla","region":"Germany / Argentina","note":"Different notes on push and pull of the bellows."}},{"name":"Harmonium","v":4,"meta":{"def":"Reed organ pumped by foot or hand bellows, common in Indian and church music.","ex":"Indian devotional and Hindustani music","region":"Europe / India","note":"Hand-pumped in South Asian styles."}},{"name":"Sheng","v":3,"meta":{"def":"Ancient Chinese mouth organ of vertical bamboo pipes over a wind chamber.","ex":"Chinese orchestra","region":"China","note":"Ancestor of the Western free reed."}},{"name":"Melodica","v":3,"meta":{"def":"Handheld free-reed instrument with a small keyboard blown through a mouthpiece.","ex":"Hohner Melodica; Augustus Pablo (dub)","note":"Also called the pianica."}}]},{"name":"Other Aerophones","v":8,"meta":{"def":"Wind instruments that fall outside the standard woodwind and brass families.","ex":"Bagpipes, didgeridoo, organ","note":"Includes reservoir and lip-buzzed drone instruments."},"children":[{"name":"Bagpipes","v":5,"meta":{"def":"Reed instrument fed from an air bag squeezed under the arm, sounding a melody chanter over drones.","ex":"Great Highland bagpipe; uilleann pipes","region":"Scotland / Ireland / Europe","note":"Bag lets the player breathe without stopping the sound."}},{"name":"Didgeridoo","v":4,"meta":{"def":"Long wooden drone pipe of Aboriginal Australia sounded with buzzed lips and circular breathing.","ex":"Yolngu ceremonial music","region":"Northern Australia","note":"Traditionally a eucalyptus branch hollowed by termites."}},{"name":"Ocarina","v":3,"meta":{"def":"Small vessel flute of clay or ceramic with finger holes and a whistle mouthpiece.","ex":"Andean and Mesoamerican styles","region":"Mesoamerica / worldwide","note":"A closed vessel, not a tube, so holes act as resonators."}}]}]},{"name":"Membranophones (Drums)","v":14,"meta":{"def":"Instruments producing sound from a stretched membrane struck, rubbed, or otherwise vibrated.","ex":"Drum kit, congas, tabla, timpani","note":"Heads are skin (animal) or plastic (Mylar)."},"children":[{"name":"Drum Kit","v":12,"meta":{"def":"A collection of drums and cymbals arranged for one seated player, foundation of popular music.","ex":"Ludwig, DW, Gretsch; Buddy Rich, John Bonham","note":"Assembled as a single instrument in the early 20th century."},"children":[{"name":"Snare Drum","v":5,"meta":{"def":"Shallow drum with a set of metal snares under the lower head giving a sharp crack.","ex":"Ludwig Black Beauty","note":"The backbeat voice of the kit; also a marching staple."}},{"name":"Bass (Kick) Drum","v":4,"meta":{"def":"Largest drum of the kit, played with a foot pedal for the low pulse.","ex":"Double-pedal metal styles","note":"Sits on its side and is struck by a beater."}},{"name":"Tom-Toms","v":4,"meta":{"def":"Tunable drums without snares, mounted and floor-standing, used for fills.","ex":"Rack toms and floor tom","note":"Rototoms have no shell, tuned by rotating the head."}},{"name":"Hi-Hat","v":4,"meta":{"def":"Pair of cymbals on a stand closed and opened by a foot pedal for timekeeping.","ex":"Zildjian, Sabian hats","note":"Chick sound comes from clashing the pair shut."}},{"name":"Cymbals (Ride & Crash)","v":4,"meta":{"def":"Suspended metal plates: the ride for steady patterns, the crash for accents.","ex":"Zildjian K, Paiste 2002","note":"Cast bronze alloy hammered and lathed by hand."}}]},{"name":"Orchestral & Tuned Drums","v":6,"meta":{"def":"Pitched membranophones used in the classical orchestra.","ex":"Timpani","note":"Some drums produce a definite pitch."},"children":[{"name":"Timpani","v":5,"meta":{"def":"Large tuned kettledrums with a pedal to change pitch by tightening the head.","ex":"Beethoven's Ninth; orchestral timpani","region":"Europe (from Middle Eastern nakers)","note":"The only common drum tuned to precise pitches."}},{"name":"Rototom","v":3,"meta":{"def":"Shell-less tunable drum whose pitch is set by rotating its rim.","ex":"Contemporary percussion works","note":"Wide, fast pitch glissandos are possible."}}]},{"name":"Hand & World Drums","v":16,"meta":{"def":"Drums played primarily with the hands across the world's musical traditions.","ex":"Congas, djembe, tabla, cajon","note":"Tone varies by where and how the hand strikes."},"children":[{"name":"Congas","v":4,"meta":{"def":"Tall single-headed Afro-Cuban drums played in sets of two or three.","ex":"Latin and salsa percussion; Mongo Santamaria","region":"Cuba","note":"Named tumbadora in Cuba; sizes quinto to tumba."}},{"name":"Bongos","v":4,"meta":{"def":"Pair of small joined single-headed drums held between the knees.","ex":"Afro-Cuban son and jazz","region":"Cuba","note":"The martillo pattern is their signature rhythm."}},{"name":"Djembe","v":4,"meta":{"def":"Goblet-shaped West African hand drum with a goatskin head and wide tonal range.","ex":"Mande drumming ensembles","region":"West Africa (Mali/Guinea)","note":"Produces bass, tone, and slap from one head."}},{"name":"Tabla","v":5,"meta":{"def":"Pair of North Indian hand drums, the small dayan and the bass bayan, with tunable syahi paste.","ex":"Zakir Hussain, Alla Rakha","region":"North India","note":"Complex finger technique yields many distinct strokes."}},{"name":"Cajon","v":4,"meta":{"def":"Box drum the player sits on and strikes on the front face.","ex":"Peruvian and flamenco music","region":"Peru","note":"Snare wires or guitar strings buzz on some models."}},{"name":"Darbuka","v":3,"meta":{"def":"Goblet-shaped hand drum of the Middle East with a sharp ringing slap.","ex":"Arabic and Turkish music","region":"Middle East","note":"Also called doumbek or tabla in Arabic."}},{"name":"Frame Drum","v":4,"meta":{"def":"Shallow drum whose head diameter far exceeds its depth, often with jingles.","ex":"Irish bodhran, Middle Eastern riq, tambourine","region":"Worldwide","note":"Among the oldest drum forms known."}},{"name":"Talking Drum","v":3,"meta":{"def":"Hourglass drum whose pitch is bent by squeezing tension cords to mimic speech.","ex":"Yoruba dundun","region":"West Africa","note":"Can imitate the tones of spoken language."}},{"name":"Timbales","v":3,"meta":{"def":"Pair of shallow single-headed metal drums played with sticks in Latin music.","ex":"Tito Puente","region":"Cuba","note":"Rims and shells (cascara) are struck as well as the heads."}},{"name":"Udu","v":3,"meta":{"def":"Clay pot drum with a side hole, giving a deep bass when the opening is slapped.","ex":"Igbo ceremonial music","region":"Nigeria","note":"Originally a water jug adapted by Igbo women."}}]},{"name":"Taiko & Large Drums","v":5,"meta":{"def":"Big, resonant drums played with heavy sticks in ensemble traditions.","ex":"Taiko","note":"Often physically demanding, full-body playing."},"children":[{"name":"Taiko","v":5,"meta":{"def":"Family of Japanese barrel drums played with thick bachi sticks in ensemble.","ex":"Kodo ensemble","region":"Japan","note":"The largest o-daiko is carved from a single log."}},{"name":"Dhol","v":3,"meta":{"def":"Double-headed barrel drum of South Asia struck with sticks for celebratory music.","ex":"Punjabi bhangra","region":"North India / Pakistan","note":"One head is bass, the other treble."}}]}]},{"name":"Idiophones (Self-Sounding)","v":14,"meta":{"def":"Instruments that produce sound from the vibration of their own rigid body, without strings or membranes.","ex":"Xylophone, gong, bells, kalimba","note":"The oldest and most varied percussion family."},"children":[{"name":"Tuned Mallet Percussion","v":12,"meta":{"def":"Pitched idiophones with tuned bars or plates struck by mallets.","ex":"Marimba, vibraphone, xylophone","note":"Bars arranged like a piano keyboard."},"children":[{"name":"Xylophone","v":4,"meta":{"def":"Tuned wooden bars struck with hard mallets for a bright, dry, percussive tone.","ex":"Orchestral and pit percussion","region":"Africa / Asia origins","note":"Name means wood sound in Greek."}},{"name":"Marimba","v":5,"meta":{"def":"Large wooden-bar idiophone with tuned resonator tubes and a warm, mellow tone.","ex":"Guatemalan and concert marimba; Keiko Abe","region":"Africa / Central America","note":"National instrument of Guatemala."}},{"name":"Vibraphone","v":5,"meta":{"def":"Metal-bar mallet instrument with motor-driven fans in the resonators giving vibrato, plus a sustain pedal.","ex":"Musser; Lionel Hampton, Gary Burton","note":"The only common mallet instrument with a sustain pedal."}},{"name":"Glockenspiel","v":4,"meta":{"def":"Small set of tuned steel bars struck with hard mallets for a bright bell-like tone, sounds two octaves high.","ex":"Orchestral and marching (bell lyre)","region":"Germany","note":"Name means play of bells in German."}},{"name":"Celesta","v":4,"meta":{"def":"Keyboard idiophone whose hammers strike metal plates over resonators for a soft chiming sound.","ex":"Tchaikovsky's Dance of the Sugar Plum Fairy","note":"Looks like a small upright piano; a keyboard idiophone."}},{"name":"Crotales","v":3,"meta":{"def":"Small thick tuned bronze discs struck with mallets or bowed for a pure high ring.","ex":"Debussy, Ravel scores","note":"Also called antique cymbals."}}]},{"name":"Struck & Concussion Idiophones","v":14,"meta":{"def":"Idiophones sounded by striking, shaking, or clashing them together.","ex":"Gong, triangle, castanets, maracas","note":"Mostly untuned percussion of indefinite pitch."},"children":[{"name":"Gong","v":4,"meta":{"def":"Large suspended metal disc struck for a deep swelling wash of sound.","ex":"Tam-tam; Chinese and Javanese gongs","region":"East / Southeast Asia","note":"Tam-tam is flat and of indefinite pitch."}},{"name":"Triangle","v":3,"meta":{"def":"Bent steel rod struck with a beater for a bright, ringing, indefinite pitch.","ex":"Liszt's Piano Concerto No. 1","note":"Left open at one corner so it rings freely."}},{"name":"Cowbell","v":3,"meta":{"def":"Clapperless metal bell struck with a stick for a dry clanking accent.","ex":"Latin and rock percussion","note":"Derived from actual bells hung on livestock."}},{"name":"Castanets","v":3,"meta":{"def":"Pair of hinged concave shells clicked together in the hand, central to flamenco.","ex":"Spanish flamenco and classical dance","region":"Spain","note":"Traditionally made of hardwood."}},{"name":"Maracas","v":3,"meta":{"def":"Pair of handheld rattles filled with beads or seeds, shaken for rhythm.","ex":"Latin American music","region":"Latin America","note":"Originally dried gourds with seeds inside."}},{"name":"Claves","v":3,"meta":{"def":"Pair of hardwood sticks struck together to sound the guiding clave rhythm.","ex":"Afro-Cuban son and salsa","region":"Cuba","note":"Name of both the sticks and the underlying rhythm."}},{"name":"Guiro","v":3,"meta":{"def":"Notched hollow gourd scraped with a stick for a ratchet-like rhythm.","ex":"Latin American dance music","region":"Latin America","note":"Traditionally a dried, serrated calabash."}},{"name":"Cabasa","v":3,"meta":{"def":"Handheld percussion of steel beads wrapped around a ridged cylinder, twisted for a rasping shake.","ex":"Latin and pop percussion","note":"A metal reworking of the beaded gourd shekere."}},{"name":"Wood Block & Temple Block","v":3,"meta":{"def":"Hollow wooden blocks struck for a sharp, resonant knock.","ex":"Orchestral and cartoon percussion","note":"Temple blocks come in tuned sets of five."}},{"name":"Cymbals (Concert)","v":3,"meta":{"def":"Pair of large bronze plates crashed together, or a single suspended plate.","ex":"Zildjian, Sabian; orchestral clash cymbals","note":"Alloy is roughly 80 percent copper, 20 percent tin."}}]},{"name":"Plucked & Melodic Idiophones","v":10,"meta":{"def":"Self-sounding instruments plucked or struck to make definite pitches.","ex":"Kalimba, steelpan, hang","note":"Include lamellophones with flexible tongues."},"children":[{"name":"Kalimba / Mbira","v":5,"meta":{"def":"African lamellophone (thumb piano) with metal tongues plucked by the thumbs over a resonator.","ex":"Shona mbira dzavadzimu","region":"Southern Africa (Zimbabwe)","note":"Mbira is sacred in Shona spirit ceremonies."}},{"name":"Steelpan","v":5,"meta":{"def":"Tuned concave playing surface hammered into an oil drum, sounding distinct pitched notes.","ex":"Trinidadian steel bands","region":"Trinidad and Tobago","note":"The only acoustic instrument invented in the 20th century."}},{"name":"Hang / Handpan","v":4,"meta":{"def":"Convex steel shell with hammered tone fields played by hand for a soft, bell-like tone.","ex":"PANArt Hang","region":"Switzerland","note":"The original Hang debuted in 2000."}},{"name":"Music Box","v":3,"meta":{"def":"Mechanical idiophone whose rotating pinned cylinder plucks a steel comb.","ex":"Swiss cylinder music boxes","region":"Switzerland","note":"Invented in the late 18th century in Geneva."}}]},{"name":"Bells & Chimes","v":6,"meta":{"def":"Resonant metal or hanging objects sounded for pitched or atmospheric tones.","ex":"Tubular bells, handbells","note":"Range from church bells to orchestral chimes."},"children":[{"name":"Tubular Bells","v":4,"meta":{"def":"Set of hanging metal tubes struck with a mallet to imitate church bells.","ex":"Mike Oldfield's Tubular Bells","note":"Also called orchestral chimes."}},{"name":"Handbells","v":3,"meta":{"def":"Tuned handheld bells rung by a choir, each player covering a few pitches.","ex":"English handbell choirs","region":"England","note":"Originally for ringers to practise tower bells."}},{"name":"Wind Chimes / Mark Tree","v":3,"meta":{"def":"Row of graduated metal rods brushed by hand for a shimmering cascade.","ex":"Studio and orchestral color percussion","note":"The mark tree was named for percussionist Mark Stevens."}},{"name":"Singing Bowl","v":3,"meta":{"def":"Standing bell rubbed or struck to produce a sustained meditative hum.","ex":"Himalayan and meditation music","region":"Himalayas","note":"Rubbing the rim with a mallet sustains the tone."}}]}]},{"name":"Keyboards","v":12,"meta":{"def":"Instruments controlled by a keyboard of levers, spanning strings, pipes, reeds, and electronics.","ex":"Piano, organ, harpsichord, Rhodes","note":"A control interface across several sound families."},"children":[{"name":"Pianos","v":8,"meta":{"def":"Keyboard instruments whose hammers strike strings, capable of soft and loud (pianoforte).","ex":"Steinway, Bosendorfer, Yamaha","note":"Invented by Bartolomeo Cristofori around 1700."},"children":[{"name":"Grand Piano","v":5,"meta":{"def":"Piano with a horizontal frame and strings, its lid lifting to project sound.","ex":"Steinway Model D; concert use","note":"Longer strings give richer bass and more volume."}},{"name":"Upright Piano","v":4,"meta":{"def":"Piano with a vertical frame and strings to save floor space.","ex":"Yamaha U-series","note":"The most common piano in homes and schools."}},{"name":"Toy / Prepared Piano","v":3,"meta":{"def":"Altered or miniature pianos, from tiny toy pianos to strings damped with objects.","ex":"John Cage's prepared piano works","note":"Cage inserted bolts and rubber between the strings."}}]},{"name":"Historical Keyboards","v":8,"meta":{"def":"Early keyboard instruments that preceded the piano.","ex":"Harpsichord, clavichord","note":"Plucked or tangent action rather than hammers."},"children":[{"name":"Harpsichord","v":5,"meta":{"def":"Keyboard whose strings are plucked by quills, giving a bright fixed-volume tone.","ex":"Bach's keyboard works","region":"Renaissance / Baroque Europe","note":"Cannot vary loudness by touch, unlike the piano."}},{"name":"Clavichord","v":4,"meta":{"def":"Quiet keyboard whose brass tangents strike the strings, allowing expressive touch and vibrato.","ex":"C.P.E. Bach repertoire","region":"Renaissance Europe","note":"So soft it was mainly a practice instrument."}},{"name":"Virginal & Spinet","v":3,"meta":{"def":"Small plucked keyboards, compact relatives of the harpsichord.","ex":"Elizabethan English virginal music","region":"Europe","note":"Strings run at an angle or parallel to the keys."}}]},{"name":"Organs","v":8,"meta":{"def":"Keyboard instruments that sound continuous tones from pipes or electric tonewheels.","ex":"Pipe organ, Hammond","note":"Held notes sustain indefinitely while a key is down."},"children":[{"name":"Pipe Organ","v":5,"meta":{"def":"Large instrument sounding ranks of pipes fed by wind, played from keyboards and pedals.","ex":"Cathedral organs; Bach toccatas","region":"Europe","note":"Called the king of instruments for its scale and range."}},{"name":"Hammond Organ","v":5,"meta":{"def":"Electric organ generating tones from spinning tonewheels, shaped by drawbars.","ex":"Hammond B-3; Jimmy Smith","note":"Paired with a rotating Leslie speaker for its swirl."}},{"name":"Reed / Pump Organ","v":3,"meta":{"def":"Free-reed keyboard driven by foot-pumped bellows, common in small churches.","ex":"American parlor organs","region":"Europe / USA","note":"A harmonium relative widespread before electricity."}}]},{"name":"Electric Pianos & Portable Keys","v":8,"meta":{"def":"Electro-mechanical and small keyboards prized for distinctive tones and portability.","ex":"Rhodes, Wurlitzer, Clavinet","note":"Bridge acoustic keyboards and synthesizers."},"children":[{"name":"Rhodes Piano","v":5,"meta":{"def":"Electro-mechanical piano whose hammers strike metal tines picked up magnetically for a bell-like tone.","ex":"Fender Rhodes; Herbie Hancock, Chick Corea","note":"The classic warm electric-piano sound of soul and jazz."}},{"name":"Wurlitzer Electric Piano","v":4,"meta":{"def":"Electric piano sounding struck metal reeds with a gritty, barking tone.","ex":"Wurlitzer 200A; Ray Charles, Supertramp","note":"Reeds give a bite the Rhodes lacks."}},{"name":"Clavinet","v":3,"meta":{"def":"Electrically amplified clavichord with a funky, percussive attack.","ex":"Hohner Clavinet D6; Stevie Wonder's Superstition","note":"Strings are struck and picked up like an electric guitar."}}]}]},{"name":"Electronic Instruments","v":12,"meta":{"def":"Instruments that generate or manipulate sound electronically rather than acoustically.","ex":"Synthesizer, theremin, drum machine, sampler","note":"Rose to prominence from the mid-20th century onward."},"children":[{"name":"Synthesizers","v":12,"meta":{"def":"Electronic instruments that generate and shape sound through oscillators, filters, and envelopes.","ex":"Moog, Prophet-5, DX7","note":"Sound built from waveforms rather than vibrating bodies."},"children":[{"name":"Analog Synthesizer","v":5,"meta":{"def":"Synth generating sound from continuous analog voltage-controlled oscillators and filters.","ex":"Minimoog, Prophet-5","note":"Prized for warm, fat oscillator tone."}},{"name":"Modular Synthesizer","v":4,"meta":{"def":"Synth built from separate modules patched together with cables to route signals freely.","ex":"Moog modular, Eurorack","note":"Eurorack revived modular synthesis in the 2000s."}},{"name":"FM Synthesizer","v":4,"meta":{"def":"Digital synth using frequency modulation of operators for bright, metallic, bell tones.","ex":"Yamaha DX7","note":"Defined the sound of 1980s pop."}},{"name":"Wavetable & Digital Synth","v":4,"meta":{"def":"Synth scanning through stored digital waveforms to create evolving timbres.","ex":"PPG Wave, Waldorf, Serum","note":"Wavetable scanning gives morphing spectral movement."}},{"name":"Rompler & Workstation","v":3,"meta":{"def":"Synth playing back sampled sounds from ROM, often in an all-in-one workstation.","ex":"Korg M1, Roland JV series","note":"The Korg M1 was a defining 1990s workstation."}}]},{"name":"Beat & Sequencing Machines","v":10,"meta":{"def":"Devices that generate, trigger, and sequence rhythms and samples.","ex":"TR-808, MPC, groovebox","note":"Backbone of hip-hop and electronic dance music."},"children":[{"name":"Drum Machine","v":5,"meta":{"def":"Electronic instrument that generates and sequences percussion sounds.","ex":"Roland TR-808, TR-909","note":"The 808 kick underpins modern hip-hop and trap."}},{"name":"Sampler","v":5,"meta":{"def":"Instrument that records audio and plays it back pitched across a keyboard or pads.","ex":"Akai MPC, E-mu SP-1200, Fairlight CMI","note":"The MPC fused sampling with sequencing for hip-hop."}},{"name":"Sequencer","v":3,"meta":{"def":"Device that records and plays back note and control events to drive other instruments.","ex":"Hardware step sequencers","note":"Can be step-based or real-time recorded."}},{"name":"Groovebox","v":3,"meta":{"def":"All-in-one unit combining synth or samples, drums, and a sequencer for live jams.","ex":"Roland MC-series, Elektron, Teenage Engineering OP-1","note":"Designed for hands-on pattern-based performance."}}]},{"name":"Electronic Performance Instruments","v":10,"meta":{"def":"Electronic instruments played expressively in real time by a performer.","ex":"Theremin, keytar, e-drums","note":"Include some of the earliest electronic instruments."},"children":[{"name":"Theremin","v":5,"meta":{"def":"Electronic instrument played without contact by moving hands near two antennas for pitch and volume.","ex":"Clara Rockmore; Good Vibrations","region":"Russia","note":"Invented by Leon Theremin around 1920."}},{"name":"Ondes Martenot","v":3,"meta":{"def":"Early electronic keyboard with a sliding ring for eerie glides, used in orchestral works.","ex":"Messiaen's Turangalila-Symphonie","region":"France","note":"A ribbon controller sweeps pitch continuously."}},{"name":"Keytar","v":3,"meta":{"def":"Synthesizer worn on a strap like a guitar for mobile stage performance.","ex":"Roland AX-series; 1980s pop","note":"Frees the keyboardist from standing at a rack."}},{"name":"Electronic Drum Kit","v":4,"meta":{"def":"Kit of rubber or mesh pads triggering sampled drum sounds through a module.","ex":"Roland V-Drums","note":"Silent practice and endless sound options."}},{"name":"MIDI Keyboard Controller","v":4,"meta":{"def":"Keyboard that sends MIDI data to control software or hardware, making no sound of its own.","ex":"Novation, Akai, Arturia controllers","note":"The hub of most modern studio setups."}}]}]},{"name":"The Voice","v":12,"meta":{"def":"The human voice used as a musical instrument, spanning ranges and vocal techniques.","ex":"Soprano, tenor, beatboxing, throat singing","note":"The only instrument every person is born with."},"children":[{"name":"Vocal Ranges","v":12,"meta":{"def":"Classification of singers by their comfortable pitch range and tone.","ex":"Soprano, alto, tenor, bass","note":"Range plus timbre (tessitura) defines voice type."},"children":[{"name":"Soprano","v":4,"meta":{"def":"Highest common female voice, typically ranging around C4 to C6.","ex":"Maria Callas, Renee Fleming","note":"Coloratura sopranos specialize in agile high runs."}},{"name":"Mezzo-Soprano","v":3,"meta":{"def":"Female voice between soprano and alto with a warm middle range.","ex":"Cecilia Bartoli","note":"Often cast in trouser roles and villains in opera."}},{"name":"Alto / Contralto","v":3,"meta":{"def":"Lowest female voice, rich and dark in the lower register.","ex":"Marian Anderson","note":"True operatic contraltos are rare."}},{"name":"Countertenor","v":3,"meta":{"def":"Adult male voice singing in the alto or soprano range using falsetto.","ex":"Andreas Scholl, Philippe Jaroussky","note":"Revived for Baroque opera once sung by castrati."}},{"name":"Tenor","v":4,"meta":{"def":"Highest common male voice, prized for ringing high notes in opera.","ex":"Luciano Pavarotti, Placido Domingo","note":"The high C is a famous tenor benchmark."}},{"name":"Baritone","v":3,"meta":{"def":"Most common male voice, between tenor and bass.","ex":"Dietrich Fischer-Dieskau","note":"Named from the Greek for deep-sounding."}},{"name":"Bass","v":4,"meta":{"def":"Lowest male voice, deep and resonant, foundation of vocal harmony.","ex":"Feodor Chaliapin; Russian basso profondo","note":"Basso profondo reaches exceptionally low notes."}}]},{"name":"Extended Vocal Techniques","v":8,"meta":{"def":"Non-standard uses of the voice to make percussion, drones, or multiple pitches.","ex":"Beatboxing, throat singing, overtone","note":"Many come from folk or urban traditions."},"children":[{"name":"Beatboxing","v":4,"meta":{"def":"Vocal percussion imitating drum machines and beats using the mouth and throat.","ex":"Rahzel, Doug E. Fresh","region":"USA (hip-hop)","note":"Grew out of 1980s hip-hop culture."}},{"name":"Throat Singing (Khoomei)","v":4,"meta":{"def":"Technique producing a fundamental drone plus reinforced overtones simultaneously.","ex":"Tuvan and Mongolian khoomei","region":"Tuva / Mongolia","note":"One singer sounds two or more pitches at once."}},{"name":"Overtone Singing","v":3,"meta":{"def":"Isolating and melodizing the natural harmonics above a sung fundamental.","ex":"Western overtone singers","note":"Related to but broader than Tuvan khoomei."}},{"name":"Yodeling","v":3,"meta":{"def":"Rapid switching between chest voice and falsetto for a leaping melodic effect.","ex":"Alpine and country yodelers","region":"Alps / USA","note":"Originally a means of calling across valleys."}},{"name":"Scat & Vocalese","v":3,"meta":{"def":"Improvised wordless jazz singing using nonsense syllables like an instrument.","ex":"Ella Fitzgerald, Louis Armstrong","note":"The voice imitates a horn solo."}}]}]},{"name":"Gear & Tools","v":14,"meta":{"def":"Amplification, effects, and accessories used to shape and support instruments.","ex":"Amps, pedals, microphones, strings","note":"Essential to the sound of amplified and recorded music."},"children":[{"name":"Amplifiers","v":8,"meta":{"def":"Devices that boost an instrument signal to drive a loudspeaker, often coloring the tone.","ex":"Fender, Marshall, Vox","note":"The amp is half of an electric guitar's sound."},"children":[{"name":"Tube Amplifier","v":5,"meta":{"def":"Amplifier using vacuum tubes, prized for warm, musical overdrive when pushed.","ex":"Fender Twin, Marshall Plexi, Vox AC30","note":"Tubes clip smoothly for classic crunch."}},{"name":"Solid-State Amplifier","v":4,"meta":{"def":"Amplifier built on transistors for clean, reliable, and affordable amplification.","ex":"Roland Jazz Chorus","note":"Stays clean and consistent at high volume."}},{"name":"Modelling Amplifier","v":4,"meta":{"def":"Digital amp that simulates many classic amps and effects in one unit.","ex":"Line 6, Kemper, Fractal Axe-Fx","note":"One box can emulate a whole rack of gear."}}]},{"name":"Effects Pedals","v":16,"meta":{"def":"Stompboxes that alter an instrument's signal for gain, modulation, or time effects.","ex":"Boss, Ibanez, Electro-Harmonix","note":"Chained together on a pedalboard."},"children":[{"name":"Overdrive","v":4,"meta":{"def":"Pedal that gently clips the signal to emulate a tube amp pushed hard.","ex":"Ibanez Tube Screamer, Klon Centaur","note":"Often stacked in front of a driven amp."}},{"name":"Distortion","v":4,"meta":{"def":"Pedal producing heavy, aggressive clipping for rock and metal tones.","ex":"Boss DS-1, ProCo RAT","note":"Harder, more compressed than overdrive."}},{"name":"Fuzz","v":4,"meta":{"def":"Pedal that squares off the waveform for a thick, buzzy, saturated tone.","ex":"Fuzz Face; Jimi Hendrix, Big Muff","note":"Among the earliest guitar effects, from the 1960s."}},{"name":"Delay","v":4,"meta":{"def":"Pedal that repeats the signal after a set time for echo effects.","ex":"Boss DD-series; Echoplex tape delay","note":"Analog, tape, and digital delays each have a character."}},{"name":"Reverb","v":4,"meta":{"def":"Pedal simulating the reflections of a physical space for depth and ambience.","ex":"Strymon BigSky; spring reverb","note":"Spring, plate, hall, and shimmer are common modes."}},{"name":"Wah-Wah","v":3,"meta":{"def":"Foot-rocked pedal sweeping a filter to create a vocal-like wah sound.","ex":"Cry Baby; Jimi Hendrix, Isaac Hayes","note":"The rocking treadle moves the filter frequency."}},{"name":"Chorus","v":3,"meta":{"def":"Modulation pedal that layers detuned copies for a shimmering, widening effect.","ex":"Boss CE-1; 1980s clean tones","note":"Emulates several instruments playing at once."}},{"name":"Looper","v":3,"meta":{"def":"Pedal that records and instantly loops phrases to build layered performances live.","ex":"Boss RC-series; Ed Sheeran","note":"Enables one player to sound like a band."}},{"name":"Compressor","v":3,"meta":{"def":"Pedal that evens out dynamics, tightening attack and sustaining notes.","ex":"MXR Dyna Comp; Nashville country","note":"Adds the snap of clean funk and country tones."}},{"name":"Octave / Pitch","v":3,"meta":{"def":"Pedal that adds notes above or below the input pitch or shifts it entirely.","ex":"Electro-Harmonix POG; DigiTech Whammy","note":"The Whammy foot-sweeps pitch in real time."}}]},{"name":"Microphones","v":8,"meta":{"def":"Transducers that convert sound waves into an electrical signal for amplification or recording.","ex":"Shure SM58, Neumann U87","note":"Chosen by pattern, transient response, and tone."},"children":[{"name":"Dynamic Microphone","v":5,"meta":{"def":"Rugged mic using a moving coil, ideal for loud sources and live stages.","ex":"Shure SM57, SM58","note":"The SM57 is a studio standard on snare and guitar amps."}},{"name":"Condenser Microphone","v":5,"meta":{"def":"Sensitive mic using a charged capsule and phantom power, favored for studio detail.","ex":"Neumann U87, AKG C414","note":"Captures fine high-frequency detail."}},{"name":"Ribbon Microphone","v":4,"meta":{"def":"Mic using a thin metal ribbon for a smooth, vintage, figure-eight sound.","ex":"Royer R-121, RCA 44","note":"Naturally warm and slightly darker on top."}}]},{"name":"Pickups & Signal Tools","v":8,"meta":{"def":"Devices that capture and route instrument signal before amplification.","ex":"Humbuckers, DI boxes","note":"Shape tone at the very start of the chain."},"children":[{"name":"Magnetic Pickup","v":4,"meta":{"def":"Coil and magnet that senses steel string vibration on an electric guitar.","ex":"Single-coil (Strat), humbucker (Les Paul)","note":"Humbuckers cancel hum by using two coils."}},{"name":"Piezo Pickup","v":3,"meta":{"def":"Crystal pickup sensing physical vibration, common under acoustic guitar saddles.","ex":"Fishman acoustic systems","note":"Responds to pressure rather than magnetism."}},{"name":"DI Box","v":3,"meta":{"def":"Direct injection box that converts an instrument signal for a mixing console.","ex":"Radial DI; Countryman","note":"Balances the signal to reject noise over long cables."}}]},{"name":"Accessories & Consumables","v":12,"meta":{"def":"Small essential parts and tools for playing and maintaining instruments.","ex":"Strings, reeds, picks, sticks, capos","note":"Consumables replaced regularly as they wear."},"children":[{"name":"Strings","v":4,"meta":{"def":"Wound or plain wires that vibrate to sound stringed instruments.","ex":"D'Addario, Ernie Ball, Elixir","note":"Gauge and material shape tone and feel."}},{"name":"Reeds","v":4,"meta":{"def":"Thin cane blades that vibrate to sound woodwind instruments.","ex":"Vandoren, Rico","note":"Graded by strength; double-reed players often make their own."}},{"name":"Picks / Plectrums","v":3,"meta":{"def":"Small flat tools held to pluck or strum strings.","ex":"Dunlop, Fender celluloid picks","note":"Thickness changes attack and tone."}},{"name":"Drumsticks & Mallets","v":4,"meta":{"def":"Sticks, brushes, and mallets used to strike drums and percussion.","ex":"Vic Firth, Vater; brushes and rutes","note":"Tip shape and material change the sound."}},{"name":"Mutes","v":3,"meta":{"def":"Devices inserted in or on an instrument to soften or alter its tone.","ex":"Harmon and cup mutes; violin practice mute","note":"Miles Davis made the Harmon mute iconic."}},{"name":"Capo","v":3,"meta":{"def":"Clamp on a guitar neck that raises the pitch of all strings to change key.","ex":"Kyser, G7th capos","note":"Lets open-chord shapes play in higher keys."}},{"name":"Tuners & Metronomes","v":3,"meta":{"def":"Tools that check pitch accuracy and keep steady tempo.","ex":"Boss TU-series, Korg; clip-on tuners","note":"Clip-on tuners read vibration through the headstock."}}]}]},{"name":"Software Tools","v":12,"meta":{"def":"Computer software used to record, produce, notate, and generate music.","ex":"Ableton, Logic, Sibelius, VST plugins","note":"The modern studio lives largely inside a computer."},"children":[{"name":"Digital Audio Workstations","v":12,"meta":{"def":"Software applications for recording, editing, mixing, and producing audio and MIDI.","ex":"Ableton Live, Logic Pro, Pro Tools","note":"The central hub of modern music production."},"children":[{"name":"Ableton Live","v":4,"meta":{"def":"DAW built around a Session View for loop-based improvisation and live performance.","ex":"Electronic producers and live acts","note":"Session View clips are unique among major DAWs."}},{"name":"Logic Pro","v":4,"meta":{"def":"Apple's full-featured DAW with a deep library of instruments and effects.","ex":"macOS studios; songwriters","note":"Descended from the older Notator and Emagic Logic."}},{"name":"Pro Tools","v":4,"meta":{"def":"Industry-standard DAW for professional recording, editing, and post-production.","ex":"Commercial studios and film mixing","note":"Long the default for major-studio tracking."}},{"name":"FL Studio","v":4,"meta":{"def":"Pattern-and-piano-roll DAW popular for beatmaking and electronic music.","ex":"Hip-hop and EDM producers","note":"Formerly FruityLoops; lifetime free updates."}},{"name":"Cubase","v":3,"meta":{"def":"Veteran Steinberg DAW that helped pioneer MIDI sequencing and VST.","ex":"Composers and producers","region":"Germany","note":"Steinberg created the VST plugin standard."}},{"name":"Reaper","v":3,"meta":{"def":"Lightweight, highly customizable, low-cost DAW with a deep feature set.","ex":"Independent engineers and hobbyists","note":"Runs well on modest hardware."}}]},{"name":"Virtual Instruments & Plugins","v":10,"meta":{"def":"Software instruments and effects loaded inside a DAW to generate or process sound.","ex":"Serum, Kontakt, VST effects","note":"VST, AU, and AAX are common plugin formats."},"children":[{"name":"Software Synthesizer (VST)","v":4,"meta":{"def":"Synthesizer running as a plugin, generating sound entirely in software.","ex":"Serum, Massive, Sylenth1","note":"Serum's visual wavetable editor made it a standard."}},{"name":"Sample Library / Sampler","v":4,"meta":{"def":"Software playing back deeply recorded acoustic instruments from sampled libraries.","ex":"Native Instruments Kontakt; Spitfire Audio","note":"Orchestral libraries can run to hundreds of gigabytes."}},{"name":"Effect Plugins","v":4,"meta":{"def":"Software processors emulating EQ, compression, reverb, and vintage hardware.","ex":"FabFilter, Waves, UAD","note":"Model classic analog gear in software."}}]},{"name":"Notation Software","v":8,"meta":{"def":"Programs for writing, editing, and printing standard musical scores.","ex":"Sibelius, Dorico, MuseScore","note":"Engrave and play back sheet music."},"children":[{"name":"Sibelius","v":4,"meta":{"def":"Widely used professional scorewriting program for composers and publishers.","ex":"Film and concert composers","note":"Named after the composer Jean Sibelius."}},{"name":"Dorico","v":3,"meta":{"def":"Modern notation program from Steinberg with advanced automatic engraving.","ex":"Contemporary engravers","note":"Built by the original Sibelius development team."}},{"name":"MuseScore","v":4,"meta":{"def":"Free and open-source notation software with a large community score library.","ex":"Students, amateurs, educators","note":"Bundled with a vast public sheet-music archive."}},{"name":"Finale","v":3,"meta":{"def":"Long-running professional notation program known for fine engraving control.","ex":"Publishers and academics","note":"Discontinued in 2024 after decades of use."}}]}]}]},{"name":"Recording & Production","type":"production","v":26,"children":[{"name":"Recording Studios","v":14,"meta":{"def":"Purpose-built acoustic spaces and facilities where music is recorded, mixed and mastered.","ex":"Abbey Road, Electric Lady, Sun Studio, Capitol","note":"Ranges from world-class commercial rooms to a laptop in a bedroom."},"children":[{"name":"Studio Facility Kinds","v":12,"meta":{"def":"The categories of studio distinguished by scale, ownership and purpose.","ex":"commercial rooms, project rooms, bedroom setups, remote trucks","note":"The line between pro and home studios has blurred since the DAW era."},"children":[{"name":"Commercial Pro Studio","v":5,"meta":{"def":"A large professional facility rented by the hour or day with high-end acoustics, consoles and staff.","ex":"Abbey Road, Capitol Studios, Ocean Way","note":"Overheads are high, so many closed as home recording rose."}},{"name":"Project Studio","v":4,"meta":{"def":"A mid-tier privately owned studio built by a producer or artist for their own and select clients' work.","ex":"Dr. Dre's early rooms, many songwriter facilities","note":"Bridges the gap between bedroom and commercial scale."}},{"name":"Home / Bedroom Studio","v":4,"meta":{"def":"A compact recording setup in a domestic space, typically a DAW, interface, one mic and monitors.","ex":"Billie Eilish and Finneas's bedroom-recorded debut","note":"Democratised production; whole hit albums now made this way."}},{"name":"Mobile / Remote Recording Truck","v":4,"meta":{"def":"A vehicle fitted as a rolling control room to capture live concerts and on-location sessions.","ex":"Rolling Stones Mobile, Record Plant truck, Le Mobile","note":"Used for many classic live albums where the room couldn't come to the band."}},{"name":"Mastering Studio","v":4,"meta":{"def":"A specialist room with flat monitoring and precision gear dedicated to the final mastering stage.","ex":"Sterling Sound, Gateway Mastering, Abbey Road Mastering","note":"Acoustics are tuned for accuracy rather than a flattering sound."}},{"name":"Post-Production / Dubbing Stage","v":4,"meta":{"def":"A facility for film and TV audio: dialogue, foley, ADR, score and final mix to picture.","ex":"Skywalker Sound, Todd-AO stages","note":"A dubbing stage mixes to surround formats against the picture."}},{"name":"Broadcast Studio","v":3,"meta":{"def":"A room built for live or recorded radio and television audio, optimised for speech and reliability.","ex":"BBC Maida Vale, radio on-air studios","note":"Maida Vale hosted the famous BBC live sessions."}},{"name":"Rehearsal / Tracking Compound","v":3,"meta":{"def":"A residential or rural facility where bands live, rehearse and record over extended sessions.","ex":"Rockfield, Real World, Bearsville","note":"The residential model let bands work without watching the clock."}}]},{"name":"Studio Spaces & Rooms","v":10,"meta":{"def":"The distinct acoustic zones within a studio, each with its own function.","ex":"live room, control room, iso booth, vocal booth","note":"Separation between rooms is what allows clean multitracking."},"children":[{"name":"Live Room","v":4,"meta":{"def":"The main recording space where musicians play, tuned for a desired natural ambience.","ex":"Abbey Road Studio Two, big drum rooms","note":"Room size and surfaces strongly colour the recorded sound."}},{"name":"Control Room","v":5,"meta":{"def":"The room housing the console, monitors and engineer, acoustically treated for accurate playback.","ex":"any console-centred nerve centre of a studio","note":"The mix reference environment; must be neutral, not flattering."}},{"name":"Isolation Booth","v":4,"meta":{"def":"A small sealed room that isolates a loud instrument or amp to prevent bleed into other mics.","ex":"amp booths, drum booths","note":"Lets a band play together while keeping tracks separate."}},{"name":"Vocal Booth","v":4,"meta":{"def":"A treated, often dead little room dedicated to recording lead and backing vocals cleanly.","ex":"whisper rooms, home closet booths","note":"Absorptive treatment stops reflections cluttering the voice."}},{"name":"Machine / Amp Room","v":3,"meta":{"def":"A separate space that houses noisy gear such as tape machines, computers and guitar amps.","ex":"server rooms, remote amp closets","note":"Keeps fan and hum noise out of the recording space."}},{"name":"Echo / Reverb Chamber","v":3,"meta":{"def":"A hard-surfaced empty room fitted with a speaker and mic to generate natural reverb.","ex":"Capitol's underground chambers, Abbey Road's chamber","note":"The original way to add lush reverb before plates and plugins."}},{"name":"Foley Stage","v":3,"meta":{"def":"A post-production room with varied surfaces and props for recording everyday sound effects to picture.","ex":"footsteps, cloth movement, prop handling","note":"Named after sound-effects pioneer Jack Foley."}}]},{"name":"Landmark Studios","v":12,"meta":{"def":"Historically important studios whose rooms and gear shaped the sound of recorded music.","ex":"Abbey Road, Sun, Motown, Muscle Shoals","note":"Many became tourist sites or protected heritage buildings."},"children":[{"name":"Abbey Road","v":5,"meta":{"def":"The London EMI studio famous for the Beatles and film scores, opened 1931.","ex":"The Beatles, Pink Floyd, film soundtracks","note":"Its Studio One is one of the largest scoring stages in the world."}},{"name":"Electric Lady Studios","v":4,"meta":{"def":"The New York studio built by Jimi Hendrix in Greenwich Village, opened 1970.","ex":"Jimi Hendrix, later Stevie Wonder, D'Angelo","note":"Designed with curved walls and mood lighting to Hendrix's taste."}},{"name":"Sun Studio","v":4,"meta":{"def":"Sam Phillips's Memphis studio where early rock and roll was born.","ex":"Elvis Presley, Johnny Cash, Jerry Lee Lewis","note":"Home of slapback echo and the 'Million Dollar Quartet'."}},{"name":"Motown / Hitsville U.S.A.","v":4,"meta":{"def":"The Detroit house-turned-studio where Motown cut its soul hits in Studio A, the 'Snakepit'.","ex":"The Supremes, Marvin Gaye, Stevie Wonder","note":"The Funk Brothers house band played on countless hits there."}},{"name":"Muscle Shoals (FAME / 3614 Jackson)","v":4,"meta":{"def":"The Alabama studios whose rhythm section gave records a distinctive Southern soul groove.","ex":"Aretha Franklin, Wilson Pickett, The Rolling Stones","note":"The 'Swampers' session players were mythologised in song."}},{"name":"Capitol Studios","v":4,"meta":{"def":"The studios in the round Capitol Tower in Hollywood, known for lush echo chambers.","ex":"Frank Sinatra, Nat King Cole, Beach Boys","note":"Underground concrete echo chambers give a signature reverb."}},{"name":"Rockfield Studios","v":4,"meta":{"def":"The pioneering residential studio on a Welsh farm, opened in the mid-1960s.","ex":"Queen's 'Bohemian Rhapsody', Oasis, Coldplay","note":"One of the world's first residential recording studios."}},{"name":"More Iconic Rooms","v":10,"meta":{"def":"Further studios of major historical importance to recorded music.","ex":"Sound City, Gold Star, Trident, Stax, Chess","note":"Each shaped the sound of a scene or an era."},"children":[{"name":"Sound City","v":3,"meta":{"def":"A no-frills Los Angeles studio famed for its Neve console and huge drum sound.","ex":"Fleetwood Mac's 'Rumours', Nirvana's 'Nevermind'","note":"Its custom Neve 8028 became a legend in its own right."}},{"name":"Gold Star Studios","v":3,"meta":{"def":"The Hollywood studio with the echo chambers behind Phil Spector's Wall of Sound.","ex":"The Ronettes, Beach Boys' 'Good Vibrations'","note":"Its trapezoidal echo chambers were key to its sound."}},{"name":"Trident Studios","v":3,"meta":{"def":"A London studio prized for its Bechstein piano and early Dolby multitrack.","ex":"David Bowie, Elton John, The Beatles' 'Hey Jude'","note":"The Trident A-Range console inspired the SSL desk."}},{"name":"Stax Studios","v":3,"meta":{"def":"The Memphis home of Southern soul, built in a former cinema.","ex":"Otis Redding, Sam & Dave, Booker T. & the M.G.'s","note":"The sloped cinema floor gave the room a unique sound."}},{"name":"Chess Studios","v":3,"meta":{"def":"The Chicago studio that documented electric blues and early rock and roll.","ex":"Muddy Waters, Chuck Berry, Etta James","note":"Immortalised as '2120 South Michigan Avenue'."}},{"name":"Sunset Sound","v":3,"meta":{"def":"A Hollywood studio known for its live chamber and versatile rooms.","ex":"The Doors, Led Zeppelin, Prince","note":"Its live echo chamber is a sought-after signature."}},{"name":"Power Station / Avatar","v":3,"meta":{"def":"A New York studio famed for big, live drum rooms in a former power plant.","ex":"Chic, Bruce Springsteen, Steely Dan","note":"The reflective wooden rooms gave punchy 1980s drums."}},{"name":"RCA Studio B","v":3,"meta":{"def":"The Nashville studio central to the polished 'Nashville Sound' of country.","ex":"Elvis Presley, Dolly Parton, Roy Orbison","note":"A cradle of countrypolitan country production."}}]}]}]},{"name":"Production Roles","v":16,"meta":{"def":"The people and jobs involved in turning a musical idea into a finished recording.","ex":"producers, engineers, arrangers, session players","note":"Roles overlap heavily; one person may wear several hats."},"children":[{"name":"Producers","v":12,"meta":{"def":"Roles that shape the creative and organisational direction of a recording.","ex":"record producer, executive producer, vocal producer","note":"The producer is often called the record's 'director'."},"children":[{"name":"Record Producer","v":5,"meta":{"def":"The overall creative lead who shapes the sound, arrangement and performances of a recording.","who":"Guides songs, hires players and engineers, and makes the final creative calls.","ex":"George Martin, Quincy Jones, Rick Rubin, Nile Rodgers"}},{"name":"Executive Producer","v":4,"meta":{"def":"The person who oversees a project's business, budget and logistics rather than day-to-day sound.","who":"Secures financing, assembles the team and keeps the project on schedule and budget.","note":"Often an artist, manager or label figure; may not touch the console."}},{"name":"Co-Producer","v":3,"meta":{"def":"A producer who shares creative leadership of a track or album with another producer.","who":"Collaborates on production decisions, often bringing a complementary skill.","note":"Common when a topline writer teams with a beatmaker."}},{"name":"Vocal Producer","v":4,"meta":{"def":"A specialist who directs and refines the singer's performance during recording.","who":"Coaches phrasing and pitch, picks the best takes and comps the lead vocal.","ex":"often used on pop where the vocal is the centrepiece"}},{"name":"Beatmaker","v":4,"meta":{"def":"A producer who builds instrumental beats, typically for hip-hop, R&B and pop.","who":"Programs drums, chooses samples and crafts the underlying track from scratch.","ex":"J Dilla, Metro Boomin, Timbaland"}},{"name":"Track Producer","v":3,"meta":{"def":"A producer credited for building the instrumental track a topliner then writes over.","who":"Delivers a finished beat or backing that others add melody and lyrics to.","note":"Reflects the modular, split-role workflow of modern pop."}},{"name":"Remixer","v":3,"meta":{"def":"A producer who reworks an existing track into a new version, often for a different context.","who":"Takes the original parts and rebuilds them into a fresh arrangement.","ex":"club and dance remixes of pop singles"}}]},{"name":"Engineers","v":12,"meta":{"def":"Technical roles responsible for capturing, shaping and finishing the audio.","ex":"tracking, mixing, mastering, assistant engineers","note":"The engineer executes the sound the producer envisions."},"children":[{"name":"Recording / Tracking Engineer","v":5,"meta":{"def":"The engineer who captures performances to the recorder with mic choice and gain staging.","who":"Sets up mics, sets levels and records clean, well-balanced tracks.","ex":"Geoff Emerick, Al Schmitt"}},{"name":"Mixing Engineer","v":5,"meta":{"def":"The engineer who blends recorded tracks into a balanced, cohesive stereo (or surround) mix.","who":"Balances levels, pans, EQs, compresses and adds effects to serve the song.","ex":"Chris Lord-Alge, Andrew Scheps, Serban Ghenea"}},{"name":"Mastering Engineer","v":5,"meta":{"def":"The engineer who finalises a mix for release across formats, ensuring translation and loudness.","who":"Applies final EQ, compression, limiting and sequencing across all tracks.","ex":"Bob Ludwig, Bernie Grundman, Emily Lazar"}},{"name":"Assistant Engineer","v":4,"meta":{"def":"A junior engineer who supports the lead engineer with setup, patching and documentation.","who":"Prepares sessions, patches gear, logs takes and keeps the room running.","note":"The traditional entry route to becoming a lead engineer."}},{"name":"Pro Tools / Session Engineer","v":4,"meta":{"def":"An engineer expert at driving the DAW, editing and keeping a session organised in real time.","who":"Records, edits, comps and manages the DAW while the producer directs.","note":"A pillar of fast-moving modern pop and hip-hop sessions."}},{"name":"Tape Op","v":3,"meta":{"def":"The historical role of operating the tape machine and logging takes in analogue studios.","who":"Runs the multitrack, marks reels and does grunt work while learning the craft.","note":"The classic apprenticeship rung before the DAW era."}},{"name":"Comper","v":3,"meta":{"def":"A person who assembles the best moments from multiple takes into one composite performance.","who":"Auditions takes and stitches together the strongest phrases line by line.","note":"Often folded into the vocal producer or session engineer role."}},{"name":"Broadcast Engineer","v":3,"meta":{"def":"An engineer who captures and mixes audio for radio and television transmission.","who":"Balances live sources and ensures reliable, compliant on-air sound.","note":"Prioritises consistency and intelligibility over studio polish."}}]},{"name":"Creative & Session Roles","v":10,"meta":{"def":"Musicians and specialists who contribute sounds, parts and design to a recording.","ex":"arranger, session musician, programmer, sound designer","note":"Often uncredited but essential to a record's identity."},"children":[{"name":"Arranger","v":4,"meta":{"def":"The person who decides how a song's parts are voiced across instruments and sections.","who":"Writes charts, sets the instrumentation and structures the musical arrangement.","ex":"orchestral arrangers, horn and string writers"}},{"name":"Session Musician","v":4,"meta":{"def":"A hired professional player who performs parts on records for many different artists.","who":"Reads or improvises parts on demand to a high, reliable standard.","ex":"The Wrecking Crew, Nashville A-Team, Funk Brothers"}},{"name":"Programmer","v":4,"meta":{"def":"A specialist who creates parts using sequencers, synths, drum machines and samplers.","who":"Programs beats, sequences synth lines and manages virtual instruments.","note":"Central to electronic, pop and film-score production."}},{"name":"Sound Designer","v":4,"meta":{"def":"A person who creates original tones, textures and effects rather than played musical parts.","who":"Builds patches, processes samples and sculpts unique sonic elements.","ex":"synth patch design, cinematic risers and drones"}},{"name":"Musical Director","v":3,"meta":{"def":"The leader responsible for the overall musical performance, especially for live and touring acts.","who":"Rehearses the band, sets arrangements and cues the show.","note":"Bridges studio recordings and their live reproduction."}},{"name":"Orchestrator","v":3,"meta":{"def":"A specialist who spreads a composer's sketch across the full instruments of an orchestra.","who":"Decides exact voicings and doublings from a lead sheet or short score.","note":"Common in film scoring under tight deadlines."}},{"name":"Session Contractor","v":3,"meta":{"def":"The person who books and coordinates session musicians for a recording date.","who":"Hires the right players, handles scheduling and manages union paperwork.","note":"The trusted hub connecting producers to top session talent."}}]}]},{"name":"Production Approaches","v":14,"meta":{"def":"The overall methods and stylistic philosophies used to make a recording.","ex":"live tracking, overdubbing, in-the-box, wall of sound","note":"The chosen approach shapes a record's feel as much as the songs."},"children":[{"name":"Tracking Methods","v":10,"meta":{"def":"How performances are physically captured, from all-at-once to layered piece by piece.","ex":"live-band tracking, overdubbing, multitrack","note":"Balances live energy against control and flexibility."},"children":[{"name":"Live-Band Tracking","v":4,"meta":{"def":"Recording a whole band playing together at once to capture group interplay.","ex":"much jazz, soul and classic rock","note":"Keeps the feel and bleed of a real ensemble performance."}},{"name":"Overdubbing","v":5,"meta":{"def":"Adding new parts on top of an existing recording, one layer at a time.","ex":"stacking vocals, doubling guitars","note":"Made modern layered production possible from the 1950s on."}},{"name":"Multitracking","v":5,"meta":{"def":"Recording each part to its own track so they can be mixed independently later.","ex":"24-track tape, unlimited DAW tracks","note":"The foundation of nearly all modern studio recording."}},{"name":"One-Take / Live-to-Two-Track","v":4,"meta":{"def":"Capturing a complete performance in a single pass, often mixed straight to stereo.","ex":"early records, purist jazz and folk sessions","note":"Prizes spontaneity over the ability to fix things later."}}]},{"name":"Mixing Philosophy","v":8,"meta":{"def":"Whether a record is made inside the computer, on hardware, or a blend of both.","ex":"in-the-box, hybrid, all-analogue","note":"A long-running debate about sound quality versus convenience."},"children":[{"name":"In-the-Box (ITB)","v":4,"meta":{"def":"Producing and mixing entirely within a DAW using software instruments and plugins.","ex":"most bedroom and modern pop production","note":"Fully recallable and portable; needs no outboard hardware."}},{"name":"Hybrid Setup","v":4,"meta":{"def":"Combining a DAW with selected analogue hardware such as a console or outboard gear.","ex":"summing through a console, hardware compressors on the bus","note":"Seeks analogue character while keeping digital flexibility."}},{"name":"All-Analogue","v":3,"meta":{"def":"Recording and mixing without a computer, using tape and hardware throughout.","ex":"purist and vintage-style productions","note":"Valued for its sonic character and hands-on workflow."}}]},{"name":"Stylistic Approaches","v":12,"meta":{"def":"Signature production aesthetics that define how a record is built and sounds.","ex":"wall of sound, lo-fi, sampling-based, orchestral","note":"Often tied to a genre, era or a particular producer."},"children":[{"name":"Wall of Sound","v":4,"meta":{"def":"A dense production style layering many instruments and heavy reverb into a big orchestral wash.","ex":"Phil Spector productions of the 1960s","note":"Doubled instruments and echo chambers created its scale."}},{"name":"Lo-Fi","v":4,"meta":{"def":"A deliberately rough, imperfect aesthetic embracing hiss, noise and low fidelity.","ex":"bedroom indie, lo-fi hip-hop beats","note":"Warmth and character are valued over technical polish."}},{"name":"Bedroom Production","v":4,"meta":{"def":"A whole record self-made at home by an artist wearing every production hat.","ex":"Billie Eilish, Steve Lacy, Clairo","note":"Enabled by cheap DAWs and capable laptops."}},{"name":"Sampling-Based","v":4,"meta":{"def":"Building tracks from chopped and repurposed snippets of existing recordings.","ex":"hip-hop, plunderphonics, breakbeat","note":"Clearance and copyright are central practical concerns."}},{"name":"Loop / Beat-Driven","v":4,"meta":{"def":"Constructing songs around repeating loops and a central programmed beat.","ex":"much electronic, trap and pop production","note":"Arrangement comes from adding and removing loop layers."}},{"name":"Orchestral Production","v":4,"meta":{"def":"Building recordings around a live orchestra or large scored ensemble.","ex":"film scores, symphonic pop and rock","note":"Requires arranging, conducting and large tracking rooms."}},{"name":"DIY Production","v":3,"meta":{"def":"A self-reliant ethos of recording, releasing and promoting music without industry support.","ex":"punk, indie and cassette-culture scenes","note":"Prizes independence and rough authenticity."}}]}]},{"name":"Recording Techniques","v":14,"meta":{"def":"The practical methods used to capture sound sources onto tracks.","ex":"mic placement, DI, re-amping, comping, click tracks","note":"Small technique choices shape the whole character of a take."},"children":[{"name":"Microphone Placement","v":10,"meta":{"def":"How far and where a mic sits relative to a source, shaping tone and ambience.","ex":"close, distant and room miking","note":"Distance trades intimacy against natural room sound."},"children":[{"name":"Close Miking","v":4,"meta":{"def":"Placing a mic very near a source for a direct, isolated sound with little room.","ex":"a mic on each drum, a mic at the guitar amp grille","note":"Maximises separation but can exaggerate proximity bass."}},{"name":"Distant Miking","v":4,"meta":{"def":"Positioning a mic well back from a source to capture it blended with the room.","ex":"orchestral and choir recording","note":"Gives a natural, contextual sound with more ambience."}},{"name":"Room Miking","v":4,"meta":{"def":"Using mics placed around the room to capture its reverberant character.","ex":"ambient drum mics for a big John Bonham sound","note":"Often blended in to add size and glue to close mics."}},{"name":"Glyn Johns Drum Method","v":3,"meta":{"def":"A minimal drum-miking setup using a kick, snare and two carefully placed overheads.","ex":"classic Led Zeppelin and Rolling Stones drums","note":"Relies on precise measured distances for a balanced stereo kit."}},{"name":"Overhead Miking","v":3,"meta":{"def":"Mics placed above a drum kit to capture the whole kit and cymbals in stereo.","ex":"spaced or XY pairs over the drummer","note":"Often the backbone of the whole drum sound."}},{"name":"Spot / Accent Miking","v":3,"meta":{"def":"Adding close mics on individual instruments within a larger ensemble capture.","ex":"a spot mic on a solo violin in an orchestra","note":"Blended lightly under the main array for definition."}},{"name":"On-Axis vs Off-Axis","v":3,"meta":{"def":"Aiming a mic directly at a source or angled away to shape brightness and tone.","ex":"off-axis on a guitar cab to tame harsh highs","note":"A few degrees of angle noticeably changes the sound."}}]},{"name":"Stereo Miking Techniques","v":12,"meta":{"def":"Paired-mic arrangements that capture a source in stereo with a sense of width and space.","ex":"XY, ORTF, Blumlein, spaced AB, mid-side, Decca tree","note":"Each balances stereo width against mono compatibility."},"children":[{"name":"XY Pair","v":4,"meta":{"def":"Two coincident cardioid mics angled apart from a shared point for solid mono-compatible stereo.","ex":"acoustic guitar, drum overheads","note":"Excellent mono compatibility but a narrower image."}},{"name":"ORTF Pair","v":4,"meta":{"def":"Two cardioids spaced 17 cm apart and angled 110 degrees, mimicking human hearing.","ex":"ensembles, acoustic instruments","note":"A French broadcast standard for natural, wide stereo."}},{"name":"Blumlein Pair","v":4,"meta":{"def":"Two coincident figure-8 mics crossed at 90 degrees for accurate, spacious stereo.","ex":"rooms and ensembles with good acoustics","note":"Named after audio pioneer Alan Blumlein; captures rear too."}},{"name":"Spaced Pair (AB)","v":4,"meta":{"def":"Two mics set well apart to capture wide stereo from timing differences between them.","ex":"piano, orchestra, room ambience","note":"Very wide and lush but with weaker mono summing."}},{"name":"Mid-Side (M-S)","v":4,"meta":{"def":"A forward cardioid plus a sideways figure-8, decoded to adjustable, mono-safe stereo width.","ex":"broadcast, adjustable-width recordings","note":"Stereo width can be dialled in after recording."}},{"name":"Decca Tree","v":3,"meta":{"def":"Three spaced omni mics on a T-bar, developed for lush orchestral stereo.","ex":"film scores, classical orchestra","note":"The centre mic anchors the image and fills the hole."}}]},{"name":"Capture & Workflow Techniques","v":12,"meta":{"def":"Techniques governing how signals are routed, timed and assembled during recording.","ex":"DI, re-amping, comping, punch-in, click track","note":"These keep sessions accurate, flexible and in time."},"children":[{"name":"Direct Injection (DI)","v":4,"meta":{"def":"Feeding an instrument straight into the desk via a DI box, bypassing an amp and mic.","ex":"bass guitar, keyboards, electronic instruments","note":"Gives a clean, hum-free signal that can be re-amped later."}},{"name":"Re-Amping","v":4,"meta":{"def":"Sending a recorded DI signal back out through an amp and mic to capture new tone.","ex":"reshaping guitar tone after tracking","note":"Lets amp choice and settings be decided at mix time."}},{"name":"Comping","v":4,"meta":{"def":"Building one ideal performance by editing together the best parts of several takes.","ex":"comping a lead vocal from ten passes","note":"DAW playlists make it fast and non-destructive."}},{"name":"Punch-In / Punch Recording","v":4,"meta":{"def":"Dropping the recorder into record over a specific spot to fix a section without redoing it.","ex":"replacing one flubbed line mid-take","note":"Requires tight timing on analogue; trivial in a DAW."}},{"name":"Click Track","v":4,"meta":{"def":"A metronome fed to performers' headphones so takes stay in strict time.","ex":"essential for editing and grid-based production","note":"Keeps overdubs alignable but can feel rigid if overused."}},{"name":"Scratch Track","v":4,"meta":{"def":"A rough guide recording of a part used for reference while others track properly.","ex":"a guide vocal to play the band in","note":"Usually discarded once final parts are recorded."}},{"name":"Headphone / Cue Mix","v":4,"meta":{"def":"The custom monitoring blend sent to a performer's headphones during recording.","ex":"more of the singer's own voice in their cans","note":"A good cue mix directly improves the performance."}},{"name":"Tracking Order","v":3,"meta":{"def":"The sequence in which parts are recorded, usually rhythm foundation first.","ex":"drums and bass, then chords, then vocals","note":"A strong rhythmic bed makes everything after it easier."}}]}]},{"name":"Signal Chain & Gear","v":12,"meta":{"def":"The equipment that carries and shapes sound from source to recorder to speakers.","ex":"console, preamp, interface, converters, monitors","note":"Every device in the chain leaves its fingerprint on the sound."},"children":[{"name":"Front-End Gear","v":12,"meta":{"def":"The devices that capture, amplify and convert a source before it is recorded.","ex":"microphones, preamps, interfaces, AD/DA converters","note":"Quality here sets the ceiling for everything downstream."},"children":[{"name":"Microphones","v":12,"meta":{"def":"Transducers that convert sound into electrical signal, differing in element and pattern.","ex":"dynamic, condenser and ribbon designs","note":"Mic choice is the first and most defining tonal decision."},"children":[{"name":"Dynamic Microphone","v":4,"meta":{"def":"A rugged moving-coil mic that handles high levels well and needs no power.","ex":"Shure SM57 and SM58, Sennheiser MD421","note":"The workhorse for loud sources like snares and amps."}},{"name":"Condenser Microphone","v":4,"meta":{"def":"A sensitive capacitor mic needing phantom power, prized for detail and transient response.","ex":"Neumann U87, AKG C414","note":"The default choice for vocals and acoustic detail."}},{"name":"Ribbon Microphone","v":4,"meta":{"def":"A mic using a thin metal ribbon in a magnetic field, known for a warm, smooth top end.","ex":"Royer R-121, RCA 44 and 77","note":"Figure-8 by nature; fragile and easily damaged by wind."}},{"name":"Large-Diaphragm Condenser","v":3,"meta":{"def":"A condenser with a big capsule giving a full, flattering sound, often for vocals.","ex":"studio vocal mics like the U87","note":"Adds body and a sense of proximity and warmth."}},{"name":"Small-Diaphragm Condenser","v":3,"meta":{"def":"A pencil condenser with a tiny capsule for fast, accurate transient capture.","ex":"drum overheads, acoustic guitar, cymbals","note":"Excellent detail and consistent off-axis response."}},{"name":"Boundary / PZM Microphone","v":3,"meta":{"def":"A mic mounted flush to a surface to avoid phase issues from reflections.","ex":"conference tables, piano lids, stage floors","note":"Uses the boundary itself as part of its pickup."}}]},{"name":"Microphone Preamp","v":4,"meta":{"def":"A device that boosts a weak mic signal to usable line level, adding its own character.","ex":"Neve 1073, API 512, SSL, Universal Audio","note":"Colored preamps are prized as much for tone as gain."}},{"name":"Audio Interface","v":4,"meta":{"def":"The hardware linking mics and instruments to a computer, with preamps and converters built in.","ex":"Universal Audio Apollo, Focusrite, RME","note":"The hub of nearly every home and project studio."}},{"name":"AD/DA Converters","v":4,"meta":{"def":"Circuits that translate analogue sound to digital data and back again.","ex":"Lavry, Prism, Apogee converters","note":"Converter quality strongly affects clarity and depth."}},{"name":"Direct / DI Box","v":3,"meta":{"def":"A unit that matches an instrument's output to a balanced mic-level input for clean capture.","ex":"Radial, Countryman DI boxes","note":"Also isolates and prevents ground-loop hum."}}]},{"name":"Consoles & Routing","v":10,"meta":{"def":"The mixing desk and patching systems that route and sum many signals.","ex":"console, patchbay, summing, bus routing","note":"The console is the traditional heart of a studio."},"children":[{"name":"Mixing Console / Desk","v":5,"meta":{"def":"A large surface with channel strips to route, process and sum many signals into a mix.","ex":"SSL 4000, Neve 8078, API 1608","note":"Each classic desk imparts its own recognisable sonic stamp."}},{"name":"Patchbay","v":4,"meta":{"def":"A panel of jacks that lets engineers reroute signal between gear quickly with patch cables.","ex":"TT and quarter-inch patchbays","note":"The flexible nerve system of a hardware studio."}},{"name":"Summing Mixer","v":3,"meta":{"def":"A device that sums separate DAW outputs together in the analogue domain.","ex":"Dangerous Music, Rupert Neve summing units","note":"Used in hybrid setups to add analogue glue."}}]},{"name":"Outboard & Recorders","v":10,"meta":{"def":"Hardware processors, recorders and monitoring at the heart of tracking and mixing.","ex":"outboard gear, tape machine, monitors, DAW","note":"Mixes analogue heritage gear with digital workstations."},"children":[{"name":"Outboard Gear","v":12,"meta":{"def":"External hardware processors such as compressors, EQs and effects units.","ex":"1176, LA-2A, Pultec EQ, Lexicon reverb","note":"Classic units are still emulated as sought-after plugins."},"children":[{"name":"FET Compressor","v":3,"meta":{"def":"A fast transistor-based compressor known for punch and aggressive character.","ex":"Universal Audio 1176","note":"The 'all-buttons' mode gives a famously gritty crush."}},{"name":"Optical Compressor","v":3,"meta":{"def":"A compressor using a light and photocell for smooth, program-dependent gain reduction.","ex":"Teletronix LA-2A","note":"Gentle and musical; a classic on vocals and bass."}},{"name":"VCA Compressor","v":3,"meta":{"def":"A compressor using a voltage-controlled amplifier for precise, fast, flexible control.","ex":"SSL bus compressor, dbx 160","note":"The SSL bus comp is a staple for mix glue."}},{"name":"Vari-Mu Compressor","v":3,"meta":{"def":"A tube compressor whose valve varies gain, giving a rich, thickening sound.","ex":"Fairchild 670, Manley Vari-Mu","note":"Beloved on the master bus for warmth and density."}},{"name":"Hardware Equaliser","v":3,"meta":{"def":"An outboard EQ used to shape tone, often with a characterful analogue circuit.","ex":"Pultec EQP-1A, Neve 1073 EQ, API 550","note":"The Pultec low-end boost-and-cut trick is legendary."}},{"name":"Hardware Reverb / Effects","v":3,"meta":{"def":"Dedicated units generating reverb, delay and modulation effects in hardware.","ex":"Lexicon 224, EMT 140 plate, AMS delay","note":"The EMT plate reverb defined countless classic records."}}]},{"name":"Tape Machine","v":4,"meta":{"def":"An analogue reel-to-reel recorder that captures audio to magnetic tape.","ex":"Studer, Ampex multitrack machines","note":"Tape's saturation and compression are prized 'warmth'."}},{"name":"Studio Monitors / Nearfields","v":4,"meta":{"def":"Accurate loudspeakers used to judge a mix, placed close on the desk (nearfields).","ex":"Yamaha NS-10, Genelec, ATC","note":"The NS-10 became a mix-translation reference standard."}},{"name":"Digital Audio Workstation (DAW)","v":5,"meta":{"def":"The software environment for recording, editing, mixing and producing music on a computer.","ex":"Pro Tools, Ableton Live, Logic, FL Studio","note":"Pro Tools became the professional recording standard."}}]}]},{"name":"Mixing","v":14,"meta":{"def":"The craft of blending recorded tracks into one balanced, cohesive whole.","ex":"levels, panning, EQ, compression, reverb, automation","note":"A great mix serves the song and helps it translate everywhere."},"children":[{"name":"Balance & Space","v":8,"meta":{"def":"Placing sounds in level and the stereo field so each part has its own space.","ex":"levels, panning, headroom, gain staging","note":"Balance is the foundation every other move builds on."},"children":[{"name":"Balance / Levels","v":4,"meta":{"def":"Setting the relative volume of every element so the mix reads clearly.","ex":"vocal sitting above the band","note":"The single most important mixing decision."}},{"name":"Panning","v":4,"meta":{"def":"Positioning sounds left to right across the stereo field for width and separation.","ex":"guitars hard left and right, vocal centred","note":"Spreads elements so they stop masking each other."}},{"name":"Headroom","v":3,"meta":{"def":"The safety margin left below clipping so peaks don't distort.","ex":"mixing to leave a few dB below zero","note":"Protects transients and leaves room for mastering."}},{"name":"Gain Staging","v":4,"meta":{"def":"Setting healthy signal levels at every stage of the chain to avoid noise and distortion.","ex":"keeping each plugin and bus at a sensible level","note":"Good gain staging keeps a session clean end to end."}}]},{"name":"Dynamics & Tone","v":12,"meta":{"def":"Processing that shapes the frequency balance and dynamic range of tracks.","ex":"EQ, compression, gating, sidechain, parallel comp","note":"Controls both the colour and the punch of a mix."},"children":[{"name":"Equalisation (EQ)","v":5,"meta":{"def":"Boosting or cutting specific frequency bands to shape tone and carve space.","ex":"high-passing a vocal, notching mud at 300 Hz","note":"Subtractive EQ often cleans a mix better than boosting."}},{"name":"Compression","v":5,"meta":{"def":"Reducing dynamic range so quiet and loud parts sit closer together and sound consistent.","ex":"evening out a vocal, tightening a bass","note":"Attack and release settings define the compressor's feel."}},{"name":"Gating / Expansion","v":4,"meta":{"def":"Attenuating or muting signal below a threshold to remove noise and bleed.","ex":"gating tom mics between hits","note":"Cleans up spill and tightens drum sounds."}},{"name":"Sidechain Compression","v":4,"meta":{"def":"Triggering compression on one track from the signal of another.","ex":"ducking a bass under each kick, EDM pumping","note":"Creates space and the rhythmic 'pump' of dance music."}},{"name":"Parallel Compression","v":4,"meta":{"def":"Blending a heavily compressed copy of a track under the dry original for punch and body.","ex":"New York drum compression","note":"Adds density without crushing the natural transients."}},{"name":"Transient Shaping","v":4,"meta":{"def":"Adjusting a sound's attack and sustain directly, independent of level threshold.","ex":"sharpening a drum's snap or softening its ring","note":"Works on the envelope rather than on volume peaks."}}]},{"name":"Time-Based & Structure","v":12,"meta":{"def":"Effects and routing that add depth, movement and organisation to a mix.","ex":"reverb, delay, automation, bus, stem mixing","note":"These create the sense of space and evolving arrangement."},"children":[{"name":"Reverb","v":5,"meta":{"def":"Simulated room reflections that place sounds in a space and add depth and glue.","ex":"plate, hall, spring, chamber reverbs","note":"Too much can wash out clarity and push things back."}},{"name":"Delay / Echo","v":4,"meta":{"def":"Repeating a signal after a set time to add rhythm, depth or width.","ex":"slapback echo, tempo-synced quarter-note delays","note":"Often preferred over reverb to keep a vocal upfront."}},{"name":"Automation","v":5,"meta":{"def":"Programmed changes to levels, effects and parameters over the course of a song.","ex":"riding a vocal fader, opening a filter into a chorus","note":"Turns a static balance into a living, dynamic mix."}},{"name":"Bus / Subgroup","v":4,"meta":{"def":"Routing several tracks to a shared channel so they can be processed together.","ex":"a drum bus, a backing-vocal group","note":"Bus compression can glue a group into one cohesive part."}},{"name":"Stem Mixing","v":4,"meta":{"def":"Mixing by grouping the arrangement into a handful of submixed stems.","ex":"drums, bass, music and vocal stems","note":"Simplifies control and eases later remixing or mastering."}},{"name":"Modulation Effects","v":4,"meta":{"def":"Effects that sweep or vary a signal over time to add movement and width.","ex":"chorus, flanger, phaser, tremolo","note":"Widen and animate guitars, synths and backing vocals."}},{"name":"Saturation / Harmonic Distortion","v":4,"meta":{"def":"Adding subtle harmonic distortion to warm, thicken and glue a sound.","ex":"tape saturation, tube emulation, console drive","note":"A little grit can make digital tracks feel analogue."}}]}]},{"name":"Mastering","v":12,"meta":{"def":"The final stage that polishes a mix and prepares it for release across all formats.","ex":"loudness, limiting, EQ, dithering, sequencing","note":"Ensures consistency and translation from earbuds to club systems."},"children":[{"name":"Processing","v":10,"meta":{"def":"The tonal and dynamic treatment applied to the finished stereo mix.","ex":"EQ, limiting, stereo enhancement, compression","note":"Usually subtle, broad-stroke moves across the whole track."},"children":[{"name":"Mastering EQ","v":4,"meta":{"def":"Gentle broadband equalisation to balance the overall tone of the final mix.","ex":"a slight high-shelf lift for air","note":"Small fractions of a dB can make a big difference here."}},{"name":"Limiting","v":4,"meta":{"def":"Catching peaks and raising overall level to reach a competitive, consistent loudness.","ex":"brickwall limiters on the master bus","note":"Over-limiting squashes dynamics and adds distortion."}},{"name":"Stereo Enhancement","v":4,"meta":{"def":"Widening or narrowing the stereo image to improve width while keeping mono compatibility.","ex":"mid-side processing of the master","note":"Excess width can collapse or thin the sound in mono."}},{"name":"Multiband Compression","v":3,"meta":{"def":"Compressing separate frequency bands independently to control tonal balance dynamically.","ex":"taming a boomy low end without dulling highs","note":"A precise but easily overdone mastering tool."}}]},{"name":"Loudness & Delivery","v":10,"meta":{"def":"Managing perceived level and preparing correct files for each release format.","ex":"LUFS, dithering, red-book, vinyl pre-master","note":"Streaming loudness normalisation reshaped modern targets."},"children":[{"name":"Loudness / LUFS","v":5,"meta":{"def":"The standardised measure of perceived loudness used to target release levels.","ex":"streaming targets around -14 LUFS integrated","note":"LUFS metering replaced peak metering for loudness."}},{"name":"Loudness War","v":4,"meta":{"def":"The trend of mastering ever louder to stand out, at the cost of dynamic range.","ex":"heavily crushed 2000s CD masters","note":"Streaming normalisation has eased the incentive to over-crush."}},{"name":"Dithering","v":4,"meta":{"def":"Adding tiny controlled noise when reducing bit depth to avoid quantisation distortion.","ex":"dithering 24-bit down to 16-bit for CD","note":"Applied last, once, at the very end of the chain."}},{"name":"Red-Book Master","v":3,"meta":{"def":"A CD master conforming to the Red Book standard with correct track IDs and gaps.","ex":"16-bit / 44.1 kHz CD delivery","note":"Includes PQ codes, ISRC and track spacing data."}},{"name":"Vinyl Pre-Master","v":4,"meta":{"def":"A master prepared for the physical limits of vinyl cutting.","ex":"controlling sibilance and low-end mono for the lathe","note":"Excess bass and stereo can make the needle skip."}},{"name":"Loudness Normalisation","v":3,"meta":{"def":"Playback-side adjustment by streaming platforms so all tracks play at a similar level.","ex":"Spotify and Apple Music turning loud masters down","note":"Removed much of the point of mastering ultra-loud."}}]},{"name":"Assembly","v":8,"meta":{"def":"Ordering and finalising a project's tracks into a coherent release.","ex":"sequencing, spacing, stem mastering, references","note":"Sequencing shapes how an album is experienced as a whole."},"children":[{"name":"Sequencing","v":4,"meta":{"def":"Deciding the running order and spacing of tracks on a release.","ex":"album track order and gap lengths","note":"Flow and level matching between songs matter as much as order."}},{"name":"Stem Mastering","v":4,"meta":{"def":"Mastering from a few submixed stems rather than a single stereo file for more control.","ex":"separate vocal, music and drum stems","note":"Sits between mixing and traditional mastering."}},{"name":"Reference Levels / Matching","v":4,"meta":{"def":"Comparing a master to commercial references to gauge tone and loudness.","ex":"A/Bing against a hit in the same genre","note":"Keeps a master competitive and honest in context."}}]}]},{"name":"Editing & Correction","v":12,"meta":{"def":"The detailed work of tidying, timing and fixing recorded performances.","ex":"comping, tuning, quantise, noise reduction, crossfades","note":"Modern DAWs make once-impossible fixes routine."},"children":[{"name":"Pitch & Time","v":12,"meta":{"def":"Correcting the intonation and timing of recorded performances.","ex":"Auto-Tune, Melodyne, quantise, time-alignment","note":"Subtle correction is invisible; heavy use becomes an effect."},"children":[{"name":"Pitch Correction (Auto-Tune)","v":5,"meta":{"def":"Software that shifts sung or played notes to correct pitch, in real time or offline.","ex":"Antares Auto-Tune's subtle fixes and hard 'T-Pain' effect","note":"Went from secret fix to a deliberate stylistic sound."}},{"name":"Melodyne / Graphical Tuning","v":4,"meta":{"def":"Detailed note-by-note editing of pitch, timing and even chords within audio.","ex":"Celemony Melodyne with DNA polyphonic editing","note":"Can retune individual notes inside a chord."}},{"name":"Quantise","v":4,"meta":{"def":"Snapping the timing of notes or audio to a rhythmic grid for tightness.","ex":"quantising a drum performance to the beat","note":"Over-quantising strips out human feel and swing."}},{"name":"Time-Alignment","v":4,"meta":{"def":"Nudging tracks so they line up in time, correcting drift and phase.","ex":"aligning double-tracked vocals, phase-aligning drum mics","note":"Tightens layered parts and prevents phase cancellation."}},{"name":"Time-Stretching / Elastic Audio","v":4,"meta":{"def":"Changing the length or tempo of audio without altering its pitch.","ex":"Pro Tools Elastic Audio, Ableton warping","note":"Lets recordings be conformed to a grid or new tempo."}},{"name":"Groove Editing (Beat Detective)","v":3,"meta":{"def":"Slicing and nudging drum hits to tighten timing while keeping human feel.","ex":"Pro Tools Beat Detective, slip editing","note":"A middle path between raw performance and rigid quantise."}}]},{"name":"Cleanup & Restoration","v":12,"meta":{"def":"Removing unwanted noise and joining edits smoothly for a clean final track.","ex":"noise reduction, restoration, crossfades, de-essing","note":"Aims to be inaudible, leaving only the intended sound."},"children":[{"name":"Noise Reduction","v":4,"meta":{"def":"Suppressing background noise such as hiss, hum and room rumble from a recording.","ex":"iZotope RX, spectral de-noise","note":"Aggressive settings introduce watery, artefact-laden sound."}},{"name":"Audio Restoration","v":4,"meta":{"def":"Repairing damaged or degraded audio by removing clicks, crackle and dropouts.","ex":"cleaning old tapes and vinyl transfers","note":"Essential to reissuing archival and historic recordings."}},{"name":"Crossfades","v":4,"meta":{"def":"Overlapping the ends of two edited clips so the join is smooth and click-free.","ex":"crossfading between comped vocal takes","note":"Prevents the pops that hard edits at zero-crossings cause."}},{"name":"De-Essing","v":4,"meta":{"def":"Taming harsh sibilant 's' and 't' sounds in a vocal with frequency-targeted compression.","ex":"smoothing bright, sibilant lead vocals","note":"A frequency-specific compressor keyed to the 'ess' band."}},{"name":"Fades & Edits","v":3,"meta":{"def":"Trimming, fading and arranging audio regions to shape the final track structure.","ex":"fade-outs, tightening intros, removing breaths","note":"The basic surgery underlying all detailed editing."}}]}]}]},{"name":"Sound & Technology","type":"sound","v":26,"children":[{"name":"Sound Science & Acoustics","v":14,"meta":{"def":"The physics of sound as vibration travelling through a medium as pressure waves.","ex":"waveforms, harmonics, resonance","aka":"acoustics","note":"Sound travels ~343 m/s in air at 20C."},"children":[{"name":"Sound Wave","v":10,"meta":{"def":"A longitudinal mechanical wave of pressure variation propagating through an elastic medium.","ex":"compressions and rarefactions in air","aka":"acoustic wave","note":"Cannot travel through a vacuum."},"children":[{"name":"Frequency & Pitch","v":5,"meta":{"def":"The number of wave cycles per second, perceived as musical pitch.","ex":"440 Hz = A4","aka":"Hz, cycles per second","note":"Doubling frequency raises pitch by one octave."}},{"name":"Amplitude & Loudness","v":5,"meta":{"def":"The magnitude of pressure variation, perceived as volume or loudness.","ex":"quiet vs loud","aka":"volume, intensity","note":"Perceived loudness is roughly logarithmic with amplitude."}},{"name":"Decibel & SPL","v":4,"meta":{"def":"A logarithmic unit measuring sound pressure level relative to a reference.","ex":"0 dB SPL threshold, 120 dB pain","aka":"dB, dB SPL","note":"Every 10 dB is a tenfold power increase."}},{"name":"Wavelength","v":4,"meta":{"def":"The physical distance between successive wave crests, inversely proportional to frequency.","ex":"20 Hz is ~17 m; 20 kHz is ~17 mm","aka":"lambda","note":"Determines how sound diffracts around objects."}},{"name":"Speed of Sound","v":4,"meta":{"def":"The velocity at which sound propagates through a medium, dependent on density and elasticity.","ex":"343 m/s air, 1480 m/s water","aka":"sonic velocity","note":"Faster in denser stiff media like steel (~5100 m/s)."}},{"name":"Phase","v":4,"meta":{"def":"The position within a wave cycle, measured in degrees or radians relative to a reference.","ex":"180 out of phase cancels","aka":"phase angle","note":"Phase relationships cause comb filtering and cancellation."}},{"name":"Interference & Beats","v":4,"meta":{"def":"The combination of waves producing reinforcement, cancellation, or slow amplitude pulsing.","ex":"two close pitches beating","aka":"beating, superposition","note":"Beat rate equals the frequency difference of the tones."}},{"name":"Doppler Effect","v":4,"meta":{"def":"The apparent shift in frequency when a source and listener move relative to each other.","ex":"passing siren dropping pitch","aka":"Doppler shift","note":"Used in Leslie speakers for a rotating vibrato."}},{"name":"Reflection & Diffraction","v":4,"meta":{"def":"The bouncing of sound off surfaces and its bending around obstacles.","ex":"echoes, sound behind a wall","aka":"acoustic reflection","note":"Low frequencies diffract more readily than highs."}}]},{"name":"Timbre & Spectrum","v":10,"meta":{"def":"The tonal colour of a sound determined by its harmonic and spectral content.","ex":"why a violin differs from a flute at the same pitch","aka":"tone colour, tone quality","note":"Often called sound's third dimension after pitch and loudness."},"children":[{"name":"Harmonics & Overtones","v":5,"meta":{"def":"Frequency components above the fundamental that shape a sound's timbre.","ex":"2f, 3f, 4f above fundamental","aka":"partials, overtones","note":"Harmonics are integer multiples; overtones need not be."}},{"name":"Fundamental Frequency","v":4,"meta":{"def":"The lowest and usually strongest frequency of a periodic sound, defining its pitch.","ex":"f0 of a plucked string","aka":"f0, first harmonic","note":"Perceived pitch even when the fundamental is absent."}},{"name":"Harmonic Series","v":5,"meta":{"def":"The natural sequence of whole-number frequency multiples above a fundamental.","ex":"1:2:3:4:5 ratios","aka":"overtone series","note":"Basis of brass instrument notes and just intonation."}},{"name":"Inharmonicity","v":4,"meta":{"def":"The degree to which partials deviate from exact integer multiples of the fundamental.","ex":"bells, stiff piano strings","aka":"stretched partials","note":"Causes piano tuning to be stretched at the extremes."}},{"name":"Formants","v":4,"meta":{"def":"Resonant peaks in a spectrum that give vowels and instruments their character.","ex":"vowel identity in speech","aka":"resonance peaks","note":"The vocal tract shapes formants to form vowels."}},{"name":"Spectral Envelope","v":4,"meta":{"def":"The overall shape of energy distribution across frequency in a sound.","ex":"bright vs dark tone","aka":"spectrum shape","note":"Filters reshape the spectral envelope."}},{"name":"Noise","v":4,"meta":{"def":"Aperiodic sound with energy spread across many frequencies.","ex":"white, pink, brown noise","aka":"broadband sound","note":"White noise has equal energy per Hz; pink per octave."}}]},{"name":"Waveforms","v":8,"meta":{"def":"The characteristic shapes of periodic oscillations, each with distinct harmonic content.","ex":"sine, square, saw, triangle","aka":"wave shapes","note":"Fourier showed any periodic wave is a sum of sines."},"children":[{"name":"Sine Wave","v":4,"meta":{"def":"The purest waveform, containing a single frequency with no harmonics.","ex":"tuning fork, test tone","aka":"sinusoid","note":"The building block of all other periodic waveforms."}},{"name":"Square Wave","v":4,"meta":{"def":"A waveform alternating instantly between two levels, rich in odd harmonics.","ex":"chiptune leads, clarinet-like","aka":"pulse (50% duty)","note":"Contains only odd-numbered harmonics."}},{"name":"Sawtooth Wave","v":4,"meta":{"def":"A ramp waveform containing all harmonics, bright and buzzy.","ex":"brass and string synth patches","aka":"saw, ramp","note":"Has both odd and even harmonics falling off as 1/n."}},{"name":"Triangle Wave","v":4,"meta":{"def":"A linear rise-and-fall waveform with weak odd harmonics, mellow tone.","ex":"soft flute-like leads","aka":"tri wave","note":"Odd harmonics roll off faster than a square wave."}},{"name":"Pulse Wave (PWM)","v":4,"meta":{"def":"A rectangular wave whose duty cycle can be swept for timbral movement.","ex":"thick moving synth bass","aka":"variable-width pulse","note":"Pulse-width modulation animates the harmonic mix."}}]},{"name":"Resonance & Standing Waves","v":8,"meta":{"def":"The amplification of sound at natural frequencies and the fixed wave patterns that result.","ex":"vibrating strings and air columns","aka":"acoustic resonance","note":"Every physical body has natural resonant modes."},"children":[{"name":"Resonance","v":4,"meta":{"def":"The tendency of a system to oscillate strongly at particular natural frequencies.","ex":"wine glass shattering at pitch","aka":"sympathetic vibration","note":"Instrument bodies resonate to amplify strings."}},{"name":"Standing Wave","v":4,"meta":{"def":"A stationary vibration pattern formed by two waves travelling in opposite directions.","ex":"guitar string vibration modes","aka":"stationary wave","note":"Fixed nodes and moving antinodes define the pattern."}},{"name":"Nodes & Antinodes","v":4,"meta":{"def":"Points of zero and maximum displacement within a standing wave.","ex":"harmonics on a string","aka":"vibration nodes","note":"Touching a string node produces a flageolet harmonic."}},{"name":"Helmholtz Resonance","v":4,"meta":{"def":"The resonance of air in a cavity with a neck, tuned by volume and opening.","ex":"blowing across a bottle","aka":"cavity resonance","note":"Governs bass response of ported loudspeaker cabinets."}}]},{"name":"Amplitude Envelope (ADSR)","v":6,"meta":{"def":"The evolution of a sound's loudness over time from onset to silence.","ex":"sharp pluck vs slow swell","aka":"dynamic envelope","note":"ADSR is the classic four-stage envelope model."},"children":[{"name":"Attack","v":4,"meta":{"def":"The time for a sound to rise from silence to its peak level.","ex":"fast percussive vs slow pad","aka":"onset time","note":"Transient attack cues are vital for instrument recognition."}},{"name":"Decay","v":4,"meta":{"def":"The fall from peak to the sustained level after the attack.","ex":"piano note settling","aka":"initial decay","note":"Shapes the perceived body of a note."}},{"name":"Sustain","v":4,"meta":{"def":"The steady level held while a note is maintained.","ex":"held organ note","aka":"hold level","note":"A level, not a time, unlike the other stages."}},{"name":"Release","v":4,"meta":{"def":"The fade to silence after a note is released.","ex":"reverb-like tail on synths","aka":"fall time","note":"Long release creates overlapping legato textures."}}]}]},{"name":"Psychoacoustics","v":12,"meta":{"def":"The scientific study of how humans perceive and interpret sound.","ex":"masking, pitch perception, loudness curves","aka":"auditory perception","note":"Underpins lossy audio codecs like MP3."},"children":[{"name":"The Hearing Mechanism","v":8,"meta":{"def":"The anatomy and physiology that convert sound waves into neural signals.","ex":"eardrum, cochlea, hair cells","aka":"auditory system","note":"The ear spans roughly 20 Hz to 20 kHz in youth."},"children":[{"name":"Cochlea","v":4,"meta":{"def":"The spiral fluid-filled inner-ear organ that transduces sound to nerve impulses.","ex":"basilar membrane tonotopy","aka":"inner ear","note":"Different positions respond to different frequencies."}},{"name":"Hair Cells","v":4,"meta":{"def":"Sensory cells on the basilar membrane that convert vibration into electrical signals.","ex":"inner and outer hair cells","aka":"stereocilia","note":"Damaged hair cells do not regenerate in humans."}},{"name":"Frequency Range","v":4,"meta":{"def":"The band of frequencies audible to human hearing, narrowing with age.","ex":"20 Hz to 20 kHz nominal","aka":"audible spectrum","note":"High-frequency loss with age is called presbycusis."}},{"name":"Critical Bands","v":4,"meta":{"def":"Frequency regions within which the ear integrates sound and masking occurs.","ex":"Bark scale bands","aka":"auditory filters","note":"About 24 critical bands span human hearing."}}]},{"name":"Loudness Perception","v":6,"meta":{"def":"How the ear judges loudness, which varies with frequency and level.","ex":"equal-loudness curves","aka":"perceived volume","note":"The ear is most sensitive around 2-5 kHz."},"children":[{"name":"Equal-Loudness Contours","v":4,"meta":{"def":"Curves showing sound levels perceived as equally loud across frequencies.","ex":"ISO 226 curves","aka":"Fletcher-Munson curves","note":"Bass and treble seem quieter at low listening levels."}},{"name":"Phon & Sone","v":4,"meta":{"def":"Units quantifying perceived loudness referenced to a 1 kHz tone.","ex":"40 phon = 1 sone","aka":"loudness units","note":"Doubling sones roughly doubles perceived loudness."}},{"name":"Loudness War","v":4,"meta":{"def":"The trend of mastering tracks ever louder at the cost of dynamic range.","ex":"hyper-compressed CDs","aka":"hypercompression","note":"LUFS metering and streaming normalisation curbed it."}}]},{"name":"Masking","v":5,"meta":{"def":"The phenomenon where one sound renders another inaudible.","ex":"loud tone hiding a soft one","aka":"auditory masking","note":"Exploited to discard inaudible data in lossy codecs."},"children":[{"name":"Frequency Masking","v":4,"meta":{"def":"A loud tone obscuring quieter tones at nearby frequencies.","ex":"bass drum hiding low synth","aka":"simultaneous masking","note":"Masking spreads more upward in frequency than downward."}},{"name":"Temporal Masking","v":4,"meta":{"def":"Masking that occurs just before and after a loud sound in time.","ex":"pre- and post-masking","aka":"non-simultaneous masking","note":"Post-masking lasts up to about 200 ms."}}]},{"name":"Pitch Perception","v":6,"meta":{"def":"How the auditory system derives musical pitch from complex sounds.","ex":"missing fundamental, mel scale","aka":"pitch hearing","note":"Pitch is a percept, not a purely physical quantity."},"children":[{"name":"Missing Fundamental","v":4,"meta":{"def":"Hearing a pitch at a fundamental that is physically absent from the sound.","ex":"bass on small speakers","aka":"virtual pitch","note":"The brain infers f0 from harmonic spacing."}},{"name":"Mel Scale","v":4,"meta":{"def":"A perceptual pitch scale spacing tones by equal perceived distance.","ex":"used in MFCC features","aka":"melody scale","note":"Basis of mel-frequency cepstral coefficients in ML."}},{"name":"Absolute Pitch","v":4,"meta":{"def":"The rare ability to name or produce a pitch without a reference.","ex":"naming a note by ear","aka":"perfect pitch","note":"More common among tonal-language speakers."}},{"name":"Relative Pitch","v":4,"meta":{"def":"The ability to identify intervals and notes relative to a reference tone.","ex":"sight-singing by interval","aka":"interval hearing","note":"Trainable, unlike absolute pitch which is largely early-fixed."}}]},{"name":"Spatial & Binaural Hearing","v":6,"meta":{"def":"How two ears localise sound sources in three-dimensional space.","ex":"left-right and front-back cues","aka":"sound localisation","note":"Relies on tiny timing and level differences between ears."},"children":[{"name":"Interaural Time Difference","v":4,"meta":{"def":"The slight delay of sound reaching one ear before the other, cueing direction.","ex":"sound from the left arrives left-first","aka":"ITD","note":"Dominant localisation cue below about 1500 Hz."}},{"name":"Interaural Level Difference","v":4,"meta":{"def":"The loudness difference between ears caused by head shadowing.","ex":"far-ear attenuation of highs","aka":"ILD","note":"Dominant localisation cue at high frequencies."}},{"name":"Precedence Effect","v":4,"meta":{"def":"The fusion of a direct sound and quick echoes into one perceived location.","ex":"PA delay-tower alignment","aka":"Haas effect, law of the first wavefront","note":"Echoes within ~35 ms fuse with the direct sound."}},{"name":"HRTF","v":4,"meta":{"def":"The filtering imposed by head, ears and torso used to synthesise 3D audio.","ex":"binaural headphone rendering","aka":"head-related transfer function","note":"Individualised HRTFs improve localisation accuracy."}}]}]},{"name":"Tuning & Temperament","v":10,"meta":{"def":"Systems for choosing the exact pitches used in music and dividing the octave.","ex":"equal temperament, just intonation","aka":"intonation systems","note":"A trade-off between pure intervals and modulation freedom."},"children":[{"name":"Equal Temperament","v":5,"meta":{"def":"Dividing the octave into equal ratio steps so all keys sound alike.","ex":"12-TET piano tuning","aka":"12-TET, ET","note":"Every semitone is the twelfth root of two, ~1.0595."}},{"name":"Just Intonation","v":5,"meta":{"def":"Tuning based on simple whole-number frequency ratios for pure intervals.","ex":"5:4 major third, 3:2 fifth","aka":"pure intonation","note":"Sounds beatless but limits free modulation between keys."}},{"name":"Pythagorean Tuning","v":4,"meta":{"def":"A tuning built by stacking pure 3:2 perfect fifths.","ex":"medieval keyboard tuning","aka":"Pythagorean intonation","note":"Leaves a leftover Pythagorean comma between keys."}},{"name":"Meantone Temperament","v":4,"meta":{"def":"A tuning tempering fifths to favour pure major thirds.","ex":"quarter-comma meantone","aka":"mean-tone","note":"Dominant on keyboards in the Renaissance and Baroque."}},{"name":"Well Temperament","v":4,"meta":{"def":"Irregular tunings letting every key be usable with distinct character.","ex":"Werckmeister III","aka":"circulating temperament","note":"Inspired Bach's Well-Tempered Clavier."}},{"name":"A = 440 Hz Standard","v":4,"meta":{"def":"The international reference pitch fixing A above middle C.","ex":"orchestral tuning note","aka":"concert pitch, A4","note":"Some orchestras tune sharper at 442-443 Hz for brilliance."}},{"name":"Cents","v":4,"meta":{"def":"A logarithmic unit dividing the equal-tempered semitone into 100 parts.","ex":"tuner readouts in cents","aka":"hundredth of a semitone","note":"1200 cents span an octave."}},{"name":"Microtonality","v":5,"meta":{"def":"The use of intervals smaller than the standard semitone.","ex":"quarter tones, 19-TET","aka":"microtonal music","note":"Explored by Partch, Carrillo, and Wendy Carlos."}},{"name":"Xenharmonic Tuning","v":4,"meta":{"def":"Tuning systems deliberately unlike standard 12-tone equal temperament.","ex":"Bohlen-Pierce scale","aka":"xen tuning","note":"The Bohlen-Pierce scale divides a 3:1 tritave."}},{"name":"Scala & Tuning Files","v":4,"meta":{"def":"Software and file formats for defining and loading custom tunings.","ex":".scl and .tun files","aka":"Scala format","note":"Scala ships an archive of thousands of historical scales."}}]},{"name":"Room & Venue Acoustics","v":10,"meta":{"def":"How enclosed spaces shape sound through reflection, absorption and resonance.","ex":"concert halls, control rooms","aka":"architectural acoustics","note":"Wallace Sabine founded the field around 1900."},"children":[{"name":"Reverberation Time (RT60)","v":5,"meta":{"def":"The time for sound to decay by 60 dB after the source stops.","ex":"cathedral vs studio","aka":"RT60, decay time","note":"Concert halls target roughly 1.8-2.2 seconds."}},{"name":"Absorption","v":4,"meta":{"def":"The conversion of sound energy into heat by soft porous materials.","ex":"foam, curtains, mineral wool","aka":"acoustic damping","note":"Rated by an absorption coefficient from 0 to 1."}},{"name":"Diffusion","v":4,"meta":{"def":"The scattering of sound in many directions to spread reflections evenly.","ex":"quadratic residue diffusers","aka":"sound scattering","note":"Preserves liveness while taming harsh echoes."}},{"name":"Room Modes","v":4,"meta":{"def":"Resonant standing waves between parallel room surfaces causing uneven bass.","ex":"boomy bass nodes in corners","aka":"eigenmodes","note":"Most troublesome in small square-proportioned rooms."}},{"name":"Standing Waves & Flutter Echo","v":4,"meta":{"def":"Repeated reflections between hard parallel walls creating buzzing echoes.","ex":"clap in an empty hallway","aka":"flutter echo","note":"Cured by angling surfaces or adding absorption."}},{"name":"Acoustic Treatment","v":4,"meta":{"def":"The placement of absorbers, diffusers and bass traps to control a room.","ex":"studio panels and traps","aka":"room treatment","note":"Bass traps target hard-to-tame low-frequency modes."}},{"name":"Early Reflections","v":4,"meta":{"def":"The first reflections arriving soon after direct sound, shaping clarity.","ex":"side-wall bounces at a mix desk","aka":"first reflections","note":"Treating reflection points sharpens stereo imaging."}},{"name":"Concert Hall Acoustics","v":4,"meta":{"def":"The design of halls for warmth, clarity and envelopment.","ex":"shoebox vs vineyard halls","aka":"auditorium acoustics","note":"Vienna's Musikverein is a benchmark shoebox hall."}},{"name":"Anechoic Chamber","v":4,"meta":{"def":"A room engineered to absorb virtually all reflections for pure measurement.","ex":"speaker and mic testing","aka":"dead room","note":"Wedge foam walls yield near-zero reverberation."}}]},{"name":"Sound Synthesis","v":14,"meta":{"def":"Techniques for generating and shaping sound electronically.","ex":"subtractive, FM, granular","aka":"synthesis methods","note":"Each method sculpts spectrum in a different way."},"children":[{"name":"Subtractive Synthesis","v":6,"meta":{"def":"Shaping sound by filtering harmonics out of a rich waveform.","ex":"Minimoog, classic analog synths","aka":"analog synthesis","note":"The dominant paradigm of vintage analog synthesizers."},"children":[{"name":"Oscillator (VCO/DCO)","v":4,"meta":{"def":"The circuit generating the raw periodic waveform of a synth voice.","ex":"saw and square generators","aka":"VCO, DCO, tone generator","note":"DCOs add digital pitch stability to analog tone."}},{"name":"Filter (VCF)","v":4,"meta":{"def":"A circuit that removes or emphasises frequency ranges to shape timbre.","ex":"Moog ladder low-pass","aka":"VCF, cutoff filter","note":"Resonance boosts frequencies near the cutoff point."}},{"name":"Amplifier (VCA)","v":4,"meta":{"def":"A gain stage that shapes a voice's loudness over time.","ex":"envelope-controlled volume","aka":"VCA","note":"Driven by an amplitude envelope for dynamics."}},{"name":"LFO","v":4,"meta":{"def":"A slow oscillator used to modulate pitch, filter or amplitude.","ex":"vibrato, tremolo, wobble bass","aka":"low-frequency oscillator","note":"Usually below 20 Hz, beneath the audible range."}},{"name":"Envelope Generator","v":4,"meta":{"def":"A control source producing an ADSR contour to modulate parameters.","ex":"filter sweep on each note","aka":"EG, ADSR generator","note":"Often routed to both filter and amplifier."}}]},{"name":"Additive Synthesis","v":4,"meta":{"def":"Building sounds by summing many individual sine-wave partials.","ex":"Kawai K5000, drawbar organ","aka":"Fourier synthesis","note":"Theoretically can recreate any timbre with enough partials."},"children":[{"name":"Partial Summation","v":4,"meta":{"def":"Combining sine components at set frequencies and amplitudes to form a tone.","ex":"hundreds of sines summed","aka":"harmonic stacking","note":"Each partial can have its own envelope over time."}},{"name":"Drawbar Organ","v":4,"meta":{"def":"An additive instrument mixing harmonic tones via sliding drawbars.","ex":"Hammond B3","aka":"tonewheel organ","note":"Nine drawbars set the balance of harmonics."}}]},{"name":"FM Synthesis","v":5,"meta":{"def":"Generating complex timbres by modulating one oscillator's frequency with another.","ex":"Yamaha DX7 electric pianos","aka":"frequency modulation, phase modulation","note":"Invented by John Chowning at Stanford."},"children":[{"name":"Carrier & Modulator","v":4,"meta":{"def":"The audible oscillator and the one that modulates its frequency.","ex":"2-operator FM pair","aka":"operator pair","note":"Their frequency ratio sets the harmonic character."}},{"name":"Operators & Algorithms","v":4,"meta":{"def":"The oscillator units and the routings connecting them in FM synths.","ex":"DX7 32 algorithms","aka":"FM routing","note":"The DX7 offered six operators in 32 configurations."}},{"name":"Modulation Index","v":4,"meta":{"def":"The depth of frequency modulation controlling how many sidebands appear.","ex":"brightness of an FM bell","aka":"FM depth","note":"Higher index yields richer, brighter sidebands."}}]},{"name":"Wavetable Synthesis","v":4,"meta":{"def":"Scanning through a table of single-cycle waveforms for evolving timbre.","ex":"PPG Wave, Serum","aka":"wave-scanning synthesis","note":"Sweeping the wavetable position animates the spectrum."},"children":[{"name":"Single-Cycle Waveforms","v":4,"meta":{"def":"Short stored waveform snapshots that make up a wavetable.","ex":"one period of a saw","aka":"wave frames","note":"Interpolation smooths the jump between frames."}},{"name":"Wavetable Position","v":4,"meta":{"def":"The scan point across a wavetable, modulatable for motion.","ex":"LFO-swept wave morph","aka":"table index","note":"Often the signature control of modern soft synths."}}]},{"name":"Granular Synthesis","v":4,"meta":{"def":"Building sound from many tiny overlapping grains of audio.","ex":"clouds, time-stretch textures","aka":"granulation","note":"Grains typically last 1 to 100 milliseconds."},"children":[{"name":"Grains & Density","v":4,"meta":{"def":"The microscopic sound particles and how many overlap per second.","ex":"sparse clicks vs dense clouds","aka":"grain clouds","note":"High density blurs grains into continuous texture."}},{"name":"Time Stretching","v":4,"meta":{"def":"Changing duration without altering pitch by respacing grains.","ex":"slowing audio without pitch drop","aka":"granular stretch","note":"Decouples playback speed from pitch."}}]},{"name":"Physical Modelling","v":4,"meta":{"def":"Synthesising sound by mathematically simulating a physical instrument.","ex":"Yamaha VL1, modelled strings","aka":"modelled synthesis","note":"Karplus-Strong models plucked strings very cheaply."},"children":[{"name":"Waveguide Synthesis","v":4,"meta":{"def":"Modelling wave travel along strings and tubes with delay lines.","ex":"modelled flute and violin","aka":"digital waveguide","note":"Developed by Julius Smith at Stanford."}},{"name":"Karplus-Strong","v":4,"meta":{"def":"A simple algorithm modelling a plucked string with a filtered delay loop.","ex":"synthetic guitar plucks","aka":"KS algorithm","note":"A short noise burst fed into a feedback delay."}}]},{"name":"Sample-Based Synthesis","v":4,"meta":{"def":"Playing back recorded audio samples, often multisampled across the keyboard.","ex":"romplers, PCM synths","aka":"PCM synthesis, sampling","note":"Underlies most realistic virtual instruments."},"children":[{"name":"Multisampling","v":4,"meta":{"def":"Recording an instrument at many pitches and dynamics for realism.","ex":"velocity layers of a piano","aka":"sample mapping","note":"Round-robin samples avoid the machine-gun effect."}},{"name":"Rompler","v":4,"meta":{"def":"A synth playing back read-only sampled waveforms with light editing.","ex":"Roland JV, Korg M1","aka":"sample-playback synth","note":"The M1 defined the workstation sound of the 1990s."}}]},{"name":"Other Synthesis Methods","v":5,"meta":{"def":"Additional or hybrid techniques for sound generation.","ex":"vector, phase distortion, west coast","aka":"alternative synthesis","note":"Many synths blend several methods."},"children":[{"name":"Vector Synthesis","v":4,"meta":{"def":"Crossfading between multiple sound sources with a joystick or envelope.","ex":"Sequential Prophet VS","aka":"vector mixing","note":"A joystick blends four corner sources."}},{"name":"Phase Distortion","v":4,"meta":{"def":"Warping a wave's phase readout to create new harmonics.","ex":"Casio CZ series","aka":"PD synthesis","note":"Casio's cheaper answer to Yamaha FM."}},{"name":"West Coast Synthesis","v":4,"meta":{"def":"A timbre-generation approach using wavefolding and complex oscillators.","ex":"Buchla, Make Noise","aka":"Buchla-style synthesis","note":"Favours wavefolders over subtractive filters."}},{"name":"Modular Synthesis","v":4,"meta":{"def":"Building patches by cabling independent modules together freely.","ex":"Eurorack, Moog modular","aka":"modular synth","note":"Eurorack revived modular in a compact 3U format."}}]}]},{"name":"Sampling & Digital Audio","v":10,"meta":{"def":"The theory of representing continuous sound as discrete digital data.","ex":"sample rate, bit depth, Nyquist","aka":"digital audio fundamentals","note":"Founded on Shannon-Nyquist sampling theory."},"children":[{"name":"Sampling","v":4,"meta":{"def":"Measuring a signal's amplitude at regular time intervals.","ex":"snapshotting a waveform","aka":"discretisation","note":"Each measurement is one sample."}},{"name":"Sample Rate","v":4,"meta":{"def":"The number of samples captured per second, setting the frequency ceiling.","ex":"44.1, 48, 96 kHz","aka":"sampling frequency","note":"CD audio uses 44.1 kHz."}},{"name":"Bit Depth","v":4,"meta":{"def":"The number of bits per sample, setting amplitude resolution and dynamic range.","ex":"16-bit, 24-bit audio","aka":"word length","note":"Each bit adds about 6 dB of dynamic range."}},{"name":"Nyquist Theorem","v":4,"meta":{"def":"The rule that sample rate must exceed twice the highest frequency captured.","ex":"44.1 kHz captures up to ~22 kHz","aka":"Nyquist-Shannon theorem","note":"The Nyquist frequency is half the sample rate."}},{"name":"Aliasing","v":4,"meta":{"def":"The false low frequencies produced when sampling above the Nyquist limit.","ex":"harsh digital artefacts","aka":"foldover","note":"Anti-aliasing filters remove content above Nyquist."}},{"name":"Quantisation","v":4,"meta":{"def":"Rounding continuous amplitude values to the nearest digital step.","ex":"staircasing of quiet signals","aka":"amplitude quantisation","note":"Introduces quantisation noise at low levels."}},{"name":"Dither","v":4,"meta":{"def":"Low-level noise added before bit reduction to mask quantisation distortion.","ex":"24-to-16-bit export","aka":"dithering","note":"Trades correlated distortion for benign noise."}},{"name":"PCM","v":4,"meta":{"def":"The standard method of storing audio as uniformly sampled amplitude values.","ex":"WAV and CD data","aka":"pulse-code modulation","note":"The baseline uncompressed digital audio format."}},{"name":"ADC & DAC","v":4,"meta":{"def":"Converters translating between analog signals and digital audio.","ex":"audio interface converters","aka":"A/D and D/A converters","note":"Converter quality strongly affects perceived fidelity."}},{"name":"Latency & Buffering","v":4,"meta":{"def":"The delay from buffering audio blocks between input and output.","ex":"monitoring lag while recording","aka":"buffer size, round-trip latency","note":"Smaller buffers cut latency but raise CPU load."}}]},{"name":"Audio Formats & Codecs","v":12,"meta":{"def":"File formats and compression schemes for storing and streaming audio.","ex":"WAV, MP3, FLAC, Opus","aka":"audio file formats","note":"Split broadly into lossless and lossy families."},"children":[{"name":"Uncompressed & Lossless","v":6,"meta":{"def":"Formats preserving the original audio data exactly.","ex":"WAV, FLAC, ALAC","aka":"lossless audio","note":"Lossless compression shrinks size without discarding data."},"children":[{"name":"WAV","v":4,"meta":{"def":"A common uncompressed PCM container developed by Microsoft and IBM.","ex":"studio master files","aka":"Waveform Audio","note":"Classic WAV files are capped near 4 GB."}},{"name":"AIFF","v":4,"meta":{"def":"Apple's uncompressed PCM audio container format.","ex":"Mac studio files","aka":"Audio Interchange File Format","note":"The Apple counterpart to WAV."}},{"name":"FLAC","v":4,"meta":{"def":"A free open lossless codec compressing audio without quality loss.","ex":"hi-res download stores","aka":"Free Lossless Audio Codec","note":"Typically shrinks files by 40-60 percent."}},{"name":"ALAC","v":4,"meta":{"def":"Apple's lossless codec used across its ecosystem.","ex":"Apple Music lossless","aka":"Apple Lossless","note":"Open-sourced by Apple in 2011."}}]},{"name":"Lossy Codecs","v":6,"meta":{"def":"Formats discarding inaudible data to shrink file size.","ex":"MP3, AAC, Opus","aka":"lossy audio","note":"Rely on psychoacoustic masking models."},"children":[{"name":"MP3","v":4,"meta":{"def":"The ubiquitous lossy codec that popularised digital music.","ex":"128-320 kbps files","aka":"MPEG-1 Audio Layer III","note":"Developed at Fraunhofer, patents expired in 2017."}},{"name":"AAC","v":4,"meta":{"def":"A more efficient successor to MP3 used by Apple and YouTube.","ex":"iTunes and streaming","aka":"Advanced Audio Coding","note":"Generally better quality than MP3 at equal bitrate."}},{"name":"Ogg Vorbis","v":4,"meta":{"def":"A free open lossy codec unencumbered by patents.","ex":"Spotify streaming, games","aka":"Vorbis","note":"Long a favourite in open-source and game audio."}},{"name":"Opus","v":4,"meta":{"def":"A modern low-latency codec spanning speech to music.","ex":"Discord, WebRTC, YouTube","aka":"IETF Opus","note":"Excels across a very wide bitrate range."}}]},{"name":"High-Resolution & Specialty","v":5,"meta":{"def":"Formats aimed at fidelity beyond CD quality or niche uses.","ex":"DSD, MQA, hi-res PCM","aka":"hi-res audio","note":"Their audible benefit over CD is debated."},"children":[{"name":"DSD","v":4,"meta":{"def":"A 1-bit high-rate format used by Super Audio CD.","ex":"SACD releases","aka":"Direct Stream Digital","note":"Uses pulse-density modulation at 2.8 MHz and up."}},{"name":"MQA","v":4,"meta":{"def":"A proprietary format folding hi-res data into a smaller stream.","ex":"Tidal Masters (former)","aka":"Master Quality Authenticated","note":"Controversial; Tidal moved away from it."}},{"name":"Hi-Res PCM","v":4,"meta":{"def":"PCM audio at sample rates and depths above CD standard.","ex":"24-bit / 96 kHz files","aka":"high-resolution audio","note":"Marketed with a Hi-Res Audio logo."}}]},{"name":"Bitrate","v":4,"meta":{"def":"The data rate of an audio stream, trading size against quality.","ex":"320 kbps MP3","aka":"kbps","note":"Constant and variable bitrate modes exist."}}]},{"name":"Signal Processing & Effects","v":14,"meta":{"def":"Digital and analog processing that alters an audio signal's tone, dynamics or space.","ex":"EQ, compression, reverb, delay","aka":"audio effects, DSP","note":"The core toolkit of mixing and sound design."},"children":[{"name":"Equalisation","v":5,"meta":{"def":"Adjusting the balance of frequency bands in a signal.","ex":"cutting mud, boosting air","aka":"EQ, tone control","note":"The most-used tool in any mix."},"children":[{"name":"Parametric EQ","v":4,"meta":{"def":"An EQ with adjustable frequency, gain and bandwidth per band.","ex":"surgical mix cuts","aka":"para EQ","note":"Q controls the width of the affected band."}},{"name":"Shelving & High/Low-Pass","v":4,"meta":{"def":"Filters that boost or cut everything above or below a corner frequency.","ex":"low-cut to remove rumble","aka":"shelf, HPF, LPF","note":"High-pass filters clean up low-end clutter."}},{"name":"Graphic EQ","v":4,"meta":{"def":"A fixed-band EQ with a slider per frequency band.","ex":"live PA tuning","aka":"graphic equaliser","note":"The slider layout visually mirrors the curve."}}]},{"name":"Dynamics Processing","v":6,"meta":{"def":"Effects controlling the loudness range of a signal.","ex":"compressor, limiter, gate","aka":"dynamics","note":"Shapes punch, sustain and consistency."},"children":[{"name":"Compressor","v":4,"meta":{"def":"A processor that reduces gain above a threshold to even out dynamics.","ex":"vocal levelling","aka":"dynamic range compressor","note":"Ratio, attack and release shape its character."}},{"name":"Limiter","v":4,"meta":{"def":"A compressor with a very high ratio preventing peaks past a ceiling.","ex":"mastering brickwall limiter","aka":"brickwall limiter","note":"Ensures a signal never exceeds a set level."}},{"name":"Noise Gate","v":4,"meta":{"def":"A processor that mutes signal below a threshold to cut noise.","ex":"tightening a noisy guitar amp","aka":"gate","note":"Used to silence bleed between drum hits."}},{"name":"Sidechain","v":4,"meta":{"def":"Triggering one signal's dynamics from another's level.","ex":"kick ducking the bass","aka":"sidechain compression","note":"The pumping staple of EDM production."}},{"name":"Expander","v":4,"meta":{"def":"A processor that increases dynamic range by lowering quiet signals.","ex":"gentle noise reduction","aka":"downward expander","note":"A softer alternative to a hard gate."}}]},{"name":"Time-Based Effects","v":6,"meta":{"def":"Effects based on delaying and layering copies of a signal.","ex":"reverb, delay, chorus","aka":"spatial effects","note":"Create depth and a sense of space."},"children":[{"name":"Reverb","v":4,"meta":{"def":"The simulation of many reflections that place a sound in a space.","ex":"hall, plate, spring reverb","aka":"reverberation","note":"Plate and spring reverbs predate digital units."}},{"name":"Delay","v":4,"meta":{"def":"Repeating a signal after a set time, from slapback to long echoes.","ex":"tape echo, ping-pong delay","aka":"echo","note":"Feedback controls the number of repeats."}},{"name":"Chorus","v":4,"meta":{"def":"Thickening sound with slightly delayed, detuned copies.","ex":"80s clean guitar shimmer","aka":"ensemble effect","note":"Emulates several performers playing in unison."}},{"name":"Flanger","v":4,"meta":{"def":"A sweeping comb-filter effect from a short modulated delay.","ex":"jet-plane whoosh","aka":"flanging","note":"Named for pressing on a tape reel flange."}},{"name":"Phaser","v":4,"meta":{"def":"A swirling effect created by sweeping notches with all-pass filters.","ex":"funk guitar and Rhodes","aka":"phase shifter","note":"Uses phase shifting rather than delay."}}]},{"name":"Distortion & Saturation","v":4,"meta":{"def":"Effects that add harmonics by clipping or warming a signal.","ex":"fuzz, overdrive, tape saturation","aka":"harmonic distortion","note":"Adds grit, warmth and perceived loudness."},"children":[{"name":"Overdrive & Fuzz","v":4,"meta":{"def":"Guitar effects clipping the signal for grit and sustain.","ex":"Tube Screamer, Fuzz Face","aka":"distortion pedals","note":"Soft clipping overdrives; hard clipping fuzzes."}},{"name":"Saturation","v":4,"meta":{"def":"Gentle harmonic colouring emulating tape or tube warmth.","ex":"tape and valve saturation","aka":"harmonic excitation","note":"Adds glue and density to a mix."}}]},{"name":"Pitch & Spectral Effects","v":5,"meta":{"def":"Effects that manipulate pitch or the frequency spectrum directly.","ex":"pitch-shift, vocoder, autotune","aka":"spectral processing","note":"Often rely on FFT analysis and resynthesis."},"children":[{"name":"Pitch Shifting","v":4,"meta":{"def":"Raising or lowering pitch without changing duration.","ex":"harmoniser, octave effects","aka":"pitch transposition","note":"Formant-preserving modes avoid the chipmunk effect."}},{"name":"Auto-Tune","v":4,"meta":{"def":"Real-time pitch correction that snaps notes to a scale.","ex":"T-Pain vocal effect","aka":"pitch correction","note":"Extreme settings became a signature sound."}},{"name":"Vocoder","v":4,"meta":{"def":"Imposing a voice's spectral envelope onto a synth carrier.","ex":"robot-voice vocals","aka":"voice encoder","note":"Originated in 1930s telephone research."}},{"name":"Talk Box","v":4,"meta":{"def":"Routing an instrument through a tube in the mouth to shape it with speech.","ex":"Frampton, Bon Jovi","aka":"talkbox","note":"The mouth acts as a physical formant filter."}}]},{"name":"Convolution","v":4,"meta":{"def":"Applying the sonic fingerprint of a real space or device to a signal.","ex":"impulse-response reverb, cab sims","aka":"convolution processing","note":"Captures a space via an impulse response."}}]},{"name":"MIDI & Protocols","v":10,"meta":{"def":"Digital protocols that let instruments, computers and gear communicate.","ex":"MIDI, MPE, OSC","aka":"music control protocols","note":"MIDI 1.0 debuted in 1983 and endures today."},"children":[{"name":"MIDI Messages","v":6,"meta":{"def":"The event data MIDI sends to represent performance.","ex":"note, velocity, control change","aka":"MIDI data","note":"Compact byte messages rather than audio."},"children":[{"name":"Note On / Off","v":4,"meta":{"def":"Messages signalling the start and end of a played note.","ex":"key press and release","aka":"note events","note":"Each carries a note number from 0 to 127."}},{"name":"Velocity","v":4,"meta":{"def":"A value expressing how hard a note is struck.","ex":"soft vs hard piano hit","aka":"note velocity","note":"Ranges from 1 to 127, with 0 meaning note off."}},{"name":"Control Change (CC)","v":4,"meta":{"def":"Messages carrying continuous controller data like mod and volume.","ex":"CC1 mod wheel, CC7 volume","aka":"MIDI CC","note":"128 controller numbers are defined."}},{"name":"Pitch Bend","v":4,"meta":{"def":"A high-resolution message that bends note pitch smoothly.","ex":"pitch wheel expression","aka":"pitch wheel","note":"Uses 14-bit resolution for smooth glides."}},{"name":"Program Change","v":4,"meta":{"def":"A message selecting a patch or preset on an instrument.","ex":"switching synth sounds","aka":"patch change","note":"Selects among 128 program slots."}}]},{"name":"MIDI 2.0","v":4,"meta":{"def":"The 2020 revision adding higher resolution and two-way communication.","ex":"per-note controllers, 32-bit values","aka":"MIDI 2.0 spec","note":"Backward compatible with MIDI 1.0 gear."}},{"name":"MPE","v":4,"meta":{"def":"An extension giving each note independent pitch, pressure and timbre control.","ex":"ROLI Seaboard, LinnStrument","aka":"MIDI Polyphonic Expression","note":"Assigns each note its own MIDI channel."}},{"name":"MIDI Clock & Sync","v":4,"meta":{"def":"Timing messages that synchronise tempo across devices.","ex":"syncing a drum machine to a DAW","aka":"MIDI beat clock","note":"Sends 24 pulses per quarter note."}},{"name":"OSC","v":4,"meta":{"def":"A flexible network protocol for controlling music and media software.","ex":"TouchOSC, Max/MSP control","aka":"Open Sound Control","note":"Sends high-resolution data over networks."}},{"name":"MIDI Connections","v":4,"meta":{"def":"The physical and virtual links carrying MIDI data.","ex":"5-pin DIN, USB, Bluetooth MIDI","aka":"MIDI ports","note":"The original DIN plug has five pins."}},{"name":"General MIDI","v":4,"meta":{"def":"A standard mapping of program numbers to instrument sounds.","ex":"program 1 = piano","aka":"GM standard","note":"Ensures a MIDI file plays consistently across devices."}}]},{"name":"Immersive & Spatial Audio","v":10,"meta":{"def":"Techniques that reproduce sound across two or three dimensions of space.","ex":"stereo, surround, Atmos","aka":"3D audio","note":"Ranges from two speakers to object-based systems."},"children":[{"name":"Mono","v":4,"meta":{"def":"Single-channel audio reproduced identically from all speakers.","ex":"AM radio, early records","aka":"monophonic","note":"Guarantees consistent playback on any system."}},{"name":"Stereo","v":4,"meta":{"def":"Two-channel audio creating a left-to-right sound stage.","ex":"standard music playback","aka":"stereophonic","note":"Became the consumer standard in the 1960s."}},{"name":"Quadraphonic","v":4,"meta":{"def":"An early four-channel surround format from the 1970s.","ex":"quad LPs","aka":"quad sound","note":"Failed commercially due to incompatible standards."}},{"name":"Surround 5.1 / 7.1","v":4,"meta":{"def":"Multichannel formats placing speakers around the listener plus a subwoofer.","ex":"home cinema systems","aka":"surround sound","note":"The .1 denotes the low-frequency effects channel."}},{"name":"Dolby Atmos","v":4,"meta":{"def":"An object-based format placing sounds anywhere in 3D space including overhead.","ex":"Apple Music spatial audio","aka":"Atmos","note":"Renders objects to whatever speaker layout is present."}},{"name":"Ambisonics","v":4,"meta":{"def":"A full-sphere surround technique encoding a whole sound field.","ex":"VR and 360 video audio","aka":"B-format","note":"Decodable to any speaker array after capture."}},{"name":"Binaural Audio","v":4,"meta":{"def":"Two-channel audio recorded or rendered for lifelike headphone 3D.","ex":"dummy-head recordings, ASMR","aka":"binaural sound","note":"Uses HRTF cues for over-headphone immersion."}},{"name":"Wave Field Synthesis","v":4,"meta":{"def":"Recreating a physical sound field with a dense array of speakers.","ex":"research and installation audio","aka":"WFS","note":"Sound localisation holds regardless of listener position."}}]},{"name":"Playback & Transducers","v":10,"meta":{"def":"Devices that convert between electrical signals and sound or motion.","ex":"speakers, microphones, styli","aka":"audio transducers","note":"A transducer changes energy from one form to another."},"children":[{"name":"Loudspeaker","v":4,"meta":{"def":"A transducer converting an electrical signal into audible sound waves.","ex":"woofer, tweeter, driver","aka":"speaker","note":"Most use a voice coil moving a cone in a magnetic field."}},{"name":"Headphones","v":4,"meta":{"def":"Small transducers worn to deliver sound directly to each ear.","ex":"open-back, closed-back, IEM","aka":"cans, earphones","note":"Open-back designs image better but leak sound."}},{"name":"Microphone","v":6,"meta":{"def":"A transducer converting sound waves into an electrical signal.","ex":"dynamic, condenser, ribbon","aka":"mic","note":"Polar patterns set which directions it captures."},"children":[{"name":"Dynamic Microphone","v":4,"meta":{"def":"A rugged mic using a moving coil in a magnetic field.","ex":"Shure SM57 / SM58","aka":"moving-coil mic","note":"Handles high sound levels and rough stage use."}},{"name":"Condenser Microphone","v":4,"meta":{"def":"A sensitive mic using a charged capacitor diaphragm.","ex":"studio vocal mics","aka":"capacitor mic","note":"Needs 48V phantom power to operate."}},{"name":"Polar Patterns","v":4,"meta":{"def":"The directional sensitivity shapes of a microphone.","ex":"cardioid, omni, figure-8","aka":"pickup patterns","note":"Cardioid rejects sound from the rear."}}]},{"name":"Amplifier","v":4,"meta":{"def":"A device boosting a low-level signal to drive speakers.","ex":"tube, solid-state, class-D","aka":"power amp","note":"Class-D amps are highly efficient and compact."}},{"name":"Turntable & Stylus","v":4,"meta":{"def":"A device tracing a record groove with a needle to recover sound.","ex":"vinyl playback","aka":"record player, cartridge","note":"The stylus vibration is turned to voltage by a cartridge."}},{"name":"Tape Head","v":4,"meta":{"def":"An electromagnet reading or writing audio on magnetic tape.","ex":"reel-to-reel, cassette","aka":"magnetic head","note":"Record, play and erase heads perform distinct roles."}},{"name":"DAC (Playback)","v":4,"meta":{"def":"A converter turning digital audio into an analog signal for playback.","ex":"USB DAC, phone DAC","aka":"digital-to-analog converter","note":"The last digital step before amplification."}}]},{"name":"Audio & Music AI","v":10,"meta":{"def":"Machine-learning techniques applied to analysing and generating audio.","ex":"stem splitting, generative music, MIR","aka":"music AI","note":"Deep learning transformed audio tasks in the 2020s."},"children":[{"name":"Source Separation","v":4,"meta":{"def":"Splitting a mix into isolated stems like vocals, drums and bass.","ex":"Demucs, Spleeter","aka":"stem splitting","note":"Enables remixing and karaoke from finished tracks."}},{"name":"Generative Music AI","v":4,"meta":{"def":"Models that compose or produce new music from prompts or data.","ex":"Suno, Udio, MusicGen","aka":"AI music generation","note":"Raised heated debates over training-data rights."}},{"name":"Automatic Transcription","v":4,"meta":{"def":"Converting audio into notation or MIDI automatically.","ex":"audio-to-MIDI, chord detection","aka":"AMT","note":"Polyphonic piano transcription is a benchmark task."}},{"name":"AI Mastering","v":4,"meta":{"def":"Automated services that master a mix using trained references.","ex":"LANDR, iZotope Ozone assistant","aka":"automatic mastering","note":"Analyses a track then applies EQ and limiting."}},{"name":"Voice Cloning & Deepfakes","v":4,"meta":{"def":"Synthesising a specific person's singing or speaking voice.","ex":"AI cover songs","aka":"voice deepfake, voice conversion","note":"Sparked major legal and ethical concerns for artists."}},{"name":"Music Information Retrieval","v":4,"meta":{"def":"Extracting features like tempo, key and mood from audio.","ex":"beat tracking, genre tagging","aka":"MIR","note":"Powers recommendation and auto-tagging engines."}},{"name":"Audio Fingerprinting","v":4,"meta":{"def":"Identifying a recording from a short acoustic signature.","ex":"Shazam song ID","aka":"acoustic fingerprinting","note":"Matches a robust hash against a huge database."}},{"name":"Neural Audio Codecs","v":4,"meta":{"def":"Codecs using neural networks to compress audio at very low bitrates.","ex":"SoundStream, EnCodec","aka":"learned audio codecs","note":"Also serve as tokenisers for generative models."}}]}]},{"name":"Genres & Styles","type":"genres","v":26,"children":[{"name":"Classical & Art Music","v":14,"meta":{"def":"The Western notated art-music tradition spanning a millennium of composed concert works.","ex":"Bach, Mozart, Beethoven, Stravinsky","region":"Europe","era":"9th century onward","note":"Distinguished by written scores and institutional performance practice."},"children":[{"name":"Medieval","v":10,"meta":{"def":"Sacred and secular music of the Middle Ages built on modal chant and early polyphony.","ex":"Hildegard von Bingen, Perotin, Guillaume de Machaut","region":"Europe","era":"500-1400","note":"Notation gradually evolved from neumes to measured rhythm."},"children":[{"name":"Gregorian Chant","v":4,"meta":{"def":"Monophonic sacred plainsong sung in free-flowing Latin liturgy.","ex":"Liber Usualis chants, Benedictine monastic recordings","region":"Rome / Frankish Empire","era":"9th-10th century","note":"Named for Pope Gregory I though largely codified later."}},{"name":"Ars Nova","v":4,"meta":{"def":"14th-century French style introducing complex rhythm and isorhythmic motets.","ex":"Machaut Messe de Nostre Dame, Philippe de Vitry","region":"France","era":"1310s-1370s","note":"Named from a treatise contrasting the older Ars Antiqua."}},{"name":"Trouvere & Troubadour Song","v":4,"meta":{"def":"Courtly secular monody of poet-composers singing of chivalric love.","ex":"Bernart de Ventadorn, Adam de la Halle","region":"Occitania / Northern France","era":"1100-1300","note":"Troubadours sang in Occitan, trouveres in Old French."}}]},{"name":"Renaissance","v":10,"meta":{"def":"Rich vocal polyphony emphasizing smooth counterpoint and text expression.","ex":"Palestrina, Josquin des Prez, Byrd","region":"Europe","era":"1400-1600","note":"The printing press spread part-books across the continent."},"children":[{"name":"Franco-Flemish Polyphony","v":4,"meta":{"def":"Dense interweaving vocal lines that dominated European church music.","ex":"Josquin, Ockeghem, Lassus","region":"Low Countries","era":"1450-1550","note":"Its composers were exported to courts across Europe."}},{"name":"Madrigal","v":4,"meta":{"def":"Secular part-song setting poetry with vivid word-painting.","ex":"Monteverdi, Gesualdo, Weelkes","region":"Italy / England","era":"1530-1620","note":"Gesualdo's chromaticism was centuries ahead of its time."}},{"name":"Sacred Motet & Mass","v":4,"meta":{"def":"Latin liturgical polyphony refined for clarity after Counter-Reformation reforms.","ex":"Palestrina Missa Papae Marcelli, Tallis Spem in alium","region":"Rome / England","era":"1550-1600","note":"Tallis's 40-voice motet is a polyphonic marvel."}}]},{"name":"Baroque","v":10,"meta":{"def":"Ornate tonal music built on basso continuo, contrast and dramatic affect.","ex":"Bach, Handel, Vivaldi","region":"Europe","era":"1600-1750","note":"The era that established functional harmony and the concerto."},"children":[{"name":"Concerto Grosso","v":4,"meta":{"def":"Interplay between a small solo group and full string orchestra.","ex":"Corelli, Handel Op.6, Bach Brandenburgs","region":"Italy","era":"1680-1750","note":"The concertino trades phrases with the ripieno tutti."}},{"name":"Fugue & Counterpoint","v":4,"meta":{"def":"Rigorous imitative writing where a theme is layered across voices.","ex":"Bach Art of Fugue, Well-Tempered Clavier","region":"Germany","era":"1700-1750","note":"Bach elevated the fugue to its intellectual peak."}},{"name":"Baroque Opera & Oratorio","v":4,"meta":{"def":"Grand sung drama with recitative, da capo arias and choruses.","ex":"Handel Messiah, Monteverdi Orfeo, Purcell Dido","region":"Italy / England","era":"1607-1750","note":"Monteverdi's Orfeo is often called the first great opera."}}]},{"name":"Classical Period","v":8,"meta":{"def":"Balanced, elegant music of clear phrasing, sonata form and the symphony.","ex":"Haydn, Mozart, early Beethoven","region":"Vienna / Europe","era":"1750-1820","note":"Haydn is nicknamed the father of both symphony and string quartet."},"children":[{"name":"Symphony","v":4,"meta":{"def":"Multi-movement orchestral work built on sonata-allegro architecture.","ex":"Mozart 40, Haydn London Symphonies","region":"Vienna","era":"1750-1820","note":"Standardized to four movements by Haydn."}},{"name":"String Quartet","v":4,"meta":{"def":"Intimate chamber conversation for two violins, viola and cello.","ex":"Haydn Op.76, Mozart Haydn Quartets","region":"Vienna","era":"1760-1820","note":"Considered the ultimate test of a composer's craft."}}]},{"name":"Romantic","v":10,"meta":{"def":"Emotionally expansive music of soaring melody, rich chromatic harmony and nationalism.","ex":"Chopin, Wagner, Tchaikovsky, Brahms","region":"Europe","era":"1800-1910","note":"The orchestra swelled to enormous size by the century's end."},"children":[{"name":"Character Piece","v":4,"meta":{"def":"Short evocative solo-piano miniature capturing a mood or scene.","ex":"Chopin Nocturnes, Schumann Kinderszenen","region":"Europe","era":"1820-1890","note":"Titles like Nocturne and Impromptu suggested poetic atmosphere."}},{"name":"Symphonic Poem","v":4,"meta":{"def":"Single-movement orchestral work depicting a story, poem or image.","ex":"Liszt Les Preludes, Strauss Also sprach Zarathustra","region":"Germany / Hungary","era":"1848-1910","note":"Liszt invented the form as program music."}},{"name":"Nationalist School","v":4,"meta":{"def":"Art music infused with folk melodies and native identity.","ex":"Dvorak, Smetana, Mussorgsky, Grieg","region":"Bohemia / Russia / Scandinavia","era":"1860-1910","note":"The Russian Five championed a distinctly national sound."}}]},{"name":"Opera","v":12,"meta":{"def":"Staged drama sung throughout with orchestra, spanning many national styles.","ex":"Verdi, Puccini, Mozart, Wagner","region":"Italy / Germany / France","era":"1600 onward","note":"A total artwork uniting music, theatre and design."},"children":[{"name":"Opera Seria","v":4,"meta":{"def":"Serious 18th-century opera on heroic or mythological subjects.","ex":"Handel Giulio Cesare, Gluck Orfeo","region":"Italy","era":"1700-1800","note":"Built around virtuoso castrato arias."}},{"name":"Bel Canto","v":4,"meta":{"def":"Early-Romantic Italian opera prizing beautiful, agile vocal line.","ex":"Bellini Norma, Donizetti, Rossini","region":"Italy","era":"1810-1840","note":"Demands florid coloratura and long legato."}},{"name":"Verismo","v":4,"meta":{"def":"Gritty realist Italian opera of everyday passion and violence.","ex":"Puccini Tosca, Mascagni Cavalleria Rusticana","region":"Italy","era":"1890-1920","note":"Brought working-class characters to the operatic stage."}}]},{"name":"Modernism","v":10,"meta":{"def":"Early-20th-century break from tonality through dissonance, rhythm and new systems.","ex":"Stravinsky, Schoenberg, Bartok","region":"Europe","era":"1900-1945","note":"The Rite of Spring premiere caused a legendary riot."},"children":[{"name":"Impressionism","v":4,"meta":{"def":"Hazy, colour-driven music of whole-tone scales and blurred harmony.","ex":"Debussy Prelude a l'apres-midi, Ravel","region":"France","era":"1890-1920","note":"Debussy disliked the borrowed painting term."}},{"name":"Serialism","v":4,"meta":{"def":"Music organized by ordered rows of all twelve chromatic pitches.","ex":"Schoenberg, Webern, Berg","region":"Vienna","era":"1920s-1950s","note":"The Second Viennese School dismantled tonal hierarchy."}},{"name":"Neoclassicism","v":4,"meta":{"def":"Modern reworking of Classical clarity, balance and forms.","ex":"Stravinsky Pulcinella, Prokofiev Classical Symphony","region":"Europe","era":"1920-1950","note":"A reaction against Romantic excess."}}]},{"name":"Contemporary & Minimalism","v":12,"meta":{"def":"Post-war experimental and process-based art music of the late 20th century onward.","ex":"Reich, Glass, Cage, Ligeti","region":"USA / Europe","era":"1950 onward","note":"Ranges from silence to repetitive pulse to electronics."},"children":[{"name":"Minimalism","v":4,"meta":{"def":"Hypnotic music built from repeating cells and gradual phase-shifting.","ex":"Steve Reich, Philip Glass, Terry Riley In C","region":"New York","era":"1960s-1980s","note":"Riley's In C launched the movement in 1964."}},{"name":"Aleatoric Music","v":4,"meta":{"def":"Composition leaving elements to chance or performer choice.","ex":"John Cage 4'33, Lutoslawski","region":"USA / Poland","era":"1950s-1970s","note":"Cage used the I Ching to determine notes."}},{"name":"Spectralism","v":4,"meta":{"def":"Music derived from the acoustic overtone spectrum of sound itself.","ex":"Gerard Grisey, Tristan Murail","region":"France","era":"1970s-1990s","note":"Scores are shaped by computer sound analysis."}}]}]},{"name":"Jazz","v":14,"meta":{"def":"African-American art form built on improvisation, swing feel and blue harmony.","ex":"Louis Armstrong, Miles Davis, John Coltrane","region":"New Orleans / USA","era":"1900 onward","note":"Often called America's classical music."},"children":[{"name":"Early Jazz","v":8,"meta":{"def":"The first hot, collectively improvised jazz of the 1910s-20s.","ex":"King Oliver, Jelly Roll Morton","region":"New Orleans","era":"1910s-1920s","note":"Grew from ragtime, blues and brass-band marches."},"children":[{"name":"Dixieland","v":4,"meta":{"def":"Collectively improvised front-line polyphony over a two-beat rhythm.","ex":"Original Dixieland Jazz Band, Louis Armstrong Hot Five","region":"New Orleans","era":"1910s-1920s","note":"The first jazz record was cut in 1917."}},{"name":"Ragtime","v":4,"meta":{"def":"Syncopated composed piano music that prefigured jazz.","ex":"Scott Joplin Maple Leaf Rag","region":"Missouri","era":"1895-1918","note":"Joplin sold hundreds of thousands of sheet copies."}}]},{"name":"Swing","v":5,"meta":{"def":"Danceable big-band jazz with a driving four-beat and riff-based arrangements.","ex":"Duke Ellington, Count Basie, Benny Goodman","region":"USA","era":"1930s-1940s","note":"The dominant popular music of the Swing Era."}},{"name":"Bebop","v":5,"meta":{"def":"Fast, harmonically intricate small-group jazz for listening, not dancing.","ex":"Charlie Parker, Dizzy Gillespie, Bud Powell","region":"New York","era":"1940s","note":"Born in late-night Harlem jam sessions."}},{"name":"Hard Bop","v":5,"meta":{"def":"Soulful, blues- and gospel-drenched extension of bebop.","ex":"Art Blakey, Horace Silver, Cannonball Adderley","region":"USA East Coast","era":"1950s-1960s","note":"The Blue Note label defined its gritty sound."}},{"name":"Cool Jazz","v":5,"meta":{"def":"Relaxed, restrained jazz with soft timbres and arranged textures.","ex":"Miles Davis Birth of the Cool, Dave Brubeck, Chet Baker","region":"USA West Coast","era":"1949-1960","note":"West Coast players gave it a laid-back polish."}},{"name":"Modal Jazz","v":5,"meta":{"def":"Improvisation over slow-moving scales rather than fast chord changes.","ex":"Miles Davis Kind of Blue, John Coltrane","region":"USA","era":"1958-1965","note":"Kind of Blue is the best-selling jazz album ever."}},{"name":"Free Jazz","v":5,"meta":{"def":"Radical improvisation abandoning fixed key, meter and chord structure.","ex":"Ornette Coleman, Albert Ayler, late Coltrane","region":"USA","era":"1959-1970s","note":"Coleman's album Free Jazz named the movement."}},{"name":"Jazz Fusion","v":6,"meta":{"def":"Jazz improvisation fused with rock rhythm, funk and electric instruments.","ex":"Miles Davis Bitches Brew, Weather Report, Mahavishnu Orchestra","region":"USA","era":"1969-1980s","note":"Electric keyboards and heavy backbeats defined it."}},{"name":"Latin Jazz","v":6,"meta":{"def":"Jazz harmony wed to Afro-Cuban and Brazilian clave rhythms.","ex":"Tito Puente, Dizzy Gillespie, Cal Tjader","region":"USA / Cuba","era":"1940s onward","note":"Chano Pozo brought conga drumming to bebop."}},{"name":"Gypsy Jazz","v":5,"meta":{"def":"Acoustic string-swing built on rapid arpeggios and la pompe rhythm guitar.","ex":"Django Reinhardt, Stephane Grappelli","region":"France","era":"1930s onward","note":"Django played with only two working fretting fingers."}},{"name":"Acid Jazz","v":5,"meta":{"def":"Dancefloor blend of jazz-funk, soul and hip-hop grooves.","ex":"Jamiroquai, Brand New Heavies, Incognito","region":"UK","era":"late 1980s-1990s","note":"Emerged from London's rare-groove club scene."}},{"name":"Nu Jazz","v":5,"meta":{"def":"Jazz merged with electronic production, broken beats and downtempo textures.","ex":"Bugge Wesseltoft, The Cinematic Orchestra, Nils Petter Molvaer","region":"Europe","era":"late 1990s-2000s","note":"Also called electro-jazz or future jazz."}}]},{"name":"Blues","v":10,"meta":{"def":"African-American folk form built on the twelve-bar form, blue notes and call-and-response.","ex":"Robert Johnson, Muddy Waters, B.B. King","region":"Mississippi Delta","era":"1900 onward","note":"The root from which jazz, rock and R&B all grew."},"children":[{"name":"Delta Blues","v":5,"meta":{"def":"Raw, acoustic solo blues with slide guitar and haunted vocals.","ex":"Robert Johnson, Son House, Charley Patton","region":"Mississippi Delta","era":"1920s-1930s","note":"Johnson's crossroads legend became blues mythology."}},{"name":"Chicago Blues","v":5,"meta":{"def":"Amplified, band-driven urban blues with harmonica and electric guitar.","ex":"Muddy Waters, Howlin' Wolf, Little Walter","region":"Chicago","era":"1940s-1950s","note":"Carried north by the Great Migration."}},{"name":"Electric Blues","v":5,"meta":{"def":"Blues built around the amplified guitar as lead voice.","ex":"B.B. King, Buddy Guy, Albert King","region":"USA","era":"1950s onward","note":"Directly seeded British and American blues-rock."}},{"name":"Jump Blues","v":5,"meta":{"def":"Uptempo, horn-driven blues that swings toward early rock and roll.","ex":"Louis Jordan, Big Joe Turner","region":"USA","era":"1940s","note":"A key bridge from swing to rhythm and blues."}},{"name":"Piedmont Blues","v":5,"meta":{"def":"Intricate ragtime-influenced fingerpicked East-Coast blues.","ex":"Blind Blake, Reverend Gary Davis, Blind Boy Fuller","region":"Southeast USA","era":"1920s-1940s","note":"The thumb keeps an alternating bass like a piano."}},{"name":"Texas Blues","v":5,"meta":{"def":"Swinging, guitar-forward blues with jazzy phrasing and stinging leads.","ex":"Blind Lemon Jefferson, T-Bone Walker, Stevie Ray Vaughan","region":"Texas","era":"1920s onward","note":"T-Bone Walker pioneered electric lead guitar."}}]},{"name":"Folk","v":10,"meta":{"def":"Traditional and acoustic story-song music passed through communities and revivals.","ex":"Woody Guthrie, Bob Dylan, Joan Baez","region":"Global","era":"Traditional onward","note":"Rooted in oral tradition long before recording."},"children":[{"name":"Traditional Folk","v":5,"meta":{"def":"Anonymous inherited ballads and work songs of a people or region.","ex":"Child Ballads, Appalachian folk songs","region":"Global","era":"Pre-20th century","note":"Collected by folklorists like Cecil Sharp and Alan Lomax."}},{"name":"Folk Revival","v":5,"meta":{"def":"Mid-century urban rediscovery of traditional song, often politically charged.","ex":"Pete Seeger, The Kingston Trio, early Dylan","region":"USA / UK","era":"1950s-1960s","note":"Centered on Greenwich Village coffeehouses."}},{"name":"Contemporary Folk","v":5,"meta":{"def":"Original singer-songwriter material rooted in acoustic folk idiom.","ex":"Joni Mitchell, Nick Drake, Fairport Convention","region":"USA / UK","era":"1960s onward","note":"Personal lyricism replaced anonymous tradition."}},{"name":"Anti-Folk","v":5,"meta":{"def":"Ironic, lo-fi, rough-edged reaction against earnest folk seriousness.","ex":"The Moldy Peaches, Kimya Dawson, Beck","region":"New York","era":"1980s-2000s","note":"Grew from Manhattan's antihoot open mics."}},{"name":"Freak Folk","v":5,"meta":{"def":"Psychedelic, whimsical, experimental folk with unconventional textures.","ex":"Devendra Banhart, Joanna Newsom, Animal Collective","region":"USA","era":"2000s","note":"Also tagged New Weird America."}}]},{"name":"Country","v":12,"meta":{"def":"American roots music of rural storytelling, twang and steel guitar.","ex":"Hank Williams, Johnny Cash, Dolly Parton","region":"Southern USA","era":"1920s onward","note":"Grew from Appalachian folk, blues and gospel."},"children":[{"name":"Honky-Tonk","v":5,"meta":{"def":"Barroom country of heartache, drinking and pedal steel.","ex":"Hank Williams, Lefty Frizzell, George Jones","region":"Texas / Southern USA","era":"1940s-1950s","note":"Named for the rowdy dance halls it filled."}},{"name":"Bluegrass","v":6,"meta":{"def":"Fast acoustic string-band music with high harmony and virtuoso banjo.","ex":"Bill Monroe, Flatt & Scruggs, Ralph Stanley","region":"Kentucky / Appalachia","era":"1940s onward","note":"Scruggs's three-finger banjo roll is its signature."}},{"name":"Outlaw Country","v":5,"meta":{"def":"Gritty, self-produced country rebelling against the polished Nashville machine.","ex":"Willie Nelson, Waylon Jennings, Merle Haggard","region":"Texas / Nashville","era":"1970s","note":"Artists demanded creative control from labels."}},{"name":"Bakersfield Sound","v":5,"meta":{"def":"Twangy, electric, honky-tonk-rooted country reacting against slick Nashville.","ex":"Buck Owens, Merle Haggard","region":"Bakersfield, California","era":"1950s-1960s","note":"Built on the bright bite of the Telecaster guitar."}},{"name":"Nashville Sound","v":5,"meta":{"def":"Smooth, pop-oriented country with strings and background choirs.","ex":"Patsy Cline, Jim Reeves, Chet Atkins productions","region":"Nashville","era":"1957-1970s","note":"Producers dropped fiddle and steel for crossover appeal."}},{"name":"Alt-Country","v":5,"meta":{"def":"Country crossed with punk and indie grit, outside the mainstream.","ex":"Uncle Tupelo, Wilco, Ryan Adams","region":"USA","era":"1990s onward","note":"The magazine No Depression named the scene."}},{"name":"Americana","v":5,"meta":{"def":"Rootsy blend of country, folk, blues and rock with organic instrumentation.","ex":"Emmylou Harris, Jason Isbell, The Avett Brothers","region":"USA","era":"1990s onward","note":"Has its own dedicated radio chart and awards."}},{"name":"Bro-Country","v":5,"meta":{"def":"Party-anthem country about trucks, girls and beer with hip-hop-tinged beats.","ex":"Florida Georgia Line, Luke Bryan, Jason Aldean","region":"Nashville","era":"2010s","note":"Dominated country radio and drew heavy debate."}}]},{"name":"Rock","v":16,"meta":{"def":"Guitar-driven popular music built on backbeat, riffs and youthful energy.","ex":"The Beatles, Led Zeppelin, Nirvana","region":"USA / UK","era":"1950s onward","note":"Grew from rock and roll's fusion of blues and country."},"children":[{"name":"Rock & Roll","v":5,"meta":{"def":"The original 1950s upbeat fusion of R&B, country and boogie.","ex":"Chuck Berry, Little Richard, Elvis Presley","region":"USA","era":"1950s","note":"Chuck Berry's guitar riffs wrote the vocabulary."}},{"name":"Classic Rock","v":5,"meta":{"def":"Melodic guitar-band rock of the golden album-radio era.","ex":"The Rolling Stones, The Who, Fleetwood Mac","region":"USA / UK","era":"1965-1980","note":"Defined by FM album-oriented radio."}},{"name":"Hard Rock","v":5,"meta":{"def":"Loud, aggressive, riff-heavy rock with distorted power chords.","ex":"Led Zeppelin, Deep Purple, AC/DC","region":"UK / USA","era":"late 1960s-1970s","note":"The gateway between blues-rock and heavy metal."}},{"name":"Psychedelic Rock","v":5,"meta":{"def":"Trippy, effects-laden rock evoking mind-altering experiences.","ex":"Jimi Hendrix, Pink Floyd, The 13th Floor Elevators","region":"USA / UK","era":"1966-1970","note":"Studio effects mimicked hallucinogenic states."}},{"name":"Progressive Rock","v":5,"meta":{"def":"Ambitious, complex rock with long suites and classical borrowings.","ex":"Yes, King Crimson, Genesis, Rush","region":"UK","era":"1970s","note":"Concept albums and odd meters were badges of honor."}},{"name":"Garage Rock","v":5,"meta":{"def":"Raw, simple, energetic amateur rock with a fuzzy edge.","ex":"The Sonics, The Stooges, The White Stripes","region":"USA","era":"1960s / revived 2000s","note":"Named for suburban bands rehearsing in garages."}},{"name":"Surf Rock","v":5,"meta":{"def":"Reverb-drenched instrumental rock evoking beaches and waves.","ex":"Dick Dale, The Ventures, The Beach Boys","region":"California","era":"early 1960s","note":"Dick Dale's tremolo picking defined the tone."}},{"name":"Glam Rock","v":5,"meta":{"def":"Flamboyant, theatrical rock of glitter, androgyny and stomping beats.","ex":"David Bowie, T. Rex, Roxy Music","region":"UK","era":"early 1970s","note":"Bowie's Ziggy Stardust was its alien avatar."}},{"name":"Southern Rock","v":5,"meta":{"def":"Blues- and country-tinged hard rock with twin lead guitars.","ex":"Lynyrd Skynyrd, The Allman Brothers Band","region":"Southern USA","era":"1970s","note":"The Allmans pioneered extended jam solos."}},{"name":"Punk Rock","v":12,"meta":{"def":"Fast, loud, stripped-down rock built on rebellion and DIY ethos.","ex":"Ramones, Sex Pistols, The Clash","region":"USA / UK","era":"1976 onward","note":"Three chords and attitude over technique."},"children":[{"name":"Hardcore Punk","v":5,"meta":{"def":"Faster, harder, more abrasive punk with shouted vocals.","ex":"Black Flag, Minor Threat, Bad Brains","region":"USA","era":"1980s","note":"Spawned the straight-edge subculture."}},{"name":"Post-Punk","v":5,"meta":{"def":"Angular, experimental, moody offshoot expanding punk's palette.","ex":"Joy Division, Gang of Four, Siouxsie and the Banshees","region":"UK","era":"late 1970s-1980s","note":"Traded aggression for atmosphere and art."}},{"name":"Pop-Punk","v":5,"meta":{"def":"Catchy, melodic punk with big hooks and teenage themes.","ex":"Green Day, Blink-182, The Offspring","region":"USA","era":"1990s-2000s","note":"Brought punk energy to mainstream radio."}},{"name":"Emo","v":5,"meta":{"def":"Confessional, emotionally raw punk-derived rock about heartbreak.","ex":"Sunny Day Real Estate, My Chemical Romance, Dashboard Confessional","region":"USA","era":"1990s-2000s","note":"Short for emotional hardcore."}},{"name":"Screamo","v":5,"meta":{"def":"Chaotic, dissonant emo with screamed vocals and sudden dynamics.","ex":"Orchid, Saetia, City of Caterpillar","region":"USA","era":"1990s-2000s","note":"Also called skramz by its underground scene."}},{"name":"Ska Punk","v":5,"meta":{"def":"Upbeat fusion of punk energy with ska horns and offbeat guitar.","ex":"Operation Ivy, Rancid, Reel Big Fish","region":"USA","era":"1990s","note":"Powered the third-wave ska revival."}}]},{"name":"Alternative Rock","v":10,"meta":{"def":"Umbrella for guitar bands outside the mainstream that later crossed over.","ex":"R.E.M., Radiohead, Pixies","region":"USA / UK","era":"1980s onward","note":"College radio was its original launchpad."},"children":[{"name":"Grunge","v":5,"meta":{"def":"Sludgy, angst-ridden fusion of punk and heavy metal with raw vocals.","ex":"Nirvana, Pearl Jam, Soundgarden","region":"Seattle","era":"early 1990s","note":"Nevermind toppled hair metal from the charts."}},{"name":"Shoegaze","v":5,"meta":{"def":"Dreamy walls of guitar noise burying vocals in reverb and distortion.","ex":"My Bloody Valentine, Slowdive, Ride","region":"UK","era":"late 1980s-1990s","note":"Named for musicians staring at effect pedals."}},{"name":"Britpop","v":5,"meta":{"def":"Melodic, distinctly British guitar-pop celebrating national identity.","ex":"Oasis, Blur, Pulp","region":"UK","era":"1990s","note":"The Blur-versus-Oasis chart battle gripped Britain."}},{"name":"Indie Rock","v":5,"meta":{"def":"Independent-label guitar rock prizing authenticity over polish.","ex":"Pavement, Arcade Fire, The Strokes","region":"USA / UK","era":"1980s onward","note":"Defined as much by ethos as by sound."}},{"name":"Math Rock","v":5,"meta":{"def":"Angular rock built on complex time signatures and intricate riffs.","ex":"Don Caballero, Battles, American Football","region":"USA / Japan","era":"1990s onward","note":"Odd meters like 7/8 are the norm."}}]},{"name":"Post-Rock","v":5,"meta":{"def":"Instrumental rock building slow, cinematic crescendos from texture over riff.","ex":"Godspeed You! Black Emperor, Explosions in the Sky, Mogwai","region":"UK / Canada / USA","era":"1990s onward","note":"Guitars are used for timbre rather than chords."}},{"name":"Krautrock","v":5,"meta":{"def":"Hypnotic, motorik German experimental rock blending electronics and repetition.","ex":"Can, Neu!, Kraftwerk, Faust","region":"Germany","era":"1970s","note":"Its steady motorik beat shaped electronic music."}},{"name":"Art Rock","v":5,"meta":{"def":"Experimental, avant-garde-influenced rock with conceptual ambition.","ex":"Velvet Underground, Talking Heads, Brian Eno","region":"USA / UK","era":"1970s onward","note":"Often overlaps with progressive and glam."}}]},{"name":"Metal","v":16,"meta":{"def":"Heavy, distorted, powerful rock offshoot built on riffs, volume and intensity.","ex":"Black Sabbath, Metallica, Iron Maiden","region":"UK / USA","era":"1970 onward","note":"Black Sabbath is widely credited as the origin."},"children":[{"name":"Heavy Metal","v":5,"meta":{"def":"The foundational form of loud, riff-driven metal with soaring vocals.","ex":"Black Sabbath, Judas Priest, Iron Maiden","region":"UK","era":"1970s-1980s","note":"The NWOBHM movement revitalized it around 1980."}},{"name":"Thrash Metal","v":5,"meta":{"def":"Fast, aggressive metal with tight palm-muted riffing and speed.","ex":"Metallica, Slayer, Megadeth, Anthrax","region":"USA","era":"1980s","note":"The Big Four defined the Bay Area scene."}},{"name":"Death Metal","v":6,"meta":{"def":"Brutal, technical metal with growled vocals and blast beats.","ex":"Death, Cannibal Corpse, Morbid Angel","region":"Florida / Sweden","era":"late 1980s onward","note":"The Gothenburg scene birthed a melodic branch."}},{"name":"Black Metal","v":6,"meta":{"def":"Raw, atmospheric, tremolo-picked metal with shrieked vocals and dark themes.","ex":"Mayhem, Burzum, Emperor, Darkthrone","region":"Norway","era":"early 1990s","note":"The Norwegian second wave was infamously extreme."}},{"name":"Doom Metal","v":5,"meta":{"def":"Slow, crushing, heavy metal steeped in dread and despair.","ex":"Candlemass, Saint Vitus, Electric Wizard","region":"UK / USA","era":"1980s onward","note":"Directly descended from early Black Sabbath."}},{"name":"Power Metal","v":5,"meta":{"def":"Fast, melodic, uplifting metal with fantasy themes and operatic vocals.","ex":"Helloween, Blind Guardian, DragonForce","region":"Germany / Europe","era":"late 1980s onward","note":"Twin-guitar harmonies and galloping drums abound."}},{"name":"Progressive Metal","v":5,"meta":{"def":"Technically complex metal with shifting meters and long compositions.","ex":"Dream Theater, Tool, Opeth","region":"USA / Sweden","era":"late 1980s onward","note":"Combines metal power with prog-rock intricacy."}},{"name":"Nu Metal","v":5,"meta":{"def":"Groove-based metal fused with hip-hop, funk and downtuned riffs.","ex":"Korn, Slipknot, Limp Bizkit","region":"USA","era":"late 1990s-2000s","note":"Seven-string guitars gave it a heavy low end."}},{"name":"Metalcore","v":5,"meta":{"def":"Fusion of hardcore punk and metal with breakdowns and screamed-sung vocals.","ex":"Killswitch Engage, As I Lay Dying, Converge","region":"USA","era":"late 1990s-2000s","note":"The breakdown mosh section is its trademark."}},{"name":"Deathcore","v":5,"meta":{"def":"Blend of death metal brutality and metalcore breakdowns.","ex":"Suicide Silence, Whitechapel, Job for a Cowboy","region":"USA","era":"2000s","note":"Features guttural growls and slam breakdowns."}},{"name":"Sludge Metal","v":5,"meta":{"def":"Thick, abrasive fusion of doom's heaviness and hardcore's aggression.","ex":"Eyehategod, Crowbar, Melvins","region":"New Orleans","era":"1990s","note":"Southern swampy tone defines the NOLA scene."}},{"name":"Stoner Metal","v":5,"meta":{"def":"Groovy, fuzzy, downtuned metal rooted in psychedelic blues rock.","ex":"Kyuss, Sleep, Electric Wizard","region":"California","era":"1990s","note":"The Palm Desert generator parties were its cradle."}},{"name":"Folk Metal","v":5,"meta":{"def":"Metal woven with traditional folk melodies and instruments.","ex":"Korpiklaani, Eluveitie, Finntroll","region":"Finland / Europe","era":"1990s onward","note":"Fiddles and accordions meet distorted guitars."}},{"name":"Symphonic Metal","v":5,"meta":{"def":"Metal grandeur augmented with orchestras and operatic female vocals.","ex":"Nightwish, Within Temptation, Epica","region":"Finland / Netherlands","era":"late 1990s onward","note":"Full choirs often join the band."}},{"name":"Djent","v":5,"meta":{"def":"Progressive metal built on syncopated, palm-muted low-string chugs.","ex":"Meshuggah, Periphery, Animals as Leaders","region":"Sweden / USA","era":"2000s-2010s","note":"Named onomatopoeically for the muted guitar sound."}},{"name":"Grindcore","v":5,"meta":{"def":"Extremely fast, short, chaotic blend of hardcore and death metal.","ex":"Napalm Death, Pig Destroyer, Brutal Truth","region":"UK","era":"late 1980s","note":"Some songs last only a few seconds."}}]},{"name":"Pop","v":16,"meta":{"def":"Broad mainstream music aimed at wide appeal through catchy hooks and production.","ex":"Michael Jackson, Madonna, Taylor Swift","region":"Global","era":"1950s onward","note":"Defined more by commercial reach than a fixed sound."},"children":[{"name":"Bubblegum Pop","v":5,"meta":{"def":"Simple, sugary, upbeat pop aimed squarely at young audiences.","ex":"The Archies, 1910 Fruitgum Company","region":"USA","era":"late 1960s-1970s","note":"Often built by studio songwriting teams."}},{"name":"Synth-Pop","v":5,"meta":{"def":"Pop built on synthesizers and drum machines as the lead instruments.","ex":"Depeche Mode, Pet Shop Boys, Eurythmics","region":"UK","era":"1980s","note":"Affordable synths made it a bedroom-producer's genre."}},{"name":"Dance-Pop","v":5,"meta":{"def":"Uptempo, club-ready pop with strong beats and polished production.","ex":"Madonna, Kylie Minogue, Lady Gaga","region":"USA / UK","era":"1980s onward","note":"Bridges the charts and the dancefloor."}},{"name":"Teen Pop","v":5,"meta":{"def":"Glossy pop marketed to teenagers via idols and boy/girl groups.","ex":"Britney Spears, Backstreet Boys, NSYNC","region":"USA","era":"late 1990s-2000s","note":"The TRL era made it a cultural juggernaut."}},{"name":"Art Pop","v":5,"meta":{"def":"Experimental, conceptually ambitious pop crossing into avant-garde.","ex":"Kate Bush, Bjork, FKA twigs","region":"UK","era":"1980s onward","note":"Treats the pop song as a canvas for art."}},{"name":"Dream Pop","v":5,"meta":{"def":"Ethereal, atmospheric pop with lush reverb and breathy vocals.","ex":"Cocteau Twins, Beach House, Mazzy Star","region":"UK / USA","era":"1980s onward","note":"Closely related to shoegaze but more melodic."}},{"name":"Hyperpop","v":5,"meta":{"def":"Maximalist, glitchy, pitched-up pop pushing production to extremes.","ex":"100 gecs, SOPHIE, Charli XCX","region":"UK / USA","era":"2010s-2020s","note":"The PC Music label helped define it."}},{"name":"City Pop","v":5,"meta":{"def":"Glossy, funk- and AOR-tinged Japanese urban pop of the bubble era.","ex":"Tatsuro Yamashita, Mariya Takeuchi, Anri","region":"Japan","era":"late 1970s-1980s","note":"Enjoyed a viral internet revival decades later."}},{"name":"K-Pop","v":6,"meta":{"def":"Highly produced Korean idol pop blending many genres with synchronized dance.","ex":"BTS, BLACKPINK, EXO","region":"South Korea","era":"1990s onward","note":"Trainee systems groom idols for years before debut."}},{"name":"J-Pop","v":5,"meta":{"def":"Mainstream Japanese pop spanning idol groups, rock and electronic styles.","ex":"Hikaru Utada, Perfume, Arashi","region":"Japan","era":"1990s onward","note":"Dominates anime and commercial tie-in music."}},{"name":"Chamber Pop","v":5,"meta":{"def":"Lush orchestral pop with strings, horns and baroque arrangements.","ex":"The Divine Comedy, Belle and Sebastian, Rufus Wainwright","region":"UK / USA","era":"1990s onward","note":"Echoes the ambition of 1960s Brian Wilson productions."}},{"name":"Indie Pop","v":5,"meta":{"def":"Melodic, twee-leaning pop made on independent labels.","ex":"The Smiths, Vampire Weekend, Alvvays","region":"UK / USA","era":"1980s onward","note":"The C86 cassette compilation was a landmark."}},{"name":"Power Pop","v":5,"meta":{"def":"Bright, hook-laden guitar pop with big harmonies and crunchy chords.","ex":"Big Star, Cheap Trick, Weezer","region":"USA / UK","era":"1970s onward","note":"Draws directly from the Beatles and the Who."}}]},{"name":"R&B, Soul & Funk","v":14,"meta":{"def":"African-American popular music of groove, emotion and gospel-rooted vocals.","ex":"Aretha Franklin, Stevie Wonder, James Brown","region":"USA","era":"1950s onward","note":"The bedrock of modern pop, disco and hip-hop."},"children":[{"name":"Motown","v":5,"meta":{"def":"Polished, pop-crossover soul from Detroit's hit-making label.","ex":"The Supremes, Marvin Gaye, The Temptations","region":"Detroit","era":"1960s","note":"Berry Gordy ran it like an assembly line of hits."}},{"name":"Southern Soul","v":5,"meta":{"def":"Raw, gospel-drenched soul with gritty horns and deep feeling.","ex":"Otis Redding, Wilson Pickett, Al Green","region":"Memphis / Muscle Shoals","era":"1960s-1970s","note":"The Stax label was its beating heart."}},{"name":"Funk","v":6,"meta":{"def":"Groove-centered music built on syncopated bass and the downbeat.","ex":"James Brown, Parliament-Funkadelic, Sly and the Family Stone","region":"USA","era":"late 1960s-1970s","note":"James Brown put everything 'on the one'."}},{"name":"Disco","v":6,"meta":{"def":"Four-on-the-floor dance music with lush strings and steady grooves.","ex":"Donna Summer, Chic, Bee Gees","region":"USA","era":"1970s","note":"Born in New York's underground club scene."}},{"name":"Quiet Storm","v":5,"meta":{"def":"Smooth, mellow, romantic soul designed for late-night radio.","ex":"Smokey Robinson, Sade, Luther Vandross","region":"USA","era":"1970s-1980s","note":"Named after a Smokey Robinson album and radio format."}},{"name":"New Jack Swing","v":5,"meta":{"def":"R&B fused with hip-hop swing beats and slick production.","ex":"Bobby Brown, Guy, Teddy Riley productions","region":"USA","era":"late 1980s-early 1990s","note":"Teddy Riley pioneered its swung drum programming."}},{"name":"Neo-Soul","v":5,"meta":{"def":"Organic, jazz- and hip-hop-informed soul revival with live feel.","ex":"D'Angelo, Erykah Badu, Jill Scott","region":"USA","era":"late 1990s-2000s","note":"The Soulquarians collective shaped its sound."}},{"name":"Contemporary R&B","v":5,"meta":{"def":"Modern, electronically produced R&B blending soul, pop and hip-hop.","ex":"Beyonce, Usher, Mariah Carey","region":"USA","era":"1990s onward","note":"Dominated the charts through the 2000s."}},{"name":"PBR&B","v":5,"meta":{"def":"Moody, atmospheric alternative R&B with electronic and indie textures.","ex":"The Weeknd, Frank Ocean, Miguel","region":"USA / Canada","era":"2010s","note":"Also called alt-R&B or hipster R&B."}}]},{"name":"Hip-Hop & Rap","v":16,"meta":{"def":"Rhythmic spoken vocals over beats, born from block-party DJ culture.","ex":"Grandmaster Flash, Tupac, Kendrick Lamar","region":"Bronx, New York","era":"1973 onward","note":"Built on four pillars: MCing, DJing, breaking and graffiti."},"children":[{"name":"Old School Hip-Hop","v":5,"meta":{"def":"The earliest party rap over disco and funk breaks.","ex":"Sugarhill Gang, Grandmaster Flash, Afrika Bambaataa","region":"New York","era":"1979-1984","note":"Rapper's Delight brought rap to the masses."}},{"name":"Boom Bap","v":5,"meta":{"def":"Hard-hitting sample-based East Coast rap with punchy kick-snare drums.","ex":"DJ Premier, Nas, Wu-Tang Clan","region":"New York","era":"early-mid 1990s","note":"Named for the onomatopoeic drum pattern."}},{"name":"Gangsta Rap","v":5,"meta":{"def":"Street-narrative rap depicting crime, violence and inner-city life.","ex":"N.W.A, Ice-T, 50 Cent","region":"Los Angeles","era":"late 1980s-1990s","note":"N.W.A's blunt realism sparked national controversy."}},{"name":"G-Funk","v":5,"meta":{"def":"Laid-back West Coast rap over Parliament-style synth funk grooves.","ex":"Dr. Dre, Snoop Dogg, Warren G","region":"Los Angeles","era":"early-mid 1990s","note":"Dre's The Chronic codified the sound."}},{"name":"Conscious Hip-Hop","v":5,"meta":{"def":"Socially and politically aware rap addressing justice and community.","ex":"Public Enemy, Common, Mos Def","region":"USA","era":"late 1980s onward","note":"Public Enemy turned rap into protest music."}},{"name":"Jazz Rap","v":5,"meta":{"def":"Hip-hop built on jazz samples and laid-back bohemian lyricism.","ex":"A Tribe Called Quest, Gang Starr, Digable Planets","region":"New York","era":"early 1990s","note":"The Native Tongues collective led the movement."}},{"name":"Trap","v":6,"meta":{"def":"Southern rap over booming 808s, rapid hi-hats and dark synths.","ex":"T.I., Gucci Mane, Future, Migos","region":"Atlanta","era":"2000s onward","note":"Named for the drug-dealing 'trap house'."}},{"name":"Drill","v":5,"meta":{"def":"Bleak, menacing trap-derived rap with sliding 808s and violent themes.","ex":"Chief Keef, Lil Durk, King Von","region":"Chicago","era":"2010s","note":"Emerged from Chicago's South Side."}},{"name":"UK Drill","v":5,"meta":{"def":"British drill with sliding basslines, syncopated beats and slang.","ex":"Headie One, Central Cee, Digga D","region":"London","era":"late 2010s","note":"Producers gave it a distinct skippy percussion."}},{"name":"Grime","v":5,"meta":{"def":"Fast, aggressive UK rap over jagged electronic beats around 140 BPM.","ex":"Dizzee Rascal, Skepta, Wiley","region":"London","era":"early 2000s","note":"Grew from UK garage and pirate radio."}},{"name":"Crunk","v":5,"meta":{"def":"Rowdy, chant-heavy Southern club rap with pounding beats.","ex":"Lil Jon, Three 6 Mafia, Ying Yang Twins","region":"Southern USA","era":"early-mid 2000s","note":"Built for maximum hype in the club."}},{"name":"Cloud Rap","v":5,"meta":{"def":"Hazy, ethereal, atmospheric rap over ambient, washed-out beats.","ex":"Lil B, Clams Casino, A$AP Rocky","region":"USA","era":"early 2010s","note":"Producer Clams Casino defined its dreamy texture."}},{"name":"Mumble Rap","v":5,"meta":{"def":"Melodic, slurred, vibe-focused trap rap prioritizing flow over clarity.","ex":"Young Thug, Lil Uzi Vert, Playboi Carti","region":"USA","era":"2010s","note":"A somewhat pejorative fan-coined label."}},{"name":"Horrorcore","v":5,"meta":{"def":"Dark, violent, horror-movie-themed rap with gruesome imagery.","ex":"Gravediggaz, Insane Clown Posse, Brotha Lynch Hung","region":"USA","era":"1990s onward","note":"Blends slasher aesthetics with hip-hop."}},{"name":"Phonk","v":5,"meta":{"def":"Lo-fi rap built on Memphis samples, cowbell and distorted 808s.","ex":"DJ Screw legacy, Ghostemane, Kordhell","region":"USA","era":"2010s-2020s","note":"Drift phonk became a viral car-video staple."}},{"name":"Lo-Fi Hip-Hop","v":5,"meta":{"def":"Relaxed, jazzy instrumental beats with warm crackle for study and chill.","ex":"Nujabes, J Dilla, streaming lofi channels","region":"Japan / USA","era":"2010s","note":"Endless-livestream channels made it ubiquitous."}}]},{"name":"Electronic & EDM","v":16,"meta":{"def":"Music produced primarily with synthesizers, drum machines and computers.","ex":"Kraftwerk, Daft Punk, Aphex Twin","region":"Global","era":"1970s onward","note":"Spans dancefloor bangers to abstract listening music."},"children":[{"name":"House","v":14,"meta":{"def":"Four-on-the-floor dance music at around 120-130 BPM born in Chicago clubs.","ex":"Frankie Knuckles, Daft Punk, Disclosure","region":"Chicago","era":"1980s onward","note":"Named for The Warehouse club where it started."},"children":[{"name":"Deep House","v":5,"meta":{"def":"Warm, soulful, laid-back house with lush chords and mellow grooves.","ex":"Larry Heard, Kerri Chandler, Maya Jane Coles","region":"Chicago / USA","era":"late 1980s onward","note":"Larry Heard's Mr Fingers defined its jazzy warmth."}},{"name":"Tech House","v":5,"meta":{"def":"Stripped, groovy hybrid of house swing and techno's minimal drive.","ex":"Green Velvet, Hot Since 82, FISHER","region":"UK","era":"late 1990s onward","note":"A club-DJ staple for its rolling basslines."}},{"name":"Acid House","v":5,"meta":{"def":"Squelchy house built on the resonant Roland TB-303 bassline.","ex":"Phuture Acid Tracks, DJ Pierre","region":"Chicago","era":"1987","note":"Sparked the UK's Second Summer of Love."}},{"name":"Progressive House","v":5,"meta":{"def":"Layered, building house with long evolving arrangements.","ex":"Sasha, John Digweed, Eric Prydz","region":"UK","era":"1990s onward","note":"Favors gradual tension over instant drops."}},{"name":"French House","v":5,"meta":{"def":"Filtered, funky, disco-sampling house with phaser-swept loops.","ex":"Daft Punk, Stardust, Cassius","region":"France","era":"late 1990s","note":"Also nicknamed the French Touch."}},{"name":"Electro House","v":5,"meta":{"def":"Big, distorted, high-energy house with aggressive synth leads.","ex":"Deadmau5, Justice, Steve Aoki","region":"Europe / USA","era":"2000s","note":"Fueled the late-2000s blog-house boom."}}]},{"name":"Techno","v":10,"meta":{"def":"Repetitive, machine-driven electronic dance music built on a steady kick.","ex":"Juan Atkins, Jeff Mills, Richie Hawtin","region":"Detroit","era":"1980s onward","note":"The Belleville Three founded the Detroit sound."},"children":[{"name":"Detroit Techno","v":5,"meta":{"def":"Soulful, futuristic original techno blending funk and machine rhythm.","ex":"Juan Atkins, Derrick May, Kevin Saunderson","region":"Detroit","era":"mid-1980s","note":"Inspired by Kraftwerk and Parliament alike."}},{"name":"Minimal Techno","v":5,"meta":{"def":"Sparse, hypnotic techno stripped to essential rhythmic elements.","ex":"Richie Hawtin, Robert Hood, Ricardo Villalobos","region":"Detroit / Germany","era":"1990s onward","note":"Robert Hood's minimalism was a key blueprint."}},{"name":"Dub Techno","v":5,"meta":{"def":"Deep, echoing techno soaked in dub reverb and cavernous space.","ex":"Basic Channel, Deepchord, Rhythm & Sound","region":"Berlin","era":"1990s","note":"Basic Channel's chords became legendary."}},{"name":"Acid Techno","v":5,"meta":{"def":"Hard, driving techno powered by squelching 303 acid lines.","ex":"Hardfloor, Chris Liberator","region":"UK / Europe","era":"1990s","note":"A staple of UK free-party raves."}}]},{"name":"Trance","v":10,"meta":{"def":"Euphoric, melodic electronic dance music built on sweeping build-ups.","ex":"Paul van Dyk, Armin van Buuren, Above & Beyond","region":"Germany","era":"1990s onward","note":"Peak-time breakdowns aim for emotional release."},"children":[{"name":"Uplifting Trance","v":5,"meta":{"def":"Grand, emotional trance with soaring melodies and huge breakdowns.","ex":"Armin van Buuren, Aly & Fila","region":"Europe","era":"late 1990s onward","note":"Also called anthem or epic trance."}},{"name":"Psytrance","v":5,"meta":{"def":"Fast, hypnotic, psychedelic trance with rolling basslines and acid textures.","ex":"Infected Mushroom, Astrix, 1200 Micrograms","region":"Goa, India","era":"1990s onward","note":"Grew from the Goa trance scene on Indian beaches."}},{"name":"Progressive Trance","v":5,"meta":{"def":"Deeper, subtler trance with gradual builds and restrained melody.","ex":"Sasha, Guy J, Jerome Isma-Ae","region":"Europe","era":"2000s onward","note":"Sits between trance and progressive house."}}]},{"name":"Drum and Bass","v":6,"meta":{"def":"Fast breakbeat music around 170 BPM with heavy sub-bass.","ex":"Goldie, Andy C, Pendulum","region":"UK","era":"1990s onward","note":"Evolved directly out of jungle."}},{"name":"Jungle","v":5,"meta":{"def":"Chopped Amen-break rhythms over deep reggae-influenced sub-bass.","ex":"Shy FX, Congo Natty, LTJ Bukem","region":"UK","era":"early 1990s","note":"The Amen break is its rhythmic DNA."}},{"name":"Dubstep","v":6,"meta":{"def":"Bass-heavy electronic music with wobbling sub-bass and half-time drums.","ex":"Skream, Burial, Skrillex","region":"London","era":"2000s","note":"The Croydon FWD>> nights were its cradle."}},{"name":"UK Garage","v":5,"meta":{"def":"Skippy, swung dance music with chopped vocals and shuffling beats.","ex":"MJ Cole, Artful Dodger, Todd Edwards","region":"London","era":"late 1990s","note":"Two-step is its most influential offshoot."}},{"name":"Breakbeat","v":5,"meta":{"def":"Dance music built on syncopated, non-four-on-the-floor drum breaks.","ex":"The Prodigy, The Chemical Brothers, Fatboy Slim","region":"UK","era":"1990s","note":"Big beat was its rowdiest festival strain."}},{"name":"Ambient","v":6,"meta":{"def":"Atmospheric, texture-focused electronic music that ignores beat and structure.","ex":"Brian Eno, Aphex Twin, Stars of the Lid","region":"UK","era":"1970s onward","note":"Eno coined the term with Music for Airports."}},{"name":"IDM","v":5,"meta":{"def":"Intricate, experimental electronic music for the mind more than the feet.","ex":"Aphex Twin, Autechre, Boards of Canada","region":"UK","era":"1990s","note":"Short for Intelligent Dance Music, a contested tag."}},{"name":"Downtempo","v":5,"meta":{"def":"Relaxed, mid-tempo electronic music for chilling rather than dancing.","ex":"Bonobo, Thievery Corporation, Zero 7","region":"UK / Global","era":"1990s onward","note":"A staple of lounge and chill-out rooms."}},{"name":"Trip-Hop","v":5,"meta":{"def":"Moody, cinematic fusion of hip-hop beats, dub and soul.","ex":"Massive Attack, Portishead, Tricky","region":"Bristol","era":"1990s","note":"The Bristol sound gave it a smoky menace."}},{"name":"Synthwave","v":5,"meta":{"def":"Retro-futurist electronic music evoking 1980s film and game soundtracks.","ex":"Kavinsky, Com Truise, The Midnight","region":"France / USA","era":"2010s","note":"The Drive soundtrack brought it mainstream attention."}},{"name":"Vaporwave","v":5,"meta":{"def":"Slowed, chopped nostalgic music built from muzak and 80s corporate samples.","ex":"Macintosh Plus, Blank Banshee","region":"Internet","era":"early 2010s","note":"As much an aesthetic and meme as a genre."}},{"name":"Hardstyle","v":5,"meta":{"def":"Hard dance music with distorted kicks, screeches and euphoric leads.","ex":"Headhunterz, Brennan Heart, Da Tweekaz","region":"Netherlands","era":"2000s","note":"The reverse-bass kick is its signature."}},{"name":"Gabber","v":5,"meta":{"def":"Extremely fast, distorted hardcore techno with pounding kicks.","ex":"Rotterdam Terror Corps, Angerfist","region":"Rotterdam","era":"1990s","note":"Tempos routinely exceed 180 BPM."}},{"name":"Big Room / Festival EDM","v":5,"meta":{"def":"Massive, anthemic electro-house built for main-stage festival drops.","ex":"Martin Garrix, Hardwell, Dimitri Vegas & Like Mike","region":"Netherlands / Global","era":"2010s","note":"Defined the EDM boom's mainstage sound."}},{"name":"Future Bass","v":5,"meta":{"def":"Melodic electronic music with pitched vocal chops and lush supersaw chords.","ex":"Flume, San Holo, Illenium","region":"Australia / USA","era":"2010s","note":"Flume's productions helped define its wobble."}},{"name":"Glitch","v":5,"meta":{"def":"Electronic music built from digital errors, clicks and stutters.","ex":"Oval, Autechre, Alva Noto","region":"Germany / Global","era":"1990s onward","note":"Turns technical malfunction into aesthetic."}}]},{"name":"Reggae & Caribbean","v":12,"meta":{"def":"Jamaican-rooted music built on the offbeat skank and deep bass.","ex":"Bob Marley, Lee Scratch Perry, King Tubby","region":"Jamaica / Caribbean","era":"1960s onward","note":"Its studio dub experiments reshaped global music."},"children":[{"name":"Ska","v":5,"meta":{"def":"Uptempo Jamaican music with walking bass and offbeat guitar chops.","ex":"The Skatalites, Prince Buster, Desmond Dekker","region":"Jamaica","era":"early 1960s","note":"The precursor to rocksteady and reggae."}},{"name":"Rocksteady","v":5,"meta":{"def":"Slower, soulful successor to ska with prominent bass and romantic themes.","ex":"Alton Ellis, The Paragons, Ken Boothe","region":"Jamaica","era":"1966-1968","note":"A brief but pivotal bridge to reggae."}},{"name":"Roots Reggae","v":5,"meta":{"def":"Spiritual, Rastafari-themed reggae of social consciousness.","ex":"Bob Marley, Burning Spear, Culture","region":"Jamaica","era":"1970s","note":"Carried the message of Rastafari worldwide."}},{"name":"Dub","v":5,"meta":{"def":"Instrumental remix art stripping tracks to bass, drums and echo.","ex":"King Tubby, Lee Scratch Perry, Augustus Pablo","region":"Jamaica","era":"1970s","note":"The mixing desk itself became an instrument."}},{"name":"Dancehall","v":5,"meta":{"def":"Sparse, digital reggae with toasted vocals over riddim tracks.","ex":"Yellowman, Shabba Ranks, Vybz Kartel","region":"Jamaica","era":"1980s onward","note":"The digital Sleng Teng riddim revolutionized it."}},{"name":"Ragga","v":5,"meta":{"def":"Fully digital dancehall built on synthesized, computerized riddims.","ex":"Shabba Ranks, Buju Banton, Super Cat","region":"Jamaica","era":"late 1980s-1990s","note":"Short for raggamuffin."}},{"name":"Reggaeton","v":6,"meta":{"def":"Latin urban music built on the dembow riddim and Spanish rap-singing.","ex":"Daddy Yankee, Don Omar, Bad Bunny","region":"Puerto Rico / Panama","era":"1990s onward","note":"The dembow beat is its rhythmic backbone."}},{"name":"Soca","v":5,"meta":{"def":"Fast, festive dance music evolved from calypso for Carnival.","ex":"Machel Montano, Bunji Garlin, Kes","region":"Trinidad and Tobago","era":"1970s onward","note":"The soundtrack to Caribbean Carnival."}},{"name":"Calypso","v":5,"meta":{"def":"Witty, storytelling Afro-Caribbean song rooted in social commentary.","ex":"Mighty Sparrow, Lord Kitchener, Harry Belafonte","region":"Trinidad and Tobago","era":"early 20th century","note":"Calypsonians competed in lyrical wordplay."}},{"name":"Zouk","v":5,"meta":{"def":"Fast carnival dance music with prominent percussion and French Creole lyrics.","ex":"Kassav', Jocelyne Beroard","region":"Guadeloupe / Martinique","era":"1980s","note":"Kassav' launched it internationally."}}]},{"name":"Latin","v":14,"meta":{"def":"Music of Latin America blending African, Indigenous and European traditions.","ex":"Celia Cruz, Carlos Gardel, Bad Bunny","region":"Latin America","era":"Traditional onward","note":"Spans folk roots to global chart-topping pop."},"children":[{"name":"Salsa","v":5,"meta":{"def":"Fiery Afro-Cuban dance music of layered percussion and brass over clave.","ex":"Celia Cruz, Hector Lavoe, Willie Colon","region":"Cuba / New York","era":"1960s-1970s","note":"The Fania label defined the New York salsa boom."}},{"name":"Cumbia","v":6,"meta":{"def":"Rhythmic Colombian folk-dance music that spread across Latin America.","ex":"Los Angeles Azules, Celso Pina, La Sonora Dinamita","region":"Colombia","era":"traditional onward","note":"Each country evolved its own local cumbia style."}},{"name":"Bachata","v":5,"meta":{"def":"Romantic Dominican guitar music of heartbreak and longing.","ex":"Juan Luis Guerra, Aventura, Romeo Santos","region":"Dominican Republic","era":"1960s onward","note":"Aventura modernized it for a global audience."}},{"name":"Merengue","v":5,"meta":{"def":"Fast, upbeat Dominican dance music with accordion and driving two-step.","ex":"Juan Luis Guerra, Wilfrido Vargas, Fernando Villalona","region":"Dominican Republic","era":"traditional onward","note":"The national dance of the Dominican Republic."}},{"name":"Bossa Nova","v":5,"meta":{"def":"Soft, sophisticated Brazilian fusion of samba rhythm and cool jazz.","ex":"Joao Gilberto, Antonio Carlos Jobim, Astrud Gilberto","region":"Rio de Janeiro","era":"late 1950s-1960s","note":"The Girl from Ipanema made it a global hit."}},{"name":"Samba","v":5,"meta":{"def":"Percussive, celebratory Afro-Brazilian music central to Carnival.","ex":"Cartola, Beth Carvalho, Zeca Pagodinho","region":"Rio de Janeiro","era":"early 20th century","note":"The heartbeat of Brazilian Carnival parades."}},{"name":"Tango","v":5,"meta":{"def":"Dramatic, melancholic dance music of the Rio de la Plata built on bandoneon.","ex":"Carlos Gardel, Astor Piazzolla","region":"Argentina / Uruguay","era":"early 20th century","note":"Piazzolla's nuevo tango revolutionized the form."}},{"name":"Mariachi","v":5,"meta":{"def":"Festive Mexican ensemble music of trumpets, violins and guitarron.","ex":"Vicente Fernandez, Mariachi Vargas de Tecalitlan","region":"Jalisco, Mexico","era":"19th century onward","note":"A UNESCO Intangible Cultural Heritage."}},{"name":"Ranchera","v":5,"meta":{"def":"Passionate Mexican folk song of love, patriotism and rural life.","ex":"Jose Alfredo Jimenez, Chavela Vargas, Vicente Fernandez","region":"Mexico","era":"early 20th century","note":"Often performed with mariachi backing."}},{"name":"Latin Trap","v":5,"meta":{"def":"Spanish-language trap fusing 808 beats with reggaeton flavor.","ex":"Bad Bunny, Anuel AA, Ozuna","region":"Puerto Rico","era":"2010s","note":"Bad Bunny brought it to global superstardom."}},{"name":"Corridos Tumbados","v":5,"meta":{"def":"Modern Mexican corridos fused with trap themes and acoustic guitar.","ex":"Peso Pluma, Natanael Cano, Junior H","region":"Mexico / USA","era":"2020s","note":"Natanael Cano pioneered the trap-corrido hybrid."}}]},{"name":"World & Pop Fusion","v":12,"meta":{"def":"Regional traditional and modern popular styles from across the globe.","ex":"Fela Kuti, Youssou N'Dour, Ravi Shankar","region":"Global","era":"Traditional onward","note":"Increasingly fused with Western pop and dance."},"children":[{"name":"Afrobeats","v":6,"meta":{"def":"Modern West African pop blending highlife, dancehall and hip-hop.","ex":"Wizkid, Burna Boy, Davido","region":"Nigeria / Ghana","era":"2010s onward","note":"Distinct from Fela Kuti's older Afrobeat."}},{"name":"Amapiano","v":5,"meta":{"def":"South African house hybrid with jazzy keys and deep log-drum basslines.","ex":"Kabza De Small, DJ Maphorisa, Focalistic","region":"South Africa","era":"late 2010s","note":"The log-drum bass sound is unmistakable."}},{"name":"Highlife","v":5,"meta":{"def":"Jazzy West African dance music with bright guitars and horns.","ex":"E.T. Mensah, Osibisa, Rex Lawson","region":"Ghana / Nigeria","era":"early-mid 20th century","note":"A foundation for later African pop."}},{"name":"Soukous","v":5,"meta":{"def":"Fast, guitar-driven Congolese dance music with intricate interplay.","ex":"Franco, Papa Wemba, Kanda Bongo Man","region":"Congo","era":"1960s onward","note":"Evolved from Congolese rumba."}},{"name":"Afrobeat","v":5,"meta":{"def":"Politically charged fusion of funk, jazz and Yoruba rhythm in long grooves.","ex":"Fela Kuti, Tony Allen, Femi Kuti","region":"Nigeria","era":"1970s","note":"Fela's marathon jams could exceed twenty minutes."}},{"name":"Bhangra","v":5,"meta":{"def":"Energetic Punjabi folk-dance music powered by the dhol drum.","ex":"Panjabi MC, Malkit Singh, Gurdas Maan","region":"Punjab / UK","era":"traditional / 1980s revival","note":"The British-Asian scene fused it with hip-hop."}},{"name":"Rai","v":5,"meta":{"def":"Algerian folk-pop of poetic rebellion updated with modern production.","ex":"Khaled, Cheb Mami, Rachid Taha","region":"Algeria","era":"early 20th century / 1980s pop","note":"Khaled's Didi was a global crossover hit."}},{"name":"Flamenco","v":6,"meta":{"def":"Passionate Andalusian art of guitar, hand-clapping, dance and anguished song.","ex":"Paco de Lucia, Camaron de la Isla, Rosalia","region":"Andalusia, Spain","era":"18th century onward","note":"Rosalia modernized it into global pop."}}]},{"name":"Other & Experimental","v":16,"meta":{"def":"Devotional, functional, avant-garde and boundary-defying music categories.","ex":"Mahalia Jackson, Throbbing Gristle, John Williams","region":"Global","era":"Varies","note":"Ranges from worship to noise to film scores."},"children":[{"name":"Gospel","v":5,"meta":{"def":"Ecstatic African-American Christian music of choirs and soaring solos.","ex":"Mahalia Jackson, Kirk Franklin, The Clark Sisters","region":"USA","era":"early 20th century onward","note":"The training ground for countless soul singers."}},{"name":"Contemporary Christian Music","v":5,"meta":{"def":"Modern pop and rock built around Christian worship themes.","ex":"Hillsong, Chris Tomlin, Amy Grant","region":"USA / Australia","era":"1970s onward","note":"Worship megachurches drive its scale."}},{"name":"New Age","v":5,"meta":{"def":"Gentle, meditative instrumental music for relaxation and healing.","ex":"Enya, Yanni, Kitaro","region":"Global","era":"1970s onward","note":"Popular for yoga, spa and meditation settings."}},{"name":"Film Score","v":6,"meta":{"def":"Orchestral and electronic music composed to underscore motion pictures.","ex":"John Williams, Ennio Morricone, Hans Zimmer","region":"Global","era":"1930s onward","note":"Williams's leitmotifs shaped modern blockbusters."}},{"name":"Video Game Music","v":6,"meta":{"def":"Music composed for games, from bleeping chiptunes to full orchestras.","ex":"Koji Kondo, Nobuo Uematsu, chiptune scene","region":"Japan / Global","era":"1970s onward","note":"Chiptune turns old sound chips into instruments."}},{"name":"Children's Music","v":5,"meta":{"def":"Simple, playful songs written to entertain and educate young children.","ex":"Raffi, The Wiggles, Sesame Street songs","region":"Global","era":"20th century onward","note":"Repetition and singalong hooks are essential."}},{"name":"Novelty Song","v":5,"meta":{"def":"Comedic or gimmicky songs built on humor and one-off hooks.","ex":"Weird Al Yankovic, Ray Stevens","region":"USA","era":"20th century onward","note":"Often parodies of existing hit records."}},{"name":"Spoken Word","v":5,"meta":{"def":"Performance of poetry and prose with rhythmic, musical delivery.","ex":"Gil Scott-Heron, The Last Poets, slam poetry","region":"USA","era":"1960s onward","note":"A direct ancestor of rap."}},{"name":"Noise","v":5,"meta":{"def":"Extreme experimental music built from distortion, feedback and harshness.","ex":"Merzbow, Whitehouse, Wolf Eyes","region":"Japan / UK","era":"1980s onward","note":"Japanoise pushed volume to punishing extremes."}},{"name":"Industrial","v":5,"meta":{"def":"Abrasive fusion of electronics, metal and noise with dystopian themes.","ex":"Throbbing Gristle, Nine Inch Nails, Ministry","region":"UK / USA","era":"late 1970s onward","note":"Throbbing Gristle coined the term industrial music."}},{"name":"EBM","v":5,"meta":{"def":"Danceable electronic body music with pounding sequences and shouted vocals.","ex":"Front 242, Nitzer Ebb, DAF","region":"Belgium / Germany","era":"1980s","note":"Front 242 named the genre Electronic Body Music."}},{"name":"Gothic Rock","v":5,"meta":{"def":"Dark, atmospheric post-punk of brooding melodies and morbid romance.","ex":"Bauhaus, The Sisters of Mercy, The Cure","region":"UK","era":"late 1970s-1980s","note":"Bauhaus's Bela Lugosi's Dead is its founding text."}},{"name":"Musique Concrete","v":5,"meta":{"def":"Avant-garde composition assembled from recorded real-world sounds.","ex":"Pierre Schaeffer, Pierre Henry","region":"France","era":"1940s-1950s","note":"Schaeffer built it from manipulated tape recordings."}}]}]},{"name":"World Traditions","type":"traditions","v":26,"children":[{"name":"South Asian Traditions","v":12,"meta":{"def":"Music systems of the Indian subcontinent rooted in raga melody and tala rhythm.","ex":"sitar, tabla, sarod, vocal khayal","region":"India, Pakistan, Bangladesh, Nepal, Sri Lanka","note":"Both classical systems share a common ancient root in the Natyashastra."},"children":[{"name":"Hindustani Classical","v":10,"meta":{"def":"North Indian art music built on melodic raga and cyclic tala frameworks.","ex":"khayal, dhrupad, Ravi Shankar, Bhimsen Joshi","region":"North India and Pakistan","note":"Absorbed Persian influence during the Mughal era."},"children":[{"name":"Raga","v":5,"meta":{"def":"A melodic framework of prescribed notes, phrases and mood governing improvisation.","ex":"Yaman, Bhairav, Malkauns, Darbari","region":"North India","note":"Ragas are traditionally tied to times of day and seasons."}},{"name":"Tala","v":4,"meta":{"def":"The cyclic rhythmic time-measure organising a composition into beats.","ex":"teental (16), jhaptal (10), ektal (12)","region":"North India","note":"The first beat, sam, is the point of resolution and emphasis."}},{"name":"Gharana","v":4,"meta":{"def":"A hereditary stylistic lineage or school transmitting a distinct performance style.","ex":"Gwalior, Kirana, Patiala, Jaipur-Atrauli","region":"North India","note":"Knowledge passes orally within the guru-shishya (teacher-disciple) bond."}},{"name":"Dhrupad","v":4,"meta":{"def":"The oldest surviving Hindustani vocal genre, austere and slow-unfolding.","ex":"Dagar brothers, pakhawaj drum, alap","region":"North India","note":"Once a temple and court music, now rare and revered."}},{"name":"Khayal","v":4,"meta":{"def":"The dominant Hindustani vocal form, more ornate and flexible than dhrupad.","ex":"bada khayal, chhota khayal, taans","region":"North India","note":"Its name means 'imagination' in Persian/Urdu."}}]},{"name":"Carnatic Classical","v":8,"meta":{"def":"South Indian art music emphasising composed devotional kritis and complex rhythm.","ex":"veena, mridangam, M. S. Subbulakshmi","region":"South India (Tamil Nadu, Karnataka, Andhra, Kerala)","note":"The 'Trinity' Tyagaraja, Dikshitar and Syama Sastri shaped its repertoire."},"children":[{"name":"Kriti","v":4,"meta":{"def":"The principal Carnatic composition form, a devotional song in three sections.","ex":"pallavi, anupallavi, charanam","region":"South India","note":"Most kritis are addressed to Hindu deities."}},{"name":"Raga (Melakarta)","v":4,"meta":{"def":"The Carnatic melodic scale system organised into 72 parent scales.","ex":"Mayamalavagowla, Shankarabharanam, Kalyani","region":"South India","note":"Beginners traditionally start with Mayamalavagowla."}},{"name":"Tala (Suladi Sapta)","v":4,"meta":{"def":"The Carnatic rhythmic cycle system of seven basic talas with counting gestures.","ex":"Adi tala, konnakol, kanjira","region":"South India","note":"Konnakol is the vocal recitation of rhythmic syllables."}}]},{"name":"Devotional and Popular Forms","v":12,"meta":{"def":"Sacred, semi-classical and popular South Asian song genres.","ex":"qawwali, ghazal, bhajan, filmi","region":"Indian subcontinent","note":"Many blur the line between spiritual devotion and mass entertainment."},"children":[{"name":"Qawwali","v":5,"meta":{"def":"Ecstatic Sufi devotional singing driven by harmonium, hand-clapping and repetition.","ex":"Nusrat Fateh Ali Khan, Sabri Brothers","region":"Pakistan and North India","note":"Performed at dargahs (shrines) to induce spiritual rapture."}},{"name":"Ghazal","v":4,"meta":{"def":"A lyric poetic form of amorous or mystical couplets set to gentle melody.","ex":"Mehdi Hassan, Begum Akhtar, Jagjit Singh","region":"North India and Pakistan","note":"Rooted in Persian and Urdu poetry."}},{"name":"Bhajan and Kirtan","v":4,"meta":{"def":"Hindu devotional songs and call-and-response chanting of the divine name.","ex":"Meera bhajans, harmonium, dholak","region":"India","note":"Kirtan involves communal antiphonal singing."}},{"name":"Filmi","v":4,"meta":{"def":"Songs written for Indian cinema, the most widely heard South Asian music.","ex":"Lata Mangeshkar, A. R. Rahman, playback singing","region":"India (Bollywood and regional cinemas)","note":"Actors lip-sync to unseen 'playback' singers."}},{"name":"Bhangra","v":4,"meta":{"def":"Energetic Punjabi harvest dance-music built on the dhol drum.","ex":"dhol, tumbi, chimta","region":"Punjab (India and Pakistan)","note":"Reinvented as a global club genre by the British-Asian diaspora."}},{"name":"Baul","v":4,"meta":{"def":"Mystic minstrel tradition of wandering singers preaching an inner divinity.","ex":"ektara, dotara, Lalon Fakir","region":"Bengal (India and Bangladesh)","note":"Recognised by UNESCO as intangible cultural heritage."}},{"name":"Thumri","v":4,"meta":{"def":"Semi-classical romantic song noted for its expressive, flexible mood.","ex":"Begum Akhtar, dadra, kajri","region":"North India","note":"Lyrics usually voice a woman's love and longing."}}]},{"name":"South Asian Folk","v":12,"meta":{"def":"Regional rural song and dance traditions across the subcontinent.","ex":"Rajasthani, Lavani, Bihu, Baila","region":"India, Pakistan, Sri Lanka, Nepal","note":"Each linguistic region sustains its own festival repertoire."},"children":[{"name":"Rajasthani Folk","v":4,"meta":{"def":"Desert ballads and dance songs of hereditary Manganiar and Langa musicians.","ex":"kamaicha, khartal, 'Kesariya Balam'","region":"Rajasthan, India","note":"Muslim Manganiar musicians sing praise for Hindu patrons."}},{"name":"Lavani","v":4,"meta":{"def":"Vigorous Marathi song-and-dance form driven by the dholki drum.","ex":"dholki, ghungroo, tamasha theatre","region":"Maharashtra, India","note":"Traditionally performed by women in nine-yard saris."}},{"name":"Bihu","v":4,"meta":{"def":"Assamese spring festival songs celebrating fertility and the harvest.","ex":"dhol, pepa horn, husori","region":"Assam, India","note":"The pepa horn is fashioned from a buffalo's horn."}},{"name":"Baila","v":4,"meta":{"def":"Upbeat Sri Lankan dance song of Portuguese-creole origin.","ex":"kaffirinha, rabana drum","region":"Sri Lanka","note":"Descends from music of the island's Portuguese-era communities."}},{"name":"Nepali Dohori","v":4,"meta":{"def":"Himalayan folk song of Nepal's many ethnic groups, often a sung duel.","ex":"madal drum, sarangi, dohori","region":"Nepal","note":"Dohori is an improvised question-and-answer singing contest."}},{"name":"Rabindra Sangeet","v":4,"meta":{"def":"The vast body of songs composed by the poet Rabindranath Tagore.","ex":"Tagore melodies, Bengali lyric","region":"Bengal, India","note":"Two of Tagore's songs became national anthems of two nations."}}]}]},{"name":"Middle Eastern and Persian Traditions","v":10,"meta":{"def":"Modal music cultures of the Arab world, Iran, Turkey and Andalusia.","ex":"oud, ney, qanun, maqam","region":"Arab world, Iran, Turkey, North Africa","note":"Built on microtonal modal systems rather than fixed equal temperament."},"children":[{"name":"Arabic Classical","v":8,"meta":{"def":"Urban art music of the Arab world organised around maqam modes and tarab.","ex":"Umm Kulthum, oud, qanun, takht ensemble","region":"Egypt, Levant, Iraq","note":"Tarab is the state of enchanted emotional ecstasy it seeks to evoke."},"children":[{"name":"Maqam","v":5,"meta":{"def":"The Arabic modal system of melodic scales including microtonal quarter-tones.","ex":"Rast, Bayati, Hijaz, Saba","region":"Arab world","note":"Each maqam has a characteristic mood and melodic development path."}},{"name":"Tarab and Muwashshah","v":4,"meta":{"def":"The ecstatic aesthetic and its classic sung poetic vocal forms.","ex":"layali, mawwal, muwashshah","region":"Egypt and Levant","note":"Skilled singers improvise to prolong the audience's rapture."}},{"name":"Andalusian (Nuba)","v":4,"meta":{"def":"Suite-based art music descended from medieval Muslim Spain.","ex":"nuba suites, oud, rebab","region":"Morocco, Algeria, Tunisia","note":"Preserved by refugees who fled Iberia after 1492."}}]},{"name":"Persian Dastgah","v":6,"meta":{"def":"The Iranian classical system organised into modal complexes and a memorised repertoire.","ex":"tar, setar, santur, kamancheh","region":"Iran","note":"The radif is the canonical body of melodies students must master."},"children":[{"name":"Dastgah and Radif","v":4,"meta":{"def":"The twelve modal systems and the traditional repertoire organised within them.","ex":"Shur, Mahur, Homayoun, gushehs","region":"Iran","note":"The radif was inscribed on UNESCO's heritage list in 2009."}},{"name":"Avaz (Persian Vocal)","v":4,"meta":{"def":"Non-metric improvised classical singing set to classical Persian poetry.","ex":"Mohammad-Reza Shajarian, tahrir ornament","region":"Iran","note":"Tahrir is a yodel-like vocal ornament central to the style."}}]},{"name":"Turkish Makam","v":6,"meta":{"def":"The modal music of Ottoman court and Turkish classical traditions.","ex":"ney, tanbur, kanun, oud","region":"Turkey","note":"Uses a microtonal system dividing the whole tone into nine commas."},"children":[{"name":"Ottoman Court Music","v":4,"meta":{"def":"The refined classical repertoire of the Ottoman palace and mansions.","ex":"peşrev, saz semaisi, fasıl suite","region":"Turkey","note":"The fasıl is a suite of pieces in a single makam."}},{"name":"Sufi and Dervish Music","v":4,"meta":{"def":"Devotional music of the Mevlevi whirling dervishes and Sufi orders.","ex":"ney flute, sema ceremony, ilahi hymns","region":"Turkey and wider Sufi world","note":"The whirling sema enacts a mystical ascent toward God."}}]},{"name":"Regional and Popular Forms","v":12,"meta":{"def":"Folk, modal and popular song genres across the wider region.","ex":"rai, mugham, dengbej, chaabi","region":"North Africa, Caucasus, Arabian Peninsula","note":"Many blend classical modes with local dialect and dance."},"children":[{"name":"Rai","v":4,"meta":{"def":"Rebellious Algerian popular song born in the port bars of Oran.","ex":"Cheb Khaled, gasba flute, synths","region":"Algeria","note":"'Rai' means opinion, reflecting its outspoken lyrics."}},{"name":"Chaabi","v":4,"meta":{"def":"Urban working-class 'people's music' of the Maghreb.","ex":"mandole, derbouka, El Anka","region":"Algeria and Morocco","note":"The name simply means popular or of the people."}},{"name":"Azerbaijani Mugham","v":4,"meta":{"def":"Modal improvised art music blending song and instrumental poetry.","ex":"tar, kamancha, sung ghazal","region":"Azerbaijan","note":"Recognised by UNESCO as a masterpiece of intangible heritage."}},{"name":"Kurdish Dengbej","v":4,"meta":{"def":"Unaccompanied storytelling song preserving Kurdish history and epic.","ex":"solo voice, laments, epics","region":"Kurdistan (Turkey, Iraq, Iran, Syria)","note":"Dengbej sang the news and memory of scattered communities."}},{"name":"Yemenite Song","v":4,"meta":{"def":"Poetic sung tradition of Yemen accompanied by lute and copper plate.","ex":"qanbus lute, sahn nuhas, humayni verse","region":"Yemen","note":"The qanbus is an ancestor of many Arab and Southeast Asian lutes."}},{"name":"Egyptian Shaabi","v":4,"meta":{"def":"Gritty working-class street music of Cairo's back alleys.","ex":"Ahmed Adaweyah, wedding songs","region":"Egypt","note":"A modern electronic offshoot is known as mahraganat."}}]}]},{"name":"East Asian Traditions","v":12,"meta":{"def":"Court, theatre and folk music of China, Japan, Korea and Inner Asia.","ex":"guqin, koto, gayageum, khoomei","region":"China, Japan, Korea, Mongolia, Tuva","note":"Many share a heritage of pentatonic scales and silk-and-bamboo instruments."},"children":[{"name":"Chinese Traditions","v":10,"meta":{"def":"Music of Chinese scholars, opera stages and folk ensembles.","ex":"guqin, pipa, erhu, Peking opera","region":"China","note":"The scholar's guqin is among the world's oldest continuous solo traditions."},"children":[{"name":"Guqin","v":4,"meta":{"def":"A seven-string zither of the literati prized for its subtle, meditative tone.","ex":"'Flowing Water', tablature notation","region":"China","note":"A guqin recording was placed on the Voyager Golden Record."}},{"name":"Pipa and Silk-and-Bamboo","v":4,"meta":{"def":"The pear-shaped lute and the chamber ensembles of southern Chinese teahouses.","ex":"pipa, dizi, sheng, sizhu ensemble","region":"China (Jiangnan region)","note":"'Ambush from All Sides' is a famous battle-depicting pipa piece."}},{"name":"Peking Opera","v":5,"meta":{"def":"A stylised music-theatre blending song, mime, acrobatics and martial arts.","ex":"jinghu fiddle, painted faces, role types","region":"China (Beijing)","note":"Painted-face makeup colours signal each character's temperament."}}]},{"name":"Japanese Traditions","v":12,"meta":{"def":"Court, theatre, folk and percussion music of Japan.","ex":"gagaku, shakuhachi, koto, taiko","region":"Japan","note":"Aesthetics prize ma, the meaningful silence between sounds."},"children":[{"name":"Gagaku","v":4,"meta":{"def":"Ancient imperial court music and dance, among the oldest orchestral traditions alive.","ex":"sho mouth-organ, hichiriki, ryuteki","region":"Japan","note":"Maintained by the Imperial Household Agency for over a millennium."}},{"name":"Shakuhachi","v":4,"meta":{"def":"An end-blown bamboo flute used by Zen monks for meditative honkyoku pieces.","ex":"honkyoku, komuso monks","region":"Japan","note":"Playing was once a form of 'blowing Zen' spiritual practice."}},{"name":"Koto","v":4,"meta":{"def":"A long thirteen-string zither central to Japanese chamber music.","ex":"'Rokudan', Michio Miyagi, sokyoku","region":"Japan","note":"Pitch is bent by pressing strings behind the movable bridges."}},{"name":"Min'yo Folk Song","v":4,"meta":{"def":"Regional Japanese folk songs tied to work, festivals and local life.","ex":"'Soran Bushi', shamisen accompaniment","region":"Japan","note":"Many originated as fishermen's or labourers' work songs."}},{"name":"Taiko","v":4,"meta":{"def":"Powerful ensemble drumming rooted in festival and temple traditions.","ex":"odaiko, Kodo, kumi-daiko","region":"Japan","note":"Modern ensemble taiko (kumi-daiko) dates only to the 1950s."}}]},{"name":"Korean Traditions","v":10,"meta":{"def":"Court, folk and dramatic music collectively known as gugak.","ex":"gayageum, pansori, samul nori","region":"Korea","note":"Han, a deep collective sorrow, colours much Korean expression."},"children":[{"name":"Pansori","v":5,"meta":{"def":"Epic dramatic storytelling by a solo singer with a single drummer.","ex":"'Chunhyangga', buk drum, sori","region":"Korea","note":"A full performance can last several hours."}},{"name":"Gugak (Court and Folk)","v":4,"meta":{"def":"The umbrella of traditional Korean music from refined court to lively folk.","ex":"gayageum, geomungo, aak court music","region":"Korea","note":"Aak is a rare surviving form of ancient Confucian ritual music."}},{"name":"Samul Nori","v":4,"meta":{"def":"Vigorous percussion quartet derived from rural farmers' band music.","ex":"kkwaenggwari, janggu, buk, jing","region":"Korea","note":"The four instruments symbolise wind, rain, clouds and thunder."}}]},{"name":"Central Asian Overtone Singing","v":6,"meta":{"def":"Throat-singing traditions producing multiple pitches from one voice.","ex":"khoomei, sygyt, kargyraa","region":"Mongolia, Tuva, Altai","note":"Singers isolate harmonic overtones to sound two notes at once."},"children":[{"name":"Mongolian Khoomei","v":4,"meta":{"def":"Mongolian throat singing evoking the sounds of the steppe landscape.","ex":"morin khuur, long-song, urtiin duu","region":"Mongolia","note":"The morin khuur horse-head fiddle is a national symbol."}},{"name":"Tuvan Throat Singing","v":4,"meta":{"def":"Siberian overtone singing imitating wind, water and animals.","ex":"Huun-Huur-Tu, igil, doshpuluur","region":"Tuva (Russia)","note":"Herders traditionally sang to soothe animals and the land."}}]},{"name":"Further East Asian Forms","v":14,"meta":{"def":"Additional opera, zither and lute traditions of the region.","ex":"kunqu, guzheng, noh, sanjo","region":"China, Japan, Korea","note":"Regional opera styles number in the hundreds across China alone."},"children":[{"name":"Kunqu Opera","v":4,"meta":{"def":"The oldest surviving Chinese opera, refined, lyrical and slow.","ex":"dizi flute, water-sleeve dance","region":"China (Jiangsu)","note":"It shaped nearly all later Chinese opera forms."}},{"name":"Cantonese Opera","v":4,"meta":{"def":"Popular southern Chinese opera blending song, martial arts and spectacle.","ex":"gaohu, yueju, folding fans","region":"Guangdong and Hong Kong","note":"Widely sustained by overseas Cantonese communities."}},{"name":"Guzheng","v":4,"meta":{"def":"A large plucked zither with movable bridges and a bright cascading tone.","ex":"'Fishermen's Song', pitch-bending","region":"China","note":"An ancestor of the Japanese koto and Korean gayageum."}},{"name":"Noh Theatre Music","v":4,"meta":{"def":"The sparse flute-and-drum music of Japan's masked Noh drama.","ex":"nohkan flute, kotsuzumi, hayashi","region":"Japan","note":"Drummers punctuate the stage with sharp vocal calls (kakegoe)."}},{"name":"Biwa","v":4,"meta":{"def":"A pear-shaped lute used to chant epic war tales and Buddhist story.","ex":"'Tale of the Heike', heikyoku","region":"Japan","note":"Blind priest-musicians once recited history to its accompaniment."}},{"name":"Okinawan Sanshin","v":4,"meta":{"def":"Snakeskin-covered three-string lute at the heart of Ryukyuan song.","ex":"sanshin, kachashi dance, min'yo","region":"Okinawa, Japan","note":"Its distinctive scale sets Okinawan music apart from mainland Japan."}},{"name":"Korean Sanjo","v":4,"meta":{"def":"Virtuosic solo instrumental music unfolding from slow to fast tempo.","ex":"gayageum, geomungo, janggu","region":"Korea","note":"Sanjo means 'scattered melodies', improvised over a drum cycle."}}]}]},{"name":"Southeast Asian Traditions","v":8,"meta":{"def":"Gong-chime and ensemble music of maritime and mainland Southeast Asia.","ex":"gamelan, piphat, kulintang","region":"Indonesia, Thailand, Vietnam, Philippines","note":"Tuned gong-chime ensembles are a defining regional feature."},"children":[{"name":"Indonesian Gamelan","v":8,"meta":{"def":"Interlocking metallophone and gong orchestras of Java and Bali.","ex":"gongs, metallophones, colotomic form","region":"Indonesia (Java and Bali)","note":"Instruments are treated as sacred and given offerings."},"children":[{"name":"Javanese Gamelan","v":4,"meta":{"def":"Refined, meditative court gamelan of Central Java.","ex":"slendro and pelog tunings, gender, rebab","region":"Java, Indonesia","note":"Often accompanies wayang shadow-puppet theatre."}},{"name":"Balinese Gamelan","v":4,"meta":{"def":"Bright, explosive gamelan famed for its rapid interlocking kotekan.","ex":"gong kebyar, reyong, ceng-ceng","region":"Bali, Indonesia","note":"Paired instruments are deliberately detuned to create a shimmering beat."}}]},{"name":"Mainland and Island Ensembles","v":6,"meta":{"def":"Classical and folk ensembles of Thailand, Vietnam and the Philippines.","ex":"piphat, dan bau, kulintang","region":"Thailand, Vietnam, Philippines","note":"Each culture tunes its gongs and idiophones distinctively."},"children":[{"name":"Thai Piphat","v":4,"meta":{"def":"A percussion-and-wind classical ensemble for theatre and ceremony.","ex":"pi oboe, ranat xylophone, khong wong gongs","region":"Thailand","note":"Accompanies khon masked dance-drama of the Ramakien."}},{"name":"Vietnamese Traditional","v":4,"meta":{"def":"Chamber and ceremonial music noted for pitch-bending instruments.","ex":"dan bau monochord, dan tranh, ca tru, nha nhac","region":"Vietnam","note":"The one-string dan bau bends notes with a flexible rod."}},{"name":"Filipino Kulintang","v":4,"meta":{"def":"Melodic gong-row ensemble music of the southern Philippine peoples.","ex":"kulintang gong-row, agung, dabakan","region":"Mindanao, Philippines","note":"A rare Philippine tradition that predates Spanish colonisation."}}]},{"name":"Other Regional Ensembles","v":12,"meta":{"def":"Harp, gong and free-reed traditions across the wider region.","ex":"saung, pinpeat, khene, qeej","region":"Myanmar, Cambodia, Laos, Vietnam","note":"Free-reed mouth organs are an ancient regional invention."},"children":[{"name":"Burmese Saung","v":4,"meta":{"def":"The arched harp of Burma, one of few surviving harp traditions in Asia.","ex":"saung gauk, hsaing waing ensemble","region":"Myanmar","note":"Its curved neck and boat-shaped body date back over a millennium."}},{"name":"Cambodian Pinpeat","v":4,"meta":{"def":"A gong-and-xylophone ensemble for court dance and temple ritual.","ex":"roneat, kong vong, sralai","region":"Cambodia","note":"It accompanies the classical Apsara dance of the royal court."}},{"name":"Lao Khene","v":4,"meta":{"def":"Music of the bamboo mouth organ, emblem of Lao identity.","ex":"khene, lam singing, mor lam","region":"Laos and northeast Thailand","note":"The khene can sound several notes at once like a portable organ."}},{"name":"Sundanese Degung","v":4,"meta":{"def":"A gentle West Javanese gamelan style with flute and zither.","ex":"suling flute, kacapi zither, degung","region":"West Java, Indonesia","note":"Distinct from Central Javanese gamelan in tuning and mood."}},{"name":"Hmong Qeej","v":4,"meta":{"def":"A free-reed pipe whose 'speaking' tones guide funeral rites.","ex":"qeej, courtship songs, funeral music","region":"Southeast Asian highlands","note":"The qeej addresses the soul of the deceased at funerals."}}]}]},{"name":"Sub-Saharan African Traditions","v":12,"meta":{"def":"Diverse oral, polyrhythmic and praise-song traditions across Africa.","ex":"kora, mbira, talking drum, griot","region":"West, Central, East and Southern Africa","note":"Interlocking polyrhythm and call-and-response are widespread features."},"children":[{"name":"West African Griot","v":10,"meta":{"def":"Hereditary praise-singers and oral historians of the Mande world.","ex":"kora, balafon, ngoni, jali","region":"Mali, Senegal, Gambia, Guinea","note":"Griots preserve genealogies and epics across generations."},"children":[{"name":"Kora and Jali Music","v":5,"meta":{"def":"The 21-string harp-lute and the epic praise-repertoire of the griots.","ex":"Toumani Diabate, Sunjata epic","region":"Mali, Gambia, Guinea","note":"The kora fuses a harp's strings with a lute's bridge."}},{"name":"Talking Drum","v":4,"meta":{"def":"Hourglass drums whose pitch bends to mimic the tones of speech.","ex":"dundun, gangan, Yoruba praise","region":"Nigeria and West Africa","note":"Squeezing the tension cords changes the drum's pitch mid-stroke."}},{"name":"Malian Desert Blues","v":4,"meta":{"def":"Hypnotic guitar music of the Sahara linked to the roots of the blues.","ex":"Ali Farka Toure, Tinariwen, ngoni","region":"Mali and the Sahel","note":"Tuareg 'assouf' expresses longing and desert exile."}}]},{"name":"Southern and Central African","v":10,"meta":{"def":"Choral, thumb-piano and rumba traditions of the south and centre.","ex":"mbira, isicathamiya, Congolese rumba","region":"Zimbabwe, South Africa, DR Congo","note":"Vocal harmony and cyclic patterns run deep across the region."},"children":[{"name":"Mbira","v":4,"meta":{"def":"A metal-tined thumb piano used to summon ancestral spirits.","ex":"mbira dzavadzimu, bira ceremony","region":"Zimbabwe (Shona people)","note":"Its buzzing bottle-cap resonators are considered essential."}},{"name":"Isicathamiya and Mbube","v":4,"meta":{"def":"Zulu a cappella choral singing developed by migrant mine workers.","ex":"Ladysmith Black Mambazo, 'Mbube'","region":"South Africa (Zulu)","note":"'Isicathamiya' refers to the soft tip-toe dance steps used."}},{"name":"Congolese Rumba and Soukous","v":4,"meta":{"def":"Guitar-led urban dance music that swept across the continent.","ex":"Franco, Tabu Ley, sebene guitar","region":"DR Congo and Congo-Brazzaville","note":"UNESCO listed Congolese rumba as world heritage in 2021."}}]},{"name":"East African and Ethiopian","v":6,"meta":{"def":"Modal and taarab traditions of the Horn and Swahili coast.","ex":"qenet modes, krar, taarab","region":"Ethiopia, Eritrea, Tanzania, Kenya","note":"Ethiopian music uses distinctive pentatonic modes unlike its neighbours."},"children":[{"name":"Ethiopian Qenet","v":4,"meta":{"def":"The four core pentatonic modes underpinning Ethiopian song.","ex":"tizita, bati, krar lyre, masinko","region":"Ethiopia","note":"'Tizita' evokes nostalgic longing, like a blues of the highlands."}},{"name":"Taarab","v":4,"meta":{"def":"Swahili coastal song fusing African, Arab and Indian elements.","ex":"oud, Siti binti Saad, Zanzibar","region":"Zanzibar and East African coast","note":"Sung in Swahili with poetic, often coded, love lyrics."}}]},{"name":"African Popular Roots","v":14,"meta":{"def":"Modern urban dance genres grown from traditional African music.","ex":"afrobeat, highlife, juju, mbalax","region":"West, East and Southern Africa","note":"These styles carried African music onto the world stage."},"children":[{"name":"Afrobeat","v":4,"meta":{"def":"Fela Kuti's fusion of Yoruba rhythm, jazz, funk and political fire.","ex":"Fela Kuti, Tony Allen, horn riffs","region":"Nigeria","note":"Not to be confused with the modern pop genre Afrobeats."}},{"name":"Highlife","v":4,"meta":{"def":"Melodic guitar-and-horn dance music of the West African coast.","ex":"palm-wine guitar, dance bands","region":"Ghana and Nigeria","note":"Named for the elite 'high life' clubs where it first flourished."}},{"name":"Juju and Fuji","v":4,"meta":{"def":"Yoruba percussion-and-guitar praise music and its drum-led offshoot.","ex":"King Sunny Ade, talking drum, fuji","region":"Nigeria (Yoruba)","note":"Fuji grew from the songs waking Muslims for Ramadan meals."}},{"name":"Mbalax","v":4,"meta":{"def":"Fast, polyrhythmic Senegalese dance pop driven by the sabar drum.","ex":"Youssou N'Dour, sabar, tama","region":"Senegal","note":"The lead sabar drummer trades breaks with the dancers."}},{"name":"Benga","v":4,"meta":{"def":"Bright, fast Kenyan guitar pop derived from Luo nyatiti lyre music.","ex":"lilting guitar, Luo lyrics","region":"Kenya","note":"It translated the plucked lyre's patterns onto electric guitar."}},{"name":"Mbaqanga","v":4,"meta":{"def":"Groove-driven South African township jive with deep 'groaner' vocals.","ex":"Mahlathini, Mahotella Queens","region":"South Africa","note":"The bass 'groaner' voice is a signature of the style."}},{"name":"Chimurenga","v":4,"meta":{"def":"Guitar music translating mbira patterns into songs of liberation.","ex":"Thomas Mapfumo, mbira-guitar","region":"Zimbabwe","note":"'Chimurenga' means struggle, tied to the independence war."}}]}]},{"name":"European Folk Traditions","v":14,"meta":{"def":"Regional folk, dance and vocal traditions across Europe.","ex":"flamenco, fado, klezmer, joik","region":"Europe","note":"Ranges from solo laments to dense vocal polyphony."},"children":[{"name":"Celtic Traditions","v":8,"meta":{"def":"Song and dance music of Ireland, Scotland and the Celtic fringe.","ex":"fiddle, uilleann pipes, bodhran","region":"Ireland, Scotland, Brittany","note":"Dance tunes are grouped into jigs, reels and hornpipes."},"children":[{"name":"Sean-nos Singing","v":4,"meta":{"def":"Unaccompanied, highly ornamented old-style Irish Gaelic singing.","ex":"melisma, Connemara style","region":"Gaelic-speaking Ireland","note":"Singers vary ornamentation freely with each verse."}},{"name":"Ceilidh and Dance Music","v":4,"meta":{"def":"Social gathering music for group set-dances and reels.","ex":"fiddle, accordion, jigs and reels","region":"Ireland and Scotland","note":"A caller often guides dancers through the figures."}},{"name":"Scottish Piping","v":4,"meta":{"def":"The Great Highland bagpipe tradition of marches and classical pibroch.","ex":"piobaireachd, Highland pipes","region":"Scotland","note":"Pibroch (ceol mor) is the pipes' 'great music' theme-and-variation art."}}]},{"name":"Iberian Traditions","v":6,"meta":{"def":"Passionate solo song traditions of Spain and Portugal.","ex":"flamenco, fado, guitar","region":"Spain and Portugal","note":"Both carry a deep sense of fate and emotional intensity."},"children":[{"name":"Flamenco","v":5,"meta":{"def":"Andalusian art of cante song, guitar and percussive dance.","ex":"cante jondo, palos, palmas, Paco de Lucia","region":"Andalusia, Spain (Romani roots)","note":"Duende is the elusive spirit of profound, soulful performance."}},{"name":"Fado","v":4,"meta":{"def":"Melancholic Portuguese urban song expressing saudade, or wistful longing.","ex":"Amalia Rodrigues, Portuguese guitarra","region":"Lisbon and Coimbra, Portugal","note":"The word fado means 'fate'."}}]},{"name":"Balkan and Eastern European","v":8,"meta":{"def":"Asymmetric-rhythm dance music and dense vocal polyphony.","ex":"brass bands, kaval, tamburica","region":"Balkans and Eastern Europe","note":"Irregular metres like 7/8 and 11/8 are commonplace."},"children":[{"name":"Bulgarian Voices","v":4,"meta":{"def":"Female choral singing with piercing timbre and close dissonant harmony.","ex":"Le Mystere des Voix Bulgares, diaphonic seconds","region":"Bulgaria","note":"Deliberate 'clashing' seconds produce a ringing resonance."}},{"name":"Klezmer","v":4,"meta":{"def":"Celebratory instrumental dance music of Ashkenazi Jewish Europe.","ex":"clarinet, freylekhs, doina","region":"Eastern European Jewish diaspora","note":"The clarinet's 'laughing and weeping' voice is a hallmark."}},{"name":"Balkan Brass","v":4,"meta":{"def":"Explosive Roma-led brass band music for weddings and festivals.","ex":"Guca festival, Boban Markovic, kolo","region":"Serbia and North Macedonia","note":"The Guca trumpet festival draws hundreds of thousands yearly."}}]},{"name":"Nordic and Alpine","v":8,"meta":{"def":"Fiddle, herding-call and indigenous traditions of northern Europe.","ex":"Hardanger fiddle, joik, yodel","region":"Scandinavia and the Alps","note":"Herding calls carry the human voice across mountains and valleys."},"children":[{"name":"Nordic Fiddle","v":4,"meta":{"def":"Folk dance music centred on resonant sympathetic-string fiddles.","ex":"Hardanger fiddle, nyckelharpa, polska","region":"Norway and Sweden","note":"The Hardanger fiddle's under-strings ring in sympathy unbowed."}},{"name":"Sami Joik","v":4,"meta":{"def":"Indigenous Sami vocal chant that evokes rather than describes its subject.","ex":"Mari Boine, personal joiks","region":"Sapmi (northern Scandinavia)","note":"A joik does not describe a person; it is the person in song."}},{"name":"Alpine Yodeling","v":4,"meta":{"def":"Wordless singing with rapid switches between chest and falsetto voice.","ex":"juchz, alphorn, Naturjodel","region":"Swiss and Austrian Alps","note":"Grew from herders' calls used to communicate across peaks."}}]},{"name":"Mediterranean Polyphony","v":6,"meta":{"def":"Rare multi-part vocal traditions of islands and mountains.","ex":"cantu a tenore, Georgian chant","region":"Sardinia, Corsica, Georgia","note":"Some of Europe's oldest surviving polyphonic styles."},"children":[{"name":"Sardinian Cantu a Tenore","v":4,"meta":{"def":"Male quartet singing with two guttural throat-produced voices.","ex":"bassu, contra, mesu boche","region":"Sardinia, Italy","note":"The bassu and contra imitate cattle and wind sounds."}},{"name":"Georgian Polyphony","v":4,"meta":{"def":"Ancient three-part harmony singing, sacred and secular.","ex":"'Chakrulo', Rustavi Choir","region":"Georgia (Caucasus)","note":"A Georgian song rides aboard the Voyager Golden Record."}}]},{"name":"Continental Folk and Song","v":14,"meta":{"def":"Dance and song traditions across mainland and Mediterranean Europe.","ex":"polka, csardas, rebetiko, tarantella","region":"Central and Southern Europe","note":"Many spread widely with 19th-century migration."},"children":[{"name":"Bohemian Polka","v":4,"meta":{"def":"A bouncy couples' dance in brisk duple time that swept 1800s Europe.","ex":"accordion, brass band, oom-pah","region":"Bohemia (Czech lands)","note":"It became a craze in the ballrooms of Paris and beyond."}},{"name":"Hungarian Csardas","v":4,"meta":{"def":"A folk dance moving from slow lassu to whirling friss, led by Roma bands.","ex":"violin, cimbalom, verbunkos","region":"Hungary","note":"Its structure inspired Liszt and Brahms."}},{"name":"French Musette","v":4,"meta":{"def":"The accordion 'bal-musette' dance music of Parisian dance halls.","ex":"accordion, valse musette, java","region":"France","note":"Italian immigrants helped make the accordion its signature voice."}},{"name":"Greek Rebetiko","v":4,"meta":{"def":"Urban 'Greek blues' of the port underworld and refugee quarters.","ex":"bouzouki, baglama, hashish songs","region":"Greece","note":"Flourished among refugees from Asia Minor after 1922."}},{"name":"Corsican Paghjella","v":4,"meta":{"def":"Three-part male polyphonic singing of the Mediterranean island.","ex":"a cappella, sacred and secular","region":"Corsica, France","note":"Listed by UNESCO as heritage in urgent need of safeguarding."}},{"name":"Sephardic Ladino Song","v":4,"meta":{"def":"Romances and ballads of Judeo-Spanish exiles in the old tongue.","ex":"Ladino romances, oud, laud","region":"Sephardic Mediterranean diaspora","note":"Preserves a form of medieval Spanish frozen in song for centuries."}},{"name":"Italian Tarantella","v":4,"meta":{"def":"A whirling southern dance once thought to cure a spider's bite.","ex":"tambourine, mandolin, pizzica","region":"Southern Italy","note":"Legend held frenzied dancing sweated out the tarantula's venom."}}]}]},{"name":"Traditions of the Americas","v":14,"meta":{"def":"Indigenous, African-descended and creolised music of the Americas.","ex":"samba, tango, blues, mariachi","region":"North, Central and South America, Caribbean","note":"Shaped by the meeting of Indigenous, African and European cultures."},"children":[{"name":"North American Roots","v":12,"meta":{"def":"Indigenous, Appalachian and African-American folk roots of the US.","ex":"blues, gospel, old-time, zydeco","region":"United States","note":"The blues and gospel became the seedbed of most 20th-century pop."},"children":[{"name":"Native American Music","v":4,"meta":{"def":"Ceremonial and social song and drum traditions of Indigenous nations.","ex":"powwow drum, vocables, courting flute","region":"United States and Canada","note":"Many songs use vocables, syllables without lexical meaning."}},{"name":"Appalachian Old-Time","v":4,"meta":{"def":"Fiddle-and-banjo string-band music of the mountain South.","ex":"clawhammer banjo, ballads, square dance","region":"Appalachia, United States","note":"Carries British Isles ballads preserved through isolation."}},{"name":"Blues Roots","v":5,"meta":{"def":"African-American secular song born of hardship in the Deep South.","ex":"Delta blues, twelve-bar form, Robert Johnson","region":"Mississippi Delta, United States","note":"The 'blue notes' bend the third and seventh of the scale."}},{"name":"Gospel and Spirituals","v":4,"meta":{"def":"African-American sacred song from plantation spirituals to church gospel.","ex":"call-and-response, Mahalia Jackson","region":"United States","note":"Spirituals often coded messages about escape and freedom."}},{"name":"Cajun and Zydeco","v":4,"meta":{"def":"French-Louisiana dance music of the Cajun and Creole communities.","ex":"accordion, fiddle, washboard, frottoir","region":"Louisiana, United States","note":"Zydeco adds bluesy Creole rhythm and the rubboard vest."}}]},{"name":"Latin American Folk","v":12,"meta":{"def":"Regional song and dance traditions of Mexico and South America.","ex":"mariachi, samba, tango, huayno","region":"Mexico, Brazil, Argentina, Andes","note":"Blends Iberian song forms with Indigenous and African rhythm."},"children":[{"name":"Mexican Son and Mariachi","v":5,"meta":{"def":"Regional string traditions and the emblematic mariachi ensemble.","ex":"son jarocho, huapango, vihuela, guitarron","region":"Mexico","note":"The falsetto shout, the grito, punctuates the music with feeling."}},{"name":"Andean Music","v":5,"meta":{"def":"Highland song and panpipe traditions of the Quechua and Aymara.","ex":"huayno, sikuri panpipes, charango, quena","region":"Peru, Bolivia, Ecuador","note":"Sikuri panpipes are split so two players must interlock the melody."}},{"name":"Brazilian Traditions","v":6,"meta":{"def":"Afro-Brazilian and northeastern song and dance genres.","ex":"samba, forro, choro, maracatu","region":"Brazil","note":"Samba schools parade for the Rio carnival competition."}},{"name":"Argentine Tango","v":4,"meta":{"def":"Passionate urban dance-song born in the ports of the River Plate.","ex":"bandoneon, Carlos Gardel, Piazzolla","region":"Argentina and Uruguay","note":"The bandoneon's plaintive wheeze defines the tango sound."}}]},{"name":"Caribbean Traditions","v":8,"meta":{"def":"African-rooted dance and drum traditions of the islands.","ex":"son, rumba, calypso, reggae","region":"Cuba, Jamaica, Trinidad","note":"Percussion and clave rhythm anchor most island styles."},"children":[{"name":"Cuban Son and Rumba","v":5,"meta":{"def":"Foundational Afro-Cuban song and drum-and-voice folk forms.","ex":"son, rumba, danzon, clave, tres","region":"Cuba","note":"The clave rhythmic pattern is the backbone of the whole system."}},{"name":"Trinidadian Calypso and Steelpan","v":4,"meta":{"def":"Witty topical song and the tuned oil-drum steelpan of carnival.","ex":"calypso, soca, steel band","region":"Trinidad and Tobago","note":"The steelpan is one of the few acoustic instruments invented in the 20th century."}},{"name":"Jamaican Roots","v":4,"meta":{"def":"Rhythmic Jamaican forms from mento to reggae and dub.","ex":"mento, ska, reggae, Nyabinghi drumming","region":"Jamaica","note":"Nyabinghi hand-drumming underlies Rastafari worship."}}]},{"name":"More American Traditions","v":14,"meta":{"def":"Further roots, string-band and Afro-Latin genres of the Americas.","ex":"bluegrass, cumbia, joropo, bomba","region":"United States, Colombia, Venezuela, Caribbean","note":"String bands and drum choirs shaped distinct regional identities."},"children":[{"name":"Bluegrass","v":4,"meta":{"def":"Fast, virtuosic acoustic string-band music with high lonesome harmony.","ex":"Bill Monroe, banjo, mandolin, breakdown","region":"Appalachian United States","note":"Named after Bill Monroe's Blue Grass Boys."}},{"name":"Sacred Harp","v":4,"meta":{"def":"Loud, unaccompanied shape-note hymn singing in a hollow square.","ex":"fasola, four-part hymns","region":"American South","note":"Singers read notes by their printed shapes, not pitch names."}},{"name":"Tex-Mex Conjunto","v":4,"meta":{"def":"Accordion-and-bajo sexto border music of Mexican-American Texas.","ex":"accordion, bajo sexto, polka, corrido","region":"Texas-Mexico border","note":"German settlers' accordions met Mexican song along the Rio Grande."}},{"name":"Colombian Cumbia","v":4,"meta":{"def":"Coastal courtship dance blending Indigenous flutes and African drums.","ex":"gaita flute, tambora, guacharaca","region":"Colombia","note":"It spread across Latin America into countless national variants."}},{"name":"Venezuelan Joropo","v":4,"meta":{"def":"Fast harp-and-cuatro dance music of the cattle plains.","ex":"arpa llanera, cuatro, maracas","region":"Venezuela and Colombia (Llanos)","note":"The plains harp drives its galloping triple rhythm."}},{"name":"Haitian Vodou and Kompa","v":4,"meta":{"def":"Sacred drumming for the lwa and the smooth kompa dance music it fed.","ex":"rada drums, kompa, Nemours Jean-Baptiste","region":"Haiti","note":"Different drum rhythms summon different Vodou spirits."}},{"name":"Puerto Rican Bomba and Plena","v":4,"meta":{"def":"Afro-Puerto Rican drum-and-dance and its news-bearing song cousin.","ex":"barril drums, pandereta, call-and-response","region":"Puerto Rico","note":"In bomba the dancer, not the drummer, leads the rhythm."}}]}]},{"name":"Oceanian Traditions","v":8,"meta":{"def":"Indigenous song, chant and instrument traditions of the Pacific.","ex":"didgeridoo, haka, waiata","region":"Australia, New Zealand, Polynesia","note":"Song often maps land, genealogy and sacred story."},"children":[{"name":"Aboriginal Australian","v":6,"meta":{"def":"The world's oldest continuous musical culture, tied to Country and Dreaming.","ex":"didgeridoo, clapsticks, songlines","region":"Australia","note":"Songlines encode maps and law across vast distances."},"children":[{"name":"Didgeridoo","v":4,"meta":{"def":"A drone wind instrument played with continuous circular breathing.","ex":"yidaki, circular breathing, clapsticks","region":"Arnhem Land, northern Australia","note":"Traditionally a men's instrument from the far north."}},{"name":"Songlines and Corroboree","v":4,"meta":{"def":"Ceremonial song-cycles narrating creation journeys across the land.","ex":"clapsticks, body paint, corroboree","region":"Australia","note":"A song can serve as a navigational map of the terrain."}}]},{"name":"Maori and Polynesian","v":6,"meta":{"def":"Chant, song and rhythmic dance of the Pacific island peoples.","ex":"haka, waiata, poi, hula","region":"New Zealand and Polynesia","note":"Vocal chant and body percussion often replace melodic instruments."},"children":[{"name":"Maori Waiata and Haka","v":4,"meta":{"def":"Sung poetry and the fierce rhythmic posture dance of the Maori.","ex":"haka, waiata, poi, karakia","region":"New Zealand (Aotearoa)","note":"'Ka Mate' is the haka famously performed by the All Blacks."}},{"name":"Polynesian Chant and Dance","v":4,"meta":{"def":"Genealogical chant and hip-swaying narrative dance of the islands.","ex":"Hawaiian hula, mele, Tahitian ote'a","region":"Hawaii, Tahiti, Samoa","note":"The hula's hand gestures tell the story the chant relates."}}]},{"name":"Melanesian and Micronesian","v":8,"meta":{"def":"Chant, panpipe and dance traditions of the western and central Pacific.","ex":"sing-sing, meke, panpipes","region":"Papua New Guinea, Fiji, Solomon Islands","note":"Vast island diversity yields hundreds of distinct song languages."},"children":[{"name":"PNG Sing-sing","v":4,"meta":{"def":"Massed festival gatherings of song, drum and feathered dance display.","ex":"kundu drum, garamut slit-drum","region":"Papua New Guinea","note":"Clans gather to display their ancestral songs and regalia."}},{"name":"Fijian Meke","v":4,"meta":{"def":"Narrative dance-song accompanied by chant and body percussion.","ex":"lali slit-drum, seated meke, clapping","region":"Fiji","note":"Meke are believed to be inspired by ancestral spirits."}},{"name":"Solomon Islands Panpipes","v":4,"meta":{"def":"Interlocking bamboo panpipe ensembles of remarkable complexity.","ex":"'Are'are bamboo pipes, water music","region":"Solomon Islands","note":"'Are'are pipers use precise mathematical tuning ratios."}},{"name":"Rapa Nui Chant","v":4,"meta":{"def":"Polynesian dance and chant of the remote Easter Island.","ex":"riu chant, kaikai string-figures","region":"Rapa Nui (Easter Island)","note":"Chants once accompanied recitation of the rongorongo script."}}]}]},{"name":"Music's Cultural Roles","v":12,"meta":{"def":"The social and spiritual functions music serves across humanity.","ex":"ritual, work song, lullaby, anthem","region":"Universal","note":"Nearly every human society uses music to mark life's key moments."},"children":[{"name":"Sacred and Religious","v":10,"meta":{"def":"Music as worship, liturgy and pathway to the divine.","ex":"chant, hymn, call to prayer","region":"Worldwide","note":"Many faiths debate the very boundary between music and sacred sound."},"children":[{"name":"Liturgical Chant","v":5,"meta":{"def":"Monophonic sacred singing of scripture and prayer in worship.","ex":"Gregorian chant, Byzantine, Vedic, Quranic tajwid","region":"Worldwide","note":"Gregorian chant gave rise to Western musical notation."}},{"name":"Hymns and Worship Song","v":4,"meta":{"def":"Congregational sacred songs of praise and communal devotion.","ex":"Lutheran chorale, contemporary worship","region":"Worldwide","note":"Luther used hymns to bring worship into the common tongue."}},{"name":"Healing and Trance","v":4,"meta":{"def":"Music to induce altered states, spirit possession and healing.","ex":"Gnawa lila, shamanic drum, Sufi zikr","region":"Worldwide","note":"Moroccan Gnawa music guides all-night healing trance ceremonies."}}]},{"name":"Life-Cycle and Communal","v":10,"meta":{"def":"Songs marking birth, labour, love, marriage and death.","ex":"lullaby, work song, wedding, lament","region":"Universal","note":"These songs bind communities through shared ritual."},"children":[{"name":"Work Songs","v":4,"meta":{"def":"Rhythmic songs that coordinate and ease collective labour.","ex":"sea shanties, field hollers, railroad songs","region":"Worldwide","note":"The pulse of the song matched the pace of the shared task."}},{"name":"Lullabies","v":4,"meta":{"def":"Gentle cradle songs sung to soothe infants to sleep.","ex":"'Wiegenlied', 'Nana', 'Suo Gan'","region":"Universal","note":"Lullaby melodies show striking similarities across cultures."}},{"name":"Wedding and Funeral Music","v":4,"meta":{"def":"Ceremonial music framing the rites of marriage and mourning.","ex":"keening, New Orleans jazz funeral, wedding brass","region":"Worldwide","note":"A New Orleans funeral turns from dirge to joyful 'second line'."}}]},{"name":"Social and Political","v":8,"meta":{"def":"Music as protest, memory, national identity and martial spirit.","ex":"protest song, anthem, praise singing","region":"Worldwide","note":"Song can rally movements and record a people's history."},"children":[{"name":"Protest Song","v":4,"meta":{"def":"Music voicing dissent and mobilising social and political movements.","ex":"'We Shall Overcome', Fela Kuti, nueva cancion","region":"Worldwide","note":"Chile's nueva cancion soundtracked its 1960s social struggles."}},{"name":"National Anthems","v":4,"meta":{"def":"Official songs symbolising a nation's identity and unity.","ex":"'La Marseillaise', ceremonial performance","region":"Worldwide","note":"'La Marseillaise' began as a revolutionary war marching song."}},{"name":"Military and Martial","v":4,"meta":{"def":"Music to signal, march and steel troops in the field.","ex":"bugle calls, fife and drum, pipe bands","region":"Worldwide","note":"Bugle calls once relayed commands across a noisy battlefield."}},{"name":"Oral History and Praise","v":4,"meta":{"def":"Sung genealogy and eulogy preserving a community's memory.","ex":"griot epic, izibongo praise poetry","region":"Africa and worldwide","note":"Zulu izibongo praise-poets chant a chief's deeds and lineage."}}]},{"name":"More Cultural Functions","v":10,"meta":{"def":"Further everyday and ceremonial uses of music in society.","ex":"initiation, terrace chant, carnival","region":"Universal","note":"Music marks belonging as much as any single occasion."},"children":[{"name":"Initiation and Coming-of-Age","v":4,"meta":{"def":"Songs marking a young person's passage into adulthood.","ex":"circumcision songs, debut ceremonies","region":"Worldwide","note":"Such songs often transmit secret or gendered knowledge."}},{"name":"Sports and Terrace Chants","v":4,"meta":{"def":"Collective singing that binds fans and rallies a crowd.","ex":"football terraces, haka, fight songs","region":"Worldwide","note":"'You'll Never Walk Alone' became an anthem of the football stands."}},{"name":"Carnival and Masquerade","v":4,"meta":{"def":"Music driving processions where masked revellers upend the social order.","ex":"carnival bands, egungun, mummers","region":"Worldwide","note":"Masking lets communities safely mock power for a season."}},{"name":"Children's Game Songs","v":4,"meta":{"def":"Rhymes and songs passed among children at play.","ex":"clapping games, ring games, skipping rhymes","region":"Universal","note":"This oral 'playground lore' spreads with little adult involvement."}},{"name":"Seasonal and Carol Song","v":4,"meta":{"def":"Songs tied to calendar festivals and turning of the seasons.","ex":"carols, wassailing, harvest songs","region":"Worldwide","note":"Wassailers once sang door to door in exchange for food and drink."}}]}]},{"name":"Scenes and Subcultures","v":12,"meta":{"def":"How musical genres bind communities into shared identities and lifestyles.","ex":"punk, hip-hop, rave, sound-system","region":"Global (modern urban)","note":"Dress, language and values cohere around a shared sound."},"children":[{"name":"Rebel and Alternative Scenes","v":10,"meta":{"def":"Youth subcultures defined by rejection of the mainstream.","ex":"punk, goth, metal, emo","region":"Global","note":"Fashion and ideology are as central as the music itself."},"children":[{"name":"Punk","v":4,"meta":{"def":"A DIY subculture of raw music, anti-establishment ethos and provocation.","ex":"mohawks, zines, mosh pit, 'DIY'","region":"UK and US (mid-1970s)","note":"'Do it yourself' rejected the need for professional polish."}},{"name":"Metalhead","v":4,"meta":{"def":"A tight-knit community around heavy metal's power, volume and virtuosity.","ex":"denim battle vests, headbanging, festivals","region":"Global","note":"Studies find metal fans to be unusually loyal and community-minded."}},{"name":"Goth","v":4,"meta":{"def":"A dark-romantic subculture built on post-punk's shadowy aesthetic.","ex":"black attire, pale makeup, Bauhaus","region":"UK (early 1980s)","note":"Grew out of the post-punk scene at London's Batcave club."}},{"name":"Emo","v":4,"meta":{"def":"An emotionally confessional guitar scene with a distinct fashion code.","ex":"swept fringes, skinny jeans, diary lyrics","region":"US (1980s hardcore roots)","note":"Short for 'emotional hardcore' from the DC punk scene."}}]},{"name":"Dance and Sound-System Culture","v":8,"meta":{"def":"Communities formed around the DJ, the dancefloor and the speaker stack.","ex":"rave, sound system, club culture","region":"Global","note":"The DJ, not the live band, is the focal artist."},"children":[{"name":"Rave","v":4,"meta":{"def":"All-night electronic dance gatherings built on collective euphoria.","ex":"acid house, PLUR, glow sticks, warehouses","region":"UK and beyond (late 1980s)","note":"'PLUR' stands for peace, love, unity and respect."}},{"name":"Jamaican Sound System","v":4,"meta":{"def":"Mobile speaker crews whose clashes shaped reggae and dub culture.","ex":"selector, toasting, dubplates, King Tubby","region":"Jamaica and UK diaspora","note":"Sound-system culture seeded hip-hop's DJ-and-MC format."}},{"name":"Club and DJ Culture","v":4,"meta":{"def":"The scenes around resident DJs, nightclubs and dance communities.","ex":"Paradise Garage, house, techno, superstar DJ","region":"Global (New York, Chicago, Detroit, Berlin)","note":"Disco's gay clubs of 1970s New York were its cradle."}}]},{"name":"Urban and Global Identities","v":8,"meta":{"def":"Music scenes that carry ethnic, class and generational identity worldwide.","ex":"hip-hop, rasta, mod, K-pop fandom","region":"Global","note":"Some grow from local roots into worldwide movements."},"children":[{"name":"Hip-Hop Culture","v":5,"meta":{"def":"A four-element culture of DJing, MCing, graffiti and breakdance.","ex":"turntablism, breakdance, graffiti, cyphers","region":"The Bronx, New York (1970s)","note":"Its founders codified DJing, MCing, b-boying and graffiti as its pillars."}},{"name":"Rasta and Reggae","v":4,"meta":{"def":"The Rastafari spiritual movement expressed through reggae music.","ex":"Bob Marley, dreadlocks, Nyabinghi, 'Jah'","region":"Jamaica","note":"Reggae carried Rastafari's message of resistance worldwide."}},{"name":"Mod","v":4,"meta":{"def":"A style-conscious British youth cult of sharp suits and scooters.","ex":"Vespa scooters, R&B, parkas, The Who","region":"United Kingdom (1960s)","note":"Mods and rockers famously clashed at English seaside towns."}},{"name":"K-pop Fandom","v":4,"meta":{"def":"Highly organised global fan communities around Korean pop idols.","ex":"fan clubs, lightsticks, streaming drives","region":"South Korea and worldwide","note":"Fandoms coordinate huge streaming and charity campaigns online."}}]},{"name":"More Scenes and Movements","v":14,"meta":{"def":"Further youth and dance subcultures bound by a shared sound.","ex":"grunge, disco, reggaeton, grime","region":"Global","note":"Each grew a distinct look, slang and set of values."},"children":[{"name":"Hardcore and Straight Edge","v":4,"meta":{"def":"Faster, harder punk offshoot with a drug-free ascetic wing.","ex":"Minor Threat, 'X' hand marks, moshing","region":"United States (1980s)","note":"Straight edge fans mark an 'X' on their hands to pledge sobriety."}},{"name":"Grunge","v":4,"meta":{"def":"Angst-ridden guitar scene of flannel-clad Pacific Northwest slackers.","ex":"Nirvana, flannel, thrift-store style","region":"Seattle, United States (1990s)","note":"Its anti-fashion look was ironically co-opted by fashion houses."}},{"name":"Disco","v":4,"meta":{"def":"Glittering 1970s dance scene born in gay, Black and Latino clubs.","ex":"four-on-the-floor, Studio 54, mirror ball","region":"New York, United States","note":"A 1979 stadium 'disco demolition' backlash targeted the scene."}},{"name":"Northern Soul","v":4,"meta":{"def":"British all-nighter scene devoted to obscure American soul 45s.","ex":"spins and backdrops, talcum floors","region":"Northern England (1970s)","note":"Collectors prized rare, unknown Detroit and Chicago singles."}},{"name":"Reggaeton and Perreo","v":4,"meta":{"def":"Latin urban scene built on the dembow beat and its close dance.","ex":"dembow riddim, perreo dance","region":"Puerto Rico and Panama","note":"The dembow rhythm derives from a single Jamaican dancehall track."}},{"name":"Grime and UK Garage","v":4,"meta":{"def":"Fast, bass-heavy British MC scene grown from pirate radio.","ex":"140 bpm, pirate radio, clashes","region":"London, United Kingdom","note":"It rose through illegal pirate FM stations and mixtapes."}},{"name":"Hippie Counterculture","v":4,"meta":{"def":"1960s movement fusing psychedelic rock with peace and communal ideals.","ex":"Woodstock, tie-dye, 'flower power'","region":"United States and worldwide","note":"The 1967 'Summer of Love' drew youth to San Francisco."}}]}]}]},{"name":"Performance & Live","type":"performance","v":26,"children":[{"name":"Performing Forces & Ensembles","v":14,"meta":{"def":"The groupings of musicians that make sound together, from a lone performer to a full orchestra.","ex":"soloist, quartet, big band, symphony orchestra, choir","note":"Ensemble size shapes repertoire, blend and how conducting or cueing works."},"children":[{"name":"Solo & Small Configurations","v":10,"meta":{"def":"One to a handful of players, where each part is exposed and individual.","ex":"soloist, duo, trio, quartet, quintet"},"children":[{"name":"Soloist","v":5,"meta":{"def":"A single musician performing alone or as the featured voice with accompaniment.","ex":"solo pianist, singer-songwriter, concerto soloist","note":"In a concerto the soloist is set against and answered by the whole orchestra."}},{"name":"Accompanist","v":4,"meta":{"def":"A player, usually pianist, who supports a soloist rather than leading.","ex":"song recital pianist, vocal coach at the keyboard","who":"Follows the soloist's phrasing, breath and rubato, filling harmony beneath the melody."}},{"name":"Duo","v":5,"meta":{"def":"Two performers sharing the music equally.","ex":"voice and piano, guitar duo, violin and cello","note":"The song-recital duo of singer plus pianist is often called a Lieder partnership."}},{"name":"Trio","v":5,"meta":{"def":"Three players, a classic chamber and jazz format.","ex":"piano trio (piano/violin/cello), jazz trio (piano/bass/drums)","note":"The jazz organ trio swaps double bass for a Hammond organ's foot pedals."}},{"name":"String Quartet","v":5,"meta":{"def":"Two violins, viola and cello, the cornerstone chamber ensemble.","ex":"Beethoven, Bartok and Shostakovich quartet cycles","note":"First violin usually leads with the eyes and bow rather than a conductor."}},{"name":"Quartet & Quintet","v":5,"meta":{"def":"Four or five players in classical, jazz or vocal formats.","ex":"wind quintet, brass quintet, jazz quintet, barbershop quartet","note":"The wind quintet is unusual in mixing flute, oboe, clarinet, horn and bassoon, four families at once."}},{"name":"Sextet, Septet & Octet","v":4,"meta":{"def":"Chamber groups of six to eight, a bridge between quartet and small orchestra.","ex":"Schubert Octet, Steve Reich ensembles, jazz nonet","note":"Larger chamber groups may quietly need a conductor for coordination."}}]},{"name":"Bands & Combos","v":10,"meta":{"def":"Amplified or rhythm-section groups in popular, rock, jazz and folk music.","ex":"rock band, jazz combo, cover band, tribute act"},"children":[{"name":"Rock / Pop Band","v":5,"meta":{"def":"A guitar/bass/drums/vocals lineup, the standard popular-music unit.","ex":"power trio, four-piece with singer, five-piece with keys","note":"The rhythm section (bass and drums) locks the groove while guitars and vocals sit on top."}},{"name":"Jazz Combo","v":5,"meta":{"def":"A small jazz group built on a rhythm section with one or more horns.","ex":"hard-bop quintet, organ trio, piano trio","note":"Head-solos-head form lets each player improvise over the same chord changes."}},{"name":"Rhythm Section","v":4,"meta":{"def":"The bass, drums and comping instruments that provide groove and harmony.","ex":"bass, drums, piano or guitar","who":"Keeps time and outlines the chords so soloists and singers can float above."}},{"name":"Horn Section","v":4,"meta":{"def":"A team of brass and saxes that punch accents and riffs behind a band.","ex":"trumpet, trombone and tenor sax stabs in funk and soul","note":"Tight ensemble breathing and articulation make a horn section 'sound like one instrument'."}},{"name":"Backing Band","v":4,"meta":{"def":"A hired ensemble that supports a featured artist or singer.","ex":"a solo star's touring band, a house band","who":"Learns the artist's catalogue and follows their cues and tempos on stage."}},{"name":"Cover Band","v":4,"meta":{"def":"A band that performs other artists' songs faithfully for audiences.","ex":"wedding and function bands, bar cover acts","note":"Distinguished from a tribute act by playing a mix of artists rather than impersonating one."}},{"name":"Tribute Act","v":4,"meta":{"def":"A band devoted to recreating one famous artist's music, look and show.","ex":"Beatles, ABBA and Pink Floyd tributes","note":"Costume, staging and note-for-note arrangements aim at authentic impersonation."}},{"name":"One-Man Band","v":4,"meta":{"def":"A single performer playing several instruments at once by hand and foot.","ex":"guitar plus kick-drum, harmonica rack and tambourine","note":"Loop pedals now let one player layer parts live to sound like a full band."}}]},{"name":"Orchestral Ensembles","v":10,"meta":{"def":"Large classical ensembles of strings, winds, brass and percussion under a conductor.","ex":"symphony orchestra, chamber orchestra, string orchestra"},"children":[{"name":"Symphony Orchestra","v":5,"meta":{"def":"A full orchestra of 70 to 100 players spanning all instrument families.","ex":"romantic and modern symphonic repertoire","note":"Seating is arranged in an arc so the conductor can cue every section."}},{"name":"Chamber Orchestra","v":5,"meta":{"def":"A smaller orchestra of roughly 15 to 40, suited to Classical-era works.","ex":"Mozart and Haydn symphonies, Baroque programmes","note":"Small enough that a leader-director may replace a conductor."}},{"name":"String Orchestra","v":4,"meta":{"def":"An orchestra of only the string family, without winds or brass.","ex":"Elgar Serenade, Tchaikovsky Serenade for Strings","note":"Often used for warm, homogeneous string writing and film scoring."}},{"name":"Concert Band","v":4,"meta":{"def":"A large wind and percussion ensemble, sometimes called a wind band.","ex":"school, university and military concert bands","note":"Has woodwinds and brass but no string section except often a double bass."}},{"name":"Wind Ensemble","v":4,"meta":{"def":"A wind group with one player per part for clarity and soloistic writing.","ex":"chamber winds, modern wind-ensemble repertoire","note":"Contrasts with a concert band's doubled sections."}},{"name":"Pit Orchestra","v":4,"meta":{"def":"The ensemble that plays for opera, ballet and musical theatre from a sunken pit.","ex":"Broadway pit band, opera-house orchestra","note":"Sited below stage front so it does not block sightlines to the singers."}},{"name":"Baroque / Period Ensemble","v":4,"meta":{"def":"A group using historical instruments and tunings for early music.","ex":"harpsichord continuo, gut strings, natural horns","note":"Often tunes lower, around A415, to match period pitch."}}]},{"name":"Jazz & Big Bands","v":8,"meta":{"def":"Larger jazz ensembles organised in reed, brass and rhythm sections.","ex":"big band, jazz orchestra, dance band"},"children":[{"name":"Big Band","v":5,"meta":{"def":"A jazz orchestra of about 17 players in sax, trumpet, trombone and rhythm sections.","ex":"Count Basie, Duke Ellington, swing-era dance bands","note":"Charts are written in section blocks with room for individual soloists."}},{"name":"Jazz Orchestra","v":4,"meta":{"def":"A large jazz ensemble playing composed, often modern, orchestral jazz.","ex":"Maria Schneider Orchestra, Vanguard Jazz Orchestra","note":"Expands the big band with extended harmony and through-composed writing."}},{"name":"Reed Section","v":4,"meta":{"def":"The saxophone and doubling-woodwind block of a big band.","ex":"two altos, two tenors and a baritone sax","who":"Blends unison and harmonised lines, players doubling on clarinet or flute."}},{"name":"Brass Section","v":4,"meta":{"def":"The trumpets and trombones of a big band.","ex":"four trumpets and four trombones","who":"Delivers high-energy shout choruses and punchy accented figures."}}]},{"name":"Vocal Ensembles","v":10,"meta":{"def":"Groups of singers, with or without instrumental backing.","ex":"choir, a cappella group, vocal harmony group"},"children":[{"name":"Choir / Chorus","v":5,"meta":{"def":"A large group of singers divided into soprano, alto, tenor and bass parts.","ex":"church choir, symphony chorus, community choir","note":"SATB is the standard four-part division of voices."}},{"name":"Chamber Choir","v":4,"meta":{"def":"A small, agile choir of a few dozen voices for detailed repertoire.","ex":"professional vocal ensembles, madrigal groups","note":"Small size allows fast, transparent and blended singing."}},{"name":"A Cappella Group","v":5,"meta":{"def":"Singers performing with no instruments, voices supplying all parts.","ex":"collegiate a cappella, gospel groups, vocal jazz","note":"A vocal percussionist or beatboxer often supplies the rhythm."}},{"name":"Barbershop Quartet","v":4,"meta":{"def":"Four voices in close, ringing harmony on the melody-below-lead style.","ex":"tenor, lead, baritone and bass","note":"Tight tuning creates audible overtone 'ringing' chords."}},{"name":"Vocal Harmony Group","v":4,"meta":{"def":"A pop or doo-wop group built on layered vocal harmonies.","ex":"doo-wop groups, close-harmony trios, girl groups","note":"Often blends a lead singer with backing 'oohs' and 'aahs'."}},{"name":"Gospel Choir","v":4,"meta":{"def":"An energetic church choir with soloists, clapping and call-and-response.","ex":"mass choirs, Sunday-service ensembles","note":"A choir director drives dynamics and cues with expressive gestures."}}]},{"name":"Marching & Band Traditions","v":8,"meta":{"def":"Mobile and street ensembles that play while moving or standing outdoors.","ex":"marching band, brass band, drum corps, pipe band"},"children":[{"name":"Marching Band","v":5,"meta":{"def":"A wind-and-percussion band that plays while marching in formation.","ex":"school and university bands, halftime shows","note":"Drum majors conduct with a mace or baton visible over the field."}},{"name":"Brass Band","v":4,"meta":{"def":"A band of cornets, tenor horns, euphoniums, tubas and percussion.","ex":"British-style brass bands, colliery bands","note":"All-brass with no woodwinds, a distinct British tradition."}},{"name":"Drum & Bugle Corps","v":4,"meta":{"def":"A competitive marching ensemble of brass, percussion and colour guard.","ex":"DCI corps, field-show competitions","note":"Uses only brass and percussion, no woodwinds."}},{"name":"Drumline","v":4,"meta":{"def":"The marching percussion battery of snares, tenors, basses and cymbals.","ex":"battery percussion, cadences on the move","note":"Front-ensemble mallet players (the pit) stay stationary on the sideline."}},{"name":"Pipe Band","v":4,"meta":{"def":"A band of Great Highland bagpipes and drums.","ex":"Scottish and Irish pipe bands","note":"A pipe major leads while the drum corps interlocks rudimental patterns."}},{"name":"Second Line Brass Band","v":4,"meta":{"def":"A New Orleans street brass band playing at parades and funerals.","ex":"sousaphone, trumpets, trombones and snare on the move","note":"The 'second line' is the dancing crowd that follows the band."}}]},{"name":"World & Folk Ensembles","v":10,"meta":{"def":"Traditional group formats from musical cultures around the world.","ex":"gamelan, mariachi, taiko, steel band, samba bloco"},"children":[{"name":"Gamelan","v":5,"meta":{"def":"An Indonesian ensemble of tuned gongs, metallophones and drums.","ex":"Javanese and Balinese gamelan","note":"Each gamelan is tuned as a unique set, so instruments are not interchangeable between orchestras."}},{"name":"Mariachi","v":4,"meta":{"def":"A Mexican ensemble of violins, trumpets, guitar, vihuela and guitarron.","ex":"serenades, weddings, plaza performances","note":"Players sing as well as play, often in charro suits."}},{"name":"Taiko Ensemble","v":4,"meta":{"def":"A Japanese group of large drums played with choreographed movement.","ex":"kumi-daiko drumming troupes","note":"The whole body and stance are part of the visual performance."}},{"name":"Steel Band","v":4,"meta":{"def":"A Caribbean ensemble of tuned steel pans in various ranges.","ex":"Trinidadian steelpan orchestras, Panorama competitions","note":"Pans are pitched by hammering dents into oil-drum tops."}},{"name":"Samba Bloco / Bateria","v":4,"meta":{"def":"A Brazilian percussion troupe driving carnival parades.","ex":"surdo, caixa, repinique and agogo players","note":"A mestre cues breaks with a whistle and hand signals."}},{"name":"Andean Ensemble","v":4,"meta":{"def":"A South American group of panpipes, charango, quena and drums.","ex":"siku, zampona and charango folk groups","note":"Interlocking panpipe halves are shared between two players."}},{"name":"Celtic / Trad Session Group","v":4,"meta":{"def":"An Irish or Scottish traditional group playing tunes together.","ex":"fiddle, flute, bodhran, accordion and guitar","note":"Sessions rotate through sets of jigs and reels by shared memory."}}]},{"name":"Electronic & DJ Performers","v":8,"meta":{"def":"Solo and small-format electronic acts using decks, controllers and computers.","ex":"DJ, laptop performer, live PA, modular act"},"children":[{"name":"DJ (Solo)","v":5,"meta":{"def":"A performer mixing recorded tracks into a continuous set.","ex":"club and festival DJs, radio DJs","who":"Beat-matches, blends and reads the crowd to build energy across a set."}},{"name":"Laptop Performer","v":4,"meta":{"def":"A musician performing electronic music from a computer live.","ex":"Ableton Live sets, glitch and IDM acts","note":"Live-coding artists write and edit code on screen as the performance."}},{"name":"Live PA","v":4,"meta":{"def":"An electronic act that builds tracks live from synths and machines rather than mixing finished songs.","ex":"hardware techno live sets, modular jams","note":"'PA' historically meant personal appearance, now performing live electronic material."}},{"name":"Turntablist","v":4,"meta":{"def":"A DJ who uses turntables as instruments through scratching and cutting.","ex":"battle DJs, hip-hop scratch routines","who":"Manipulates vinyl by hand against the crossfader to make rhythmic and melodic sounds."}},{"name":"Modular / Hardware Act","v":4,"meta":{"def":"A performer patching modular synths and drum machines in real time.","ex":"Eurorack live sets, dub-techno hardware jams","note":"Patch cables are re-routed on the fly, so no two shows are identical."}}]}]},{"name":"Performance Forms","v":14,"meta":{"def":"The recognised shapes a live musical event can take, from formal recital to spontaneous jam.","ex":"concert, recital, gig, DJ set, jam session, open mic","note":"Form sets audience expectation, dress, length and how much is improvised."},"children":[{"name":"Formal Concert Forms","v":10,"meta":{"def":"Structured, ticketed performances of prepared repertoire.","ex":"concert, recital, orchestral concert, opera"},"children":[{"name":"Concert","v":5,"meta":{"def":"A public performance of music before a seated or standing audience.","ex":"rock concert, symphony concert, choral concert","note":"The word covers everything from arena shows to intimate hall events."}},{"name":"Recital","v":5,"meta":{"def":"A concert by a soloist or small group, often with an accompanist.","ex":"piano recital, song recital, student recital","note":"Traditionally more intimate and repertoire-focused than an orchestral concert."}},{"name":"Orchestral Concert","v":4,"meta":{"def":"A programme performed by a full orchestra under a conductor.","ex":"overture, concerto and symphony format","note":"Often follows a classic three-part structure with an interval."}},{"name":"Opera Performance","v":5,"meta":{"def":"A fully staged dramatic work sung throughout with orchestra.","ex":"grand opera, opera buffa, verismo","note":"Singers act, costume and stage while the orchestra plays from the pit."}},{"name":"Musical Theatre","v":5,"meta":{"def":"A staged show blending songs, dialogue, acting and dance.","ex":"Broadway and West End musicals","note":"A pit orchestra follows the musical director watching both stage and score."}},{"name":"Chamber Concert","v":4,"meta":{"def":"A small-ensemble concert in an intimate hall or room.","ex":"string quartet evening, piano trio recital","note":"Players coordinate by eye contact and breath rather than a conductor."}},{"name":"Choral Concert","v":4,"meta":{"def":"A concert given by a choir, sometimes with orchestra.","ex":"cantatas, oratorios, carol concerts","note":"Large choral-orchestral works like requiems anchor the tradition."}}]},{"name":"Popular & Club Forms","v":10,"meta":{"def":"Amplified performance shapes in rock, pop, dance and hip-hop.","ex":"gig, set, DJ set, live PA, back-to-back"},"children":[{"name":"Gig","v":5,"meta":{"def":"An informal booking for a band or artist to play a venue.","ex":"club gig, pub gig, one-nighter","note":"The word comes from early jazz slang for a job or engagement."}},{"name":"Set","v":5,"meta":{"def":"A single continuous block of songs performed by an act.","ex":"opening set, headline set, 45-minute set","note":"A night can hold several sets by different acts with changeovers between."}},{"name":"DJ Set","v":5,"meta":{"def":"A continuous mix of tracks performed live by a DJ.","ex":"club set, festival set, warm-up set","note":"A skilled DJ shapes a narrative arc rather than just playing songs in a row."}},{"name":"Back-to-Back (b2b)","v":4,"meta":{"def":"Two or more DJs sharing the decks and alternating tracks.","ex":"b2b sets, b3b three-way sets","note":"Selectors respond to each other's choices in real time, part duel, part duet."}},{"name":"Live PA (Form)","v":4,"meta":{"def":"An electronic act performing tracks live rather than DJing recordings.","ex":"hardware live sets between DJ slots","note":"Blurs the line between concert and DJ set."}},{"name":"Unplugged / Acoustic Set","v":4,"meta":{"def":"A stripped-back performance using acoustic instruments and little amplification.","ex":"acoustic sessions, MTV Unplugged style shows","note":"Reworked arrangements expose the songwriting behind amplified originals."}},{"name":"Rap Cypher","v":4,"meta":{"def":"An informal circle where rappers take turns freestyling.","ex":"street cyphers, radio freestyles","note":"Often built over a single looping beat or beatboxer."}}]},{"name":"Improvised & Open Forms","v":10,"meta":{"def":"Loosely structured events built on spontaneity and participation.","ex":"jam session, open mic, sit-in, session work"},"children":[{"name":"Jam Session","v":5,"meta":{"def":"An informal gathering where musicians improvise together.","ex":"jazz jams, blues jams, funk jams","note":"A house band often anchors a jam and invites players up to sit in."}},{"name":"Open Mic","v":5,"meta":{"def":"An event where anyone can sign up to perform a short slot.","ex":"singer-songwriter open mics, comedy-and-music nights","note":"Performers usually get two or three songs on a first-come list."}},{"name":"Sit-In","v":4,"meta":{"def":"A guest musician joining another act on stage for a song or two.","ex":"a horn player sitting in with a band","who":"Reads the group's cues and blends in without rehearsal."}},{"name":"Session Work","v":5,"meta":{"def":"Professional playing hired for studio recordings or live dates.","ex":"session guitarist, session drummer, first-call players","who":"Delivers polished parts fast, sight-reading or crafting to a producer's brief."}},{"name":"Free Improvisation","v":4,"meta":{"def":"Music created spontaneously with no fixed key, form or chart.","ex":"free jazz, experimental improv sessions","note":"Players listen and respond with no predetermined structure."}},{"name":"Song Circle / Swap","v":4,"meta":{"def":"A round where writers take turns sharing songs.","ex":"Nashville-style writers' rounds","note":"Performers sit in a semicircle and pass the lead song to song."}}]},{"name":"Street & Public Forms","v":8,"meta":{"def":"Performances staged in public and outdoor spaces.","ex":"busking, parade, flash mob, house concert"},"children":[{"name":"Busking / Street Performance","v":5,"meta":{"def":"Playing in public spaces for voluntary donations.","ex":"street corners, subways, markets","note":"Many cities require a busking permit or a booked pitch."}},{"name":"Marching / Parade","v":4,"meta":{"def":"Music performed while processing through streets in formation.","ex":"carnival parades, festival processions, second lines","note":"Repertoire is memorised since players cannot read while marching."}},{"name":"Flash Mob","v":4,"meta":{"def":"A surprise performance that erupts in a public place then disperses.","ex":"station and mall flash-mob choirs and orchestras","note":"Coordinated in secret and revealed to unsuspecting passers-by."}},{"name":"House Concert","v":5,"meta":{"def":"An intimate gig held in someone's home for a small invited audience.","ex":"living-room shows, salon concerts","note":"The host handles hospitality and passes a hat or ticket for the artist."}},{"name":"Serenade","v":4,"meta":{"def":"A performance offered outdoors to honour or court someone.","ex":"mariachi serenades, birthday serenades","note":"Traditionally sung beneath a window in the evening."}}]}]},{"name":"Live Formats & Occasions","v":12,"meta":{"def":"The billing and event contexts in which a performance is booked and staged.","ex":"headline show, support slot, residency, festival slot, livestream","note":"The same act plays very differently as a headliner, a support or a private booking."},"children":[{"name":"Billing & Slots","v":10,"meta":{"def":"Where an act sits on a bill and how long they play.","ex":"headliner, support, opener, co-headline, festival slot"},"children":[{"name":"Headline Show","v":5,"meta":{"def":"The top-billed act that the audience mainly came to see.","ex":"closing arena act, festival headliner","note":"The headliner gets the longest set, the latest slot and full production."}},{"name":"Support / Opening Act","v":5,"meta":{"def":"An act that plays earlier to warm up the crowd for the headliner.","ex":"opener, main support, direct support","note":"Support acts get shorter sets and limited use of the stage and lights."}},{"name":"Co-Headline","v":4,"meta":{"def":"Two acts of similar stature sharing top billing on a bill or tour.","ex":"co-headline tours, double-header shows","note":"Acts may alternate who closes from city to city."}},{"name":"Festival Slot","v":5,"meta":{"def":"A timed set on a festival stage among many acts across a day.","ex":"main stage headline, afternoon slot, clashing sets","note":"Tight changeovers mean festival sets often use shared or fly-in backline."}},{"name":"Club Night","v":4,"meta":{"def":"A recurring or one-off themed night at a club with DJs or acts.","ex":"resident-DJ nights, promoter-branded nights","note":"Often built around a genre, label or promoter brand."}},{"name":"Rave","v":4,"meta":{"def":"A large, often all-night electronic dance event.","ex":"warehouse raves, free parties, mega-raves","note":"Historically underground and unlicensed, now often legitimised as festivals."}}]},{"name":"Special Engagements","v":10,"meta":{"def":"Distinctive one-off or recurring booking types.","ex":"residency, one-off, secret show, pop-up, silent disco"},"children":[{"name":"Residency","v":5,"meta":{"def":"A repeated engagement at one venue over a run of dates.","ex":"Las Vegas residencies, weekly club residencies","note":"Lets an act build elaborate staging that would not travel on tour."}},{"name":"One-Off","v":4,"meta":{"def":"A single standalone show outside any tour or run.","ex":"festival-only appearances, charity concerts","note":"Often commands a premium fee because there is no economy of scale."}},{"name":"Secret Show","v":4,"meta":{"def":"An unannounced or last-minute gig, often under a fake name.","ex":"warm-up club shows before a tour, surprise sets","note":"Small venues let big acts test material intimately."}},{"name":"Pop-Up Show","v":4,"meta":{"def":"A performance in a temporary or unexpected location.","ex":"rooftop sets, in-store performances","note":"Frequently used for promotion around a release."}},{"name":"Silent Disco","v":4,"meta":{"def":"An event where the audience listens on wireless headphones.","ex":"multi-channel silent discos, quiet-venue events","note":"Dancers can switch between DJ channels, and the room is nearly silent to outsiders."}},{"name":"Livestream / Virtual Concert","v":5,"meta":{"def":"A performance broadcast online to a remote audience.","ex":"ticketed streams, in-game concerts, empty-venue films","note":"Some virtual concerts stage avatars inside video games for millions at once."}}]},{"name":"Private & Function Events","v":8,"meta":{"def":"Bookings for private hosts rather than a public ticketed crowd.","ex":"wedding band, corporate event, cruise ship, private party"},"children":[{"name":"Wedding Band","v":4,"meta":{"def":"A band hired to perform at wedding receptions.","ex":"function bands, ceilidh bands","note":"Repertoire is broad and crowd-pleasing across generations."}},{"name":"Corporate / Private Event","v":4,"meta":{"def":"A performance booked for a company or private host.","ex":"product launches, galas, holiday parties","note":"Often high-fee, low-profile and non-ticketed to the public."}},{"name":"Cruise Ship","v":4,"meta":{"def":"Resident or guest musicians performing aboard cruise liners.","ex":"showband, lounge acts, themed music cruises","note":"Contracts run for months with multiple sets per day."}},{"name":"House Band / Resident Band","v":4,"meta":{"def":"A band employed by a venue or show to play regularly.","ex":"TV show bands, casino house bands","who":"Backs guest artists and fills the room whatever the night's programme."}},{"name":"Ceremony Music","v":4,"meta":{"def":"Musicians playing at rites such as weddings, funerals and services.","ex":"string quartet at a ceremony, church organist","note":"Timing is cued to processions and readings rather than a setlist."}}]}]},{"name":"Touring","v":12,"meta":{"def":"The logistics and structures of taking a live show on the road.","ex":"world tour, leg, routing, load-in, soundcheck, rider","note":"A tour is a business operation as much as an artistic one, planned months ahead."},"children":[{"name":"Tour Structures","v":10,"meta":{"def":"The overall shapes and categories a concert tour can take.","ex":"headline tour, world tour, promo tour, festival run"},"children":[{"name":"Headline Tour","v":4,"meta":{"def":"A tour where the act is the top-billed draw at each show.","ex":"album tours, arena headline runs","note":"The act controls staging, set length and supporting bill."}},{"name":"Co-Headline Tour","v":4,"meta":{"def":"A tour shared by two acts of comparable standing.","ex":"package co-headline tours","note":"Costs, staging time and closing slots are negotiated between camps."}},{"name":"Support Tour","v":4,"meta":{"def":"A run where an act opens for a bigger headliner across dates.","ex":"opening for an arena act","note":"Valuable exposure to a headliner's larger audience."}},{"name":"World Tour","v":5,"meta":{"def":"A large tour spanning multiple continents over many months.","ex":"global stadium tours","note":"Often split into continental legs with breaks and re-routing between."}},{"name":"Promo Tour","v":4,"meta":{"def":"A short run of appearances to promote a release rather than sell tickets.","ex":"radio, TV and in-store visits","note":"May feature stripped acoustic sets and interviews rather than full shows."}},{"name":"Festival Run","v":4,"meta":{"def":"A summer string of festival slots rather than own headline dates.","ex":"European festival-season routing","note":"Uses fly-dates and shared backline to hop between festivals efficiently."}},{"name":"Tour Cycle","v":4,"meta":{"def":"The whole touring period supporting one album, from launch to final leg.","ex":"an 18-month album campaign of legs","note":"Ends when the act comes off the road to write and record again."}}]},{"name":"Routing & Scheduling","v":8,"meta":{"def":"How dates are ordered geographically and across time.","ex":"leg, routing, run-of-show, advance, day off"},"children":[{"name":"Leg","v":4,"meta":{"def":"A continuous block of tour dates within a region or period.","ex":"North American leg, European leg","note":"Legs are separated by breaks, re-routing or a change of continent."}},{"name":"Routing","v":5,"meta":{"def":"The geographic ordering of tour dates to minimise travel.","ex":"efficient city-to-city routing, avoiding backtracking","note":"Poor routing wastes fuel, time and driver hours between shows."}},{"name":"Advance","v":5,"meta":{"def":"Confirming every show detail with each venue ahead of arrival.","ex":"advancing load-in times, power, catering and curfews","who":"The tour or production manager phones and emails venues to lock in logistics before the date."}},{"name":"Run-of-Show","v":4,"meta":{"def":"A minute-by-minute schedule of a show day and the performance itself.","ex":"doors, support, changeover, headline, curfew","note":"Keeps crew, act and venue aligned to a shared timeline."}},{"name":"Day Off / Travel Day","v":4,"meta":{"def":"A non-show day used for rest or long-distance travel.","ex":"overnight drives, flight days","note":"Overnight drives on the nightliner double as travel and sleep."}},{"name":"Curfew","v":4,"meta":{"def":"The mandated time by which sound must stop, set by the venue or city.","ex":"11pm noise curfews, festival hard stops","note":"Overrunning can bring fines or cut power mid-song."}}]},{"name":"Show-Day Logistics","v":10,"meta":{"def":"The recurring sequence of tasks that make a show happen on the day.","ex":"load-in, soundcheck, doors, load-out, changeover"},"children":[{"name":"Load-In","v":5,"meta":{"def":"Bringing gear into the venue and setting up stage and PA.","ex":"flightcases off the truck, rigging up the PA","note":"The first crew task of the day, often early morning."}},{"name":"Soundcheck","v":5,"meta":{"def":"Testing and balancing every input and monitor before the show.","ex":"line check, full-band soundcheck, virtual soundcheck","note":"FOH and monitor engineers set levels and tone with the band on stage."}},{"name":"Line Check","v":4,"meta":{"def":"A quick channel-by-channel test that each input is live and routed.","ex":"checking every mic and DI signal reaches the desk","note":"Faster than a full soundcheck, used at festivals with no time."}},{"name":"Changeover","v":4,"meta":{"def":"The switch between acts, clearing one setup and building the next.","ex":"20-minute festival changeovers","note":"Rolling risers and stage boxes speed multi-act changeovers."}},{"name":"Doors","v":4,"meta":{"def":"The time the venue opens and the audience is let in.","ex":"doors at 7, show at 8","note":"Everything on stage must be ready and safe before doors."}},{"name":"Load-Out","v":4,"meta":{"def":"Striking the show and packing gear back onto the truck after the gig.","ex":"the post-show teardown","note":"Often the longest and most tiring part of a crew's day."}}]},{"name":"Riders & Hospitality","v":8,"meta":{"def":"The contractual demands and comforts an act requires on tour.","ex":"technical rider, hospitality rider, per diem, dressing room"},"children":[{"name":"Technical Rider","v":5,"meta":{"def":"The document specifying an act's stage, sound and power needs.","ex":"PA spec, stage plot, input list, power requirements","note":"Venues use it to prepare the stage before the crew arrives."}},{"name":"Hospitality Rider","v":5,"meta":{"def":"The catering and comfort requests for the act and crew backstage.","ex":"meals, drinks, towels, dressing-room requests","note":"The famous 'no brown M&Ms' clause was really a test that the rider had been read."}},{"name":"Per Diem","v":4,"meta":{"def":"A daily cash allowance given to touring personnel for meals and incidentals.","ex":"a set dollar amount handed out each day on the road","note":"Often paid in local currency at the start of each leg."}},{"name":"Dressing Room / Green Room","v":4,"meta":{"def":"The backstage space where acts prepare and wait.","ex":"star dressing room, shared green room","note":"The green room is the communal waiting area shared before and after the show."}},{"name":"Guest List / Aftershow","v":4,"meta":{"def":"Complimentary entry and backstage access for the act's guests.","ex":"plus-ones, aftershow passes, meet-and-greets","note":"Managed by the tour manager against a strict headcount."}}]},{"name":"Transport & Gear","v":8,"meta":{"def":"The vehicles and equipment that move a tour between cities.","ex":"tour bus, nightliner, backline, flightcase, splitter van"},"children":[{"name":"Tour Bus / Nightliner","v":5,"meta":{"def":"A sleeper coach that moves the act and crew overnight between shows.","ex":"bunk-bed sleeper buses with a lounge","note":"A nightliner drives while everyone sleeps, arriving at the next city by morning."}},{"name":"Splitter Van","v":4,"meta":{"def":"A van split between passenger seats and a gear compartment for smaller tours.","ex":"van tours for club-level bands","note":"The economical rig before an act can afford a bus and trailer."}},{"name":"Backline","v":5,"meta":{"def":"The amps, drums and keyboards set up behind the front line on stage.","ex":"guitar amps, bass rigs, drum kit, keyboards","note":"At fly-dates backline is rented locally to identical spec to avoid shipping it."}},{"name":"Flightcase","v":4,"meta":{"def":"A rugged wheeled road case protecting gear in transit.","ex":"amp cases, guitar cases, rack cases","note":"Colour-coded and labelled so load-in and load-out go fast."}},{"name":"Production Truck","v":4,"meta":{"def":"The articulated lorry carrying staging, PA, lights and backline.","ex":"one or several 45-foot trailers","note":"Big tours run a fleet of trucks packed in a fixed loading order."}}]}]},{"name":"Venues","v":14,"meta":{"def":"The physical spaces where music is performed, from stadiums to basements.","ex":"arena, concert hall, club, festival stage, church","note":"Venue size and acoustics shape the whole approach to a performance."},"children":[{"name":"Large-Scale Venues","v":8,"meta":{"def":"Big-capacity spaces for major touring acts and events.","ex":"arena, stadium, amphitheatre, bowl"},"children":[{"name":"Stadium","v":5,"meta":{"def":"A very large outdoor sports venue used for the biggest concerts.","ex":"football and baseball stadium shows","note":"Capacities of 40,000 or more demand delay towers and giant video screens."}},{"name":"Arena","v":5,"meta":{"def":"A large indoor venue for major touring shows and sports.","ex":"10,000 to 20,000 seat arenas","note":"Central-hung PA and in-the-round staging are common."}},{"name":"Amphitheatre","v":4,"meta":{"def":"An outdoor venue with tiered or lawn seating around a stage.","ex":"shed venues, natural amphitheatres","note":"US 'sheds' pair a covered pavilion with an open lawn."}},{"name":"Bandshell","v":4,"meta":{"def":"An outdoor stage with a curved acoustic shell behind the performers.","ex":"park bandshells, civic shells","note":"The shell projects sound outward to an open-air crowd."}}]},{"name":"Classical & Formal Halls","v":8,"meta":{"def":"Purpose-built acoustic spaces for classical and formal performance.","ex":"concert hall, opera house, recital hall, church"},"children":[{"name":"Concert Hall","v":5,"meta":{"def":"A hall designed for the acoustics of orchestral and choral music.","ex":"shoebox and vineyard-shaped halls","note":"Reverberation is tuned so unamplified sound fills the room."}},{"name":"Opera House","v":4,"meta":{"def":"A theatre built for staged opera with an orchestra pit.","ex":"grand opera houses with tiered boxes","note":"Horseshoe layouts and boxes maximise both sightlines and prestige."}},{"name":"Recital Hall","v":4,"meta":{"def":"A smaller, intimate hall for soloists and chamber groups.","ex":"conservatoire recital rooms","note":"Warm, close acoustics suit a single voice or instrument."}},{"name":"Church / Cathedral","v":4,"meta":{"def":"A place of worship also used for concerts, especially choral and organ music.","ex":"cathedral choral evensong, organ recitals","note":"Long reverberation flatters slow choral music but blurs fast rhythms."}},{"name":"Theatre","v":4,"meta":{"def":"A proscenium venue for staged shows, plays and mid-size concerts.","ex":"playhouses, variety theatres, seated tours","note":"Seated capacity and a raised stage suit both drama and music."}}]},{"name":"Clubs & Small Venues","v":10,"meta":{"def":"Intimate rooms and bars where grassroots and club music happen.","ex":"club, dive bar, jazz club, listening room, DIY space"},"children":[{"name":"Nightclub","v":5,"meta":{"def":"A late-night venue centred on DJs and dancing.","ex":"superclubs, underground clubs","note":"A powerful, bass-heavy sound system is the club's core instrument."}},{"name":"Live Music Club","v":4,"meta":{"def":"A small venue programming bands most nights.","ex":"toilet-circuit clubs, 200-to-500 cap rooms","note":"The grassroots grounding where new acts build a following."}},{"name":"Dive Bar","v":4,"meta":{"def":"A small, rough-and-ready bar with a stage in the corner.","ex":"neighbourhood bars with live acts","note":"Minimal production means acts rely on their own gear and grit."}},{"name":"Jazz Club","v":4,"meta":{"def":"An intimate room devoted to live jazz, often with table seating.","ex":"basement jazz clubs, supper clubs","note":"Close, quiet listening lets acoustic subtlety carry."}},{"name":"Listening Room","v":4,"meta":{"def":"A venue where the audience sits silently and focuses on the music.","ex":"songwriter listening rooms","note":"No talking or bar noise, so quiet acoustic material can breathe."}},{"name":"DIY / Basement Space","v":4,"meta":{"def":"An informal, often unlicensed space run by a scene for its own shows.","ex":"house shows, warehouse gigs, squat gigs","note":"Community-run, cheap and central to underground and punk scenes."}},{"name":"Warehouse","v":4,"meta":{"def":"A large industrial space repurposed for raves and gigs.","ex":"warehouse parties, converted units","note":"Raw acoustics and legal grey areas define the vibe."}}]},{"name":"Bars, Pubs & Roots Venues","v":8,"meta":{"def":"Drinking establishments and regional venue types with music traditions.","ex":"pub, honky-tonk, tavern, working men's club"},"children":[{"name":"Pub","v":4,"meta":{"def":"A bar, especially British, hosting gigs, sessions and open mics.","ex":"back-room pub gigs, trad sessions","note":"The backbone of grassroots and folk performance in Britain and Ireland."}},{"name":"Honky-Tonk","v":4,"meta":{"def":"A country-music bar with live bands and dancing, especially in the US South.","ex":"Nashville and Texas honky-tonks","note":"Bands often play for tips across long multi-hour shifts."}},{"name":"Tavern / Roadhouse","v":4,"meta":{"def":"A roadside bar with a stage for touring roots and rock bands.","ex":"roadhouse blues and rock nights","note":"A staple stop on regional touring circuits."}},{"name":"Cabaret / Supper Club","v":4,"meta":{"def":"A venue mixing dining with intimate staged musical entertainment.","ex":"cabaret rooms, dinner shows","note":"Performers work close to seated, dining patrons."}}]},{"name":"Festival Stages","v":8,"meta":{"def":"The various stages that make up a music festival site.","ex":"main stage, second stage, tent, dance arena"},"children":[{"name":"Main Stage","v":5,"meta":{"def":"The largest festival stage, home to headliners and big crowds.","ex":"the headline stage of a festival","note":"Huge PA wings and delay towers cover vast standing fields."}},{"name":"Second Stage","v":4,"meta":{"def":"A smaller festival stage for mid-billing and rising acts.","ex":"the tent or B-stage","note":"Often where tomorrow's headliners are first seen."}},{"name":"Big-Top / Tent Stage","v":4,"meta":{"def":"A covered marquee stage sheltering acts and crowd from weather.","ex":"circus-tent dance and band stages","note":"The enclosed space traps sound and heat, raising the atmosphere."}},{"name":"Dance Arena / DJ Tent","v":4,"meta":{"def":"A festival area dedicated to DJs and electronic acts.","ex":"dance tents, silent-disco areas","note":"Programmed late and loud, separate from the live-band stages."}}]}]},{"name":"Live Production & Crew Roles","v":16,"meta":{"def":"The specialists behind the show who run sound, light, stage and logistics.","ex":"tour manager, FOH engineer, lighting designer, guitar tech, rigger","note":"For every musician on stage a big show may carry many crew off it."},"children":[{"name":"Management & Coordination","v":8,"meta":{"def":"The people who plan, schedule and run the tour and the show day.","ex":"tour manager, production manager, stage manager, promoter's rep"},"children":[{"name":"Tour Manager","v":5,"meta":{"def":"The person running the tour's day-to-day logistics and money.","ex":"TM handling schedules, settlements and travel","who":"Wrangles the schedule, pays the crew, settles the box office and keeps the act on time."}},{"name":"Production Manager","v":5,"meta":{"def":"The head of the technical production across the tour.","ex":"PM overseeing sound, lights, staging and trucking","who":"Advances technical needs with venues and directs all department heads on site."}},{"name":"Stage Manager","v":5,"meta":{"def":"The person running everything that happens on stage during the show.","ex":"cueing acts on, managing changeovers","who":"Controls the stage, calls cues and keeps performers and crew moving to schedule."}},{"name":"Promoter's Rep","v":4,"meta":{"def":"The local promoter's contact who represents the show's buyer.","ex":"settling the deal, handling venue relations","who":"Liaises between the venue, promoter and touring party on the day."}},{"name":"Tour Accountant","v":4,"meta":{"def":"The person tracking budgets, settlements and cash on the road.","ex":"reconciling box-office splits nightly","who":"Handles per diems, settlements and the tour's finances leg by leg."}},{"name":"Runner","v":4,"meta":{"def":"A local driver-helper who fetches people and supplies during the show day.","ex":"airport pickups, shopping runs, errands","who":"Runs errands and drives the act and crew around the host city."}}]},{"name":"Audio Crew","v":8,"meta":{"def":"The engineers and techs responsible for sound at the show.","ex":"FOH engineer, monitor engineer, systems tech, RF tech"},"children":[{"name":"Front-of-House Engineer","v":5,"meta":{"def":"The engineer mixing the sound the audience hears from a desk in the crowd.","ex":"FOH mix, house mix","who":"Balances every instrument and voice into the room from the front-of-house console."}},{"name":"Monitor Engineer","v":5,"meta":{"def":"The engineer mixing what the performers hear on stage.","ex":"wedge mixes, in-ear monitor mixes","who":"Builds a separate mix for each musician so they can hear themselves and each other."}},{"name":"Systems / PA Tech","v":5,"meta":{"def":"The specialist who deploys and tunes the main sound system.","ex":"line-array hang, room tuning, delay alignment","who":"Rigs, aims and equalises the PA so coverage is even across the venue."}},{"name":"RF / Wireless Tech","v":4,"meta":{"def":"The tech managing wireless mics and in-ear frequencies.","ex":"coordinating radio frequencies, avoiding dropouts","who":"Assigns and monitors radio channels so no wireless link interferes or drops."}},{"name":"Playback / Ableton Tech","v":4,"meta":{"def":"The tech running backing tracks, click and timecode.","ex":"launching stems, sending click to the drummer","who":"Keeps the show's programmed audio and timecode locked to the band."}}]},{"name":"Lighting & Visual Crew","v":8,"meta":{"def":"The team creating the show's light, video and visual effects.","ex":"lighting designer, LD operator, VJ, pyro tech"},"children":[{"name":"Lighting Designer","v":5,"meta":{"def":"The person who designs the show's lighting looks and cues.","ex":"designing the rig and every scene","who":"Plans the fixtures, colours and moments that shape the show visually."}},{"name":"Lighting Operator (LD)","v":4,"meta":{"def":"The person running the lighting console live during the show.","ex":"busking lights, running the cue stack","who":"Triggers and rides the lighting cues in time with the music."}},{"name":"Video / VJ","v":5,"meta":{"def":"The person running screen content and live visuals.","ex":"IMAG camera mixing, VJ visuals on LED walls","who":"Mixes camera feeds and clips onto the video screens behind and beside the act."}},{"name":"Pyro / SFX Tech","v":4,"meta":{"def":"The licensed specialist firing pyrotechnics and special effects.","ex":"flames, confetti, CO2 jets, cryo","who":"Rigs and safely fires the flames, sparks and confetti on cue."}},{"name":"Follow-Spot Operator","v":4,"meta":{"def":"A crew member aiming a spotlight to track a performer.","ex":"keeping the singer in a beam of light","who":"Manually follows the star around the stage with a hand-aimed spotlight."}}]},{"name":"Stage & Instrument Crew","v":10,"meta":{"def":"The techs who set up, maintain and change instruments and stage gear.","ex":"backline tech, guitar tech, drum tech, stagehand"},"children":[{"name":"Backline Tech","v":5,"meta":{"def":"The tech responsible for the band's on-stage instruments and amps.","ex":"setting and maintaining amps, drums and keys","who":"Sets up, tunes and troubleshoots the backline so it works flawlessly on stage."}},{"name":"Guitar Tech","v":5,"meta":{"def":"The tech who maintains and swaps a guitarist's instruments live.","ex":"restringing, tuning, quick guitar changes","who":"Hands the player tuned guitars mid-set and fixes strings and gear on the fly."}},{"name":"Drum Tech","v":4,"meta":{"def":"The tech who builds, tunes and maintains the drum kit.","ex":"tuning heads, replacing broken sticks and skins","who":"Sets up and tunes the kit and keeps spares ready during the show."}},{"name":"Keyboard / Tech","v":4,"meta":{"def":"The tech managing keyboards, patches and synth rigs.","ex":"loading sounds, wiring MIDI rigs","who":"Keeps the keyboard rig patched, powered and on the right sounds."}},{"name":"Stagehand","v":5,"meta":{"def":"General crew who load, build and strike the stage and gear.","ex":"pushing cases, building risers, load-in labour","who":"Provides the muscle to move, assemble and tear down the show's equipment."}},{"name":"Rigger","v":5,"meta":{"def":"The specialist who works at height hanging PA, lights and staging.","ex":"climbing to fix motors and points in the roof","who":"Attaches hoists and rigging overhead so heavy equipment can fly safely."}}]},{"name":"Performance Support Roles","v":8,"meta":{"def":"On-stage or show-facing roles that support the artistic performance.","ex":"musical director, dancer, hype man, security, merch"},"children":[{"name":"Musical Director (MD)","v":5,"meta":{"def":"The lead musician who directs the band's performance and arrangements.","ex":"counting in songs, cueing sections, arranging the set","who":"Shapes arrangements, rehearses the band and cues changes live from the stage."}},{"name":"Dancer / Choreography","v":4,"meta":{"def":"Performers who dance as part of the staged show.","ex":"backing dancers, dance captains","who":"Executes choreographed routines that visualise the music alongside the act."}},{"name":"Hype Man","v":4,"meta":{"def":"A performer who energises the crowd and backs the lead vocalist.","ex":"hip-hop hype men echoing lines and rousing the crowd","who":"Amps up the audience, fills gaps and shouts call-and-response with the star."}},{"name":"Master of Ceremonies (MC)","v":4,"meta":{"def":"A host who introduces acts and keeps the show flowing.","ex":"compere, event host, DJ mic-work","who":"Announces performers, fills changeovers and holds the room between sets."}},{"name":"Security","v":4,"meta":{"def":"The crew keeping performers and audience safe at the show.","ex":"barrier security, artist protection","who":"Works the front barrier and stage edges to manage the crowd safely."}},{"name":"Merch Seller","v":4,"meta":{"def":"The person selling the act's merchandise at the show.","ex":"T-shirt and record stall, settling the merch count","who":"Runs the merch stand and reconciles stock and cash after the gig."}}]}]},{"name":"Stagecraft","v":12,"meta":{"def":"The tools, documents and techniques that organise and enhance a live performance.","ex":"setlist, stage plot, input list, in-ears, line array, encore","note":"Good stagecraft is invisible, letting the audience feel only the music."},"children":[{"name":"Planning Documents","v":8,"meta":{"def":"The paperwork that tells the crew how to build and run the show.","ex":"setlist, stage plot, input list, patch list"},"children":[{"name":"Setlist","v":5,"meta":{"def":"The ordered list of songs an act plans to perform.","ex":"taped to the stage floor, drummer's setlist","note":"Sequenced to pace energy, with encores marked separately at the end."}},{"name":"Stage Plot","v":5,"meta":{"def":"A diagram showing where each performer and piece of gear sits on stage.","ex":"positions of amps, drums, mics and monitors","note":"Sent ahead in the rider so the stage is pre-set before load-in."}},{"name":"Input List","v":5,"meta":{"def":"A numbered list of every audio source and how it connects to the desk.","ex":"channel 1 kick, channel 2 snare, DIs and mics","note":"Lets the audio crew patch the stage box quickly and correctly."}},{"name":"Patch List","v":4,"meta":{"def":"The mapping of stage inputs to console channels and outputs.","ex":"stagebox-to-desk routing","note":"Ensures every mic lands on the right fader at both desks."}}]},{"name":"Sound Reinforcement","v":10,"meta":{"def":"The gear and methods that amplify and distribute sound to the audience.","ex":"PA, line array, DI, subwoofer, delay tower"},"children":[{"name":"PA System","v":5,"meta":{"def":"The public-address speaker system that projects sound to the crowd.","ex":"house PA, festival rig","note":"'PA' covers everything from a small powered speaker to a stadium array."}},{"name":"Line Array","v":5,"meta":{"def":"A hung column of speaker boxes that projects sound evenly over distance.","ex":"flown left-and-right array wings","note":"The tight vertical column throws sound far while limiting reflections."}},{"name":"Subwoofer","v":4,"meta":{"def":"Speakers dedicated to reproducing the lowest bass frequencies.","ex":"ground-stacked or flown subs, cardioid sub arrays","note":"Cardioid arraying keeps bass off the stage and out of neighbours' windows."}},{"name":"DI Box","v":4,"meta":{"def":"A device converting an instrument's signal to feed the mixing desk.","ex":"bass DI, acoustic guitar DI, keyboard DI","note":"Turns a high-impedance instrument output into a clean balanced mic-level signal."}},{"name":"Delay Tower","v":4,"meta":{"def":"Extra speakers set back in a large crowd, time-delayed to match the main PA.","ex":"field delays at festivals and stadiums","note":"Delayed so distant listeners hear sound aligned with the stage, not as an echo."}},{"name":"Stage Box / Snake","v":4,"meta":{"def":"The multi-channel connector carrying stage signals to the desks.","ex":"analogue multicore, digital stage box","note":"Digital stage boxes send all channels down a single network cable."}}]},{"name":"Monitoring","v":8,"meta":{"def":"How performers hear themselves and the band on stage.","ex":"wedge, in-ear monitor, monitor mix, side-fill"},"children":[{"name":"Monitor Mix","v":5,"meta":{"def":"A personalised blend of sources sent to a performer to hear themselves.","ex":"vocalist wanting 'more me' in the mix","note":"Each player gets a different balance from the monitor engineer."}},{"name":"Stage Wedge","v":4,"meta":{"def":"A floor monitor speaker angled up toward a performer.","ex":"vocal wedges across the stage front","note":"The classic wedge shape aims sound at the singer's ears."}},{"name":"In-Ear Monitors","v":5,"meta":{"def":"Earpieces delivering a personal monitor mix directly to a performer.","ex":"custom-moulded in-ears, wireless IEM packs","note":"Isolate stage noise and let players hear a clean click and mix."}},{"name":"Side-Fill","v":4,"meta":{"def":"Larger monitor speakers at the sides of the stage covering the whole band.","ex":"side-fill stacks feeding general stage sound","note":"Fill in a broad wash where individual wedges cannot."}}]},{"name":"Timing & Backing","v":8,"meta":{"def":"The synchronisation tools that lock a live band to programmed elements.","ex":"click track, backing tracks, timecode, in-ear click"},"children":[{"name":"Click Track","v":5,"meta":{"def":"A metronome fed to the players' in-ears to keep tempo locked.","ex":"drummer's click, whole-band click","note":"Essential when a show syncs to backing tracks, video or lights."}},{"name":"Backing Tracks","v":5,"meta":{"def":"Pre-recorded parts played alongside the live band.","ex":"extra synths, strings, vocal stacks","note":"Run in stems so the engineer can drop parts in and out live."}},{"name":"Timecode","v":4,"meta":{"def":"A time reference that synchronises audio, lighting and video automatically.","ex":"SMPTE timecode driving light and video cues","note":"Locks the whole production to a single running clock."}},{"name":"Loop / Sampler Rig","v":4,"meta":{"def":"Gear letting a performer layer and trigger loops live.","ex":"loop-station solo acts, pad triggering","note":"Turns one player into a layered, self-accompanied performance."}}]},{"name":"Performance Techniques","v":10,"meta":{"def":"The stage moves and rituals that shape how a show is delivered.","ex":"encore, banter, choreography, staging, crowd work"},"children":[{"name":"Encore","v":5,"meta":{"def":"Extra songs performed after the main set in response to applause.","ex":"walking off then returning for the encore","note":"The 'false ending' encore is a near-universal, semi-scripted ritual."}},{"name":"Banter / MC-ing","v":5,"meta":{"def":"The between-song talk that connects a performer to the audience.","ex":"song intros, jokes, dedications, crowd work","note":"Good banter buys time for tuning changes while holding the room."}},{"name":"Choreography","v":4,"meta":{"def":"Planned movement and dance built into a staged performance.","ex":"synchronised routines, staged blocking","note":"Rehearsed so movement hits musical accents exactly."}},{"name":"Staging / Production Design","v":5,"meta":{"def":"The overall visual design of set, risers, screens and effects.","ex":"stage set pieces, LED design, catwalks","note":"Ties lighting, video and props into a single show concept."}},{"name":"Crowd Work / Call-and-Response","v":4,"meta":{"def":"Directly engaging the audience to sing, clap or answer back.","ex":"'everybody put your hands up', sing-alongs","note":"Turns spectators into participants and lifts energy."}},{"name":"Stage Blocking","v":4,"meta":{"def":"The planned positioning and movement of performers across the stage.","ex":"who stands where, when singers move downstage","note":"Keeps performers in their light and out of each other's way."}}]}]}]},{"name":"Events & Experiences","type":"events","v":26,"children":[{"name":"Festivals","v":13,"meta":{"def":"Multi-act, often multi-day gatherings staged around live music.","ex":"Glastonbury, Coachella, Tomorrowland","region":"Worldwide","note":"The modern template dates to the 1960s Monterey and Woodstock era."},"children":[{"name":"Mega Greenfield Gatherings","v":6,"meta":{"def":"Huge open-field festivals drawing six-figure crowds across many stages.","ex":"Glastonbury, Roskilde","region":"Europe and North America","note":"Often built on farmland or greenfield sites with temporary cities."},"children":[{"name":"Glastonbury","v":3,"meta":{"def":"Vast performing-arts and music festival on Worthy Farm.","ex":"Glastonbury Festival at Pilton","region":"Somerset, England","note":"Runs a fallow year roughly every five years to let the land recover."}},{"name":"Coachella","v":3,"meta":{"def":"Two-weekend desert festival known for headline reunions and art.","ex":"Coachella Valley Music and Arts Festival","region":"Indio, California","note":"Beyonce's 2018 'Beychella' set is among its most-streamed moments."}},{"name":"Roskilde","v":3,"meta":{"def":"Non-profit Nordic mega-festival donating surplus to charity.","ex":"Roskilde Festival","region":"Roskilde, Denmark","note":"One of Europe's oldest large festivals, running since 1971."}},{"name":"Pinkpop","v":3,"meta":{"def":"Long-running greenfield rock and pop festival.","ex":"Pinkpop Festival","region":"Landgraaf, Netherlands","note":"Held annually since 1970, among the oldest still running."}},{"name":"Rock Werchter","v":3,"meta":{"def":"Belgian greenfield rock festival on farmland near Leuven.","ex":"Rock Werchter","region":"Werchter, Belgium","note":"Repeatedly voted best festival at the international festival awards."}},{"name":"Reading and Leeds","v":3,"meta":{"def":"Twin-site August rock and alternative festival in England.","ex":"Reading and Leeds Festivals","region":"Reading and Leeds, England","note":"Reading traces its lineage to the National Jazz and Blues Festival."}}]},{"name":"City and Urban Festivals","v":6,"meta":{"def":"Festivals spread across a city's venues, streets and parks.","ex":"SXSW, Primavera Sound","region":"Urban centres worldwide","note":"Often double as tourism and cultural-economy drivers."},"children":[{"name":"SXSW Music","v":3,"meta":{"def":"Austin showcase festival blending music, film and tech.","ex":"South by Southwest","region":"Austin, Texas","note":"Thousands of acts play tiny official and unofficial venue showcases."}},{"name":"Primavera Sound","v":3,"meta":{"def":"Seafront indie and electronic festival at Parc del Forum.","ex":"Primavera Sound","region":"Barcelona, Spain","note":"Known for a curatorial gender-balanced lineup policy."}},{"name":"Iceland Airwaves","v":3,"meta":{"def":"Downtown showcase festival across Reykjavik's small rooms.","ex":"Iceland Airwaves","region":"Reykjavik, Iceland","note":"Launched with a gig in an airplane hangar in 1999."}},{"name":"The Great Escape","v":3,"meta":{"def":"Seaside new-music showcase across dozens of city venues.","ex":"The Great Escape","region":"Brighton, England","note":"Billed as Europe's answer to SXSW for emerging artists."}},{"name":"Fuji Rock","v":3,"meta":{"def":"Mountain-set festival despite its name, near a ski resort.","ex":"Fuji Rock Festival","region":"Naeba, Niigata, Japan","note":"Named after Mount Fuji though it moved away from it after year one."}},{"name":"Mostly Mozart Style City Series","v":3,"meta":{"def":"Urban summer concert series drawing on a city's cultural halls.","ex":"Mostly Mozart Festival, Lincoln Center","region":"New York City","note":"Renamed within Lincoln Center's summer programming over the years."}}]},{"name":"Electronic and Dance Festivals","v":6,"meta":{"def":"Festivals centred on DJs, producers and dance music.","ex":"Tomorrowland, Ultra","region":"Global dance-music circuit","note":"Grew from 1990s rave culture into stadium-scale spectacle."},"children":[{"name":"Tomorrowland","v":3,"meta":{"def":"Elaborate themed EDM festival with fairy-tale stage design.","ex":"Tomorrowland Boom","region":"Boom, Belgium","note":"Its ticket sales routinely sell out globally within minutes."}},{"name":"Ultra Music Festival","v":3,"meta":{"def":"Downtown electronic festival and global brand franchise.","ex":"Ultra Miami","region":"Miami, Florida","note":"Anchors Miami Music Week each March."}},{"name":"Electric Daisy Carnival","v":3,"meta":{"def":"Night-time carnival-themed rave with rides and fireworks.","ex":"EDC Las Vegas","region":"Las Vegas, Nevada","note":"Held at the Las Vegas Motor Speedway under the electric sky."}},{"name":"Sonar","v":3,"meta":{"def":"Festival of advanced music and new-media art, day and night.","ex":"Sonar Barcelona","region":"Barcelona, Spain","note":"Pairs a daytime cultural program with a nocturnal club program."}},{"name":"Awakenings","v":3,"meta":{"def":"Techno-focused festival and event brand.","ex":"Awakenings Festival","region":"Spaarnwoude, Netherlands","note":"Devoted almost exclusively to pure techno lineups."}},{"name":"Time Warp","v":3,"meta":{"def":"Indoor overnight techno and house marathon.","ex":"Time Warp Mannheim","region":"Mannheim, Germany","note":"Known for warehouse-scale production running until dawn."}}]},{"name":"Metal and Rock Festivals","v":6,"meta":{"def":"Festivals dedicated to heavy, hard and extreme guitar music.","ex":"Wacken, Download","region":"Europe and worldwide","note":"German and UK events anchor the global metal touring calendar."},"children":[{"name":"Wacken Open Air","v":3,"meta":{"def":"Rural village festival that is metal's largest gathering.","ex":"Wacken Open Air","region":"Wacken, Germany","note":"Tiny village swells to a temporary metal city each August."}},{"name":"Download","v":3,"meta":{"def":"UK rock and metal festival at a former motor-racing circuit.","ex":"Download Festival","region":"Donington Park, England","note":"Successor to the classic Monsters of Rock events at Donington."}},{"name":"Hellfest","v":3,"meta":{"def":"Extreme-music festival with elaborate metal-themed stages.","ex":"Hellfest Open Air","region":"Clisson, France","note":"Features permanent decorative structures on its festival grounds."}},{"name":"Graspop Metal Meeting","v":3,"meta":{"def":"Belgian heavy-metal festival on farmland.","ex":"Graspop Metal Meeting","region":"Dessel, Belgium","note":"One of the mainland European metal-circuit anchors."}},{"name":"Bloodstock Open Air","v":3,"meta":{"def":"Independent UK metal festival with an unsigned-band contest.","ex":"Bloodstock Open Air","region":"Catton Hall, England","note":"Its Metal 2 the Masses contest feeds a new-blood stage."}},{"name":"Rock am Ring","v":3,"meta":{"def":"Large rock festival at a motorsport circuit with a twin event.","ex":"Rock am Ring and Rock im Park","region":"Nurburgring, Germany","note":"Runs simultaneously with Rock im Park in Nuremberg."}}]},{"name":"Jazz Festivals","v":5,"meta":{"def":"Festivals built around jazz, improvisation and related forms.","ex":"Montreux, Newport","region":"Europe and North America","note":"Newport is often cited as the first modern jazz festival."},"children":[{"name":"Montreux Jazz Festival","v":3,"meta":{"def":"Lakeside festival famous for legendary recorded live sets.","ex":"Montreux Jazz Festival","region":"Montreux, Switzerland","note":"Its 1971 fire inspired Deep Purple's 'Smoke on the Water'."}},{"name":"Newport Jazz Festival","v":3,"meta":{"def":"Historic seaside American jazz festival.","ex":"Newport Jazz Festival","region":"Newport, Rhode Island","note":"Founded in 1954, the template for the modern jazz festival."}},{"name":"North Sea Jazz Festival","v":3,"meta":{"def":"Indoor multi-stage jazz and soul festival.","ex":"North Sea Jazz Festival","region":"Rotterdam, Netherlands","note":"One of the world's largest indoor jazz events."}},{"name":"Montreal Jazz Festival","v":3,"meta":{"def":"Downtown festival that closes streets for free stages.","ex":"Festival International de Jazz de Montreal","region":"Montreal, Canada","note":"Recognized as one of the largest jazz festivals on record."}},{"name":"New Orleans Jazz and Heritage","v":3,"meta":{"def":"Festival celebrating the birthplace of jazz and its culture.","ex":"Jazz Fest","region":"New Orleans, Louisiana","note":"Pairs music with Creole food and craft heritage tents."}}]},{"name":"Classical and Opera Festivals","v":5,"meta":{"def":"Festivals devoted to orchestral, chamber and operatic repertoire.","ex":"Salzburg, BBC Proms, Bayreuth","region":"Europe chiefly","note":"Several are tied to a single composer or a specific opera house."},"children":[{"name":"Salzburg Festival","v":3,"meta":{"def":"Prestigious summer opera and concert festival.","ex":"Salzburger Festspiele","region":"Salzburg, Austria","note":"Founded in 1920 in Mozart's birthplace."}},{"name":"BBC Proms","v":3,"meta":{"def":"Eight-week season of daily orchestral concerts with cheap standing.","ex":"The Proms, Royal Albert Hall","region":"London, England","note":"The flag-waving Last Night is a broadcast institution."}},{"name":"Bayreuth Festival","v":3,"meta":{"def":"Festival performing only the operas of Richard Wagner.","ex":"Bayreuther Festspiele","region":"Bayreuth, Germany","note":"Staged in the composer's purpose-built Festspielhaus."}},{"name":"Glyndebourne","v":3,"meta":{"def":"Country-house opera festival with long dinner intervals.","ex":"Glyndebourne Festival Opera","region":"East Sussex, England","note":"Audiences traditionally picnic on the lawns in black tie."}},{"name":"Verona Opera Festival","v":3,"meta":{"def":"Grand open-air opera in a Roman amphitheatre.","ex":"Arena di Verona Opera Festival","region":"Verona, Italy","note":"Audiences light candles in the ancient stone arena."}}]},{"name":"Folk and World Festivals","v":5,"meta":{"def":"Festivals of traditional, roots and global-music traditions.","ex":"WOMAD, Cambridge Folk","region":"Worldwide","note":"WOMAD was co-founded by Peter Gabriel to spotlight world music."},"children":[{"name":"WOMAD","v":3,"meta":{"def":"World of Music, Arts and Dance festival franchise.","ex":"WOMAD Charlton Park","region":"UK and international editions","note":"Its name explicitly stands for World of Music, Arts and Dance."}},{"name":"Cambridge Folk Festival","v":3,"meta":{"def":"Long-running intimate folk and roots festival.","ex":"Cambridge Folk Festival","region":"Cambridge, England","note":"Held on the grounds of Cherry Hinton Hall since 1965."}},{"name":"Fes Festival of Sacred Music","v":3,"meta":{"def":"Festival of spiritual music from many faith traditions.","ex":"Fes Festival of World Sacred Music","region":"Fes, Morocco","note":"Concerts are set among historic medina palaces and gardens."}},{"name":"Rainforest World Music Festival","v":3,"meta":{"def":"Festival of indigenous and world music in Borneo.","ex":"Rainforest World Music Festival","region":"Kuching, Sarawak, Malaysia","note":"Staged at a cultural village at the foot of Mount Santubong."}},{"name":"Festival au Desert","v":3,"meta":{"def":"Tuareg desert festival showcasing Saharan music.","ex":"Festival au Desert, Essakane","region":"Near Timbuktu, Mali","note":"Suspended for security reasons and now often held in exile."}}]},{"name":"Hip-Hop and Rap Festivals","v":4,"meta":{"def":"Festivals centred on rap, trap and hip-hop culture.","ex":"Rolling Loud","region":"US-led, now global","note":"A comparatively young festival category that scaled fast in the 2010s."},"children":[{"name":"Rolling Loud","v":3,"meta":{"def":"The largest touring hip-hop festival brand.","ex":"Rolling Loud Miami","region":"Miami and global editions","note":"Grew from a single Florida event into worldwide franchises."}},{"name":"Wireless Festival","v":3,"meta":{"def":"UK festival increasingly focused on rap and R and B.","ex":"Wireless Festival","region":"London, England","note":"Shifted decisively toward a hip-hop-heavy lineup in the 2010s."}},{"name":"A3C","v":3,"meta":{"def":"Hip-hop festival and conference blending shows and panels.","ex":"A3C Festival and Conference","region":"Atlanta, Georgia","note":"Nicknamed the hip-hop equivalent of a music-business summit."}},{"name":"Openair Frauenfeld","v":3,"meta":{"def":"Europe's largest hip-hop festival by attendance.","ex":"Openair Frauenfeld","region":"Frauenfeld, Switzerland","note":"Draws crowds far larger than the host town's population."}}]},{"name":"Country Festivals","v":4,"meta":{"def":"Festivals dedicated to country, Americana and roots.","ex":"Stagecoach","region":"Chiefly the US South and West","note":"Often paired logistically with adjacent pop or rock events."},"children":[{"name":"Stagecoach","v":3,"meta":{"def":"Large country festival on the Coachella grounds.","ex":"Stagecoach Festival","region":"Indio, California","note":"Held the weekend after Coachella on the same polo fields."}},{"name":"CMA Fest","v":3,"meta":{"def":"Fan-focused downtown country festival with stadium nights.","ex":"CMA Fest","region":"Nashville, Tennessee","note":"Formerly known as Fan Fair, run by the Country Music Association."}},{"name":"Country Thunder","v":3,"meta":{"def":"Camping country-music festival franchise.","ex":"Country Thunder Arizona","region":"Arizona and Wisconsin","note":"Runs multiple editions across North America each year."}},{"name":"C2C Country to Country","v":3,"meta":{"def":"Arena country festival exporting Nashville to Europe.","ex":"C2C: Country to Country","region":"London, Glasgow and Dublin","note":"Runs simultaneously across multiple European arenas."}}]},{"name":"Boutique and Camping Festivals","v":4,"meta":{"def":"Smaller, curated festivals prizing atmosphere over scale.","ex":"End of the Road, Green Man","region":"UK and Europe especially","note":"Often family-friendly with strong food, arts and wellness offerings."},"children":[{"name":"End of the Road","v":3,"meta":{"def":"Intimate independent festival in a Dorset country park.","ex":"End of the Road Festival","region":"Larmer Tree Gardens, England","note":"Famous for peacocks roaming the woodland grounds."}},{"name":"Green Man","v":3,"meta":{"def":"Welsh mountain festival crowned by a burning effigy.","ex":"Green Man Festival","region":"Brecon Beacons, Wales","note":"Closes with the ceremonial burning of a giant Green Man."}},{"name":"Pitchfork Music Festival","v":3,"meta":{"def":"Curated indie festival tied to the music-review site.","ex":"Pitchfork Music Festival","region":"Union Park, Chicago","note":"Known for an eclectic critically-driven lineup."}},{"name":"Meredith Music Festival","v":3,"meta":{"def":"Single-stage Australian camping festival with no bar on genre.","ex":"Meredith Music Festival","region":"Meredith, Victoria, Australia","note":"Runs a single stage under the 'no dickheads' community policy."}}]},{"name":"Cruise and Floating Festivals","v":3,"meta":{"def":"Festivals staged aboard chartered cruise ships at sea.","ex":"Holy Ship, Groove Cruise","region":"Caribbean and Mediterranean routes","note":"Artists and fans share the boat for the full multi-day voyage."},"children":[{"name":"Holy Ship","v":3,"meta":{"def":"Electronic-music cruise festival with pool-deck stages.","ex":"Holy Ship!","region":"Caribbean sailings from Florida","note":"Fans call themselves shipfam across recurring voyages."}},{"name":"Kiss Kruise","v":3,"meta":{"def":"Rock-band-branded cruise with themed sets and meet-ups.","ex":"The Kiss Kruise","region":"Caribbean sailings","note":"Features indoor and unplugged sets exclusive to sailings."}},{"name":"Mahogany and Jazz Cruises","v":3,"meta":{"def":"Genre-themed cruises for jazz and soul audiences.","ex":"The Jazz Cruise, Blue Note at Sea","region":"Caribbean itineraries","note":"Marketed as a floating jazz-club residency at sea."}}]},{"name":"Desert and Destination Festivals","v":4,"meta":{"def":"Immersive festivals set in remote deserts or exotic locales.","ex":"Burning Man, AfrikaBurn","region":"Deserts and remote destinations","note":"Many emphasize participation and self-reliance over passive spectating."},"children":[{"name":"Burning Man","v":3,"meta":{"def":"Temporary desert city built on radical self-expression.","ex":"Burning Man, Black Rock City","region":"Black Rock Desert, Nevada","note":"Runs on a gift economy with no vendors selling on the playa."}},{"name":"AfrikaBurn","v":3,"meta":{"def":"African regional burn event in the Karoo desert.","ex":"AfrikaBurn, Tankwa Karoo","region":"Tankwa Karoo, South Africa","note":"The largest regional offshoot of Burning Man culture."}},{"name":"Oasis Festival","v":3,"meta":{"def":"Destination dance festival at a Moroccan resort.","ex":"Oasis Festival, Marrakech","region":"Marrakech, Morocco","note":"Combines poolside house sets with local cultural excursions."}},{"name":"Sea Dance and Exit Beach Events","v":3,"meta":{"def":"Adriatic beach-set destination festivals.","ex":"Sea Dance Festival","region":"Budva, Montenegro","note":"Spun off from Serbia's Exit festival brand."}}]},{"name":"Free and Community Festivals","v":3,"meta":{"def":"No-ticket public festivals funded by cities or sponsors.","ex":"Fete de la Musique, Notting Hill Carnival","region":"Worldwide","note":"Often civic celebrations rather than commercial promotions."},"children":[{"name":"Fete de la Musique","v":3,"meta":{"def":"Global day of free street music on the summer solstice.","ex":"Fete de la Musique, World Music Day","region":"Originated in France, now worldwide","note":"Anyone can perform in public for free on 21 June."}},{"name":"Notting Hill Carnival","v":3,"meta":{"def":"Caribbean street carnival with sound systems and steel bands.","ex":"Notting Hill Carnival","region":"London, England","note":"One of the world's largest street festivals, led by Caribbean culture."}},{"name":"Make Music Day","v":3,"meta":{"def":"Community day of free amateur and pro performances.","ex":"Make Music Day","region":"US and international cities","note":"The American sibling of Fete de la Musique."}}]}]},{"name":"Concerts and Shows","v":12,"meta":{"def":"Discrete live performances by artists for an audience.","ex":"Headline tours, arena shows, club gigs","region":"Worldwide","note":"Spans intimate recitals to record-breaking stadium spectacles."},"children":[{"name":"Headline Concert","v":3,"meta":{"def":"A show topped by the main billed act of the evening.","ex":"Taylor Swift Eras Tour night","region":"Worldwide","note":"The headliner closes the bill and commands the longest set."}},{"name":"Arena Show","v":3,"meta":{"def":"Indoor concert in a large capacity sports-style arena.","ex":"Concert at Madison Square Garden or The O2","region":"Major cities worldwide","note":"Typical capacities run from roughly ten to twenty thousand."}},{"name":"Stadium Show","v":3,"meta":{"def":"Massive outdoor concert in a football or baseball stadium.","ex":"U2 or Beyonce stadium dates, Wembley Stadium","region":"Worldwide","note":"Requires elaborate touring stages and multi-day load-ins."}},{"name":"Club Gig","v":3,"meta":{"def":"Small-venue performance in an intimate club setting.","ex":"A gig at the 100 Club or CBGB-style room","region":"Worldwide","note":"The grassroots proving ground for developing artists."}},{"name":"Recital","v":3,"meta":{"def":"Solo or small-ensemble classical performance.","ex":"A piano recital at Wigmore Hall","region":"Concert halls worldwide","note":"Traditionally focused on a single instrument or voice."}},{"name":"Benefit and Charity Concert","v":4,"meta":{"def":"Concert staged to raise money or awareness for a cause.","ex":"Live Aid, Live 8","region":"Worldwide","note":"Live Aid was broadcast simultaneously from London and Philadelphia."},"children":[{"name":"Live Aid","v":3,"meta":{"def":"1985 dual-venue famine-relief benefit for Ethiopia.","ex":"Live Aid, Wembley and JFK Stadium","region":"London and Philadelphia","note":"Queen's set is often voted the greatest live performance ever."}},{"name":"Live 8","v":3,"meta":{"def":"2005 multi-city concerts pressuring G8 on poverty.","ex":"Live 8","region":"Ten cities worldwide","note":"Timed to coincide with the G8 summit at Gleneagles."}},{"name":"Concert for Bangladesh","v":3,"meta":{"def":"Pioneering 1971 all-star benefit organized by George Harrison.","ex":"The Concert for Bangladesh","region":"Madison Square Garden, New York","note":"Widely regarded as the first major benefit rock concert."}},{"name":"One Love Manchester","v":3,"meta":{"def":"2017 benefit responding to the Manchester Arena attack.","ex":"One Love Manchester","region":"Manchester, England","note":"Organized by Ariana Grande for victims and their families."}}]},{"name":"Tribute Concert","v":3,"meta":{"def":"Event honouring an artist through covers and guest performers.","ex":"The Freddie Mercury Tribute Concert","region":"Worldwide","note":"Often a memorial gathering after a musician's death."}},{"name":"Reunion Show","v":3,"meta":{"def":"One-off or tour by a band regrouping after a split.","ex":"Led Zeppelin at the O2 in 2007","region":"Worldwide","note":"Reunions can command extraordinary ticket demand."}},{"name":"Farewell Tour Show","v":3,"meta":{"def":"Performance on a billed final or retirement tour.","ex":"Elton John Farewell Yellow Brick Road","region":"Worldwide","note":"Farewell branding sometimes precedes later comebacks."}},{"name":"Las Vegas Residency","v":3,"meta":{"def":"Extended run of shows by an artist at one Vegas venue.","ex":"Celine Dion at Caesars Palace","region":"Las Vegas, Nevada","note":"Residencies let artists build elaborate fixed stage productions."}},{"name":"Livestream Concert","v":3,"meta":{"def":"Performance broadcast live to a remote online audience.","ex":"Travis Scott's Astronomical inside Fortnite","region":"Online","note":"Surged during pandemic lockdowns as venues closed."}},{"name":"Unplugged Show","v":3,"meta":{"def":"Stripped-down acoustic performance format.","ex":"MTV Unplugged, Nirvana in New York","region":"Originated as an MTV series","note":"Nirvana's 1993 taping became a landmark posthumous album."}}]},{"name":"Industry and Trade Events","v":8,"meta":{"def":"Business-facing gatherings for the music trade.","ex":"ADE, MIDEM, NAMM","region":"Global industry hubs","note":"Where deals, showcases and networking drive the business side."},"children":[{"name":"Amsterdam Dance Event","v":3,"meta":{"def":"Vast electronic-music conference paired with a city festival.","ex":"ADE, Amsterdam Dance Event","region":"Amsterdam, Netherlands","note":"Combines daytime business panels with hundreds of night events."}},{"name":"MIDEM Legacy Market","v":3,"meta":{"def":"Historic global music-business trade fair on the Riviera.","ex":"MIDEM, Cannes","region":"Cannes, France","note":"For decades the main international rights and licensing marketplace."}},{"name":"The Great Escape Conference","v":3,"meta":{"def":"Industry conference bolted to a new-music showcase festival.","ex":"The Great Escape","region":"Brighton, England","note":"Pairs delegate panels with hundreds of emerging-act sets."}},{"name":"Reeperbahn Festival","v":3,"meta":{"def":"Club festival and conference in Hamburg's entertainment district.","ex":"Reeperbahn Festival","region":"Hamburg, Germany","note":"Europe's largest club-festival and business meeting hybrid."}},{"name":"Music Biz and Winter Music Conference","v":3,"meta":{"def":"Trade conferences for the record business and dance sector.","ex":"Music Biz, Winter Music Conference","region":"US host cities","note":"WMC has long anchored Miami's dance-industry calendar."}},{"name":"NAMM Show","v":3,"meta":{"def":"Trade show for musical-instrument and gear manufacturers.","ex":"The NAMM Show","region":"Anaheim, California","note":"Where new instruments and audio gear debut to dealers."}},{"name":"A&R and Sync Showcases","v":3,"meta":{"def":"Curated sets and summits to place artists and license music.","ex":"A&R showcase, Sync Summit","region":"Industry cities","note":"Sync summits connect music owners with film, TV and ad buyers."}},{"name":"Panels and Networking Mixers","v":3,"meta":{"def":"Talks and social sessions for professional dealmaking.","ex":"Keynote panels, delegate mixers","region":"Attached to most conferences","note":"Often where informal deals and collaborations actually begin."}}]},{"name":"Award Shows","v":12,"meta":{"def":"Ceremonies honouring recorded and live musical achievement.","ex":"Grammy Awards, BRIT Awards","region":"Worldwide","note":"Both industry-voted and public-voted formats coexist."},"children":[{"name":"Grammy Awards","v":3,"meta":{"def":"Peer-voted awards of the US Recording Academy.","ex":"The Grammy Awards","region":"United States","note":"The gramophone trophy gives the ceremony its nickname."}},{"name":"BRIT Awards","v":3,"meta":{"def":"The British record industry's flagship awards ceremony.","ex":"The BRIT Awards","region":"United Kingdom","note":"Run by the British Phonographic Industry."}},{"name":"MTV Video Music Awards","v":3,"meta":{"def":"Music-video awards famous for headline-grabbing performances.","ex":"MTV VMAs, the Moonman trophy","region":"United States","note":"Its Moonman statuette references the first MTV broadcast."}},{"name":"American Music Awards","v":3,"meta":{"def":"Fan-voted US awards based on popularity metrics.","ex":"American Music Awards","region":"United States","note":"Created by Dick Clark as an alternative to the Grammys."}},{"name":"Billboard Music Awards","v":3,"meta":{"def":"Awards driven by Billboard chart performance data.","ex":"Billboard Music Awards","region":"United States","note":"Winners are determined largely by measured chart success."}},{"name":"BET and MOBO Awards","v":3,"meta":{"def":"Awards celebrating Black and urban music achievement.","ex":"BET Awards, MOBO Awards","region":"United States and United Kingdom","note":"MOBO stands for Music of Black Origin."}},{"name":"Mercury Prize","v":3,"meta":{"def":"Award for the best British or Irish album of the year.","ex":"The Mercury Prize","region":"United Kingdom and Ireland","note":"A single album is chosen from a twelve-record shortlist."}},{"name":"Ivor Novello Awards","v":3,"meta":{"def":"Songwriting and composing awards judged by peers.","ex":"The Ivors","region":"United Kingdom","note":"Honour craft in composition rather than sales."}},{"name":"Latin Grammy Awards","v":3,"meta":{"def":"Awards for Spanish and Portuguese-language recordings.","ex":"Latin Grammy Awards","region":"Ibero-America","note":"Run by the Latin Recording Academy as a Grammy sibling."}},{"name":"Juno and ARIA Awards","v":3,"meta":{"def":"National music awards of Canada and Australia.","ex":"Juno Awards, ARIA Music Awards","region":"Canada and Australia","note":"ARIA is named for the Australian Recording Industry Association."}},{"name":"Polar Music Prize","v":3,"meta":{"def":"Prestigious international prize spanning genres.","ex":"Polar Music Prize","region":"Sweden","note":"Often described as the Nobel Prize of music."}},{"name":"Kennedy Center Honors","v":3,"meta":{"def":"Lifetime-achievement honours for the performing arts.","ex":"Kennedy Center Honors","region":"Washington, D.C.","note":"Recipients wear distinctive rainbow ribbon medallions."}}]},{"name":"Competitions and Contests","v":8,"meta":{"def":"Events where musicians compete for titles or prizes.","ex":"Eurovision, DMC, Chopin Competition","region":"Worldwide","note":"Range from televised pop contests to elite classical juries."},"children":[{"name":"Eurovision Song Contest","v":3,"meta":{"def":"Pan-European televised song competition between nations.","ex":"Eurovision Song Contest","region":"European Broadcasting Union members","note":"Launched ABBA's career after their 1974 win with 'Waterloo'."}},{"name":"Battle of the Bands","v":3,"meta":{"def":"Contest pitting live bands against each other for a title.","ex":"Local and national battle of the bands","region":"Worldwide","note":"A classic grassroots route for unsigned acts to gain exposure."}},{"name":"DMC DJ Championships","v":3,"meta":{"def":"World turntablism contest judged on scratching and juggling.","ex":"DMC World DJ Championships","region":"International, London finals","note":"The premier competition for battle turntablists."}},{"name":"Televised Talent Shows","v":4,"meta":{"def":"Broadcast singing contests with public voting.","ex":"Idol, The Voice, The X Factor","region":"Global franchises","note":"Formats are licensed and localized across dozens of countries."},"children":[{"name":"Idol Franchise","v":3,"meta":{"def":"Singing contest built on audition and elimination rounds.","ex":"Pop Idol, American Idol","region":"Originated in the UK","note":"Spawned a global format sold to dozens of territories."}},{"name":"The Voice","v":3,"meta":{"def":"Contest with blind auditions where coaches turn their chairs.","ex":"The Voice","region":"Originated in the Netherlands","note":"Coaches pick teams without seeing the singers first."}},{"name":"The X Factor","v":3,"meta":{"def":"Talent contest with mentored categories and live finals.","ex":"The X Factor","region":"Originated in the UK","note":"Created by Simon Cowell after the Idol format."}},{"name":"Got Talent Music Acts","v":3,"meta":{"def":"Variety talent contest often won by singers and musicians.","ex":"Britain's Got Talent, America's Got Talent","region":"Global franchise","note":"Open to all acts but frequently crowns musical performers."}}]},{"name":"Classical Competitions","v":4,"meta":{"def":"Elite juried contests launching classical careers.","ex":"Chopin, Tchaikovsky, Van Cliburn","region":"Worldwide","note":"Winning a top prize can define a soloist's whole career."},"children":[{"name":"Chopin Piano Competition","v":3,"meta":{"def":"Prestigious piano contest featuring only Chopin's works.","ex":"International Chopin Piano Competition","region":"Warsaw, Poland","note":"Held every five years since 1927."}},{"name":"Tchaikovsky Competition","v":3,"meta":{"def":"Major contest across piano, strings, voice and winds.","ex":"International Tchaikovsky Competition","region":"Moscow, Russia","note":"Van Cliburn's 1958 win became a Cold War sensation."}},{"name":"Van Cliburn Competition","v":3,"meta":{"def":"American piano competition named for its Cold War hero.","ex":"Van Cliburn International Piano Competition","region":"Fort Worth, Texas","note":"Founded to honour Cliburn's own Moscow triumph."}},{"name":"BBC Young Musician","v":3,"meta":{"def":"Televised UK contest for classical instrumentalists under 18.","ex":"BBC Young Musician of the Year","region":"United Kingdom","note":"Nicola Benedetti won it as a teenage violinist in 2004."}}]},{"name":"Choir and Brass-Band Contests","v":3,"meta":{"def":"Competitions for choral ensembles and brass bands.","ex":"Llangollen Eisteddfod, British Open brass contest","region":"UK and worldwide","note":"Brass-band contesting is a deep-rooted community tradition."}},{"name":"Beatbox Championships","v":3,"meta":{"def":"Contests judging vocal-percussion battles head to head.","ex":"Grand Beatbox Battle, Beatbox World Championship","region":"International","note":"Rounds are typically judged in knockout head-to-head battles."}},{"name":"Songwriting Contests","v":3,"meta":{"def":"Competitions awarding original song composition.","ex":"International Songwriting Competition","region":"Worldwide","note":"Often judged on lyric, melody and production together."}}]},{"name":"Club and Underground Events","v":10,"meta":{"def":"Nightlife and grassroots dance gatherings.","ex":"Raves, warehouse parties, Boiler Room","region":"Worldwide nightlife scenes","note":"Where scenes incubate away from the mainstream spotlight."},"children":[{"name":"Club Night","v":3,"meta":{"def":"Recurring themed night at a nightclub with resident DJs.","ex":"A resident club night at Berghain or Fabric","region":"Worldwide","note":"Long-running nights build loyal scene followings."}},{"name":"Rave","v":3,"meta":{"def":"All-night electronic dance party, often outside clubs.","ex":"Early UK acid-house raves","region":"Originated UK and US","note":"The 1988 Second Summer of Love spread rave culture in Britain."}},{"name":"Warehouse Party","v":3,"meta":{"def":"Dance event in a repurposed industrial building.","ex":"Detroit and Chicago warehouse parties","region":"Worldwide","note":"Industrial spaces shaped the raw sound of early house and techno."}},{"name":"Illegal and Free Party","v":3,"meta":{"def":"Unlicensed gathering in unofficial or outdoor spaces.","ex":"Castlemorton Common free festival","region":"UK free-party scene and beyond","note":"The 1992 Castlemorton rave prompted the UK Criminal Justice Act."}},{"name":"Silent Disco","v":3,"meta":{"def":"Party where dancers hear music through wireless headphones.","ex":"Silent disco tents at festivals","region":"Worldwide","note":"Lets multiple channels play at once with no external noise."}},{"name":"Block Party","v":3,"meta":{"def":"Street gathering with music for a neighbourhood.","ex":"1970s Bronx hip-hop block parties","region":"United States especially","note":"DJ Kool Herc's Bronx block parties helped birth hip-hop."}},{"name":"Sound-System Dance","v":3,"meta":{"def":"Event built around a custom-built reggae sound system.","ex":"Notting Hill sound-system dances","region":"Jamaica and the UK","note":"Rooted in Jamaican dancehall and dub culture."}},{"name":"Listening Party","v":3,"meta":{"def":"Communal first play-through of a new album.","ex":"Tim Burgess Listening Parties","region":"Worldwide, often online","note":"Twitter-based album listen-alongs surged during lockdowns."}},{"name":"After-Party","v":3,"meta":{"def":"Late continuation event after a main show or club night.","ex":"Post-festival and post-gig after-parties","region":"Worldwide","note":"Often where headliners themselves turn up to dance."}},{"name":"Boiler Room Style Stream","v":3,"meta":{"def":"Intimate DJ set filmed live and streamed to the world.","ex":"Boiler Room broadcasts","region":"Global online","note":"Cameras face the crowd as much as the DJ."}}]},{"name":"Ceremonial and Social Occasions","v":9,"meta":{"def":"Life events and public rituals where music is central.","ex":"Weddings, funerals, state ceremonies","region":"All cultures","note":"Music marks transitions and shared communal moments."},"children":[{"name":"Wedding","v":3,"meta":{"def":"Marriage celebration with processional and reception music.","ex":"Wagner's Bridal Chorus, first-dance songs","region":"Worldwide","note":"Bands and DJs are a major slice of the live-music economy."}},{"name":"Funeral","v":3,"meta":{"def":"Memorial rite marked by hymns, laments or requiems.","ex":"New Orleans jazz funeral second line","region":"Worldwide","note":"The jazz funeral turns mourning into a joyful send-off."}},{"name":"Graduation","v":3,"meta":{"def":"Commencement ceremony with processional music.","ex":"Elgar's 'Pomp and Circumstance'","region":"Worldwide","note":"The Elgar march is the near-universal graduation anthem."}},{"name":"Religious Service","v":3,"meta":{"def":"Worship gathering built around sacred music.","ex":"Gospel church service, call to prayer, kirtan","region":"Worldwide faiths","note":"Many musical traditions began in sacred worship."}},{"name":"State and Coronation Ceremony","v":3,"meta":{"def":"National rite scored by ceremonial and choral music.","ex":"Handel's 'Zadok the Priest' at coronations","region":"Monarchies and republics","note":"Zadok has been sung at every British coronation since 1727."}},{"name":"Parade and Procession","v":3,"meta":{"def":"Marching musical procession through public streets.","ex":"Macy's Thanksgiving Parade bands, Mardi Gras","region":"Worldwide","note":"Marching bands are the backbone of civic parade music."}},{"name":"Sporting-Event Music","v":4,"meta":{"def":"Music staged around athletic competition.","ex":"Super Bowl halftime show, national anthems","region":"Worldwide","note":"The Super Bowl halftime slot is among TV's biggest stages."},"children":[{"name":"Halftime Show","v":3,"meta":{"def":"Marquee mid-game concert at a major sporting final.","ex":"Super Bowl Halftime Show","region":"United States","note":"Prince's 2007 rain-soaked set is a fan-favourite performance."}},{"name":"Stadium Anthems","v":3,"meta":{"def":"Songs sung en masse by crowds at sporting grounds.","ex":"'You'll Never Walk Alone' at Anfield","region":"Worldwide","note":"Liverpool fans adopted the Rodgers and Hammerstein show tune."}},{"name":"National Anthem Performance","v":3,"meta":{"def":"Solo rendition of an anthem before competition.","ex":"Whitney Houston's 1991 Super Bowl anthem","region":"Worldwide","note":"Houston's Star-Spangled Banner was later released as a single."}},{"name":"Olympic Ceremony Music","v":3,"meta":{"def":"Live music score for the opening and closing of the Games.","ex":"London 2012 opening ceremony","region":"Host cities","note":"Ceremonies double as showcases of a nation's musical heritage."}}]},{"name":"New Year Celebration","v":3,"meta":{"def":"Countdown gathering with communal singing and music.","ex":"'Auld Lang Syne', Vienna New Year's Concert","region":"Worldwide","note":"The Vienna Philharmonic's concert is broadcast globally each 1 January."}},{"name":"Carnival and Festival Rite","v":3,"meta":{"def":"Seasonal cultural festival with music at its core.","ex":"Rio Carnival samba parade, Trinidad Carnival","region":"Latin America and Caribbean","note":"Rio's samba-school parade is judged in the Sambadrome."}}]},{"name":"Halls of Fame and Inductions","v":5,"meta":{"def":"Institutions and ceremonies enshrining musical greats.","ex":"Rock and Roll Hall of Fame","region":"Chiefly the United States","note":"Induction ceremonies double as all-star tribute concerts."},"children":[{"name":"Rock and Roll Hall of Fame","v":3,"meta":{"def":"Museum and annual induction honouring rock's influencers.","ex":"Rock and Roll Hall of Fame, Cleveland","region":"Cleveland, Ohio","note":"Artists become eligible 25 years after their first release."}},{"name":"Country Music Hall of Fame","v":3,"meta":{"def":"Nashville institution honouring country greats.","ex":"Country Music Hall of Fame","region":"Nashville, Tennessee","note":"Inductees are commemorated with bronze plaques in a rotunda."}},{"name":"Songwriters Hall of Fame","v":3,"meta":{"def":"Honour for those who write music and lyrics.","ex":"Songwriters Hall of Fame","region":"United States","note":"Recognizes the writers behind hits rather than the performers."}},{"name":"Dance Music Hall of Fame","v":3,"meta":{"def":"Recognition for pioneers of dance and electronic music.","ex":"Dance Music Hall of Fame","region":"United States","note":"Honoured DJs, producers and records that shaped club culture."}},{"name":"Grand Ole Opry Induction","v":3,"meta":{"def":"Membership in the historic country radio institution.","ex":"Grand Ole Opry, Nashville","region":"Nashville, Tennessee","note":"Opry membership is a coveted lifelong honour in country music."}}]}]},{"name":"Media & Distribution","type":"media","v":26,"children":[{"name":"Physical Formats & Media","v":14,"meta":{"def":"Tangible carriers on which recorded music is manufactured, sold and played.","ex":"vinyl, CD, cassette, MiniDisc","aka":"hard copies, physical product","note":"Vinyl outsold CDs in US dollar terms in 2022 for the first time since 1987."},"children":[{"name":"Vinyl Records","v":11,"meta":{"def":"Analogue discs storing sound in a modulated spiral groove read by a stylus.","ex":"LP, 7-inch single, picture disc","aka":"records, wax, black plastic","note":"Standard speeds are 33 1/3, 45 and 78 rpm."},"children":[{"name":"LP (12-inch album)","v":5,"meta":{"def":"Long-play 12-inch record at 33 1/3 rpm holding roughly 22 minutes per side.","ex":"Sgt. Pepper, Thriller","aka":"long player","note":"Introduced by Columbia in 1948 using microgroove technology."}},{"name":"7-inch / 45 single","v":4,"meta":{"def":"Small 45 rpm disc holding one song per side with a wide centre hole.","ex":"jukebox singles, A-side/B-side","aka":"45, seven-inch","note":"RCA introduced the 45 in 1949 as a rival to Columbia's LP."}},{"name":"12-inch single","v":4,"meta":{"def":"Full-size single cut with wider grooves for louder, extended club mixes.","ex":"disco and dance remixes","aka":"maxi-single, twelve","note":"Favoured by DJs for superior bass and long fade mixes."}},{"name":"10-inch record","v":3,"meta":{"def":"Intermediate-size disc used for shorter albums, EPs and early 78s.","ex":"jazz 10-inchers, RSD releases","aka":"ten-inch","note":"Common album format in the early 1950s before the 12-inch dominated."}},{"name":"EP (extended play vinyl)","v":3,"meta":{"def":"Record with more tracks than a single but fewer than an album, often 7-inch at 45.","ex":"1950s pop EPs","aka":"extended play","note":"Popular in Europe as a cheaper multi-track alternative to the LP."}},{"name":"Picture disc","v":3,"meta":{"def":"Vinyl pressed with a printed image visible through the transparent playing surface.","ex":"collector editions","aka":"picture vinyl","note":"Image layer can add surface noise versus standard black vinyl."}},{"name":"Coloured vinyl","v":3,"meta":{"def":"Records pressed in translucent, opaque or splattered colours instead of black.","ex":"splatter, marble, glow","aka":"colour vinyl, splatter","note":"Carbon black adds strength, so some colours are more noise-prone."}},{"name":"180-gram audiophile vinyl","v":3,"meta":{"def":"Heavyweight pressing marketed for flatness, durability and premium feel.","ex":"reissue box sets","aka":"heavyweight vinyl","note":"Weight itself does not improve fidelity but resists warping."}},{"name":"Flexi disc","v":3,"meta":{"def":"Thin flexible sheet of plastic playable on a turntable, cheap to produce.","ex":"magazine giveaways","aka":"flexi, phonosheet","note":"Often bound into magazines or given as promotional inserts."}},{"name":"Shellac 78 rpm","v":3,"meta":{"def":"Brittle pre-vinyl disc of shellac resin played at 78 rpm.","ex":"pre-1950 recordings","aka":"78s, gramophone record","note":"Dominant format from the 1900s until vinyl microgroove arrived."}},{"name":"Lathe-cut record","v":3,"meta":{"def":"Short-run disc individually cut on a lathe rather than pressed from a stamper.","ex":"micro-label releases","aka":"dubplate, one-off","note":"Economical for tiny editions where pressing plates are too costly."}}]},{"name":"Optical Discs","v":8,"meta":{"def":"Discs storing audio as digital pits read by a laser.","ex":"CD, SACD, DVD-Audio","aka":"silver discs","note":"The 74-minute CD length is said to fit Beethoven's Ninth Symphony."},"children":[{"name":"CD album","v":4,"meta":{"def":"12-cm compact disc holding a full album of 16-bit/44.1 kHz digital audio.","ex":"standard retail CD","aka":"compact disc, CD","note":"Co-developed by Sony and Philips and launched commercially in 1982."}},{"name":"CD single","v":3,"meta":{"def":"Compact disc carrying one or a few tracks, often with B-sides.","ex":"chart single CDs","aka":"CDS","note":"The 3-inch mini CD single was briefly popular in the late 1980s."}},{"name":"Maxi CD single","v":3,"meta":{"def":"Extended CD single with remixes and bonus tracks, longer than a standard single.","ex":"dance remix singles","aka":"maxi-single","note":"Common in club and dance markets for multiple mixes."}},{"name":"Enhanced CD","v":3,"meta":{"def":"CD combining audio tracks with computer-readable multimedia content.","ex":"videos, artwork data track","aka":"CD Extra, CD Plus","note":"Used a mixed-mode or blue-book layout to add data safely."}},{"name":"HDCD","v":3,"meta":{"def":"High Definition Compatible Digital CD encoding extra resolution playable on decoders.","ex":"Reference Recordings titles","aka":"High Definition Compatible Digital","note":"Encoded data is inaudible on standard players lacking a decoder."}},{"name":"SACD","v":3,"meta":{"def":"Super Audio CD using DSD encoding for high-resolution and multichannel sound.","ex":"hybrid SACD reissues","aka":"Super Audio CD","note":"Hybrid discs carry a standard CD layer for backward compatibility."}},{"name":"DVD-Audio","v":3,"meta":{"def":"DVD-based format delivering high-resolution stereo and surround audio.","ex":"5.1 surround albums","aka":"DVD-A","note":"Lost a format war with SACD and never reached the mainstream."}},{"name":"Blu-ray Audio","v":3,"meta":{"def":"Blu-ray disc used purely for high-resolution and immersive audio playback.","ex":"Pure Audio Blu-ray","aka":"Pure Audio","note":"High capacity supports lossless multichannel and Dolby Atmos mixes."}}]},{"name":"Tape & Magnetic Formats","v":6,"meta":{"def":"Formats recording sound as magnetic patterns on moving tape.","ex":"cassette, 8-track, DAT","aka":"magnetic media","note":"The Compact Cassette made portable and home recording mainstream."},"children":[{"name":"Compact cassette","v":4,"meta":{"def":"Miniature twin-reel tape cartridge for playback and home recording.","ex":"mixtapes, Walkman tapes","aka":"tape, cassette","note":"Introduced by Philips in 1963 and revived as a niche format."}},{"name":"8-track cartridge","v":3,"meta":{"def":"Endless-loop tape cartridge splitting music into four stereo programs.","ex":"1970s car stereos","aka":"eight-track, Stereo 8","note":"Popular in American cars before the cassette overtook it."}},{"name":"DAT (Digital Audio Tape)","v":3,"meta":{"def":"Cassette storing digital audio, widely used for professional mastering.","ex":"studio master tapes","aka":"Digital Audio Tape","note":"Consumer sales were limited by copy-protection concerns."}},{"name":"Reel-to-reel","v":3,"meta":{"def":"Open-reel magnetic tape offering high fidelity for studios and audiophiles.","ex":"master tapes, tape decks","aka":"open reel, quarter-inch tape","note":"Faster tape speeds and wider tape give higher fidelity."}},{"name":"MiniDisc","v":3,"meta":{"def":"Magneto-optical disc in a cartridge using ATRAC compression, recordable and small.","ex":"portable MD recorders","aka":"MD","note":"Sony format popular in Japan and among gig recordists."}},{"name":"Wire recording","v":3,"meta":{"def":"Early magnetic recording storing audio on thin steel wire.","ex":"1940s dictation and radio","aka":"magnetic wire","note":"Preceded tape and was used for wartime broadcast archiving."}}]},{"name":"Mechanical & Novelty Media","v":5,"meta":{"def":"Pre-electronic or unconventional carriers of recorded or encoded music.","ex":"wax cylinder, piano roll","aka":"legacy media, novelty formats","note":"Edison's wax cylinder was the first commercial sound-recording medium."},"children":[{"name":"Wax cylinder","v":3,"meta":{"def":"Rotating wax cylinder holding sound in a groove read by a stylus.","ex":"Edison phonograph cylinders","aka":"phonograph cylinder","note":"Dominant recorded-sound format in the 1890s and early 1900s."}},{"name":"Piano roll","v":3,"meta":{"def":"Perforated paper roll encoding note data for a player piano.","ex":"reproducing pianos","aka":"player-piano roll","note":"Captured performances by pianists before audio recording matured."}},{"name":"USB / card release","v":3,"meta":{"def":"Album delivered on a USB stick or memory card, sometimes as merch.","ex":"USB wristband albums","aka":"USB album, SD release","note":"Used by artists for high-res files plus collectible packaging."}},{"name":"Music box cylinder","v":3,"meta":{"def":"Pinned cylinder or disc plucking metal tines to play a melody mechanically.","ex":"antique music boxes","aka":"cylinder musical box","note":"An early consumer form of programmed automatic music."}},{"name":"Vinyl-shaped novelty","v":3,"meta":{"def":"Playable records cut into unusual shapes or materials as collectibles.","ex":"shaped picture discs, chocolate records","aka":"shaped disc","note":"Non-round edges can cause tracking and speed irregularities."}}]}]},{"name":"Release Formats","v":12,"meta":{"def":"The way recorded content is packaged and presented regardless of medium.","ex":"single, album, EP, box set","aka":"release types, product configurations","note":"Streaming has blurred the old single-versus-album commercial divide."},"children":[{"name":"Singles & Short Releases","v":6,"meta":{"def":"Releases built around one or a few tracks rather than a full album.","ex":"single, double A-side, EP","aka":"short-form releases","note":"Instant-grat tracks release ahead of an album to drive pre-orders."},"children":[{"name":"Single","v":3,"meta":{"def":"A release centred on one lead track, the primary chart and radio unit.","ex":"lead single, promo single","aka":"45, cut","note":"Historically the A-side was the promoted commercial track."}},{"name":"Double A-side","v":3,"meta":{"def":"Single promoting two tracks equally rather than an A-side and B-side.","ex":"Day Tripper / We Can Work It Out","aka":"AA-side","note":"Both songs are pushed to radio as lead tracks."}},{"name":"B-side","v":3,"meta":{"def":"Secondary track on the flip of a single, often non-album material.","ex":"rarities, exclusives","aka":"flip side, coupling","note":"Collector demand can make B-sides more prized than the A-side."}},{"name":"EP (extended play)","v":3,"meta":{"def":"Mid-length release with more tracks than a single but shorter than an album.","ex":"debut EPs, buzz EPs","aka":"extended play","note":"A common low-risk vehicle for emerging artists to build audience."}},{"name":"Remix EP","v":3,"meta":{"def":"Release collecting multiple remixes of one or more songs.","ex":"club remix packages","aka":"remix package","note":"Extends a single's life and reaches new club and dance audiences."}},{"name":"Demo release","v":3,"meta":{"def":"Early rough recordings issued to fans or labels rather than final masters.","ex":"demo tapes, session demos","aka":"demos","note":"Vintage demos are frequently repackaged as archival bonus content."}}]},{"name":"Albums & Long Players","v":8,"meta":{"def":"Full-length releases collecting a body of tracks as a cohesive product.","ex":"LP, double album, concept album","aka":"long players, records","note":"The album emerged as an artistic statement format in the late 1960s."},"children":[{"name":"Studio album","v":4,"meta":{"def":"Full-length collection of newly recorded studio tracks.","ex":"debut album, sophomore album","aka":"LP, record","note":"The core artistic and commercial release for most artists."}},{"name":"Double album","v":3,"meta":{"def":"Album spanning two discs or records due to extended running time.","ex":"The White Album","aka":"2LP","note":"Ambitious length can be a creative statement or a filler risk."}},{"name":"Concept album","v":3,"meta":{"def":"Album unified by a narrative, character or theme across its tracks.","ex":"rock operas, song cycles","aka":"themed album","note":"The Who's Tommy popularised the rock-opera concept album."}},{"name":"Live album","v":3,"meta":{"def":"Album recorded during concert performances rather than in studio.","ex":"live-at venue records","aka":"concert album","note":"Can capture improvisation and crowd energy absent in studio cuts."}},{"name":"Deluxe edition","v":3,"meta":{"def":"Expanded album with bonus tracks, remixes or extras to re-drive sales.","ex":"deluxe reissue, expanded edition","aka":"expanded edition","note":"Extra tracks can add chart-eligible streams late in a cycle."}},{"name":"Soundtrack album","v":3,"meta":{"def":"Album collecting music from a film, show, or game.","ex":"OST, cast recording","aka":"OST, score album","note":"Can outsell the underlying film and revive catalogue songs."}},{"name":"Instrumental album","v":3,"meta":{"def":"Full release with no or minimal vocals, foregrounding the music.","ex":"jazz, ambient, score","aka":"vocal-free album","note":"Often issued alongside a vocal version for sync licensing."}},{"name":"Visual album","v":3,"meta":{"def":"Album released with accompanying film or video for every track.","ex":"Lemonade, Beyoncé","aka":"film album","note":"Blurs the line between album, music video and streaming film."}}]},{"name":"Compilations & Special Editions","v":8,"meta":{"def":"Releases assembling existing or curated material rather than a single new work.","ex":"greatest hits, box set, mixtape","aka":"collections","note":"Compilations exploit catalogue value and mark career milestones."},"children":[{"name":"Compilation album","v":3,"meta":{"def":"Collection of tracks by one or various artists gathered by theme or era.","ex":"Now That's What I Call Music","aka":"comp, various-artists album","note":"Various-artists comps have their own dedicated chart categories."}},{"name":"Greatest hits","v":3,"meta":{"def":"Compilation of an artist's best-known or best-selling songs.","ex":"best-of albums","aka":"best-of, hits collection","note":"Often includes one or two new tracks to entice existing fans."}},{"name":"Box set","v":3,"meta":{"def":"Premium multi-disc collection with extras, packaging and rarities.","ex":"anniversary box sets","aka":"boxset, anthology","note":"High-margin product targeting dedicated collectors."}},{"name":"Reissue","v":3,"meta":{"def":"Re-release of a past album, often remastered or expanded.","ex":"anniversary reissue, remaster","aka":"re-release","note":"Common on vinyl anniversaries to tap nostalgia and collectors."}},{"name":"Mixtape","v":3,"meta":{"def":"Informal release, historically hosted or DJ-mixed, now a free hip-hop album form.","ex":"hosted hip-hop mixtapes","aka":"tape","note":"Once a legal grey zone using uncleared beats to build hype."}},{"name":"Split release","v":3,"meta":{"def":"Single release shared by two or more artists, each contributing tracks.","ex":"split 7-inch, split EP","aka":"split single","note":"Common in punk and metal to cross-promote scene bands."}},{"name":"Tribute album","v":3,"meta":{"def":"Compilation of one artist's songs performed by other acts.","ex":"covers tribute records","aka":"covers album","note":"Introduces a legacy catalogue to new audiences via new artists."}},{"name":"Bootleg","v":3,"meta":{"def":"Unofficial, unauthorised recording distributed without label consent.","ex":"audience recordings, leaks","aka":"unofficial release","note":"Live bootlegs can circulate widely among collector communities."}}]}]},{"name":"Digital Formats & Delivery","v":10,"meta":{"def":"File-based and networked ways of encoding and delivering recorded music.","ex":"MP3, FLAC, digital single, stems","aka":"digital audio, downloads","note":"MP3 compression drove the download era before streaming took over."},"children":[{"name":"Audio File Formats","v":7,"meta":{"def":"Encoding schemes for storing digital audio as files.","ex":"MP3, AAC, FLAC, WAV","aka":"codecs, file types","note":"Lossy codecs discard data to shrink size; lossless preserve it."},"children":[{"name":"MP3","v":3,"meta":{"def":"Lossy compressed audio format that made downloads and sharing practical.","ex":"iTunes downloads, ripped files","aka":"MPEG-1 Layer 3","note":"Its efficiency and small size fuelled the file-sharing era."}},{"name":"AAC","v":3,"meta":{"def":"Advanced Audio Coding lossy format offering better quality than MP3 at similar sizes.","ex":"Apple Music, YouTube","aka":"Advanced Audio Coding","note":"Default for the iTunes Store and many streaming services."}},{"name":"FLAC","v":3,"meta":{"def":"Free Lossless Audio Codec compressing audio with no quality loss.","ex":"Bandcamp lossless, hi-fi tiers","aka":"Free Lossless Audio Codec","note":"Open format popular for audiophile downloads and archiving."}},{"name":"WAV / AIFF","v":3,"meta":{"def":"Uncompressed PCM formats storing full-resolution studio-quality audio.","ex":"master files, CD source","aka":"PCM audio","note":"Large files preferred for editing and mastering workflows."}},{"name":"ALAC","v":3,"meta":{"def":"Apple Lossless Audio Codec giving lossless quality within the Apple ecosystem.","ex":"Apple Music Lossless","aka":"Apple Lossless","note":"Apple's counterpart to FLAC, now open-sourced."}},{"name":"Ogg Vorbis / Opus","v":3,"meta":{"def":"Open royalty-free lossy codecs used by several streaming services.","ex":"Spotify streams","aka":"Vorbis, Opus","note":"Opus is favoured for low-latency and low-bitrate streaming."}},{"name":"MQA","v":3,"meta":{"def":"Master Quality Authenticated codec folding hi-res audio into a smaller stream.","ex":"Tidal Masters","aka":"Master Quality Authenticated","note":"Controversial as a proprietary, non-lossless hi-res claim."}}]},{"name":"Digital Release Configurations","v":5,"meta":{"def":"Ways music is packaged for digital sale or delivery.","ex":"digital single, digital album, stems","aka":"digital products","note":"Digital deliverables must carry metadata like ISRC and UPC codes."},"children":[{"name":"Digital single","v":3,"meta":{"def":"Individually purchasable or streamable track sold as a download or file.","ex":"iTunes 99-cent single","aka":"download single","note":"The download single briefly revived singles-driven charts."}},{"name":"Digital album","v":3,"meta":{"def":"Full album delivered as a bundle of downloadable or streamable files.","ex":"album download bundle","aka":"digital LP","note":"Bundling can restrict cherry-picking of individual tracks."}},{"name":"Stems","v":3,"meta":{"def":"Separated instrument or group tracks sold for remixing or sync use.","ex":"remix stems, multitrack packs","aka":"multitracks, parts","note":"Enable official remix contests and flexible sync re-editing."}},{"name":"Ringtone / ringback","v":3,"meta":{"def":"Short audio clip sold to play on phone calls, big in the 2000s.","ex":"polyphonic and mastertone","aka":"ringtones, truetones","note":"Mastertones once generated substantial mobile music revenue."}},{"name":"Spatial / immersive mix","v":3,"meta":{"def":"Object-based mix delivering 3D surround audio to compatible playback.","ex":"Dolby Atmos Music","aka":"Dolby Atmos, 360 Reality Audio","note":"Apple pays a higher royalty rate for Spatial Audio streams."}}]}]},{"name":"Distribution","v":12,"meta":{"def":"The channels that move recordings from artists and labels to retailers and platforms.","ex":"aggregators, distributors, wholesalers","aka":"supply chain, delivery","note":"Digital aggregators democratised access to global streaming shelves."},"children":[{"name":"Physical Distribution","v":5,"meta":{"def":"Getting manufactured product into shops and warehouses.","ex":"major distributor, one-stop, wholesaler","aka":"physical supply chain","note":"The three major label groups each run global distribution arms."},"children":[{"name":"Major distributor","v":3,"meta":{"def":"Large distribution arm of a major label group serving retail worldwide.","ex":"Universal, Sony, Warner arms","aka":"major-label distribution","note":"Controls shelf access, returns and retail relationships at scale."}},{"name":"Independent distributor","v":3,"meta":{"def":"Company distributing indie labels' physical product to stores.","ex":"indie physical distributors","aka":"indie distro","note":"Vital lifeline for labels outside the major system."}},{"name":"One-stop","v":3,"meta":{"def":"Wholesaler stocking many labels so retailers order from a single source.","ex":"record store suppliers","aka":"one-stop wholesaler","note":"Simplifies ordering for small independent record shops."}},{"name":"Rack jobber","v":3,"meta":{"def":"Distributor that stocks and manages music racks in non-specialist stores.","ex":"supermarket music racks","aka":"rackjobber","note":"Historically supplied department and grocery store music sections."}},{"name":"Pressing & fulfilment","v":3,"meta":{"def":"Manufacturing and order-fulfilment services that produce and ship physical stock.","ex":"vinyl pressing plants","aka":"manufacturing and fulfilment","note":"Pressing-plant backlogs became a bottleneck in the vinyl revival."}}]},{"name":"Digital Distributors & Aggregators","v":9,"meta":{"def":"Services that deliver recordings to streaming platforms and stores.","ex":"DistroKid, TuneCore, Believe","aka":"aggregators, digital distributors","money":"Flat annual fees or a commission on streaming and download revenue.","note":"They handle metadata, delivery and royalty collection to DSPs."},"children":[{"name":"DistroKid","v":3,"meta":{"def":"Flat-fee unlimited-upload distributor popular with DIY artists.","ex":"indie bedroom artists","aka":"distrokid","money":"Annual subscription lets artists keep all their royalties.","note":"Pioneered the unlimited-uploads-for-one-fee model."}},{"name":"TuneCore","v":3,"meta":{"def":"Distributor charging per-release fees while artists keep their revenue.","ex":"self-releasing artists","aka":"tunecore","money":"Per-release and per-year fees plus publishing administration.","note":"Now owned by Believe as part of its artist-services group."}},{"name":"CD Baby","v":3,"meta":{"def":"Long-running distributor offering physical and digital, one-time fee per release.","ex":"indie catalogue distribution","aka":"cdbaby","money":"One-time upload fee plus a percentage of sales revenue.","note":"One of the earliest digital distributors for independents."}},{"name":"Believe","v":3,"meta":{"def":"Global digital distribution and artist-services company for labels and creators.","ex":"TuneCore parent, label services","aka":"believe digital","money":"Commission on distribution plus artist and label services.","note":"Publicly listed and a major force in local-market distribution."}},{"name":"The Orchard","v":3,"meta":{"def":"Sony-owned distributor and label-services firm for independents.","ex":"indie label distribution","aka":"orchard","money":"Revenue share on distribution and marketing services.","note":"Operates at a larger, more label-focused scale than DIY tools."}},{"name":"AWAL","v":3,"meta":{"def":"Selective distribution and services arm offering funding and marketing.","ex":"curated artist roster","aka":"awal","money":"Revenue share in exchange for marketing and advance funding.","note":"Acquired by Sony to compete for career-stage independents."}},{"name":"Symphonic Distribution","v":3,"meta":{"def":"Independent distributor strong in urban, Latin and dance genres.","ex":"hip-hop and Latin indies","aka":"symphonic","money":"Percentage-based distribution plus optional services.","note":"Known for genre-focused marketing and playlist support."}},{"name":"Amuse / free tiers","v":3,"meta":{"def":"Mobile-first distributors offering a free entry tier to unsigned artists.","ex":"Amuse free distribution","aka":"free distributor","money":"Free basic tier upsells premium plans and A&R deals.","note":"Uses streaming data to scout and sign promising artists."}},{"name":"White-label distribution","v":3,"meta":{"def":"Back-end distribution rebranded and resold by labels and platforms.","ex":"SaaS distribution platforms","aka":"distribution SaaS","money":"Licensing or per-delivery fees to the reselling partner.","note":"Lets companies offer distribution without building the pipes."}}]},{"name":"Direct-to-Fan & Self-Distribution","v":6,"meta":{"def":"Selling and delivering music straight to fans without traditional retail.","ex":"Bandcamp, D2C stores, self-release","aka":"D2C, direct sales","money":"Artists keep a larger share by cutting out intermediaries.","note":"Direct channels also capture fan data and email addresses."},"children":[{"name":"Bandcamp","v":3,"meta":{"def":"Direct-to-fan platform selling downloads, physical goods and merch.","ex":"Bandcamp Fridays","aka":"bandcamp","money":"Takes a revenue share, waived on periodic fee-free days.","note":"Bandcamp Fridays passed 100% of sales to artists to boost income."}},{"name":"Artist web store","v":3,"meta":{"def":"Artist-owned online shop selling music, merch and bundles directly.","ex":"official D2C store","aka":"D2C store, webstore","money":"Direct margin on goods plus ownership of customer data.","note":"Bundling music with merch can lift chart-eligible unit counts."}},{"name":"Exclusive window release","v":3,"meta":{"def":"Timed exclusive giving one retailer or platform first access to a release.","ex":"streaming exclusives","aka":"windowing, exclusive","money":"Advance or promotion in exchange for temporary exclusivity.","note":"Exclusives can boost one platform but fuel piracy and backlash."}},{"name":"Crowdfunded release","v":3,"meta":{"def":"Album funded in advance by fan pledges before it is made.","ex":"Kickstarter, PledgeMusic","aka":"fan-funded release","money":"Fans pre-pay for tiers funding production and rewards.","note":"Shifts financial risk from label to the fanbase upfront."}},{"name":"Subscription / membership","v":3,"meta":{"def":"Recurring fan support unlocking exclusive music and content.","ex":"Patreon, membership tiers","aka":"fan subscription","money":"Monthly recurring payments for perks and exclusives.","note":"Provides predictable income independent of streaming payouts."}},{"name":"NFT / token release","v":3,"meta":{"def":"Music or ownership stakes sold as blockchain tokens to fans.","ex":"music NFTs, royalty tokens","aka":"music NFT","money":"Primary sale plus resale royalties encoded in the token.","note":"A speculative, volatile channel that peaked around 2021."}}]}]},{"name":"Streaming & Platforms","v":14,"meta":{"def":"On-demand and video services that deliver music over the internet for a fee or ads.","ex":"Spotify, Apple Music, YouTube","aka":"DSPs, streaming services","money":"Subscription fees and advertising pooled and paid out as royalties.","note":"Streaming is now the dominant source of recorded-music revenue."},"children":[{"name":"On-Demand Audio Services","v":9,"meta":{"def":"Services letting users play any track on demand from a large catalogue.","ex":"Spotify, Apple Music, Tidal","aka":"DSPs, audio streamers","money":"Monthly subscriptions and ad revenue split with rights holders.","note":"DSP stands for Digital Service Provider in industry parlance."},"children":[{"name":"Spotify","v":4,"meta":{"def":"Leading audio streaming service with free ad-supported and premium tiers.","ex":"Discover Weekly, Wrapped","aka":"spotify","money":"Premium subscriptions plus advertising on the free tier.","note":"Its editorial and algorithmic playlists heavily shape discovery."}},{"name":"Apple Music","v":3,"meta":{"def":"Subscription streaming service integrated across Apple devices.","ex":"lossless, Spatial Audio","aka":"apple music","money":"Subscription-only with no permanent free ad-supported tier.","note":"Pays a higher per-play rate for Dolby Atmos Spatial Audio."}},{"name":"Amazon Music","v":3,"meta":{"def":"Amazon's streaming service bundled with Prime and hi-fi tiers.","ex":"Amazon Music Unlimited","aka":"amazon music","money":"Subscriptions plus a Prime-bundled tier driving loyalty.","note":"Prime bundling gives it a huge built-in potential audience."}},{"name":"YouTube Music","v":3,"meta":{"def":"Google's music service combining official audio, videos and user uploads.","ex":"YouTube Premium music","aka":"youtube music","money":"Premium subscriptions plus ad revenue on free playback.","note":"Ties into YouTube's vast catalogue of user and official video."}},{"name":"Tidal","v":3,"meta":{"def":"Streaming service emphasising hi-fi audio and artist-friendly payouts.","ex":"Tidal HiFi, Masters","aka":"tidal","money":"Subscription tiers with a premium hi-fi lossless option.","note":"Marketed on artist ownership and high-resolution audio."}},{"name":"Deezer","v":3,"meta":{"def":"Global streaming service that pioneered advocacy for user-centric payouts.","ex":"Flow personalised radio","aka":"deezer","money":"Subscriptions and advertising across many markets.","note":"Championed the artist-centric royalty payment model."}},{"name":"Qobuz","v":3,"meta":{"def":"Audiophile streaming and hi-res download store aimed at collectors.","ex":"hi-res downloads, editorial","aka":"qobuz","money":"Hi-fi subscriptions plus high-resolution download sales.","note":"Combines streaming with a curated hi-res purchase store."}},{"name":"SoundCloud","v":3,"meta":{"def":"Open upload platform blending streaming with creator community features.","ex":"SoundCloud rap, remixes","aka":"soundcloud","money":"Subscriptions, ads and fan-powered royalty payouts.","note":"Its fan-powered royalties pay per a listener's own subscription."}},{"name":"Regional streamers","v":3,"meta":{"def":"Major streaming services dominant in specific national markets.","ex":"NetEase, Gaana, Anghami","aka":"local DSPs","money":"Local subscriptions, ads and telecom bundles.","note":"Local platforms often lead where global services lag."}}]},{"name":"Video & Short-Form Platforms","v":6,"meta":{"def":"Platforms where video is the primary vehicle for music consumption.","ex":"YouTube, Vevo, TikTok","aka":"video streaming, social video","money":"Advertising and licensing deals split with rights holders.","note":"Short-form video is now a top driver of song discovery."},"children":[{"name":"YouTube","v":4,"meta":{"def":"Dominant video platform hosting official videos, covers and user content.","ex":"official videos, lyric videos","aka":"youtube","money":"Advertising revenue shared through Content ID and partners.","note":"Content ID lets rights holders monetise fan uploads automatically."}},{"name":"Vevo","v":3,"meta":{"def":"Premium music-video network distributing official videos across platforms.","ex":"official artist channels","aka":"vevo","money":"Advertising on premium official music-video inventory.","note":"Delivers verified official videos syndicated to YouTube and TVs."}},{"name":"TikTok","v":4,"meta":{"def":"Short-form video app where sound clips drive viral music trends.","ex":"viral sounds, dances","aka":"tiktok","money":"Advertising plus licensing deals with labels for its library.","note":"A song's TikTok clip can outshine the full track in impact."}},{"name":"Instagram Reels","v":3,"meta":{"def":"Short-form video feature within Instagram using licensed music clips.","ex":"Reels audio trends","aka":"reels","money":"Advertising within the broader Meta platform.","note":"Meta licenses music so creators can soundtrack Reels legally."}},{"name":"YouTube Shorts","v":3,"meta":{"def":"YouTube's short vertical video format competing with TikTok.","ex":"Shorts music trends","aka":"shorts","money":"Ad revenue shared with creators and music rights holders.","note":"Feeds discovery back into full YouTube and YouTube Music."}},{"name":"Twitch / live streams","v":3,"meta":{"def":"Live-streaming platforms where artists perform and DJ in real time.","ex":"live DJ sets, listening parties","aka":"twitch","money":"Subscriptions, tips and ads shared with streamers.","note":"Music licensing on live platforms remains a legal grey area."}}]},{"name":"Streaming Economics & Discovery","v":8,"meta":{"def":"How streaming pays out and how listeners find music on platforms.","ex":"pro-rata, playlists, algorithms","aka":"royalty models, discovery","money":"Royalty pools are divided by share of total platform streams.","note":"The payout model shapes which artists benefit most from streams."},"children":[{"name":"Pro-rata payout","v":3,"meta":{"def":"Model pooling all revenue and paying by each artist's share of total streams.","ex":"standard Spotify model","aka":"big-pool model","money":"Total revenue split proportionally to overall stream share.","note":"Favours the most-streamed artists over niche listening."}},{"name":"User-centric payout","v":3,"meta":{"def":"Model paying each subscriber's fee only to the artists they actually played.","ex":"SoundCloud fan-powered","aka":"artist-centric, UCPS","money":"Each user's fee is divided among the acts that user streamed.","note":"Argued to better reward niche and superfan-driven artists."}},{"name":"Free / ad-supported tier","v":3,"meta":{"def":"No-cost access funded by advertising, with limits versus premium.","ex":"Spotify Free, YouTube ads","aka":"freemium, ad tier","money":"Advertising revenue shared with rights holders per stream.","note":"Acts as a funnel converting free users to paid subscriptions."}},{"name":"Premium subscription","v":3,"meta":{"def":"Paid ad-free tier with offline listening and full on-demand control.","ex":"Spotify Premium, individual plans","aka":"paid tier","money":"Recurring monthly fees pooled for royalty payouts.","note":"Family and student plans expand the paying subscriber base."}},{"name":"Editorial playlist","v":3,"meta":{"def":"Human-curated playlist maintained by a platform's editors.","ex":"RapCaviar, Today's Top Hits","aka":"curated playlist","money":"Free placement that drives streams and thus royalties.","note":"A flagship editorial slot can transform a song's trajectory."}},{"name":"Algorithmic playlist","v":3,"meta":{"def":"Personalised playlist generated by recommendation algorithms.","ex":"Discover Weekly, Release Radar","aka":"personalised playlist","money":"Drives engagement and streams that generate royalties.","note":"Algorithmic reach scales personalised discovery to millions."}},{"name":"Hi-fi / lossless tier","v":3,"meta":{"def":"Premium option streaming lossless or high-resolution audio quality.","ex":"Apple Lossless, Tidal HiFi","aka":"lossless tier","money":"Higher-priced tier or included as a premium upgrade.","note":"Requires more bandwidth and compatible playback hardware."}},{"name":"Radio-style streaming","v":3,"meta":{"def":"Non-interactive personalised stations that play music without on-demand control.","ex":"Pandora, algorithmic radio","aka":"internet radio streaming","money":"Ads and subscriptions under statutory radio-style licensing.","note":"Non-interactive services pay different, often statutory, royalty rates."}}]}]},{"name":"Radio & Broadcast","v":10,"meta":{"def":"Over-the-air and streamed broadcasting that programs music to mass audiences.","ex":"commercial radio, public radio, SiriusXM","aka":"broadcasting, airwaves","money":"Advertising, subscriptions and licence fees fund broadcasting.","note":"Airplay remains a powerful driver of hits and catalogue value."},"children":[{"name":"Broadcast Radio Sectors","v":7,"meta":{"def":"The different ownership and funding models of radio stations.","ex":"commercial, public, community","aka":"radio sectors","money":"Ads, listener support, licence fees or subscriptions.","note":"Each sector serves distinct audiences and playlist strategies."},"children":[{"name":"Commercial radio","v":3,"meta":{"def":"Advertising-funded stations chasing ratings with popular formats.","ex":"Top 40 FM stations","aka":"commercial FM","money":"Sells advertising airtime priced on audience ratings.","note":"Playlists are tightly programmed to maximise listener retention."}},{"name":"Public / national radio","v":3,"meta":{"def":"Publicly funded broadcasters with wide-ranging and cultural programming.","ex":"BBC Radio, NPR","aka":"public service radio","money":"Licence fees, government grants and listener donations.","note":"Tastemaker shows can break new artists nationally."}},{"name":"College / community radio","v":3,"meta":{"def":"Non-commercial local stations run by campuses or volunteers.","ex":"campus stations, low-power FM","aka":"student radio, LPFM","money":"Grants, donations and underwriting rather than ads.","note":"Historically vital for breaking indie and alternative acts."}},{"name":"Internet radio","v":3,"meta":{"def":"Stations streamed online rather than broadcast over the air.","ex":"webcasts, online stations","aka":"webradio, streaming radio","money":"Ads, subscriptions and donations under webcast licences.","note":"Removes transmitter costs and reaches global audiences."}},{"name":"Satellite radio","v":3,"meta":{"def":"Subscription radio broadcast nationwide via satellite with many channels.","ex":"SiriusXM","aka":"satellite radio","money":"Monthly subscriptions plus some advertising.","note":"Offers ad-free niche and genre channels beyond local reach."}},{"name":"Pirate radio","v":3,"meta":{"def":"Unlicensed stations broadcasting outside legal regulation.","ex":"UK garage pirates","aka":"pirate stations","money":"Informal, often ad hoc or scene-supported funding.","note":"Pirate stations incubated UK dance genres like grime and jungle."}},{"name":"DAB / HD digital radio","v":3,"meta":{"def":"Digital broadcast standards carrying multiple stations with data.","ex":"DAB+, HD Radio","aka":"digital radio","money":"Same ad and licence models delivered digitally.","note":"Allows more stations and text data within the same spectrum."}}]},{"name":"Radio Formats","v":8,"meta":{"def":"Programming identities defining a station's music and audience.","ex":"Top 40, AC, AOR, country","aka":"station formats","note":"Format dictates which songs get playlisted and how often."},"children":[{"name":"Top 40 / CHR","v":3,"meta":{"def":"Contemporary Hit Radio playing the current biggest pop hits on heavy rotation.","ex":"mainstream pop stations","aka":"CHR, Top 40","note":"Tight rotations repeat hits to capture passive listeners."}},{"name":"Adult Contemporary","v":3,"meta":{"def":"Format of softer pop and ballads aimed at an older mainstream audience.","ex":"AC, soft rock stations","aka":"AC, easy listening","note":"Skews toward familiar melodic songs and lighter current hits."}},{"name":"Album-Oriented Rock","v":3,"meta":{"def":"Rock format built on album tracks rather than just hit singles.","ex":"classic rock, AOR","aka":"AOR, classic rock","note":"Emerged in the 1970s to play deeper cuts than Top 40."}},{"name":"Urban / hip-hop","v":3,"meta":{"def":"Format centred on hip-hop, R&B and related contemporary genres.","ex":"urban contemporary stations","aka":"urban, rhythmic","note":"Rhythmic crossover variants blend urban and pop playlists."}},{"name":"Country radio","v":3,"meta":{"def":"Format dedicated to current and classic country music.","ex":"country hits stations","aka":"country format","note":"Country radio wields strong influence over the genre's charts."}},{"name":"Classical / jazz","v":3,"meta":{"def":"Formats programming classical repertoire or jazz for niche audiences.","ex":"classical FM, jazz stations","aka":"fine-arts radio","note":"Often found on public and subscriber-supported stations."}},{"name":"Talk / spoken word","v":3,"meta":{"def":"Non-music format of talk, news and speech, relevant as a music-free competitor.","ex":"talk radio, news radio","aka":"talk format","note":"Competes with music radio for the same listening hours."}},{"name":"Oldies / gold","v":3,"meta":{"def":"Format built on past hits and catalogue from earlier decades.","ex":"classic hits, gold stations","aka":"oldies, classic hits","note":"Monetises nostalgia and delivers reliable older demographics."}}]},{"name":"Airplay & Radio Promotion","v":5,"meta":{"def":"The business of getting and measuring songs played on radio.","ex":"radio plugging, adds, spins","aka":"radio promo, airplay","money":"Labels invest in promotion to convert airplay into sales.","note":"Airplay is tracked to feed radio charts and royalty payments."},"children":[{"name":"Radio plugging","v":3,"meta":{"def":"Pitching songs to radio programmers to secure airplay.","ex":"plugger campaigns","aka":"radio promotion, plugging","money":"Labels pay pluggers and promo staff to win playlist adds.","note":"Independent pluggers specialise in relationships with stations."}},{"name":"Airplay & spins","v":3,"meta":{"def":"The count of times a song is broadcast, tracked to gauge exposure.","ex":"monitored spins, gross impressions","aka":"spins, rotation","note":"Monitoring services log detected plays across many stations."}},{"name":"Adds & rotation","v":3,"meta":{"def":"A station adding a song and how frequently it is scheduled to play.","ex":"heavy, medium, light rotation","aka":"playlist add","note":"Moving into heavy rotation sharply increases a song's reach."}},{"name":"Payola (illegal)","v":3,"meta":{"def":"Undisclosed payment to secure airplay, illegal in many jurisdictions.","ex":"pay-for-play scandals","aka":"pay-for-play","note":"US law requires disclosure of any consideration for airplay."}},{"name":"Radio charts","v":3,"meta":{"def":"Rankings built from airplay data measuring radio popularity.","ex":"airplay charts, radio panels","aka":"airplay chart","note":"Airplay charts often feed into combined all-format hit charts."}}]}]},{"name":"Sync & Placement","v":10,"meta":{"def":"Licensing music to accompany visual and interactive media.","ex":"film, TV, ads, games, trailers","aka":"synchronisation, licensing","money":"Upfront sync fees plus performance royalties from broadcasts.","note":"A single big placement can revive or launch a song's popularity."},"children":[{"name":"Placement Media","v":8,"meta":{"def":"The types of visual media that license music for synchronisation.","ex":"film, TV, advertising, games","aka":"sync markets","money":"Each medium has its own fee scales and usage terms.","note":"Sync fees vary widely by media, territory, and usage rights."},"children":[{"name":"Film sync","v":3,"meta":{"def":"Licensing a song or score to appear in a motion picture.","ex":"needle-drops, end-credits songs","aka":"film licensing","money":"Negotiated sync fee scaled to budget, placement and term.","note":"A key scene placement can turn a catalogue song into a hit again."}},{"name":"Television sync","v":3,"meta":{"def":"Licensing music for use in TV shows and series.","ex":"drama montages, theme songs","aka":"TV licensing","money":"Sync fee plus ongoing broadcast performance royalties.","note":"Hit shows can send featured songs surging up streaming charts."}},{"name":"Advertising sync","v":3,"meta":{"def":"Licensing music for commercials and branded campaigns.","ex":"TV spots, brand campaigns","aka":"commercial licensing, ad sync","money":"Often the highest-paying sync fees, scaled to campaign reach.","note":"Exclusivity and territory drive premium ad-sync fees."}},{"name":"Video game sync","v":3,"meta":{"def":"Licensing music for use within video games and their soundtracks.","ex":"rhythm games, sports titles","aka":"game licensing","money":"Sync fee, sometimes with buyout or per-unit terms.","note":"Rhythm and sports franchises are major music licensees."}},{"name":"Trailer sync","v":3,"meta":{"def":"Licensing music, often re-arranged, for film and game trailers.","ex":"epic trailer cues","aka":"trailer placement","money":"Sync fee for high-visibility promotional exposure.","note":"Trailers often commission bespoke, intensified trailer versions."}},{"name":"Sports & live event sync","v":3,"meta":{"def":"Music used in sports broadcasts, arenas and live event production.","ex":"stadium anthems, highlight reels","aka":"sports licensing","money":"Licensing fees for broadcast and in-venue use.","note":"Association with a team or event can cement a song as an anthem."}},{"name":"Social & UGC licensing","v":3,"meta":{"def":"Blanket licensing letting creators use music in social videos.","ex":"TikTok library, Reels music","aka":"creator licensing, UGC","money":"Platform pays rights holders under bulk licensing deals.","note":"Powers commercial music libraries inside social apps."}},{"name":"Podcast & audio sync","v":3,"meta":{"def":"Licensing music for use in podcasts and other audio productions.","ex":"podcast beds, intros","aka":"podcast licensing","money":"Sync fees or library subscriptions for cleared audio use.","note":"Rights clearance for on-demand audio can be complex and costly."}}]},{"name":"Sync Ecosystem","v":6,"meta":{"def":"The people and catalogues that source and supply music for placement.","ex":"music supervisors, library music","aka":"sync business","money":"Supervisors and libraries earn fees and revenue shares.","note":"Pre-cleared catalogues speed up tight production timelines."},"children":[{"name":"Music supervision","v":3,"meta":{"def":"Selecting, licensing and placing music into a visual production.","ex":"TV and film supervisors","aka":"music supervisor","money":"Fees from productions for curating and clearing music.","note":"A supervisor's taste can define a show's sonic identity."}},{"name":"Production / library music","v":3,"meta":{"def":"Pre-made music catalogued and pre-cleared for easy licensing.","ex":"production music libraries","aka":"library music, stock music","money":"Licensing fees and blanket deals with broadcasters.","note":"Pre-cleared rights let editors drop in tracks instantly."}},{"name":"Trailer music house","v":3,"meta":{"def":"Specialist companies producing dramatic music built for trailers.","ex":"epic trailer libraries","aka":"trailer music company","money":"Sync licences and catalogue placements in trailers.","note":"Their sound emphasises rising tension and huge climaxes."}},{"name":"Needle-drop","v":3,"meta":{"def":"Using a pre-existing commercial recording in a scene rather than a score.","ex":"hit songs in film scenes","aka":"source music, needledrop","note":"Contrasts with bespoke score written for the picture."}},{"name":"Sync agency / pitching","v":3,"meta":{"def":"Firms that represent catalogues and pitch songs for placements.","ex":"sync licensing agencies","aka":"sync rep, sync agent","money":"Commission on the sync deals they broker.","note":"They maintain relationships with supervisors and ad agencies."}},{"name":"Master vs sync licence","v":3,"meta":{"def":"The two clearances needed: one for the recording and one for the song.","ex":"master use plus sync licence","aka":"dual clearance","money":"Fees paid separately to the label and the publisher.","note":"Both master and publishing rights must be cleared to use a track."}}]}]},{"name":"Charts & Metrics","v":10,"meta":{"def":"Systems that rank and measure the popularity and success of music.","ex":"Billboard, UK charts, certifications","aka":"charts, analytics","note":"Charts now blend sales, streams and airplay into unified rankings."},"children":[{"name":"Sales & Streaming Charts","v":8,"meta":{"def":"Rankings measuring how music performs in sales and streaming.","ex":"Hot 100, Billboard 200, UK Singles","aka":"hit charts","note":"Streams are converted to equivalent units to combine with sales."},"children":[{"name":"Billboard Hot 100","v":3,"meta":{"def":"US chart ranking the top songs by combined sales, streams and airplay.","ex":"number-one singles","aka":"Hot 100","note":"The definitive all-genre US singles chart since 1958."}},{"name":"Billboard 200","v":3,"meta":{"def":"US chart ranking the top albums by equivalent-album units.","ex":"number-one albums","aka":"Billboard 200","note":"Streams and track sales now count toward album-equivalent units."}},{"name":"UK Singles Chart","v":3,"meta":{"def":"Official UK ranking of the week's most popular singles.","ex":"Official Charts number ones","aka":"Official Singles Chart","note":"Compiled by the Official Charts Company from sales and streams."}},{"name":"UK Albums Chart","v":3,"meta":{"def":"Official UK ranking of the week's best-performing albums.","ex":"Official Albums Chart","aka":"Official Albums Chart","note":"Streaming-equivalent albums feed into the modern methodology."}},{"name":"Genre & regional charts","v":3,"meta":{"def":"Specialised charts for individual genres or countries.","ex":"Hot Country, dance charts","aka":"sub-charts","note":"Let niche scenes measure success within their own market."}},{"name":"Global streaming charts","v":3,"meta":{"def":"Worldwide rankings aggregating streams across platforms and countries.","ex":"Spotify Global, Billboard Global","aka":"global charts","note":"Reflect cross-border virality faster than national charts."}},{"name":"First-week sales","v":3,"meta":{"def":"Units a release sells or streams in its opening tracking week.","ex":"big debut weeks","aka":"opening week, debut","note":"A strong debut week can guarantee a number-one entry."}},{"name":"Chart-eligible streams","v":3,"meta":{"def":"The rules deciding which streams count toward chart position.","ex":"premium vs free weighting","aka":"stream weighting","note":"Paid streams are often weighted more heavily than free ones."}}]},{"name":"Certifications","v":5,"meta":{"def":"Awards marking sales and streaming milestones for releases.","ex":"gold, platinum, diamond","aka":"sales certifications","note":"Thresholds and streaming formulas differ by country."},"children":[{"name":"Gold certification","v":3,"meta":{"def":"Award for reaching the first major sales or streaming milestone.","ex":"gold single, gold album","aka":"gold record","note":"The US gold threshold is 500,000 equivalent units."}},{"name":"Platinum certification","v":3,"meta":{"def":"Award marking a higher sales tier above gold, with multi-platinum levels.","ex":"multi-platinum albums","aka":"platinum record","note":"US platinum equals one million equivalent units."}},{"name":"Diamond certification","v":3,"meta":{"def":"Elite award for enormous sales, typically ten times platinum.","ex":"diamond albums","aka":"diamond record","note":"Marks ten million units in the US, a rare achievement."}},{"name":"RIAA (US)","v":3,"meta":{"def":"US body that certifies sales and streaming milestones.","ex":"RIAA gold and platinum","aka":"Recording Industry Association of America","note":"Incorporated on-demand streams into certifications in 2016."}},{"name":"BPI & IFPI","v":3,"meta":{"def":"UK and international bodies certifying sales and tracking global figures.","ex":"BPI awards, IFPI reports","aka":"BPI, IFPI","note":"IFPI publishes worldwide recorded-music industry statistics."}}]},{"name":"Analytics & Discovery Metrics","v":5,"meta":{"def":"Data tools measuring listening, discovery and audience trends.","ex":"Shazam, Chartmetric, stream counts","aka":"music data, analytics","note":"Labels mine these signals to spot and sign emerging talent."},"children":[{"name":"Stream counts","v":3,"meta":{"def":"Cumulative totals of how many times tracks have been streamed.","ex":"billion-stream club","aka":"play counts","note":"Milestone counts have become marketing badges in their own right."}},{"name":"Shazam","v":3,"meta":{"def":"Song-identification app whose search data signals rising demand.","ex":"Shazam charts","aka":"shazam","money":"Owned by Apple and feeds discovery into its ecosystem.","note":"Spikes in Shazams often precede mainstream breakout."}},{"name":"Chartmetric / analytics platforms","v":3,"meta":{"def":"Services aggregating streaming, social and playlist data for the industry.","ex":"Chartmetric, Soundcharts","aka":"music analytics platforms","money":"Subscription fees from labels, managers and agencies.","note":"Used for A&R scouting and campaign performance tracking."}},{"name":"Playlist & follower metrics","v":3,"meta":{"def":"Data on playlist adds, reach and follower growth on platforms.","ex":"playlist reach, monthly listeners","aka":"playlist analytics","note":"Monthly listeners is a headline momentum indicator for artists."}},{"name":"Social & engagement metrics","v":3,"meta":{"def":"Measures of fan activity across social platforms tied to music.","ex":"TikTok creations, video views","aka":"social analytics","note":"Volume of TikTok creations can forecast a song's chart climb."}}]}]},{"name":"Promotion & Marketing","v":12,"meta":{"def":"The activities that build awareness and demand for a release or artist.","ex":"PR, playlist pitching, music videos","aka":"marketing, promo","money":"Marketing spend aims to convert attention into streams and sales.","note":"A coordinated rollout sequences content to sustain momentum."},"children":[{"name":"Publicity & Press","v":6,"meta":{"def":"Earning media coverage and managing an artist's public image.","ex":"PR, press release, EPK","aka":"publicity, media relations","money":"Publicists charge fees or retainers to secure coverage.","note":"Earned media builds credibility that paid ads cannot buy."},"children":[{"name":"PR / publicist","v":3,"meta":{"def":"Professional securing press coverage, interviews and features.","ex":"PR campaigns, media outreach","aka":"publicist","money":"Charges retainers or campaign fees to artists and labels.","note":"Relationships with journalists and editors are the core asset."}},{"name":"Press release","v":3,"meta":{"def":"Official announcement distributed to media about a release or news.","ex":"album announcement, tour news","aka":"press statement","note":"The template document that seeds coverage across outlets."}},{"name":"EPK","v":3,"meta":{"def":"Electronic press kit bundling bio, photos, music and press for media.","ex":"digital press kit","aka":"Electronic Press Kit","note":"A one-stop resource pitched to bookers, press and partners."}},{"name":"Music blogs & press","v":3,"meta":{"def":"Online and print outlets that review and feature new music.","ex":"tastemaker blogs, magazines","aka":"music media","note":"Early blog support can help build an artist's initial buzz."}},{"name":"Interviews & features","v":3,"meta":{"def":"Longer coverage giving artists a platform to tell their story.","ex":"cover stories, podcasts","aka":"press features","note":"Deep features build the narrative that sustains a campaign."}},{"name":"Radio & TV appearances","v":3,"meta":{"def":"Booked performances and interviews on broadcast programmes.","ex":"late-night TV, radio sessions","aka":"promo appearances","note":"A single high-profile TV slot can spike streams overnight."}}]},{"name":"Digital & Social Marketing","v":8,"meta":{"def":"Promotion carried out across social, streaming and online channels.","ex":"playlist pitching, ads, influencers","aka":"digital marketing, online promo","money":"Paid ads and creator deals amplify organic content.","note":"Short-form virality is now central to breaking new music."},"children":[{"name":"Playlist pitching","v":3,"meta":{"def":"Submitting tracks to editors and curators for playlist placement.","ex":"editorial pitch, curator outreach","aka":"playlist plugging","money":"Can involve pluggers' fees to reach influential curators.","note":"Spotify's editorial pitch form feeds its playlisting decisions."}},{"name":"Pre-save campaign","v":3,"meta":{"def":"Letting fans save a release before launch to boost day-one streams.","ex":"pre-save links","aka":"pre-save","note":"Concentrates listens into release day to aid chart impact."}},{"name":"Social media marketing","v":3,"meta":{"def":"Building audience and hype through posts across social platforms.","ex":"content calendars, teasers","aka":"social marketing","money":"Paid social ads target listeners by taste and behaviour.","note":"Consistent content keeps an artist visible between releases."}},{"name":"Influencer / creator marketing","v":3,"meta":{"def":"Paying or partnering with creators to feature music in their content.","ex":"TikTok creator campaigns","aka":"creator marketing","money":"Creators are paid to make videos using the track.","note":"Seeding a sound with creators can spark organic trends."}},{"name":"TikTok virality","v":3,"meta":{"def":"A song spreading through user-made short videos and sound trends.","ex":"viral dances, sped-up versions","aka":"going viral","note":"Labels engineer clip hooks and challenges to court virality."}},{"name":"Paid advertising","v":3,"meta":{"def":"Buying ad placements to promote a release across digital media.","ex":"streaming ads, social ads","aka":"digital ads","money":"Ad spend targeted to convert reach into streams and follows.","note":"Retargeting and lookalike audiences refine ad efficiency."}},{"name":"Rollout / campaign","v":3,"meta":{"def":"The planned sequence of singles, content and events around a release.","ex":"album era rollout","aka":"release campaign, era","money":"Coordinates spend across phases to sustain momentum.","note":"A well-paced rollout builds an album era before launch day."}},{"name":"Fan club & community","v":3,"meta":{"def":"Organised superfan structures nurturing loyalty and direct engagement.","ex":"fan clubs, Discord communities","aka":"fanbase, street team","money":"Memberships and exclusive drops monetise superfans.","note":"Engaged superfans amplify every release organically."}}]},{"name":"Visual & Content Assets","v":6,"meta":{"def":"Video and visual content produced to promote music.","ex":"music video, lyric video, visualiser","aka":"content, creative assets","money":"Videos can earn ad revenue while building brand and reach.","note":"A striking video can define a song's cultural identity."},"children":[{"name":"Music video","v":3,"meta":{"def":"Filmed visual narrative or performance produced for a song.","ex":"cinematic music videos","aka":"promo video, MV","money":"Ad revenue on platforms plus brand-building value.","note":"MTV's rise made the music video a core marketing tool."}},{"name":"Lyric video","v":3,"meta":{"def":"Video displaying a song's lyrics, cheaper than a full production.","ex":"animated lyric videos","aka":"lyric visualiser","note":"Often released first to satisfy demand before the main video."}},{"name":"Visualiser","v":3,"meta":{"def":"Simple looping visual accompanying audio, especially on streaming.","ex":"Spotify Canvas, YouTube loops","aka":"visualizer, canvas","note":"Spotify Canvas adds short looping visuals to track pages."}},{"name":"Behind-the-scenes / vlog","v":3,"meta":{"def":"Documentary-style content showing an artist's process and life.","ex":"studio diaries, tour vlogs","aka":"BTS content","note":"Builds intimacy and gives fans a reason to keep following."}},{"name":"Cover art & branding","v":3,"meta":{"def":"The visual identity of a release, from artwork to campaign design.","ex":"album covers, era aesthetics","aka":"artwork, visual identity","note":"Strong cover art becomes shorthand for an era or album."}},{"name":"Merch & D2C drops","v":3,"meta":{"def":"Limited product releases that promote music and monetise fans.","ex":"merch drops, bundles","aka":"merchandise, drops","money":"Direct merch sales with high margins tied to campaigns.","note":"Bundling merch with music can lift chart-eligible unit counts."}}]}]}]},{"name":"Roles & Careers","type":"roles","v":26,"children":[{"name":"Performing & Creative","v":14,"meta":{"def":"The people who create and perform the music itself, on stage and on record.","who":"Write, arrange, sing and play music, working with bandmates, producers and audiences.","money":"Mix of performance fees, advances, royalties and streaming income.","note":"The most visible careers in music, but often the least financially stable."},"children":[{"name":"Vocalists","v":10,"meta":{"def":"Singers who carry melody and lyrics with the human voice.","who":"Rehearse, record and perform vocal parts, working with bands, MDs and producers.","money":"Session fees, gig fees, royalties and sometimes salaries in ensembles.","note":"Vocal health and stamina are as important as raw talent."},"children":[{"name":"Lead Singer","v":5,"meta":{"def":"The primary vocalist who delivers a song's main melody and lyric.","who":"Fronts the band, sings lead lines and connects with the crowd nightly.","money":"Share of band income, performance fees and songwriting royalties.","note":"Often doubles as the group's public face and frontperson."}},{"name":"Backing Vocalist","v":4,"meta":{"def":"A singer who supports the lead with harmonies and layered parts.","who":"Sings harmony stacks and ad-libs live and in the studio behind the star.","money":"Per-session or per-show fees, occasionally small royalty points.","note":"Elite backing singers tour the world for A-list headliners."}},{"name":"Session Vocalist","v":4,"meta":{"def":"A hired singer who records vocals for other artists' projects.","who":"Turns up, learns parts fast and nails takes for producers on demos and records.","money":"Flat session fees; sometimes buyouts or royalties on hits.","note":"Anonymous but steady work behind countless famous records."}},{"name":"Opera Singer","v":5,"meta":{"def":"A classically trained vocalist performing operatic repertoire.","who":"Learns roles in multiple languages and performs with orchestras and companies.","money":"Per-production contracts and fees, often via an artist agent.","note":"Voice type (soprano, tenor, bass) defines which roles you can sing."}},{"name":"Choral Singer","v":4,"meta":{"def":"A singer performing as part of a blended vocal ensemble.","who":"Reads music, blends into a section and follows a choir director.","money":"Salaried in pro choirs, freelance deps, or unpaid in community choirs.","note":"Professional chamber choirs demand fast sight-reading."}},{"name":"Topliner","v":4,"meta":{"def":"A vocalist-writer who creates melodies and lyrics over finished tracks.","who":"Improvises hooks and toplines over beatmakers' instrumentals in sessions.","money":"Songwriting splits, publishing royalties and occasional advances.","note":"Central to modern pop and EDM writing camps."}}]},{"name":"Instrumentalists","v":10,"meta":{"def":"Musicians whose craft is playing an instrument.","who":"Practise, rehearse and perform parts alone or within ensembles.","money":"Gig and session fees, ensemble salaries, teaching on the side.","note":"Versatility across genres widens the work available."},"children":[{"name":"Session Musician","v":5,"meta":{"def":"A hired player who records or performs parts for others' projects.","who":"Reads charts, adapts quickly and delivers polished parts under pressure.","money":"Union session rates, buyouts, occasional royalty points.","note":"The best sight-readers become first-call players in music hubs."}},{"name":"Orchestral Player","v":4,"meta":{"def":"A musician holding a chair in a symphony or chamber orchestra.","who":"Rehearses and performs repertoire under a conductor within a section.","money":"Salaried tenured post or freelance per-service payments.","note":"Auditions for tenured chairs are famously competitive."}},{"name":"Solo Recitalist","v":4,"meta":{"def":"A soloist who performs concert programmes as the featured artist.","who":"Builds programmes, tours venues and performs with piano or orchestra.","money":"Concert fees and competition prizes, managed by an agent.","note":"International competitions launch many solo careers."}},{"name":"Band Instrumentalist","v":4,"meta":{"def":"A guitarist, bassist, drummer or keyboardist in a working band.","who":"Writes and rehearses parts and gigs regularly with bandmates.","money":"Split of band earnings, merch and recording royalties.","note":"Rhythm sections quietly define a band's whole sound."}},{"name":"Accompanist","v":4,"meta":{"def":"A pianist or player who supports soloists and singers.","who":"Sight-reads and follows performers in recitals, auditions and exams.","money":"Hourly rehearsal and performance fees.","note":"Skilled repetiteurs are indispensable to opera houses."}},{"name":"Multi-Instrumentalist","v":4,"meta":{"def":"A player fluent across several instruments.","who":"Covers many parts in sessions and one-person projects.","money":"Session fees and self-produced project income.","note":"Prized in low-budget productions and self-made records."}}]},{"name":"Songwriting & Composition","v":12,"meta":{"def":"The people who invent the songs, scores and cues.","who":"Craft melodies, lyrics and structures for artists, screen and stage.","money":"Publishing royalties, commissions, sync fees and advances.","note":"Owning a share of the copyright is the long-term prize."},"children":[{"name":"Songwriter","v":5,"meta":{"def":"A creator of songs' words and music, often for other artists.","who":"Writes in sessions, pitches songs and collaborates in writing camps.","money":"Publishing royalties, co-writes splits and advances.","note":"A single cut by a major artist can fund years of work."}},{"name":"Lyricist","v":4,"meta":{"def":"A specialist who writes the words of songs.","who":"Shapes themes and rhymes to fit melodies and briefs.","money":"Lyric share of publishing royalties.","note":"In musical theatre the lyricist is often a named marquee credit."}},{"name":"Composer","v":5,"meta":{"def":"A creator of original musical works, from concert pieces to scores.","who":"Writes scores, meets commissioners and oversees premieres.","money":"Commission fees, performance royalties and grants.","note":"Concert composers rely heavily on commissions and residencies."}},{"name":"Film & TV Composer","v":5,"meta":{"def":"A composer who writes original music to picture.","who":"Spots scenes with directors, writes cues and delivers to deadlines.","money":"Upfront fees, package deals and performance royalties.","note":"A hit franchise score can define an entire career."}},{"name":"Jingle Writer","v":4,"meta":{"def":"A composer of short music for adverts and brands.","who":"Turns briefs into memorable hooks fast for agencies.","money":"Production fees plus broadcast use royalties.","note":"A single national campaign can pay handsomely in residuals."}},{"name":"Video Game Composer","v":4,"meta":{"def":"A composer writing adaptive music for interactive games.","who":"Builds looping and branching cues that react to player action.","money":"Project fees, buyouts and occasional royalties.","note":"Interactive scoring needs technical middleware skills."}}]},{"name":"Music Direction & Arranging","v":12,"meta":{"def":"The people who shape and lead how music is realised.","who":"Arrange parts, rehearse ensembles and lead performances.","money":"Fees, salaries and arranging royalties.","note":"Bridges the creative and the practical on any production."},"children":[{"name":"Conductor","v":5,"meta":{"def":"The leader who directs an orchestra, choir or band in performance.","who":"Interprets scores, rehearses players and shapes tempo and dynamics.","money":"Salaried chief posts or guest-conducting fees.","note":"Music directorships come with major artistic and admin duties."}},{"name":"Music Director (MD)","v":5,"meta":{"def":"The person who leads a band or show musically.","who":"Chooses arrangements, hires players and cues the band live.","money":"Retainer or per-show fees, often a premium over side players.","note":"Touring pop shows live or die on a strong MD."}},{"name":"Arranger","v":4,"meta":{"def":"A musician who adapts a piece for specific voices or instruments.","who":"Reworks songs into charts for bands, choirs and orchestras.","money":"Per-arrangement fees and mechanical royalties.","note":"A great arrangement can revive an old song entirely."}},{"name":"Orchestrator","v":4,"meta":{"def":"A specialist who assigns a composer's music to orchestral instruments.","who":"Takes sketches and voices them across the full orchestra to deadline.","money":"Per-minute or per-project fees, often on film scores.","note":"Behind many film scores the composer sketches and orchestrators expand."}},{"name":"Copyist","v":4,"meta":{"def":"A specialist who prepares clean, accurate performance parts.","who":"Engraves scores into readable parts for players and sessions.","money":"Per-page or per-project fees.","note":"Notation software skill is now the core of the trade."}},{"name":"Vocal Arranger","v":4,"meta":{"def":"An arranger specialising in harmony and vocal parts.","who":"Writes stacks and background parts for singers and choirs.","money":"Arranging fees and occasional royalties.","note":"Central to gospel, a cappella and pop backing vocals."}}]},{"name":"Producers & Beatmakers","v":10,"meta":{"def":"The people who craft the sound and shape of a recording.","who":"Build tracks, guide artists and make sonic decisions in the studio.","money":"Production fees, points on sales and publishing shares.","note":"Producer points on a hit album can outlast the artist's fame."},"children":[{"name":"Record Producer","v":5,"meta":{"def":"The person overseeing the making of a recording.","who":"Chooses songs, directs performances and shapes the final sound.","money":"Advance fees plus points (a royalty percentage) on the record.","note":"Ranges from hands-off overseer to full auteur."}},{"name":"Beatmaker","v":4,"meta":{"def":"A producer who builds instrumental beats, often for hip-hop and pop.","who":"Programmes drums and samples and pitches beats to artists.","money":"Beat leases, exclusive sales and production royalties.","note":"Online beat marketplaces built a whole new economy."}},{"name":"Remixer","v":4,"meta":{"def":"A producer who reworks an existing track into a new version.","who":"Takes stems and rebuilds a song for clubs or new audiences.","money":"Flat remix fees and sometimes royalty splits.","note":"Official remixes extend a single's chart life."}},{"name":"Programmer","v":4,"meta":{"def":"A specialist who creates and edits programmed and electronic parts.","who":"Sequences MIDI, edits audio and builds sounds for productions.","money":"Session and project fees.","note":"The unsung backbone of modern electronic production."}},{"name":"Vocal Producer","v":4,"meta":{"def":"A producer specialising in getting the best vocal takes.","who":"Coaches singers, comps takes and tunes vocals in sessions.","money":"Session fees and occasional production points.","note":"Comping and tuning skills are the modern core of the job."}}]},{"name":"DJs & Electronic Performers","v":10,"meta":{"def":"Performers who play, mix and manipulate recorded music live.","who":"Curate sets, read crowds and mix tracks in clubs and festivals.","money":"Gig fees, residencies and production royalties.","note":"Top touring DJs rank among music's highest earners."},"children":[{"name":"Club DJ","v":4,"meta":{"def":"A DJ who plays extended mixed sets in venues.","who":"Selects and beatmatches tracks to keep a dancefloor moving.","money":"Per-gig fees and residency retainers.","note":"A prized residency can anchor a DJ's income and reputation."}},{"name":"Radio DJ","v":4,"meta":{"def":"A presenter who plays and introduces music on air.","who":"Curates playlists, chats to listeners and hosts guests live.","money":"Salaried or per-show broadcast fees.","note":"A tastemaker slot can break new artists nationally."}},{"name":"Turntablist","v":4,"meta":{"def":"A DJ who uses turntables as an instrument through scratching.","who":"Performs cuts, scratches and beat juggling routines.","money":"Battle prizes, gig fees and session work.","note":"Rooted in hip-hop's DJ battle culture."}},{"name":"Live Electronic Act","v":4,"meta":{"def":"A performer who builds electronic music live on stage.","who":"Triggers loops and plays hardware to perform tracks in real time.","money":"Show fees, festival slots and streaming royalties.","note":"Blurs the line between DJ and band performance."}},{"name":"VJ (Visual Jockey)","v":4,"meta":{"def":"A performer who mixes visuals live in sync with music.","who":"Cues and blends video and effects alongside DJs and bands.","money":"Event fees and creative commissions.","note":"Increasingly central to festival main stages."}}]},{"name":"Rap & Spoken Word","v":8,"meta":{"def":"Performers whose craft is rhythmic speech and rhyme.","who":"Write and deliver verses, host crowds and record with producers.","money":"Performance fees, streaming and publishing royalties.","note":"The MC role grew from hosting parties to global stardom."},"children":[{"name":"Rapper / MC","v":5,"meta":{"def":"A performer who delivers rhymed lyrics over beats.","who":"Writes verses, records with producers and performs live.","money":"Streaming, performance fees and publishing royalties.","note":"MC originally meant master of ceremonies at parties."}},{"name":"Hype Man","v":4,"meta":{"def":"A performer who energises the crowd behind a lead artist.","who":"Echoes lines, fills gaps and keeps the show's energy high.","money":"Per-show fees paid by the headliner.","note":"A great hype man makes a solo rapper feel like a group."}},{"name":"Spoken Word Artist","v":4,"meta":{"def":"A performer of rhythmic poetry, often with musical backing.","who":"Writes and performs poems at nights, festivals and on record.","money":"Performance fees, book sales and commissions.","note":"Bridges the poetry and music worlds."}},{"name":"Battle Rapper","v":4,"meta":{"def":"An MC who competes in head-to-head lyrical contests.","who":"Writes and performs punchlines against opponents before judges.","money":"Event purses, ticket splits and sponsorships.","note":"Battle leagues now stream to millions online."}}]},{"name":"Street & Movement Performers","v":8,"meta":{"def":"Performers who take music to the street or add movement to it.","who":"Perform in public spaces or dance to music on stage and screen.","money":"Tips, busking fees, gig and tour fees.","note":"Busking has launched more than a few major careers."},"children":[{"name":"Busker","v":4,"meta":{"def":"A musician who performs in public spaces for donations.","who":"Sets up in streets and stations and plays to passersby.","money":"Cash tips and, increasingly, contactless donations.","note":"Many cities now require busking permits and auditions."}},{"name":"Dancer","v":5,"meta":{"def":"A performer who interprets music through movement.","who":"Learns choreography and performs in shows, tours and videos.","money":"Rehearsal and performance fees, tour retainers.","note":"Tour and video dancers are cast through competitive calls."}},{"name":"Choreographer","v":4,"meta":{"def":"The creator of dance routines for performances.","who":"Designs moves and drills dancers for shows and videos.","money":"Creation fees and per-project rates.","note":"Star choreographers shape whole eras of pop staging."}},{"name":"Street Performer (Circus/Variety)","v":4,"meta":{"def":"A variety artist whose act combines music with performance.","who":"Draws and works a crowd with a music-driven routine.","money":"Tips and booked pitch or festival fees.","note":"Festivals curate and pay top street acts."}}]}]},{"name":"Studio & Technical","v":12,"meta":{"def":"The people who capture, shape and finish recorded sound.","who":"Run studios and sessions, engineer audio and build and maintain gear.","money":"Session fees, studio salaries, day rates and craft fees.","note":"The craft that turns a performance into a lasting record."},"children":[{"name":"Recording & Mixing","v":12,"meta":{"def":"Engineers who capture and balance recorded sound.","who":"Set up mics, run sessions and blend tracks for release.","money":"Session fees, day rates and mix fees, sometimes points.","note":"A great engineer is invisible in the finished record."},"children":[{"name":"Recording Engineer","v":5,"meta":{"def":"The engineer who captures performances to record.","who":"Places mics, sets levels and runs the recording session.","money":"Session fees or a studio salary.","note":"Also called a tracking engineer."}},{"name":"Mixing Engineer","v":5,"meta":{"def":"The engineer who balances recorded tracks into a final mix.","who":"Adjusts levels, EQ and effects to blend every element.","money":"Per-song or per-project mix fees, sometimes royalty points.","note":"Top mixers are booked years ahead for major records."}},{"name":"Assistant Engineer","v":4,"meta":{"def":"A junior engineer supporting sessions and the lead engineer.","who":"Sets up gear, patches signal and keeps sessions running.","money":"Junior salary or day rates.","note":"The classic entry route into an engineering career."}},{"name":"Pro Tools Operator","v":4,"meta":{"def":"A specialist who runs the digital audio workstation in sessions.","who":"Edits, comps and manages sessions fast under a producer's direction.","money":"Session and day-rate fees.","note":"Speed and tidiness in the session are everything."}},{"name":"Front-of-House Recordist","v":4,"meta":{"def":"An engineer who records live concerts and broadcasts.","who":"Captures multitrack live audio for release or broadcast.","money":"Event and broadcast fees.","note":"Live albums live and die on this capture."}}]},{"name":"Post-Production & Sound","v":10,"meta":{"def":"Specialists who finish, sculpt and design audio.","who":"Master records and design and edit sound for media.","money":"Per-project fees and studio salaries.","note":"The final polish before anything reaches the public."},"children":[{"name":"Mastering Engineer","v":5,"meta":{"def":"The engineer who finalises a mix for release across formats.","who":"Applies final EQ, loudness and sequencing for the master.","money":"Per-track or per-album mastering fees.","note":"The last creative ear before a record ships."}},{"name":"Sound Designer","v":5,"meta":{"def":"A creator of custom sounds and sonic textures.","who":"Builds patches, effects and sound elements for music and media.","money":"Project fees, sample-pack sales and salaries.","note":"Straddles music, film and games."}},{"name":"Dialogue & Foley Editor","v":4,"meta":{"def":"An audio editor working on speech and effects for media.","who":"Cleans and syncs recorded sound for film and broadcast.","money":"Per-project post-production fees.","note":"Adjacent to music but shares the same craft roots."}},{"name":"Restoration Engineer","v":4,"meta":{"def":"A specialist who cleans and restores old or damaged recordings.","who":"Removes noise and repairs archival audio for reissue.","money":"Per-project restoration fees.","note":"Essential to remaster and reissue catalogues."}}]},{"name":"Instrument Craft","v":12,"meta":{"def":"The people who build, tune and maintain instruments.","who":"Handcraft, repair and set up instruments for players.","money":"Sale prices, repair fees and craft commissions.","note":"Some of the oldest continuous trades in all of music."},"children":[{"name":"Luthier","v":5,"meta":{"def":"A craftsperson who builds and repairs stringed instruments.","who":"Handcrafts guitars, violins and more and sets them up for players.","money":"Instrument sale prices and repair fees.","note":"A single fine violin can take months to build."}},{"name":"Piano Tuner","v":4,"meta":{"def":"A technician who tunes and regulates pianos.","who":"Visits homes, halls and studios to tune and voice pianos.","money":"Per-visit tuning fees.","note":"Concert tuners travel with touring soloists."}},{"name":"Instrument Technician","v":4,"meta":{"def":"A specialist who repairs and maintains instruments.","who":"Diagnoses and fixes instruments for players and shops.","money":"Repair and setup fees or a shop salary.","note":"Brass and woodwind repair is a distinct specialism."}},{"name":"Instrument Maker / Builder","v":4,"meta":{"def":"A craftsperson who manufactures instruments.","who":"Builds pianos, drums, brass or electronics by hand or in workshops.","money":"Sale prices and custom commissions.","note":"Boutique makers command long waiting lists."}},{"name":"Bow Maker","v":4,"meta":{"def":"A specialist who crafts bows for stringed instruments.","who":"Shapes and hairs bows to precise weight and balance.","money":"Sale prices and rehairing fees.","note":"A fine bow can cost as much as an instrument."}},{"name":"Synth & Electronics Builder","v":4,"meta":{"def":"A maker of synthesizers and electronic instruments.","who":"Designs and assembles hardware synths and modules.","money":"Product sales and custom builds.","note":"The modular synth boom revived boutique building."}}]},{"name":"Studio Operations","v":8,"meta":{"def":"The people who keep recording facilities running.","who":"Book, staff and maintain studios and their equipment.","money":"Salaries and studio revenue shares.","note":"A studio's reputation rests on smooth operations."},"children":[{"name":"Studio Manager","v":4,"meta":{"def":"The person who runs a recording studio's business and bookings.","who":"Schedules sessions, staffs rooms and manages clients.","money":"Salary plus possible profit share.","note":"Balances creative needs with commercial reality."}},{"name":"Maintenance Technician","v":4,"meta":{"def":"The engineer who keeps studio equipment working.","who":"Services consoles, tape machines and outboard gear.","money":"Salary or contracted service fees.","note":"Vintage analogue gear needs constant expert care."}},{"name":"Studio Runner","v":4,"meta":{"def":"A junior who supports sessions with practical tasks.","who":"Fetches supplies, sets up and keeps sessions comfortable.","money":"Junior wage or day rate.","note":"A classic foot-in-the-door role in studios."}}]}]},{"name":"Live & Touring","v":14,"meta":{"def":"The people who put on and run live music and tours.","who":"Plan, build, mix and manage shows on the road and in venues.","money":"Day rates, tour salaries, event and commission fees.","note":"A live show is a small army working in tight coordination."},"children":[{"name":"Tour & Stage Management","v":12,"meta":{"def":"The people who run the logistics of shows and tours.","who":"Plan routing, budgets and daily schedules and run the stage.","money":"Weekly tour salaries or per-show fees.","note":"When it works, nobody notices they exist."},"children":[{"name":"Tour Manager","v":5,"meta":{"def":"The person who runs the day-to-day of a tour.","who":"Handles travel, money, schedules and the artist's needs on the road.","money":"Weekly retainer or a percentage of touring income.","note":"Part logistics chief, part diplomat, part therapist."}},{"name":"Production Manager","v":5,"meta":{"def":"The person who oversees the technical build of a show.","who":"Coordinates crew, gear, staging and load-ins for every date.","money":"Tour salary or day rates.","note":"Owns the budget and timeline of the physical show."}},{"name":"Stage Manager","v":4,"meta":{"def":"The person who runs the stage during a performance.","who":"Cues changeovers, keeps time and manages what happens onstage.","money":"Day rates or tour salary.","note":"Keeps festivals to the minute across many acts."}},{"name":"Runner","v":4,"meta":{"def":"A local helper who handles errands during a show or tour.","who":"Drives, collects supplies and supports crew and artists.","money":"Day rates.","note":"A common entry point into touring crews."}},{"name":"Tour Driver","v":4,"meta":{"def":"The professional who drives tour buses or trucks.","who":"Moves crew, artists and gear safely between cities overnight.","money":"Day rates or tour salary.","note":"Sleeper-bus drivers work while the band sleeps."}}]},{"name":"Live Sound & Lighting","v":12,"meta":{"def":"The engineers who make shows sound and look right.","who":"Mix live audio and design and run lighting for performances.","money":"Day rates and tour salaries.","note":"The audience feels their work without seeing it."},"children":[{"name":"Front-of-House (FOH) Engineer","v":5,"meta":{"def":"The engineer who mixes the sound the audience hears.","who":"Balances the live mix from the middle of the room every night.","money":"Day rates or a tour salary.","note":"The most senior sound role on most tours."}},{"name":"Monitor Engineer","v":5,"meta":{"def":"The engineer who mixes what performers hear on stage.","who":"Builds individual monitor and in-ear mixes for each artist.","money":"Day rates or a tour salary.","note":"Keeping the singer happy is the whole job."}},{"name":"Lighting Designer","v":5,"meta":{"def":"The designer who creates a show's lighting look.","who":"Designs rigs and programmes cues to match the music.","money":"Design fees and tour salaries.","note":"Arena shows are as much light as sound."}},{"name":"Systems Tech","v":4,"meta":{"def":"The engineer who tunes and manages the PA system.","who":"Deploys and optimises speaker systems for each venue.","money":"Day rates.","note":"Ensures even sound across a whole room."}},{"name":"Lighting Operator","v":4,"meta":{"def":"The technician who runs lighting cues during a show.","who":"Operates the lighting desk live to the designer's plot.","money":"Day rates.","note":"Busks cues live when shows change nightly."}}]},{"name":"Stage Crew & Techs","v":12,"meta":{"def":"The hands who build, run and strike the show.","who":"Rig, set up, tune and maintain gear and staging.","money":"Day rates and tour salaries.","note":"The physical labour behind every performance."},"children":[{"name":"Guitar Tech","v":4,"meta":{"def":"The technician who maintains and preps guitars and basses.","who":"Strings, tunes and swaps instruments and fixes gear mid-show.","money":"Day rates or tour salary.","note":"Hands the right guitar over at the right second."}},{"name":"Drum Tech","v":4,"meta":{"def":"The technician who sets up and maintains drum kits.","who":"Tunes drums, builds kits and repairs during shows.","money":"Day rates or tour salary.","note":"Kit tuning shapes a band's live sound."}},{"name":"Backline Tech","v":4,"meta":{"def":"A technician responsible for the band's stage gear.","who":"Sets up amps, keys and instruments and keeps them running.","money":"Day rates or tour salary.","note":"Backline covers everything the band plays through."}},{"name":"Rigger","v":4,"meta":{"def":"The specialist who hangs equipment safely overhead.","who":"Climbs and secures rigging points for lights and speakers.","money":"Day rates, often premium for the risk.","note":"A safety-critical, highly certified trade."}},{"name":"Stagehand","v":4,"meta":{"def":"A crew member who loads, builds and strikes the show.","who":"Carries gear, assembles staging and clears out after.","money":"Hourly or per-call rates, often via a local union.","note":"Load-in and load-out are gruelling physical work."}},{"name":"Roadie","v":4,"meta":{"def":"A touring crew member who moves and sets up a band's gear.","who":"Travels with the act, hauling and prepping equipment nightly.","money":"Day rates or tour salary.","note":"The classic catch-all term for touring crew."}},{"name":"Pyrotechnician","v":4,"meta":{"def":"A licensed specialist who runs stage pyrotechnics.","who":"Designs and safely fires flames and fireworks in shows.","money":"Event fees, premium for certification.","note":"Tightly regulated and licence-controlled work."}}]},{"name":"Booking & Promotion","v":10,"meta":{"def":"The people who book acts and sell the shows.","who":"Negotiate dates and fees and market events to fill rooms.","money":"Commissions, promoter margins and salaries.","note":"The commercial engine behind live music."},"children":[{"name":"Booking Agent","v":5,"meta":{"def":"The person who books live performances for artists.","who":"Pitches acts, negotiates fees and routes tours with promoters.","money":"Commission, typically a percentage of gig fees.","note":"Agents hold the keys to the touring circuit."}},{"name":"Promoter","v":5,"meta":{"def":"The person who stages and finances a concert or event.","who":"Books acts, hires venues and takes the financial risk.","money":"Profit (or loss) on ticket sales after costs.","note":"Wins big on a sell-out, loses on an empty room."}},{"name":"Talent Buyer","v":4,"meta":{"def":"The person who books which acts play a venue or festival.","who":"Curates line-ups and negotiates deals with agents.","money":"Salary, sometimes tied to event performance.","note":"Shapes a venue's identity through booking taste."}},{"name":"Festival Programmer","v":4,"meta":{"def":"The curator who builds a festival's whole line-up.","who":"Balances headliners, stages and budgets across a bill.","money":"Salary or contract fee.","note":"One booking can define a festival's year."}}]},{"name":"Venue & Event Staff","v":10,"meta":{"def":"The people who run venues and serve show audiences.","who":"Sell tickets and merch, keep order and host the crowd.","money":"Wages, commissions and event fees.","note":"The public-facing side of live music."},"children":[{"name":"Box Office Staff","v":4,"meta":{"def":"The people who sell and manage tickets at a venue.","who":"Handle sales, guest lists and entry on show days.","money":"Hourly wages.","note":"First point of contact for most audiences."}},{"name":"Merch Seller","v":4,"meta":{"def":"The person who sells an act's merchandise at shows.","who":"Sets up stalls, sells goods and cashes up after.","money":"Day rate or commission on sales.","note":"Merch can outsell tickets on some tours."}},{"name":"Merch Manager","v":4,"meta":{"def":"The person who runs an artist's merchandise operation.","who":"Orders stock, sets prices and manages sellers on tour.","money":"Salary or share of merch revenue.","note":"A major income stream for touring acts."}},{"name":"Event Security","v":4,"meta":{"def":"Staff who keep audiences and artists safe at events.","who":"Manage crowds, entry and safety across the venue.","money":"Hourly event wages.","note":"Front-of-stage barrier work is safety-critical."}},{"name":"Usher / Steward","v":4,"meta":{"def":"Staff who guide and assist audiences in venues.","who":"Seat guests, answer questions and manage crowd flow.","money":"Hourly wages, sometimes volunteer at festivals.","note":"Festival stewarding is often volunteer-for-ticket."}}]}]},{"name":"Business & Management","v":14,"meta":{"def":"The people who build and run the business of music.","who":"Manage artists, sign and market acts and handle money and rights.","money":"Commissions, salaries, royalties and deal fees.","note":"The commercial machinery behind every career."},"children":[{"name":"Artist Management","v":10,"meta":{"def":"The people who guide and represent artists' careers.","who":"Set strategy, coordinate teams and handle day-to-day business.","money":"Commission, typically a share of the artist's income.","note":"A manager's fortunes rise and fall with the artist."},"children":[{"name":"Artist Manager","v":5,"meta":{"def":"The person who oversees an artist's whole career.","who":"Sets strategy, builds the team and makes big decisions with the artist.","money":"Commission, usually around a fifth of income.","note":"The most powerful role in an artist's team."}},{"name":"Day-to-Day Manager","v":4,"meta":{"def":"The manager who handles an artist's daily business.","who":"Runs schedules, admin and coordination beneath the lead manager.","money":"Salary or share of the management commission.","note":"Keeps the machine running behind the scenes."}},{"name":"Business Manager","v":4,"meta":{"def":"The person who manages an artist's finances and assets.","who":"Handles budgets, taxes, investments and payments.","money":"Percentage fee or retainer.","note":"Distinct from the career manager; guards the money."}},{"name":"Personal Assistant","v":4,"meta":{"def":"The person who supports an artist's personal and work life.","who":"Manages diaries, travel and daily needs closely.","money":"Salary.","note":"A trusted, high-access role."}}]},{"name":"Labels & A&R","v":10,"meta":{"def":"The people who sign, develop and release recordings.","who":"Scout talent, fund records and steer roster and catalogue.","money":"Salaries, bonuses and a share of label success.","note":"A&R ears can make or break a label's fortunes."},"children":[{"name":"A&R (Artists & Repertoire)","v":5,"meta":{"def":"The person who scouts and develops signed talent.","who":"Finds artists, pairs them with songs and guides records.","money":"Salary plus bonuses on successful signings.","note":"The creative talent-spotter of a label."}},{"name":"Label Head","v":4,"meta":{"def":"The executive who runs a record label.","who":"Sets roster, strategy and budgets and leads the staff.","money":"Salary, bonuses and equity or profit share.","note":"Owns the label's overall creative and commercial direction."}},{"name":"Product Manager","v":4,"meta":{"def":"The person who coordinates an artist's releases at a label.","who":"Aligns marketing, timelines and teams around each release.","money":"Salary.","note":"The hub connecting label departments per project."}},{"name":"Label Manager","v":4,"meta":{"def":"The person who runs the operations of a label.","who":"Handles releases, distribution and day-to-day running.","money":"Salary.","note":"Common on small and independent labels."}}]},{"name":"Marketing & Promotion","v":12,"meta":{"def":"The people who build audiences and awareness for music.","who":"Plan campaigns, pitch media and drive streams and sales.","money":"Salaries, retainers and campaign fees.","note":"Data and storytelling now sit at the core."},"children":[{"name":"Marketing Manager","v":4,"meta":{"def":"The person who plans and runs music marketing campaigns.","who":"Builds strategy, budgets and assets around releases.","money":"Salary.","note":"Blends creative and analytics."}},{"name":"Radio Plugger","v":4,"meta":{"def":"The person who pitches records to radio for airplay.","who":"Works relationships with stations to secure plays.","money":"Retainer and bonuses on airplay wins.","note":"Airplay still drives major exposure."}},{"name":"Publicist / PR","v":5,"meta":{"def":"The person who secures press and media coverage.","who":"Pitches stories, arranges interviews and manages an act's image.","money":"Monthly retainers per client.","note":"Crisis management is part of the brief too."}},{"name":"Digital / Streaming Marketer","v":4,"meta":{"def":"A specialist in online and streaming-platform marketing.","who":"Runs ads, targets audiences and optimises digital campaigns.","money":"Salary or campaign fees.","note":"Central to how modern releases grow."}},{"name":"Playlist Pitcher","v":4,"meta":{"def":"A specialist who pitches tracks to streaming playlists.","who":"Builds curator relationships to land placements.","money":"Fees and retainers.","note":"Playlist adds can transform a track's reach."}},{"name":"Brand Partnerships Manager","v":4,"meta":{"def":"The person who builds deals between artists and brands.","who":"Negotiates sponsorships, endorsements and collaborations.","money":"Commission or salary on deals brokered.","note":"A growing revenue stream as recorded income shifts."}}]},{"name":"Publishing & Rights","v":12,"meta":{"def":"The people who manage song copyrights and their income.","who":"Sign writers, license songs and collect what is owed.","money":"Publishing shares, admin fees and salaries.","note":"The song copyright can outlive everyone involved."},"children":[{"name":"Music Publisher","v":5,"meta":{"def":"The company or person who manages songwriters' copyrights.","who":"Signs writers, pitches songs and collects royalties.","money":"A share of the publishing royalties.","note":"Owns or administers the song, not the recording."}},{"name":"Sync Agent","v":4,"meta":{"def":"The person who licenses music for film, TV and ads.","who":"Pitches songs to media and negotiates sync fees.","money":"Commission on sync deals.","note":"One big placement can dwarf years of streaming."}},{"name":"Music Supervisor","v":5,"meta":{"def":"The person who chooses and clears music for screen.","who":"Picks songs for scenes and negotiates the rights.","money":"Project fees.","note":"A tastemaker who can break new artists via placement."}},{"name":"Catalogue Manager","v":4,"meta":{"def":"The person who manages and exploits a rights catalogue.","who":"Maximises income from existing songs and recordings.","money":"Salary or share of catalogue income.","note":"Catalogue sales are now a huge investment market."}},{"name":"Royalty Analyst","v":4,"meta":{"def":"A specialist who tracks and reconciles royalty income.","who":"Audits statements and ensures artists are paid correctly.","money":"Salary.","note":"Untangling global royalty flows is painstaking work."}}]},{"name":"Legal & Finance","v":10,"meta":{"def":"The people who handle contracts and money in music.","who":"Draft deals, protect rights and manage finances.","money":"Fees, retainers and salaries.","note":"The safety net that keeps careers solvent and legal."},"children":[{"name":"Music Lawyer","v":5,"meta":{"def":"A lawyer specialising in music contracts and rights.","who":"Negotiates deals, protects copyrights and advises clients.","money":"Hourly fees or a percentage of deals.","note":"Deal-making lawyers often broker the introductions too."}},{"name":"Music Accountant","v":4,"meta":{"def":"An accountant who handles music-industry finances.","who":"Manages tax, royalties and touring accounts for clients.","money":"Fees or retainers.","note":"Royalty and touring accounting is a niche specialism."}},{"name":"Royalty Auditor","v":4,"meta":{"def":"A specialist who audits labels and publishers on artists' behalf.","who":"Examines statements to recover underpaid royalties.","money":"Fees, often a share of recovered money.","note":"High-profile audits can recover large sums."}},{"name":"Collections Society Officer","v":4,"meta":{"def":"Staff at a body that collects and distributes royalties.","who":"Track usage and pay writers, artists and rights holders.","money":"Salary.","note":"Societies handle billions in royalties worldwide."}}]}]},{"name":"Media & Content","v":12,"meta":{"def":"The people who cover, curate and create content about music.","who":"Write, broadcast, shoot and post about music and artists.","money":"Fees, salaries, ad and content revenue.","note":"How most people discover and hear about music."},"children":[{"name":"Journalism & Criticism","v":10,"meta":{"def":"The people who write and report about music.","who":"Interview artists, review releases and cover the scene.","money":"Per-piece fees, staff salaries and freelance rates.","note":"A shrinking but still influential field."},"children":[{"name":"Music Journalist","v":5,"meta":{"def":"A writer who reports on music, artists and the industry.","who":"Researches, interviews and writes features and news.","money":"Per-article fees or a staff salary.","note":"Increasingly freelance and multi-platform."}},{"name":"Music Critic","v":4,"meta":{"def":"A writer who reviews and evaluates music and performances.","who":"Attends shows, listens to releases and publishes verdicts.","money":"Per-review fees or salary.","note":"A strong review still moves discovery."}},{"name":"Music Editor","v":4,"meta":{"def":"The person who commissions and shapes music coverage.","who":"Assigns stories, edits copy and sets the editorial line.","money":"Salary.","note":"Sets the voice of a publication's music section."}},{"name":"Music Blogger","v":4,"meta":{"def":"An independent writer who covers music online.","who":"Posts reviews, premieres and discoveries to a following.","money":"Ad revenue, sponsorship and premieres.","note":"Influential blogs help break new artists."}}]},{"name":"Broadcast & Podcasting","v":10,"meta":{"def":"The people who present and produce audio programming.","who":"Host shows, produce segments and craft the on-air sound.","money":"Salaries, per-show fees and sponsorship.","note":"Radio and podcasts remain powerful tastemakers."},"children":[{"name":"Radio Presenter","v":4,"meta":{"def":"The host who presents a music radio show.","who":"Introduces tracks, interviews guests and talks to listeners.","money":"Salary or per-show fees.","note":"Star presenters draw big audiences to a station."}},{"name":"Radio Producer","v":4,"meta":{"def":"The person who plans and runs a radio programme behind the scenes.","who":"Books guests, builds running orders and directs the show.","money":"Salary.","note":"Shapes the show the presenter fronts."}},{"name":"Podcast Host","v":4,"meta":{"def":"The presenter of a music podcast.","who":"Interviews guests and discusses music for an audience.","money":"Ad revenue, sponsorship and subscriptions.","note":"Music podcasts range from hobby to full business."}},{"name":"Announcer / Voiceover Artist","v":4,"meta":{"def":"A voice professional for stations and events.","who":"Records idents, links and announcements.","money":"Per-session fees and usage royalties.","note":"A distinctive voice becomes a station's brand."}}]},{"name":"Visual & Social Content","v":12,"meta":{"def":"The people who create images, video and social content.","who":"Shoot, edit and post visual content for artists and media.","money":"Shoot fees, salaries and content revenue.","note":"Now central to how artists are marketed."},"children":[{"name":"Music Photographer","v":4,"meta":{"def":"A photographer who shoots artists and live music.","who":"Captures gigs, portraits and press and cover images.","money":"Shoot fees and image licensing.","note":"Live shooting often means the first three songs only."}},{"name":"Music Video Director","v":5,"meta":{"def":"The creative lead who directs music videos.","who":"Develops concepts and directs shoots for artists' songs.","money":"Project fees from video budgets.","note":"A breakout video can define an artist's image."}},{"name":"Videographer / Editor","v":4,"meta":{"def":"A specialist who shoots and edits music video content.","who":"Films performances and cuts clips for release and social.","money":"Project and day-rate fees.","note":"Tour and social content is constant demand."}},{"name":"Social Media Manager","v":4,"meta":{"def":"The person who runs an artist's social presence.","who":"Plans posts, engages fans and grows the following.","money":"Salary or retainer.","note":"Voice and consistency build fan loyalty."}},{"name":"Content Creator","v":4,"meta":{"def":"A creator who makes music-related content online.","who":"Produces videos and posts around music for a platform audience.","money":"Platform revenue, sponsorship and merch.","note":"Some creators become artists in their own right."}}]},{"name":"Curation & Editorial","v":8,"meta":{"def":"The people who select and present music to audiences.","who":"Build playlists and editorial around discovery.","money":"Salaries and platform roles.","note":"Curators wield enormous power over discovery."},"children":[{"name":"Playlist Curator","v":4,"meta":{"def":"The person who builds and maintains playlists.","who":"Selects and sequences tracks around moods or genres.","money":"Salary at platforms, or independent revenue.","note":"A single big-playlist add can change a career."}},{"name":"Streaming Editor","v":4,"meta":{"def":"An editorial curator at a streaming platform.","who":"Programmes flagship playlists and editorial features.","money":"Salary.","note":"Among the most sought-after gatekeepers today."}},{"name":"Record Store Buyer","v":4,"meta":{"def":"The person who selects stock for a record shop.","who":"Chooses releases, orders stock and advises customers.","money":"Retail salary.","note":"Independent shops shape local scenes."}}]}]},{"name":"Education, Therapy & Scholarship","v":12,"meta":{"def":"The people who teach, heal and study music.","who":"Instruct students, treat clients and research music.","money":"Salaries, session fees and grants.","note":"Often the steadiest careers in the whole field."},"children":[{"name":"Teaching & Instruction","v":12,"meta":{"def":"The people who teach music to others.","who":"Instruct students in schools, studios and privately.","money":"Salaries and hourly lesson fees.","note":"Teaching underpins the income of countless musicians."},"children":[{"name":"Private Music Tutor","v":4,"meta":{"def":"An independent teacher of instrument or voice lessons.","who":"Coaches individual students on their instrument.","money":"Hourly lesson fees.","note":"A staple income source for working musicians."}},{"name":"School Music Teacher","v":5,"meta":{"def":"A teacher who delivers music in schools.","who":"Plans lessons, leads ensembles and prepares students for exams.","money":"Teaching salary.","note":"One of the most stable jobs in music."}},{"name":"Conservatory Professor","v":4,"meta":{"def":"A senior teacher at a music college or conservatory.","who":"Trains advanced students and often performs and researches.","money":"Academic salary plus performance income.","note":"Prestigious posts are fiercely competitive."}},{"name":"Vocal Coach","v":4,"meta":{"def":"A specialist who trains and develops singers' voices.","who":"Builds technique, health and range with singers.","money":"Hourly session fees.","note":"Elite coaches travel with touring artists."}},{"name":"Masterclass Clinician","v":4,"meta":{"def":"An expert who teaches intensive workshops and masterclasses.","who":"Delivers focused sessions to groups of students.","money":"Clinic and workshop fees.","note":"A prestige sideline for touring virtuosos."}}]},{"name":"Ensemble Direction (Education)","v":10,"meta":{"def":"The people who lead ensembles in schools and communities.","who":"Rehearse and conduct choirs and bands of students or amateurs.","money":"Salaries and per-service fees.","note":"Builds the grassroots of every music culture."},"children":[{"name":"Choir Director","v":5,"meta":{"def":"The person who leads and rehearses a choir.","who":"Selects music, trains singers and conducts performances.","money":"Salary, per-service fees or stipend.","note":"Ranges from community groups to cathedral choirs."}},{"name":"Band Director","v":4,"meta":{"def":"The person who leads a school or community band.","who":"Rehearses players and conducts concerts and events.","money":"Teaching salary or stipend.","note":"Marching-band directors run huge programmes in some countries."}},{"name":"Youth Orchestra Conductor","v":4,"meta":{"def":"A conductor who leads young players in an orchestra.","who":"Develops technique and ensemble skills through rehearsal.","money":"Fees or salary.","note":"Nurtures the next generation of orchestral players."}}]},{"name":"Scholarship & Archives","v":10,"meta":{"def":"The people who research, document and preserve music.","who":"Study, catalogue and safeguard music and its history.","money":"Academic and institutional salaries.","note":"Guardians of music's memory and knowledge."},"children":[{"name":"Musicologist","v":5,"meta":{"def":"A scholar who researches the history and theory of music.","who":"Studies scores and sources and publishes research.","money":"University salary and research grants.","note":"Work spans teaching, writing and archival research."}},{"name":"Ethnomusicologist","v":5,"meta":{"def":"A scholar who studies music in its cultural context.","who":"Does fieldwork, records traditions and analyses culture.","money":"University salary and grants.","note":"Fieldwork can mean years living within a community."}},{"name":"Music Librarian","v":4,"meta":{"def":"A specialist who manages music scores and recordings.","who":"Catalogues, sources and lends music materials.","money":"Institutional salary.","note":"Orchestra librarians prepare parts for every concert."}},{"name":"Music Archivist","v":4,"meta":{"def":"A specialist who preserves music recordings and documents.","who":"Conserves, digitises and organises collections.","money":"Institutional salary.","note":"Racing to save decaying tape and formats."}}]},{"name":"Music Therapy & Wellbeing","v":8,"meta":{"def":"The people who use music for health and healing.","who":"Work with clients and patients using music clinically.","money":"Salaries and session fees.","note":"A regulated healthcare profession in many countries."},"children":[{"name":"Music Therapist","v":5,"meta":{"def":"A clinician who uses music to support health and wellbeing.","who":"Runs sessions with patients in health and care settings.","money":"Health-service salary or private fees.","note":"Requires accredited clinical training."}},{"name":"Community Music Worker","v":4,"meta":{"def":"A practitioner who leads music with community groups.","who":"Runs inclusive workshops in schools, care and outreach settings.","money":"Project funding, grants and fees.","note":"Often grant- and project-funded work."}},{"name":"Sound Healer","v":4,"meta":{"def":"A practitioner who uses sound for relaxation and wellbeing.","who":"Runs sessions with gongs, bowls and voice.","money":"Session and workshop fees.","note":"A growing wellness-sector niche."}}]}]},{"name":"Specialist & Support Roles","v":12,"meta":{"def":"The niche and support jobs that keep music working.","who":"Fill specialist gaps across worship, ceremony, service and craft.","money":"Fees, salaries and per-engagement pay.","note":"Often overlooked, but the field could not run without them."},"children":[{"name":"Worship & Ceremony","v":10,"meta":{"def":"Musicians who serve religious and ceremonial life.","who":"Lead and play music in worship, rites and ceremonies.","money":"Salaries, stipends and per-service fees.","note":"Some of the oldest paid musical roles anywhere."},"children":[{"name":"Worship Music Director","v":4,"meta":{"def":"The person who leads music in a place of worship.","who":"Plans and leads songs and the band for services.","money":"Salary or stipend.","note":"Contemporary worship supports large music teams."}},{"name":"Church Organist","v":4,"meta":{"def":"A keyboardist who plays organ for services.","who":"Accompanies hymns and choirs and plays for ceremonies.","money":"Salary, stipend or per-service fees.","note":"Weddings and funerals add extra income."}},{"name":"Cantor","v":4,"meta":{"def":"A singer who leads sung prayer in worship.","who":"Chants and leads congregational singing in services.","money":"Salary or per-service fees.","note":"A central role in several faith traditions."}},{"name":"Wedding & Funeral Musician","v":4,"meta":{"def":"A musician who plays for life-event ceremonies.","who":"Performs at weddings, funerals and civil ceremonies.","money":"Per-event fees.","note":"Reliable, steady, year-round demand."}}]},{"name":"Function & Service Music","v":10,"meta":{"def":"Musicians who provide music for events and venues.","who":"Play weddings, parties, ships and hospitality settings.","money":"Contract and per-engagement fees.","note":"Unglamorous but among the most reliable music work."},"children":[{"name":"Wedding Band Leader","v":4,"meta":{"def":"The person who leads a band playing functions.","who":"Books gigs, hires players and fronts the function band.","money":"Per-event fees, splitting with the band.","note":"A well-run function band earns steady money."}},{"name":"Cruise Ship Musician","v":4,"meta":{"def":"A musician employed to perform aboard cruise ships.","who":"Plays sets in ship venues across long contracts at sea.","money":"Contract salary plus board and lodging.","note":"Months-long contracts with travel included."}},{"name":"Hotel & Lounge Pianist","v":4,"meta":{"def":"A pianist who provides background music in hospitality.","who":"Plays sets in lobbies, bars and restaurants.","money":"Per-session or residency fees.","note":"Discreet, steady, evening-based work."}},{"name":"Military Bandsman","v":4,"meta":{"def":"A musician serving in a military band.","who":"Performs at ceremonies, parades and official events.","money":"Military salary and benefits.","note":"A rare full-time, pensioned music job."}},{"name":"Theme Park Musician","v":4,"meta":{"def":"A performer employed at a theme park or resort.","who":"Plays scheduled shows and roaming sets for visitors.","money":"Contract or hourly wages.","note":"Steady seasonal and year-round performing work."}}]},{"name":"Behind-the-Scenes Support","v":10,"meta":{"def":"The specialist helpers who support performers and productions.","who":"Fix, coordinate and assist at rehearsals and performances.","money":"Fees and per-engagement pay.","note":"Small roles that keep big machines turning."},"children":[{"name":"Contractor / Fixer","v":5,"meta":{"def":"The person who hires musicians for sessions and shows.","who":"Books the right players and staffs ensembles for projects.","money":"A booking fee or a percentage of the budget.","note":"A good fixer's contact book is their whole business."}},{"name":"Orchestra Librarian","v":4,"meta":{"def":"The person who manages an orchestra's sheet music.","who":"Prepares, marks and distributes parts for every concert.","money":"Salary.","note":"Marks bowings and cuts before rehearsals begin."}},{"name":"Page Turner","v":4,"meta":{"def":"A person who turns pages for a performing pianist.","who":"Sits alongside and turns the score at the right moment.","money":"A small per-performance fee.","note":"A tiny but high-pressure concert-hall role."}},{"name":"Repetiteur","v":4,"meta":{"def":"A pianist who coaches and rehearses opera singers.","who":"Plays reductions and drills singers on their parts.","money":"Salary or session fees.","note":"Essential to every opera house's rehearsal room."}},{"name":"Wardrobe & Styling","v":4,"meta":{"def":"The people who dress and style performers.","who":"Source, fit and maintain stage looks for artists.","money":"Day rates or salary.","note":"Image is part of the whole performance."}}]}]}]},{"name":"Education & Scholarship","type":"education","v":26,"children":[{"name":"Scholarly Fields","v":14,"meta":{"def":"Academic disciplines that study music as a phenomenon of sound, culture, cognition and history.","ex":"Musicology, ethnomusicology, music theory, MIR","note":"Formalised in Europe in the late 19th century under the term Musikwissenschaft"},"children":[{"name":"Historical Musicology","v":6,"meta":{"def":"The study of Western art music through its history, composers, sources and stylistic development.","ex":"Guido Adler, Manfred Bukofzer, Richard Taruskin; study of manuscripts and editions","note":"Long the dominant strand of Anglo-American musicology, sometimes just called 'music history'"},"children":[{"name":"Source Studies & Philology","v":4,"meta":{"def":"Examination of original manuscripts, prints and sketches to establish authentic musical texts.","ex":"Bach autograph studies; Beethoven sketchbooks; watermark and paper analysis","note":"Borrows codicological methods from literary textual criticism"}},{"name":"Style History & Periodisation","v":4,"meta":{"def":"Charting how musical style evolves and how eras such as Baroque or Classical are defined.","ex":"Debates over the boundaries of Renaissance, Baroque, Romantic labels","note":"Era names were mostly applied retrospectively by 19th and 20th-century scholars"}},{"name":"Biographical & Composer Studies","v":4,"meta":{"def":"Research into the lives, working methods and reception of individual composers.","ex":"Bach-Jahrbuch, Mozart's letters, Wagner biography industry","note":"The '-ology' suffix spawns fields like Bach studies and Beethoven studies"}},{"name":"Reception History","v":4,"meta":{"def":"How musical works have been performed, interpreted and valued by audiences over time.","ex":"The changing status of Bach's Passions; Beethoven's Ninth as political symbol","note":"Draws on reception theory from literary studies (Hans Robert Jauss)"}},{"name":"Historical Performance Practice","v":4,"meta":{"def":"Scholarly reconstruction of how earlier music was actually performed.","ex":"Nikolaus Harnoncourt, period instruments, tempo and ornamentation research","note":"Underpins the historically informed performance (HIP) movement"}},{"name":"Feminist & Gender Musicology","v":4,"meta":{"def":"Study of gender, sexuality and the recovery of women composers in music history.","ex":"Susan McClary's Feminine Endings; Marcia Citron; recovery of Clara Schumann, Hildegard","note":"Part of the 'New Musicology' turn of the 1980s-90s"}}]},{"name":"Systematic Musicology","v":6,"meta":{"def":"The scientific, non-historical study of music's acoustic, psychological and systematic aspects.","ex":"Acoustics, tuning systems, aesthetics, empirical study of listening","note":"Guido Adler paired it with historical musicology in his 1885 disciplinary map"},"children":[{"name":"Music Acoustics","v":4,"meta":{"def":"Physics of musical sound: how instruments and voices produce and radiate tone.","ex":"Hermann von Helmholtz; violin resonance studies; formant analysis","note":"Bridges physics, engineering and music"}},{"name":"Tuning & Temperament Theory","v":4,"meta":{"def":"Study of how pitches are tuned into scales and how compromises like equal temperament arise.","ex":"Pythagorean, just intonation, meantone, well-tempered systems","note":"The 'comma' problem drives centuries of tuning compromise"}},{"name":"Empirical Aesthetics","v":4,"meta":{"def":"Experimental study of how and why listeners find music beautiful or pleasing.","ex":"Gustav Fechner's founding experiments; preference and complexity research","note":"One of the oldest branches of experimental psychology"}},{"name":"Systematic Comparison of Scales","v":4,"meta":{"def":"Cross-cultural analysis of scale and interval systems as sound structures.","ex":"Alexander Ellis's cents system for comparing world scales","note":"Ellis coined the 'cent' unit in 1885 to compare tunings numerically"}}]},{"name":"Ethnomusicology","v":8,"meta":{"def":"The study of music in its cultural and social context, especially non-Western and vernacular traditions.","ex":"Bruno Nettl, Mantle Hood, Alan Merriam; fieldwork and participant observation","note":"Renamed from 'comparative musicology' by Jaap Kunst around 1950"},"children":[{"name":"Fieldwork & Ethnography","v":4,"meta":{"def":"Immersive study of music-making within a living community through observation and participation.","ex":"Learning to perform locally ('bi-musicality', Mantle Hood); field notes","note":"Ethnomusicologists often spend years living with the communities they study"}},{"name":"Applied Ethnomusicology","v":4,"meta":{"def":"Use of ethnomusicological knowledge to serve communities, advocacy and cultural policy.","ex":"Repatriation of recordings; supporting endangered traditions","note":"Emphasises ethics and giving back to source communities"}},{"name":"Urban Ethnomusicology","v":4,"meta":{"def":"Study of music within cities, migration, diaspora and modern media environments.","ex":"Immigrant music scenes; global-city club cultures","note":"Challenged the old assumption that 'authentic' music is rural and traditional"}},{"name":"Organological Fieldwork","v":4,"meta":{"def":"Documentation of instruments as used within their originating cultures.","ex":"Gamelan, mbira, sitar construction and social role","note":"Bridges ethnomusicology and organology"}},{"name":"Ethno-choreology","v":4,"meta":{"def":"Study of dance and body movement as inseparable from musical performance.","ex":"Notating traditional dance alongside music; movement analysis","note":"Recognises that in many cultures music and dance are a single concept"}},{"name":"Music & Ritual Studies","v":4,"meta":{"def":"Analysis of music's role in religious, ceremonial and healing practices.","ex":"Trance music, shamanic drumming, liturgical chant","note":"Overlaps with anthropology of religion"}}]},{"name":"Music Sociology","v":5,"meta":{"def":"Study of music as a social institution: production, consumption, taste and power.","ex":"Theodor Adorno, Pierre Bourdieu, Tia DeNora, Simon Frith","note":"Adorno's writings are a foundational and controversial reference point"},"children":[{"name":"Taste & Distinction","v":4,"meta":{"def":"How musical preference marks and reproduces social class and identity.","ex":"Bourdieu's 'Distinction'; omnivore vs univore listening","note":"Cultural capital theory links classical taste to social standing"}},{"name":"Scenes & Subcultures","v":4,"meta":{"def":"Sociological study of local music communities and their identities.","ex":"Punk, rave, metal, hip-hop scenes; Birmingham CCCS school","note":"'Scene' partly replaced 'subculture' as the preferred analytic term"}},{"name":"Music & Everyday Life","v":4,"meta":{"def":"How people use music to manage mood, memory and social situations day to day.","ex":"Tia DeNora's research on music as a technology of the self","note":"Shifts focus from the work to the listener's active use of music"}}]},{"name":"Music Psychology","v":6,"meta":{"def":"Scientific study of how humans perceive, respond to and are affected by music.","ex":"Carl Seashore, John Sloboda, Diana Deutsch; emotion and ability research","note":"Seashore's 1919 test of musical talents was an early landmark"},"children":[{"name":"Music & Emotion","v":4,"meta":{"def":"Study of how music induces and expresses emotional states.","ex":"Juslin & Sloboda; chills/frisson research; expectancy and tension","note":"The BRECVEMA framework lists mechanisms by which music arouses emotion"}},{"name":"Auditory Perception","v":4,"meta":{"def":"How the ear and brain group sounds into pitch, timbre and streams.","ex":"Albert Bregman's auditory scene analysis; pitch illusions (Deutsch)","note":"Explains how we hear a melody separate from accompaniment"}},{"name":"Musical Development","v":4,"meta":{"def":"How musical abilities emerge and change across the lifespan.","ex":"Infant preference studies; the 'nature vs nurture' talent debate","note":"Absolute pitch appears to depend on early exposure and a critical period"}},{"name":"Performance Science","v":4,"meta":{"def":"Psychology of practice, expertise, memory and performance anxiety.","ex":"Deliberate practice research; music performance anxiety (MPA)","note":"Beta-blockers are sometimes used by performers to control anxiety symptoms"}}]},{"name":"Music Cognition & Neuroscience","v":5,"meta":{"def":"Study of the mental and neural processes underlying music perception and production.","ex":"Aniruddh Patel, Isabelle Peretz, Robert Zatorre; fMRI and EEG studies","note":"The field is sometimes called 'neuromusicology' or 'cognitive musicology'"},"children":[{"name":"Rhythm & Entrainment","v":4,"meta":{"def":"How brains track a beat and synchronise movement to music.","ex":"Beat-based timing; Snowball the dancing cockatoo studies","note":"Beat synchronisation may be rare among non-human animals"}},{"name":"Music & Language","v":4,"meta":{"def":"Comparison of shared and distinct brain resources for music and speech.","ex":"Patel's OPERA hypothesis; shared syntax processing","note":"Broca's area appears active in both language and musical syntax"}},{"name":"Amusia","v":4,"meta":{"def":"Study of disorders that impair the perception or production of music.","ex":"Congenital 'tone deafness'; acquired amusia after brain injury","note":"True congenital amusia affects roughly 1.5-4% of people"}},{"name":"Musical Imagery & Memory","v":4,"meta":{"def":"How music is stored, recalled and replayed mentally.","ex":"Earworms (involuntary musical imagery); tonal memory tests","note":"Earworms are studied under the term 'involuntary musical imagery' (INMI)"}}]},{"name":"Music Aesthetics & Philosophy","v":5,"meta":{"def":"Philosophical inquiry into the nature, meaning and value of music.","ex":"Eduard Hanslick, Peter Kivy, Stephen Davies; formalism vs expression debates","note":"Hanslick's 1854 tract argued music's content is 'tonally moving forms'"},"children":[{"name":"Formalism & Expression","v":4,"meta":{"def":"Debate over whether music's meaning is purely structural or genuinely expressive.","ex":"Hanslick's formalism vs Romantic expression theories","note":"The 'paradox of negative emotion' asks why we enjoy sad music"}},{"name":"Ontology of the Musical Work","v":4,"meta":{"def":"Questions about what a musical work is and how it relates to its performances.","ex":"Is a symphony the score, a sound-event, or an abstract type?","note":"The 'work concept' is argued to be a 19th-century invention (Lydia Goehr)"}},{"name":"Meaning & Semiotics","v":4,"meta":{"def":"How music signifies, refers and carries cultural meaning.","ex":"Jean-Jacques Nattiez; topic theory; musical signs","note":"Musical semiotics adapts Peirce and Saussure to sound"}}]},{"name":"Music Informatics & MIR","v":6,"meta":{"def":"Computational study and retrieval of music information from audio and symbolic data.","ex":"ISMIR conference; Spotify/Shazam algorithms; content-based retrieval","note":"Music Information Retrieval (MIR) coalesced as a field around the year 2000"},"children":[{"name":"Audio Feature Extraction","v":4,"meta":{"def":"Deriving descriptors like pitch, tempo, timbre and chroma from raw audio.","ex":"MFCCs, chroma vectors, onset detection, beat tracking","note":"Chroma features fold all octaves into 12 pitch classes"}},{"name":"Music Recommendation","v":4,"meta":{"def":"Algorithms that suggest music based on listening data and audio content.","ex":"Collaborative filtering; Spotify Discover Weekly; content-based systems","note":"Hybrid systems combine listening behaviour with audio analysis"}},{"name":"Automatic Transcription","v":4,"meta":{"def":"Converting recorded audio into symbolic notation automatically.","ex":"Polyphonic piano transcription; audio-to-MIDI","note":"Polyphonic transcription remains an unsolved hard problem"}},{"name":"Optical Music Recognition","v":4,"meta":{"def":"Software reading of printed or handwritten scores into digital notation.","ex":"OMR engines like Audiveris; PhotoScore","note":"The music-notation analogue of OCR for text"}},{"name":"Computational Musicology","v":4,"meta":{"def":"Using large-scale data and algorithms to answer musicological questions.","ex":"Corpus studies of harmony; big-data analysis of pop-chart evolution","note":"Sometimes framed as the 'digital humanities' of music"}}]},{"name":"Organology","v":6,"meta":{"def":"The scholarly study of musical instruments, their construction, history and classification.","ex":"Curt Sachs, Erich von Hornbostel; museum instrument collections","note":"The Hornbostel-Sachs system (1914) is the standard instrument taxonomy"},"children":[{"name":"Instrument Classification","v":4,"meta":{"def":"Systematic grouping of instruments by how they produce sound.","ex":"Hornbostel-Sachs: idiophones, membranophones, chordophones, aerophones","note":"A fifth class, electrophones, was added later for electronic instruments"}},{"name":"Instrument History","v":4,"meta":{"def":"Tracing the origins and evolution of specific instruments.","ex":"Development of the piano from harpsichord; valve brass invention","note":"Cristofori built the first piano around 1700"}},{"name":"Instrument Conservation","v":4,"meta":{"def":"Preservation, restoration and playable maintenance of historic instruments.","ex":"Stradivari violin care; keeping museum organs playable","note":"Curators debate whether to play or merely preserve fragile instruments"}}]},{"name":"Music Criticism","v":4,"meta":{"def":"Evaluative writing about musical works, performances and recordings.","ex":"Eduard Hanslick, Virgil Thomson, Robert Christgau, Lester Bangs","note":"Rooted in 19th-century journalism and the rise of concert culture"},"children":[{"name":"Classical Criticism","v":4,"meta":{"def":"Reviewing art-music performances, recordings and new works.","ex":"Gramophone reviews; New York Times classical desk","note":"Full-time classical critic posts have dwindled in recent decades"}},{"name":"Popular Music Journalism","v":4,"meta":{"def":"Reviewing and interpreting popular music for general audiences.","ex":"Rolling Stone, NME, Pitchfork; the 'rockism vs poptimism' debate","note":"Robert Christgau styled himself the 'Dean of American Rock Critics'"}}]},{"name":"Popular Music Studies","v":4,"meta":{"def":"Academic study of popular, vernacular and commercial music and its industries.","ex":"IASPM association; Simon Frith, Philip Tagg; genre and industry analysis","note":"Long marginalised in music departments before gaining legitimacy from the 1980s"},"children":[{"name":"Genre & Style Analysis","v":4,"meta":{"def":"Analysis of the musical and cultural codes that define popular genres.","ex":"Studying the conventions of blues, funk, EDM, hip-hop","note":"Philip Tagg pioneered analysis of popular and film music"}},{"name":"Industry & Production Studies","v":4,"meta":{"def":"Study of how popular music is produced, marketed and monetised.","ex":"Recording studio ethnography; streaming economics","note":"Overlaps with media studies and cultural economics"}}]},{"name":"Performance Studies","v":4,"meta":{"def":"Study of musical performance as an act, embodiment and social event.","ex":"Nicholas Cook; analysing recordings and gesture rather than scores","note":"Shifts focus from the notated 'work' to the sounding performance"},"children":[{"name":"Recording Analysis","v":4,"meta":{"def":"Studying historic recordings to reveal changing performance styles.","ex":"CHARM project; measuring tempo, rubato and portamento over time","note":"Early-1900s string players used far more portamento than today"}},{"name":"Gesture & Embodiment","v":4,"meta":{"def":"How physical movement shapes and communicates musical meaning.","ex":"Motion-capture of pianists; conductor gesture studies","note":"Draws on embodied-cognition theory"}}]},{"name":"Music Semiotics","v":4,"meta":{"def":"The study of musical signs, codes and how music communicates meaning.","ex":"Jean-Jacques Nattiez, Kofi Agawu, Robert Hatten; topic theory","note":"Nattiez's tripartition splits creation, sound-trace and reception"},"children":[{"name":"Topic Theory","v":4,"meta":{"def":"Identification of conventional musical 'topics' that carry cultural associations.","ex":"Hunt, march, pastoral and lament topics in Classical music","note":"Leonard Ratner introduced the term 'topic' to music analysis in 1980"}},{"name":"Narrative & Meaning","v":4,"meta":{"def":"How music is heard to tell stories or enact dramatic trajectories.","ex":"Musical narrative theory; agency and 'plot' in symphonies","note":"Borrows narratology from literary theory"}}]}]},{"name":"Theory, Analysis & Pedagogy Topics","v":14,"meta":{"def":"Bodies of knowledge and skill studied to understand and read music.","ex":"Harmony, counterpoint, ear training, Schenkerian analysis, set theory","note":"These form the core curriculum of most conservatory theory programmes"},"children":[{"name":"Fundamentals of Music Theory","v":5,"meta":{"def":"The basic building blocks: notation, scales, intervals, keys and rhythm.","ex":"Reading the staff, major/minor scales, time signatures","note":"Usually the first-year foundation before harmony and counterpoint"},"children":[{"name":"Notation & Clefs","v":4,"meta":{"def":"Reading and writing pitch and rhythm on the staff with clefs and accidentals.","ex":"Treble, bass, alto and tenor clefs; ledger lines","note":"The C-clef can move on the staff to suit different instruments"}},{"name":"Scales & Modes","v":4,"meta":{"def":"Ordered pitch collections that supply the raw material of melody and harmony.","ex":"Major, natural/harmonic/melodic minor, Dorian, Mixolydian","note":"The church modes predate the modern major/minor system"}},{"name":"Intervals","v":4,"meta":{"def":"The distance between two pitches and the quality that defines its sound.","ex":"Perfect fifth, major third, tritone; consonance vs dissonance","note":"The tritone was nicknamed 'diabolus in musica' in medieval theory"}},{"name":"Rhythm & Meter","v":4,"meta":{"def":"Organisation of durations into beats, measures and metrical patterns.","ex":"Simple vs compound meter; syncopation; polyrhythm","note":"Additive meters like 7/8 are common in Balkan music"}}]},{"name":"Harmony Studies","v":6,"meta":{"def":"The study of chords and how they progress to create tonal music.","ex":"Roman-numeral analysis, voice leading, chromatic harmony","note":"Rameau's 1722 Treatise founded modern chord-based harmony"},"children":[{"name":"Roman Numeral Analysis","v":4,"meta":{"def":"Labelling chords by scale degree to describe harmonic function.","ex":"I-IV-V-I progressions; secondary dominants (V/V)","note":"Capital vs lowercase numerals distinguish major and minor chords"}},{"name":"Voice Leading","v":4,"meta":{"def":"Rules for smoothly connecting the individual lines within a chord progression.","ex":"Avoiding parallel fifths and octaves; resolving tendency tones","note":"The leading tone conventionally resolves up to the tonic"}},{"name":"Chromatic Harmony","v":4,"meta":{"def":"Advanced harmony using notes outside the key for colour and modulation.","ex":"Neapolitan and augmented-sixth chords; modal mixture","note":"The 'Tristan chord' is a famous emblem of chromatic ambiguity"}},{"name":"Jazz Harmony","v":4,"meta":{"def":"Extended and altered chords and their function in jazz idioms.","ex":"ii-V-I; tritone substitution; upper extensions and tensions","note":"Chord-scale theory links each chord to a compatible scale"}}]},{"name":"Counterpoint Studies","v":5,"meta":{"def":"The art of combining independent melodic lines that sound well together.","ex":"Palestrina style, Bach fugue, invertible counterpoint","note":"'Punctus contra punctum' means note against note"},"children":[{"name":"Species Counterpoint","v":4,"meta":{"def":"A graded pedagogical method teaching counterpoint in five progressive species.","ex":"Fux's Gradus ad Parnassum (1725); first to fifth species","note":"Haydn, Mozart and Beethoven all learned from Fux's treatise"}},{"name":"Fugue & Imitation","v":4,"meta":{"def":"Study of imitative textures where a subject is answered across voices.","ex":"Bach's Art of Fugue; subject, answer, countersubject, stretto","note":"A fugue is a procedure, not a fixed form"}},{"name":"Modal Counterpoint","v":4,"meta":{"def":"Counterpoint in the style of 16th-century modal polyphony.","ex":"Palestrina and Lassus style; Jeppesen's textbook","note":"The Palestrina style is treated as the model of 'strict' vocal counterpoint"}}]},{"name":"Form & Analysis","v":5,"meta":{"def":"Study of how musical works are structured into sections and forms.","ex":"Sonata form, rondo, theme and variations, phrase structure","note":"Formal categories were codified mostly in the 19th century by theorists like A.B. Marx"},"children":[{"name":"Sonata Form","v":4,"meta":{"def":"Analysis of the exposition-development-recapitulation design central to Classical music.","ex":"First movements of Haydn, Mozart, Beethoven symphonies","note":"Sonata Theory (Hepokoski & Darcy) reframes it via 'rotations' and defaults"}},{"name":"Phrase & Period Structure","v":4,"meta":{"def":"How melodies group into phrases, periods and sentences.","ex":"Antecedent-consequent periods; the 'sentence' (Satz)","note":"Schoenberg and Caplin formalised the sentence vs period distinction"}},{"name":"Formenlehre","v":4,"meta":{"def":"The systematic doctrine of musical forms and their conventions.","ex":"William Caplin's theory of formal functions","note":"German term literally meaning 'the teaching of forms'"}}]},{"name":"Schenkerian Analysis","v":4,"meta":{"def":"A method revealing the deep structural voice-leading beneath tonal surfaces.","ex":"Heinrich Schenker; the Ursatz; foreground/middleground/background","note":"Recent scholarship critically examines Schenker's own ethnonationalist views"},"children":[{"name":"The Ursatz","v":4,"meta":{"def":"The fundamental structure Schenker held to underlie every tonal masterpiece.","ex":"Fundamental line (3-2-1) over a bass arpeggiation I-V-I","note":"Schenker believed only a small canon of works displayed true organic unity"}},{"name":"Structural Levels","v":4,"meta":{"def":"The layered reduction from surface detail to underlying structure.","ex":"Foreground, middleground, background graphs","note":"Analysis is shown through specialised layered graphic notation"}}]},{"name":"Pitch-Class Set Theory","v":4,"meta":{"def":"A method for analysing atonal music using unordered collections of pitch classes.","ex":"Allen Forte; prime form, interval vectors, set classes","note":"Forte's 1973 book catalogued all set classes with 'Forte numbers'"},"children":[{"name":"Set Classes & Prime Form","v":4,"meta":{"def":"Grouping pitch collections into equivalence classes under transposition and inversion.","ex":"The '0,1,4' trichord; normal and prime form reduction","note":"There are exactly 220 set classes for 12-tone equal temperament"}},{"name":"Twelve-Tone & Serial Analysis","v":4,"meta":{"def":"Analysis of music built from ordered twelve-tone rows and their transformations.","ex":"Schoenberg's method; prime, retrograde, inversion, matrix","note":"A tone row and its transforms yield 48 possible ordered forms"}}]},{"name":"Figured Bass & Continuo","v":4,"meta":{"def":"The Baroque shorthand of numbers under a bass line indicating harmonies to improvise.","ex":"Realising a continuo part on harpsichord or organ","note":"Also called 'thoroughbass' or 'basso continuo'"},"children":[{"name":"Figure Realisation","v":4,"meta":{"def":"Interpreting the numeric figures to fill in the correct chords above the bass.","ex":"6/4, 7, and 4/2 figures; realising Corelli sonatas","note":"An unfigured bass leaves the harmony to the player's judgement"}},{"name":"Partimento","v":4,"meta":{"def":"An 18th-century method teaching composition through improvised keyboard bass patterns.","ex":"Neapolitan conservatory partimenti; Fenaroli, Durante","note":"Rediscovered by modern scholars (Gjerdingen) as a historical pedagogy"}}]},{"name":"Aural Skills & Ear Training","v":6,"meta":{"def":"Training the ear to recognise, sing and notate what one hears.","ex":"Interval recognition, melodic dictation, sight-singing","note":"A core lab component alongside written theory in most curricula"},"children":[{"name":"Interval & Chord Recognition","v":4,"meta":{"def":"Identifying intervals and chord qualities purely by ear.","ex":"Naming a minor sixth or a diminished-seventh chord on hearing it","note":"Learners often anchor intervals to familiar song openings"}},{"name":"Melodic & Harmonic Dictation","v":4,"meta":{"def":"Transcribing heard melodies and progressions into notation.","ex":"Writing down a played melody; identifying a chord progression","note":"A staple and often-feared component of theory exams"}},{"name":"Solfège","v":4,"meta":{"def":"A system of syllables for singing and internalising pitch relationships.","ex":"Do-re-mi-fa-sol-la-ti; fixed vs movable do","note":"Guido of Arezzo devised the original hexachord syllables around 1025"}},{"name":"Sight-Singing","v":4,"meta":{"def":"Singing written music accurately at first sight.","ex":"Sing melodies from a score using solfège or numbers","note":"Curwen hand signs give a physical cue for each scale degree"}},{"name":"Rhythmic Reading","v":4,"meta":{"def":"Reading and performing rhythms accurately by clapping or speaking.","ex":"Takadimi and Kodály rhythm syllables","note":"Different systems use 'ta', 'ti-ti' or number-based counting"}}]},{"name":"Sight-Reading","v":4,"meta":{"def":"Performing written music on an instrument at first encounter.","ex":"Graded sight-reading tests; accompanist sight-reading skill","note":"A distinct skill from repertoire practice, valued highly in accompanists"},"children":[{"name":"Instrumental Sight-Reading","v":4,"meta":{"def":"Playing unfamiliar notation fluently on one's instrument.","ex":"Pianists reading a new score in real time","note":"Skilled readers look ahead of the notes they are currently playing"}},{"name":"Score Reading","v":4,"meta":{"def":"Reading and playing from a multi-stave full or open score.","ex":"Reducing an orchestral score at the keyboard; transposing clefs","note":"Requires reading transposing instruments at concert pitch on the fly"}}]},{"name":"Conducting Study","v":4,"meta":{"def":"Learning the techniques of leading ensembles through gesture and score preparation.","ex":"Baton technique, score study, rehearsal craft","note":"Modern conducting emerged in the 19th century with Berlioz and Wagner"},"children":[{"name":"Baton Technique","v":4,"meta":{"def":"The physical gestures used to convey beat, tempo and dynamics.","ex":"Beat patterns for 2, 3, 4; cueing and cutoffs","note":"The left hand typically shapes expression while the right keeps time"}},{"name":"Score Study & Preparation","v":4,"meta":{"def":"In-depth analysis and memorisation of a score before rehearsal.","ex":"Marking cues, analysing form, planning interpretation","note":"Many conductors internalise the full score before the first rehearsal"}}]}]},{"name":"Teaching Methods & Approaches","v":12,"meta":{"def":"Structured pedagogical systems and formats used to teach music.","ex":"Suzuki, Kodály, Orff, Dalcroze, private lessons, masterclass","note":"The major 20th-century methods each grew from a single founder's philosophy"},"children":[{"name":"Suzuki Method","v":4,"meta":{"def":"A 'mother-tongue' approach teaching young children by ear before reading notation.","ex":"Shinichi Suzuki; Talent Education; parent involvement","note":"Founded on the idea that any child can learn music like a native language"},"children":[{"name":"Listening & Imitation","v":4,"meta":{"def":"Learning pieces by repeated listening and copying, delaying notation.","ex":"Daily recordings played at home; ear-first repertoire","note":"Reading is introduced only after basic playing is established"}},{"name":"Parental Involvement","v":4,"meta":{"def":"Parents attend lessons and supervise daily home practice.","ex":"The 'Suzuki triangle' of teacher, child and parent","note":"Parents sometimes learn the instrument first to model it"}}]},{"name":"Kodály Method","v":4,"meta":{"def":"A sequential approach centred on singing, folk song and musical literacy.","ex":"Zoltán Kodály; movable-do solfège; Curwen hand signs","note":"Built on Hungarian folk song as the child's musical mother tongue"},"children":[{"name":"Movable-Do Solfège","v":4,"meta":{"def":"Relative solfège where 'do' is the tonic of whatever key is used.","ex":"Singing scale degrees with hand signs and rhythm syllables","note":"Emphasises hearing pitches by their function within the key"}},{"name":"Folk Song Repertoire","v":4,"meta":{"def":"Use of authentic folk songs as the basis for teaching.","ex":"Pentatonic children's songs; graded folk material","note":"Kodály and Bartók collected thousands of Hungarian folk songs"}}]},{"name":"Orff Schulwerk","v":4,"meta":{"def":"An approach integrating music, movement, speech and improvisation for children.","ex":"Carl Orff & Gunild Keetman; Orff instruments (xylophones, metallophones)","note":"Named 'Schulwerk' meaning 'schoolwork' or teaching material"},"children":[{"name":"Elemental Music-Making","v":4,"meta":{"def":"Simple, rhythmic, participatory music combining speech, song and movement.","ex":"Body percussion; ostinato patterns; speech rhymes","note":"'Elemental' means basic, natural and close to play and dance"}},{"name":"Orff Instrumentarium","v":4,"meta":{"def":"The purpose-built barred percussion instruments used in the method.","ex":"Removable-bar xylophones, metallophones, glockenspiels","note":"Removable bars let children play without hitting wrong notes"}}]},{"name":"Dalcroze Eurhythmics","v":4,"meta":{"def":"Teaching music through bodily movement to develop rhythm and musicality.","ex":"Émile Jaques-Dalcroze; movement, solfège and improvisation","note":"The word 'eurhythmics' means 'good rhythm/flow'"},"children":[{"name":"Rhythmic Movement","v":4,"meta":{"def":"Expressing musical rhythm and phrasing through whole-body movement.","ex":"Walking the beat; embodying meter and dynamics","note":"The body is treated as the student's first instrument"}},{"name":"Dalcroze Solfège & Improvisation","v":4,"meta":{"def":"Ear training and keyboard improvisation integrated with movement.","ex":"Improvising responses to movement; fixed-do solfège","note":"The three pillars are eurhythmics, solfège and improvisation"}}]},{"name":"Gordon Music Learning Theory","v":4,"meta":{"def":"A research-based theory emphasising 'audiation' as the basis of musical understanding.","ex":"Edwin Gordon; tonal and rhythm pattern learning sequences","note":"Gordon coined 'audiation' for hearing and comprehending music mentally"},"children":[{"name":"Audiation","v":4,"meta":{"def":"The ability to hear and comprehend music not physically present.","ex":"Thinking in music the way one thinks in language","note":"Gordon deemed audiation the musical equivalent of thought"}},{"name":"Pattern Instruction","v":4,"meta":{"def":"Teaching through sequenced tonal and rhythm patterns.","ex":"Tonal and rhythm 'vocabulary' drilled before notation","note":"Learning sequences move from aural to notational stages"}}]},{"name":"El Sistema","v":4,"meta":{"def":"A Venezuelan model of intensive, free ensemble education for social change.","ex":"José Antonio Abreu; youth orchestras; Gustavo Dudamel","note":"Founded in 1975 and copied by 'Sistema-inspired' programmes worldwide"},"children":[{"name":"Ensemble-First Learning","v":4,"meta":{"def":"Children join an orchestra almost immediately, learning through group playing.","ex":"Núcleos (community music centres); daily rehearsals","note":"Social inclusion is treated as the primary goal, music the means"}},{"name":"Sistema-Inspired Programmes","v":4,"meta":{"def":"Global initiatives adapting El Sistema's model to other countries.","ex":"Sistema Scotland (Big Noise); YOLA in Los Angeles","note":"Adaptations vary widely in fidelity to the original model"}}]},{"name":"Yamaha Music Education","v":4,"meta":{"def":"A worldwide group-based curriculum starting young children on keyboard and singing.","ex":"Yamaha Music School; group keyboard classes from age 3-4","note":"Founded in Japan in the 1950s and now taught in dozens of countries"},"children":[{"name":"Group Keyboard Class","v":4,"meta":{"def":"Young children learn keyboard together in structured group settings.","ex":"Junior Music Course; ensemble keyboard playing","note":"Emphasises playing by ear and creativity before reading"}}]},{"name":"Private Lessons","v":4,"meta":{"def":"One-to-one instruction tailored to an individual student's development.","ex":"Weekly instrumental or vocal lessons with a studio teacher","note":"Still the dominant model for serious instrumental training worldwide"},"children":[{"name":"Studio Teaching","v":4,"meta":{"def":"A teacher's private studio of students following a shared pedagogical lineage.","ex":"Piano studio recitals; teacher 'schools' passed down generations","note":"Pedagogical lineages can be traced back through teacher genealogies"}},{"name":"Repertoire & Technique Coaching","v":4,"meta":{"def":"Guided work on pieces, technical exercises and interpretation.","ex":"Scales, études, and graded repertoire assignments","note":"Method books like Hanon and Czerny drill piano technique"}}]},{"name":"Group & Class Teaching","v":4,"meta":{"def":"Instruction of multiple students together in schools or workshops.","ex":"Classroom music; whole-class instrumental (WCET) schemes","note":"Whole-class instrumental teaching aims to give every child an instrument"},"children":[{"name":"Classroom Music","v":4,"meta":{"def":"General music education delivered to all pupils as part of schooling.","ex":"Singing, listening, composing in primary and secondary schools","note":"National curricula vary hugely in the status they give music"}},{"name":"Large-Ensemble Programmes","v":4,"meta":{"def":"School bands, orchestras and choirs as the vehicle for instruction.","ex":"American school band programme; concert and marching bands","note":"The US school band tradition is a distinctive model of mass music education"}}]},{"name":"Masterclass","v":4,"meta":{"def":"A public lesson where an expert coaches advanced students before an audience.","ex":"Visiting-artist masterclasses at conservatories and festivals","note":"Franz Liszt is often credited with popularising the format"},"children":[{"name":"Performance Coaching","v":4,"meta":{"def":"Detailed on-the-spot refinement of a prepared performance.","ex":"A soloist reworks phrasing under a maestro's guidance","note":"The audience learns vicariously alongside the performing student"}}]},{"name":"Peer & Online Learning","v":5,"meta":{"def":"Learning music from peers, communities and digital resources.","ex":"Band mentoring, YouTube tutorials, forums, apps","note":"Informal peer learning is how most popular musicians actually learn"},"children":[{"name":"Informal Peer Learning","v":4,"meta":{"def":"Musicians teaching each other within bands and communities without formal instruction.","ex":"Learning by ear from records; garage-band knowledge sharing","note":"Lucy Green's research documents how pop musicians learn informally"}},{"name":"Video Tutorials","v":4,"meta":{"def":"Learning technique and repertoire from online video demonstrations.","ex":"YouTube lessons; play-along and tab videos","note":"Has become the default first resource for self-taught players"}},{"name":"Interactive Learning Apps","v":4,"meta":{"def":"Software and apps that gamify practice with real-time feedback.","ex":"Yousician, Simply Piano, Flowkey, Melodics","note":"Many use pitch detection to score a learner's playing live"}}]},{"name":"Simply Music","v":4,"meta":{"def":"A playing-based piano method that teaches pieces before reading notation.","ex":"Neil Moore; 'playing-based' curriculum","note":"Students play repertoire early and learn to read music later"},"children":[{"name":"Playing-Based Sequence","v":4,"meta":{"def":"Learning to play a body of songs before tackling notation.","ex":"Pattern-based accompaniments; delayed reading","note":"Aims to reduce early dropout by producing quick musical results"}}]}]},{"name":"Institutions","v":10,"meta":{"def":"Organisations that provide formal and community music education.","ex":"Conservatoires, universities, music schools, youth orchestras","note":"The conservatory model spread across Europe in the 18th-19th centuries"},"children":[{"name":"Conservatoire / Conservatory","v":8,"meta":{"def":"A specialist institution training professional performers and composers to elite level.","ex":"Juilliard, Curtis, Paris, Moscow, Royal Academy","note":"The word derives from Italian orphanages ('conservatori') that trained foundlings in music"},"children":[{"name":"Juilliard School","v":4,"meta":{"def":"Leading US performing-arts conservatory in New York City.","ex":"Founded 1905; alumni include Yo-Yo Ma, Miles Davis, Renée Fleming","note":"Also trains dancers and actors alongside musicians"}},{"name":"Berklee College of Music","v":4,"meta":{"def":"The world's largest independent college of contemporary and popular music.","ex":"Boston; jazz, pop, film scoring, music business; Quincy Jones alumnus","note":"Founded 1945 with a then-radical focus on jazz and popular idioms"}},{"name":"Curtis Institute of Music","v":4,"meta":{"def":"A highly selective, fully tuition-free conservatory in Philadelphia.","ex":"Founded 1924; Leonard Bernstein, Lang Lang studied there","note":"Every admitted student receives a full-tuition scholarship"}},{"name":"Paris Conservatoire","v":4,"meta":{"def":"France's historic national conservatory, influential across European training.","ex":"Founded 1795; Berlioz, Debussy, Ravel connections","note":"Its solfège and harmony methods shaped conservatory pedagogy worldwide"}},{"name":"Moscow Conservatory","v":4,"meta":{"def":"Russia's premier conservatory and centre of the Russian performance tradition.","ex":"Founded 1866 by Nikolai Rubinstein; Tchaikovsky taught there","note":"Home to the International Tchaikovsky Competition"}},{"name":"Royal Academy & Royal College (London)","v":4,"meta":{"def":"Britain's leading London conservatoires training performers and composers.","ex":"RAM (1822) and RCM (1882); Elton John, Simon Rattle links","note":"London hosts several major conservatoires within a few miles"}},{"name":"Vienna & German Hochschulen","v":4,"meta":{"def":"The Austro-German university-level music academies at the heart of the classical tradition.","ex":"mdw Vienna; Hochschule für Musik in Berlin, Leipzig, Munich","note":"The German 'Musikhochschule' is the equivalent of a conservatoire"}}]},{"name":"University Music Departments","v":5,"meta":{"def":"Academic departments offering degrees combining scholarship and practice.","ex":"Oxford, Harvard, music BAs and research degrees","note":"Universities emphasise musicology and theory more than pure performance"},"children":[{"name":"Music Research Departments","v":4,"meta":{"def":"University units focused on musicological and theoretical research.","ex":"Doctoral programmes; research centres and journals","note":"Produce most of the field's peer-reviewed scholarship"}},{"name":"Ethnomusicology Programmes","v":4,"meta":{"def":"University units specialising in the study of world and vernacular music.","ex":"UCLA, SOAS, Indiana ethnomusicology programmes","note":"Often maintain their own world-music performance ensembles"}},{"name":"Composition Programmes","v":4,"meta":{"def":"University tracks training composers of concert and electroacoustic music.","ex":"University composition studios and electronic music labs","note":"Many house computer-music research centres such as CCRMA or IRCAM affiliates"}}]},{"name":"Community Music Schools","v":4,"meta":{"def":"Non-profit schools offering lessons and ensembles to the wider public of all ages.","ex":"Settlement music schools; local music academies","note":"Often subsidise tuition to widen access to music education"},"children":[{"name":"Settlement Music School Model","v":4,"meta":{"def":"Community schools rooted in the social-settlement movement serving diverse populations.","ex":"Settlement Music School, Philadelphia (1908)","note":"Among the largest community arts providers in the US"}},{"name":"Local Music Academies","v":4,"meta":{"def":"Independent neighbourhood schools offering graded lessons and exams.","ex":"After-school lessons; recital and exam preparation","note":"Frequently prepare students for graded exam boards"}}]},{"name":"Specialist Arts Schools","v":4,"meta":{"def":"Pre-college schools giving gifted young musicians intensive training alongside academics.","ex":"Purcell School; Interlochen; Chetham's; specialist music schools","note":"Some combine boarding education with conservatoire-level music training"},"children":[{"name":"Specialist Music Schools","v":4,"meta":{"def":"Secondary schools dedicated to training exceptionally talented young performers.","ex":"Yehudi Menuhin School; Chetham's School of Music","note":"The UK runs a government scheme funding places at such schools"}},{"name":"Summer Arts Camps & Academies","v":4,"meta":{"def":"Residential summer programmes offering intensive tuition and performance.","ex":"Interlochen; Aspen; Tanglewood; Verbier academies","note":"Often pair students with professional-orchestra faculty"}}]},{"name":"Youth Ensembles","v":4,"meta":{"def":"Orchestras and choirs training young musicians through ensemble performance.","ex":"National Youth Orchestra; Simón Bolívar Youth Orchestra","note":"Serve as a bridge between school music and professional careers"},"children":[{"name":"Youth Orchestras","v":4,"meta":{"def":"Auditioned orchestras giving young players full symphonic experience.","ex":"National Youth Orchestra of Great Britain; EUYO","note":"Many top professionals cite youth orchestra as formative"}},{"name":"Youth & Children's Choirs","v":4,"meta":{"def":"Choral programmes developing young singers and vocal literacy.","ex":"Cathedral choirs; Vienna Boys' Choir; children's choruses","note":"Cathedral chorister schools maintain a centuries-old training tradition"}}]}]},{"name":"Qualifications & Examinations","v":8,"meta":{"def":"Formal credentials and graded assessments certifying musical attainment.","ex":"ABRSM grades, diplomas, BMus, MMus, PhD, DMA","note":"Graded exam systems are especially strong in the UK and Commonwealth"},"children":[{"name":"Graded Music Exams","v":6,"meta":{"def":"A ladder of practical and theory exams from beginner to advanced levels.","ex":"Grades 1-8 in performance, plus supporting tests","note":"Higher grades can carry university entrance points in some countries"},"children":[{"name":"ABRSM","v":4,"meta":{"def":"The Associated Board of the Royal Schools of Music, a leading UK-based exam board.","ex":"Graded and diploma exams offered in over 90 countries","note":"Founded 1889 by the UK's royal conservatoires"}},{"name":"Trinity College London","v":4,"meta":{"def":"An international exam board known for flexible, performance-focused syllabuses.","ex":"Graded music, Rock & Pop, and diploma exams","note":"Lets candidates choose their own supporting tests in some grades"}},{"name":"RCM Examinations (Canada)","v":4,"meta":{"def":"The Royal Conservatory of Music's graded assessment system in North America.","ex":"Certificate Program; the ARCT diploma","note":"The RCM's US arm operates as the Music Development Program"}},{"name":"Rockschool & Contemporary Exams","v":4,"meta":{"def":"Graded exams designed specifically for rock and popular instruments.","ex":"Rockschool (RSL) guitar, bass, drums, vocals","note":"Brought graded-exam structure to electric guitar and drum kit"}}]},{"name":"Diplomas","v":4,"meta":{"def":"Post-grade professional qualifications in performance or teaching below degree level.","ex":"DipABRSM, LRSM, FRSM; LTCL diplomas","note":"Diploma recitals resemble a professional-standard concert"},"children":[{"name":"Performance Diplomas","v":4,"meta":{"def":"Advanced recital-based credentials certifying professional playing ability.","ex":"LRSM, FRSM, LTCL, FTCL","note":"The Fellowship (F-) level represents concert-artist standard"}},{"name":"Teaching Diplomas","v":4,"meta":{"def":"Qualifications certifying competence to teach an instrument or voice.","ex":"DipABRSM (Teaching); Certificate for Music Educators","note":"Combine a viva, written work and demonstration of teaching"}}]},{"name":"Undergraduate Degrees","v":4,"meta":{"def":"First university degrees in music, performance or production.","ex":"BMus, BA in Music, BFA, music-production BSc/BA","note":"The BMus is typically more practice-focused than a BA in Music"},"children":[{"name":"Bachelor of Music (BMus)","v":4,"meta":{"def":"A performance- or composition-focused undergraduate music degree.","ex":"Conservatoire BMus in performance, composition or jazz","note":"Usually requires a competitive audition for entry"}},{"name":"Music Production Degrees","v":4,"meta":{"def":"Undergraduate programmes in recording, mixing and music technology.","ex":"BSc/BA in Music Production, Audio Engineering, Tonmeister","note":"The Tonmeister combines deep musicianship with audio engineering"}},{"name":"Music Education Degrees","v":4,"meta":{"def":"Undergraduate degrees preparing qualified school music teachers.","ex":"BMusEd; combined music and teacher-certification programmes","note":"Often lead directly to a state teaching licence"}}]},{"name":"Postgraduate Degrees","v":5,"meta":{"def":"Advanced degrees in performance, composition, scholarship and pedagogy.","ex":"MMus, PhD, DMA, artist diplomas","note":"The DMA is a practice-based doctorate distinct from the research PhD"},"children":[{"name":"Master of Music (MMus)","v":4,"meta":{"def":"A postgraduate degree deepening performance, composition or scholarly specialism.","ex":"MMus in performance; artist master's programmes","note":"Often a stepping stone toward a professional solo or orchestral career"}},{"name":"PhD in Music","v":4,"meta":{"def":"A research doctorate producing an original scholarly dissertation.","ex":"PhD in musicology, theory, or ethnomusicology","note":"The standard qualification for a university teaching-research post"}},{"name":"Doctor of Musical Arts (DMA)","v":4,"meta":{"def":"A performance- or composition-based doctorate for practising musicians.","ex":"DMA recitals plus a document; common in the US","note":"Balances high-level performance with a written research component"}}]},{"name":"Teaching Certification","v":4,"meta":{"def":"Credentials licensing individuals to teach music in schools or studios.","ex":"State teaching licences; certificate for music educators","note":"Requirements for classroom teaching vary greatly by country"},"children":[{"name":"School Music Teacher Licensure","v":4,"meta":{"def":"State or national certification required to teach music in schools.","ex":"US state licensure; UK QTS with music specialism","note":"Usually requires supervised classroom practicum hours"}},{"name":"Method Teacher Certification","v":4,"meta":{"def":"Credentials issued by pedagogical method organisations to certify practitioners.","ex":"Suzuki, Kodály, Orff and Dalcroze teacher certification","note":"Often awarded in multiple levels through registered training courses"}}]}]},{"name":"Learning Paths & Skills","v":8,"meta":{"def":"The routes and skill sets individuals pursue to become musicians.","ex":"Instrumental study, composition, self-teaching, camps, mentorship","note":"Paths range from formal conservatoire training to entirely self-taught"},"children":[{"name":"Instrumental Study","v":5,"meta":{"def":"Systematic development of skill on a musical instrument.","ex":"Piano, violin, guitar, drums; scales, études, repertoire","note":"The '10,000 hours' idea popularised the role of sustained practice"},"children":[{"name":"Technique Development","v":4,"meta":{"def":"Building physical control, agility and tone on an instrument.","ex":"Scales, arpeggios, études by Czerny, Kreutzer","note":"Injury-prevention and ergonomics are a growing focus"}},{"name":"Repertoire Building","v":4,"meta":{"def":"Learning a body of pieces spanning styles and difficulty levels.","ex":"Standard concerto and sonata repertoire; audition lists","note":"Orchestral players prepare standard 'excerpt' passages for auditions"}},{"name":"Practice Methods","v":4,"meta":{"def":"Strategies for effective, focused and deliberate practice.","ex":"Slow practice, chunking, spaced repetition, mental practice","note":"Deliberate practice research stresses quality over sheer quantity"}}]},{"name":"Vocal Study","v":4,"meta":{"def":"Training the singing voice in technique, repertoire and health.","ex":"Classical voice, musical theatre, contemporary vocal training","note":"Voice teachers span classical bel canto to contemporary methods"},"children":[{"name":"Vocal Technique","v":4,"meta":{"def":"Development of breath support, resonance, range and registration.","ex":"Bel canto breathing; passaggio; belt vs head voice","note":"The 'passaggio' is the tricky register-transition zone"}},{"name":"Diction & Lyric Study","v":4,"meta":{"def":"Learning correct pronunciation and text interpretation in multiple languages.","ex":"IPA for singers; Italian, German, French lyric diction","note":"Singers routinely learn the International Phonetic Alphabet"}}]},{"name":"Composition Study","v":4,"meta":{"def":"Learning to create original music through craft and creative development.","ex":"Orchestration, form, notation software, private tutelage","note":"Historically taught via counterpoint and figured bass"},"children":[{"name":"Orchestration Study","v":4,"meta":{"def":"Learning to write idiomatically for instruments and combine their colours.","ex":"Rimsky-Korsakov and Adler orchestration treatises","note":"Ranges and transpositions of every instrument must be internalised"}},{"name":"Notation & Engraving","v":4,"meta":{"def":"Producing clear, professional scores and parts.","ex":"Sibelius, Finale, Dorico, MuseScore, LilyPond","note":"Good engraving follows conventions codified by publishers like Henle"}}]},{"name":"Music Production Education","v":5,"meta":{"def":"Learning to record, arrange, mix and produce music with technology.","ex":"DAWs, mixing, sound design, beat-making courses","note":"Much of it is now learned online outside formal institutions"},"children":[{"name":"DAW & Recording Skills","v":4,"meta":{"def":"Operating digital audio workstations to record and arrange music.","ex":"Ableton Live, Logic Pro, Pro Tools, FL Studio","note":"Ableton runs its own certified training programme"}},{"name":"Mixing & Mastering","v":4,"meta":{"def":"Balancing, processing and finalising recordings for release.","ex":"EQ, compression, reverb; loudness and LUFS standards","note":"Streaming platforms normalise loudness to around -14 LUFS"}},{"name":"Beat-Making & Sound Design","v":4,"meta":{"def":"Creating rhythms and synthesised sounds for electronic and hip-hop styles.","ex":"Sampling, drum programming, synthesis tutorials","note":"The MPC sampler became a foundational hip-hop production tool"}}]},{"name":"Self-Teaching","v":4,"meta":{"def":"Learning music independently without a regular teacher.","ex":"Method books, online resources, learning by ear","note":"Many celebrated popular musicians never had formal lessons"},"children":[{"name":"Learning by Ear","v":4,"meta":{"def":"Working out music directly from recordings without notation.","ex":"Transcribing solos; figuring out chords from records","note":"A core skill in jazz, blues and folk traditions"}},{"name":"Method Books & Tabs","v":4,"meta":{"def":"Self-study using printed methods, tablature and songbooks.","ex":"Guitar tab; Mel Bay and Hal Leonard method books","note":"Tablature shows finger positions rather than pitches"}}]},{"name":"Online Courses & Platforms","v":4,"meta":{"def":"Structured digital courses and subscription platforms for music learning.","ex":"Coursera, ArtistWorks, MasterClass, Berklee Online","note":"MOOCs opened conservatory-affiliated courses to global audiences"},"children":[{"name":"MOOCs & Video Courses","v":4,"meta":{"def":"Massive open or subscription courses taught by institutions and artists.","ex":"Berklee Online; Coursera music theory; MasterClass artists","note":"Some carry academic credit toward degrees"}},{"name":"Gamified Practice Apps","v":4,"meta":{"def":"Apps turning practice into games with feedback and progress tracking.","ex":"Yousician, Simply Piano, Melodics, Duolingo-style drills","note":"Use microphone or MIDI input to score playing in real time"}}]},{"name":"Music Camps","v":4,"meta":{"def":"Intensive residential or day programmes combining learning and performance.","ex":"Summer band camps; jazz workshops; rock 'schools of rock'","note":"Offer immersion and peer bonding hard to get in weekly lessons"},"children":[{"name":"Summer Music Camps","v":4,"meta":{"def":"Seasonal camps offering ensemble playing, lessons and concerts.","ex":"Interlochen Arts Camp; jazz and band camps","note":"Some run for over a century as summer institutions"}},{"name":"Genre Workshops","v":4,"meta":{"def":"Short intensive courses focused on a specific style or skill.","ex":"Jazz combo workshops; songwriting and rock camps","note":"Often culminate in a group performance or recording"}}]},{"name":"Apprenticeship & Mentorship","v":4,"meta":{"def":"Learning a craft by working closely under an experienced musician.","ex":"Guru-shishya tradition; band apprenticeships; assistantships","note":"In many oral traditions this is the primary mode of transmission"},"children":[{"name":"Guru-Shishya Parampara","v":4,"meta":{"def":"The Indian tradition of intimate, long-term learning from a master.","ex":"Living with the guru; oral transmission over years","note":"A 'gharana' is a stylistic lineage passed through such teaching"}},{"name":"Professional Mentorship","v":4,"meta":{"def":"Guidance from an established professional shaping a musician's career.","ex":"Assistantships; sideman apprenticeships; conducting fellowships","note":"Jazz sidemen historically learned on the bandstand with elders"}}]}]},{"name":"Music Therapy & Health","v":8,"meta":{"def":"Clinical and community uses of music to support health and wellbeing.","ex":"Music therapy, neurologic music therapy, GIM, music medicine","note":"Music therapy became a formal profession in the US after World War II"},"children":[{"name":"Clinical Music Therapy","v":5,"meta":{"def":"Use of music by trained therapists to meet therapeutic goals with clients.","ex":"Board-certified music therapists (MT-BC); NHS and hospital settings","note":"Requires accredited training and supervised clinical practice"},"children":[{"name":"Active Methods","v":4,"meta":{"def":"Therapy where clients make music through playing, singing or improvising.","ex":"Clinical improvisation; songwriting; instrument play","note":"Client music-making is the therapeutic medium, not performance"}},{"name":"Receptive Methods","v":4,"meta":{"def":"Therapy through guided listening and response to music.","ex":"Song-based reminiscence; relaxation listening","note":"Often used where clients cannot actively play"}},{"name":"Nordoff-Robbins Approach","v":4,"meta":{"def":"An improvisation-based approach centred on the 'music child' in everyone.","ex":"Creative Music Therapy; Paul Nordoff and Clive Robbins","note":"Originally developed working with disabled children"}}]},{"name":"Neurologic Music Therapy","v":4,"meta":{"def":"Research-based use of music to treat neurological injury and disease.","ex":"Michael Thaut; stroke, Parkinson's, brain-injury rehab","note":"Techniques are standardised and grounded in neuroscience research"},"children":[{"name":"Rhythmic Auditory Stimulation","v":4,"meta":{"def":"Using rhythmic cues to improve gait and movement in neurological patients.","ex":"Metronomic or musical cues for Parkinson's and stroke gait","note":"Rhythm helps entrain and regularise impaired walking patterns"}},{"name":"Melodic Intonation Therapy","v":4,"meta":{"def":"Using melody and rhythm to help aphasic patients regain speech.","ex":"Singing phrases to recover language after left-hemisphere stroke","note":"Exploits the right hemisphere's role in singing to bypass damage"}}]},{"name":"Guided Imagery and Music (GIM)","v":4,"meta":{"def":"A receptive, depth-therapy method using classical music to evoke imagery.","ex":"Helen Bonny; the Bonny Method of GIM","note":"Clients report evolving imagery while listening in a relaxed state"},"children":[{"name":"Bonny Method","v":4,"meta":{"def":"The original structured GIM protocol using curated music programmes.","ex":"Set 'music programmes' matched to therapeutic phases","note":"Developed by Helen Bonny in the 1970s"}}]},{"name":"Community Music Therapy","v":4,"meta":{"def":"A socially oriented practice using music-making to build community wellbeing.","ex":"Community choirs for health; participatory group work","note":"Blurs the line between therapy, community music and social work"},"children":[{"name":"Group Music-Making for Wellbeing","v":4,"meta":{"def":"Facilitated group singing or playing to support mental and social health.","ex":"Dementia singing groups; wellbeing choirs","note":"Group singing is linked to social bonding and mood benefits"}}]},{"name":"Music Medicine","v":4,"meta":{"def":"Medical use of music interventions, often delivered by healthcare staff.","ex":"Music for pain and anxiety in hospitals; pre-op relaxation","note":"Distinguished from music therapy by the absence of a trained therapist relationship"},"children":[{"name":"Music for Pain & Anxiety","v":4,"meta":{"def":"Using recorded or live music to reduce clinical pain and stress.","ex":"Music during surgery, dialysis, chemotherapy","note":"Trials suggest music can reduce perceived pain and sedative needs"}},{"name":"Music in Neonatal & Palliative Care","v":4,"meta":{"def":"Music interventions for premature infants and end-of-life care.","ex":"Live lullaby singing in NICUs; bedside palliative music","note":"NICU music is timed to support infant feeding and heart rate"}}]},{"name":"Performing Arts Medicine","v":4,"meta":{"def":"Medical care and research addressing musicians' occupational health.","ex":"Playing-related injuries; hearing loss; focal dystonia","note":"Musician's focal dystonia can end careers and resists easy treatment"},"children":[{"name":"Injury Prevention","v":4,"meta":{"def":"Ergonomics and habits protecting musicians from strain injuries.","ex":"Repetitive strain; posture; Alexander Technique","note":"The Alexander Technique is widely taught in conservatoires"}},{"name":"Hearing Conservation","v":4,"meta":{"def":"Protecting musicians' hearing from noise-induced damage.","ex":"Custom musician earplugs; monitoring stage sound levels","note":"Orchestral brass and percussion can exceed safe exposure limits"}}]}]},{"name":"Preservation & Scholarship Infrastructure","v":10,"meta":{"def":"The archives, libraries, editions and heritage frameworks that preserve music.","ex":"Sound archives, critical editions, UNESCO heritage, encyclopedias","note":"Preservation combines physical conservation with digital reformatting"},"children":[{"name":"Music Archives","v":5,"meta":{"def":"Repositories preserving manuscripts, papers and documents relating to music.","ex":"Composer archives; Paul Sacher Stiftung; label archives","note":"The Paul Sacher Foundation holds many 20th-century composers' manuscripts"},"children":[{"name":"Composer Manuscript Archives","v":4,"meta":{"def":"Collections of composers' autograph scores, sketches and letters.","ex":"Bach-Archiv Leipzig; Sacher Stiftung Basel","note":"Sketch material offers insight into the creative process"}},{"name":"Record Label Archives","v":4,"meta":{"def":"Corporate archives preserving master tapes and industry documents.","ex":"Universal, Sony vault collections; master-tape preservation","note":"A 2008 fire at Universal reportedly destroyed many original masters"}}]},{"name":"Sound Archives","v":5,"meta":{"def":"Institutions preserving audio recordings from cylinders to born-digital files.","ex":"British Library Sound Archive; Berlin Phonogramm-Archiv","note":"Obsolete formats race against media decay in a 'magnetic tape crisis'"},"children":[{"name":"Ethnographic Recording Collections","v":4,"meta":{"def":"Archives of field recordings documenting world and traditional music.","ex":"Berlin Phonogramm-Archiv; Lomax Archive; Smithsonian Folkways","note":"The Berlin archive's wax cylinders are UNESCO-listed"}},{"name":"Audio Preservation & Digitisation","v":4,"meta":{"def":"Reformatting fragile recordings to preserve their content digitally.","ex":"Cylinder and shellac transfer; IASA standards","note":"IASA sets international best-practice standards for audio archiving"}},{"name":"National Sound Archives","v":4,"meta":{"def":"State-level collections preserving a nation's recorded sound heritage.","ex":"British Library Sound Archive; US National Recording Registry","note":"The US Registry adds recordings deemed culturally significant each year"}}]},{"name":"Music Libraries","v":4,"meta":{"def":"Collections of scores, books and recordings supporting study and performance.","ex":"Conservatoire libraries; IAML; performance part libraries","note":"IAML is the international association of music libraries"},"children":[{"name":"Performance Material Libraries","v":4,"meta":{"def":"Collections of orchestral scores and parts loaned for performance.","ex":"Hire libraries; orchestral parts with bowings marked","note":"Publishers rent large-work parts rather than selling them"}},{"name":"Digital Score Repositories","v":4,"meta":{"def":"Online libraries providing free or licensed access to scores.","ex":"IMSLP (Petrucci Library); public-domain score collections","note":"IMSLP hosts hundreds of thousands of public-domain scores"}}]},{"name":"Critical Editions","v":4,"meta":{"def":"Scholarly editions establishing an authoritative text from all sources.","ex":"Neue Bach-Ausgabe; Urtext editions; complete-works projects","note":"'Urtext' aims to present the composer's intentions free of editorial additions"},"children":[{"name":"Complete Works Editions","v":4,"meta":{"def":"Multi-volume scholarly editions of a composer's entire output.","ex":"Neue Mozart-Ausgabe; Gesamtausgabe projects","note":"Such editions can take decades and many scholars to complete"}},{"name":"Urtext & Editorial Method","v":4,"meta":{"def":"The principles and apparatus behind establishing a reliable musical text.","ex":"Henle Urtext; critical commentary and variant readings","note":"A critical report documents every editorial decision made"}}]},{"name":"Discography & Cataloguing","v":4,"meta":{"def":"Systematic documentation and cataloguing of recordings and works.","ex":"Discographies; thematic catalogues; work numbering systems","note":"Köchel numbers (K.) catalogue Mozart's works chronologically"},"children":[{"name":"Thematic Catalogues","v":4,"meta":{"def":"Reference works numbering and identifying a composer's works.","ex":"Köchel (Mozart), BWV (Bach), Deutsch (Schubert)","note":"BWV stands for Bach-Werke-Verzeichnis, ordered by genre not date"}},{"name":"Recording Discographies","v":4,"meta":{"def":"Detailed listings documenting the recordings of artists or repertoire.","ex":"Jazz session discographies; label matrix numbers","note":"Matrix numbers etched in run-out grooves help date old discs"}}]},{"name":"Field Recording & Collecting","v":4,"meta":{"def":"Documenting living music traditions through on-site recording and collection.","ex":"Alan Lomax; Bartók's folk collecting; song collecting expeditions","note":"Early collectors used wax cylinders carried into remote areas"},"children":[{"name":"Folk Song Collecting","v":4,"meta":{"def":"Gathering and notating traditional songs from oral tradition.","ex":"Cecil Sharp in England and Appalachia; Bartók in Hungary","note":"Collectors sometimes 'cleaned up' songs, raising authenticity debates"}},{"name":"Ethnographic Field Recording","v":4,"meta":{"def":"Audio and video documentation of music in its cultural setting.","ex":"Lomax's global recordings; contemporary fieldwork archives","note":"Modern practice stresses consent and returning copies to communities"}}]},{"name":"Intangible Heritage & Cultural Policy","v":4,"meta":{"def":"Frameworks safeguarding living musical traditions as cultural heritage.","ex":"UNESCO Intangible Cultural Heritage lists; safeguarding programmes","note":"UNESCO's 2003 Convention created the intangible-heritage lists"},"children":[{"name":"UNESCO Intangible Heritage Listings","v":4,"meta":{"def":"International recognition of music traditions needing safeguarding.","ex":"Flamenco, fado, Georgian polyphony, reggae on the ICH lists","note":"Listing aims to raise awareness and support transmission"}},{"name":"Living Human Treasures","v":4,"meta":{"def":"National recognition of master tradition-bearers to ensure transmission.","ex":"Japan's Living National Treasures; Korea's holders of intangible assets","note":"Japan pioneered the concept in 1950 to protect master artisans"}}]},{"name":"Reference Works & Encyclopedias","v":4,"meta":{"def":"Authoritative dictionaries and encyclopedias documenting music knowledge.","ex":"Grove Dictionary; MGG; RILM bibliographies","note":"Grove has been the standard English music dictionary since 1879"},"children":[{"name":"Music Dictionaries & Encyclopedias","v":4,"meta":{"def":"Comprehensive reference works covering composers, works and terms.","ex":"New Grove Dictionary of Music and Musicians; MGG","note":"MGG stands for Die Musik in Geschichte und Gegenwart"}},{"name":"Bibliographies & Research Databases","v":4,"meta":{"def":"Indexes cataloguing scholarly writing and sources on music.","ex":"RILM Abstracts; RISM source inventory; JSTOR","note":"RISM catalogues surviving musical sources held worldwide"}}]}]}]}]};
